def _is_known_center_source(source: Any) -> bool:
    return str(source or "").strip() in VALID_KNOWN_CENTER_SOURCES


def _is_model_center_source(source: Any) -> bool:
    return str(source or "").strip() == "model_box_center"


def _is_robust_center_source(source: Any) -> bool:
    return _is_known_center_source(source) or _is_model_center_source(source)


def _is_known_yaw_source(source: Any) -> bool:
    return str(source or "").strip() in VALID_KNOWN_YAW_SOURCES


def _detection_box_like_shape(det: Dict[str, Any]) -> bool:
    col = det.get("collision_dims")
    if isinstance(col, dict):
        if is_box_like_known_shape(str(col.get("shape", ""))):
            return True
    label = str(det.get("label", "")).strip().lower()
    return label in STRICT_BOX_POSE_GATE_LABELS


def _to_float(value: Any) -> Optional[float]:
    try:
        if value is None:
            return None
        return float(value)
    except (TypeError, ValueError):
        return None


def _xyz_from_list(values: Any) -> Optional[Tuple[float, float, float]]:
    if not isinstance(values, (list, tuple)) or len(values) < 3:
        return None
    x = _to_float(values[0])
    y = _to_float(values[1])
    z = _to_float(values[2])
    if x is None or y is None or z is None:
        return None
    return (x, y, z)


class PerceptionToPregraspTest(Node):
    def __init__(self) -> None:
        super().__init__("perception_to_pregrasp_test")

        self._group_name = "arm"
        self._planning_frame = panda.base_link_name()
        self._target_link = "panda_hand"

        self.declare_parameter("target_label", "")
        self.declare_parameter("scene_id", "")
        self.declare_parameter("demo_golden_candidate_path", "")

        _early_target = str(self.get_parameter("target_label").value).strip()
        _early_scene = str(self.get_parameter("scene_id").value).strip()
        self._demo_profile = resolve_demo_profile(_early_scene, _early_target)
        if self._demo_profile is not None:
            _prof_params = dict(self._demo_profile.get("parameters") or {})
            if not _early_scene:
                _early_scene = str(_prof_params.get("scene_id") or "").strip()
            if not _early_target:
                _early_target = str(_prof_params.get("target_label") or "").strip()
            if _early_scene or _early_target:
                self._demo_profile = (
                    resolve_demo_profile(_early_scene, _early_target)
                    or self._demo_profile
                )
        self._demo_golden_candidate_path = ""
        self._demo_layout_version = ""
        _custom_golden_path = str(
            self.get_parameter("demo_golden_candidate_path").value
        ).strip()
        if _custom_golden_path:
            from panda_controller.demo_golden_pick_candidate import (
                resolve_golden_candidate_path,
            )

            self._demo_golden_candidate_path = resolve_golden_candidate_path(
                _custom_golden_path
            )
        if self._demo_profile:
            log_demo_profile_load(self.get_logger(), self._demo_profile)
            if not self._demo_golden_candidate_path:
                self._demo_golden_candidate_path = resolve_golden_path_from_profile(
                    self._demo_profile
                )
            self._demo_layout_version = str(
                self._demo_profile.get("layout_version") or ""
            ).strip()
        _pp = dict((self._demo_profile or {}).get("parameters") or {})

        def _pd(name: str, default: Any) -> Any:
            if name in _pp:
                return _pp[name]
            return default

