    def _init_early_demo_runtime_identity_attrs(self) -> None:
        """Atributos usados durante init de benchmark/cache antes de la hidratación completa."""
        self._scene_id = str(self.get_parameter("scene_id").value).strip()
        if not self._scene_id and self._demo_profile:
            self._scene_id = str(self._demo_profile.get("scene_id") or "").strip()

        self._place_slot_index = int(self.get_parameter("place_slot_index").value)
        prof_params = dict((self._demo_profile or {}).get("parameters") or {})
        profile_slot = prof_params.get("place_slot_index")
        if profile_slot is not None:
            slot_source = (
                "profile"
                if _values_equal(self._place_slot_index, profile_slot)
                else "cli"
            )
        elif self._place_slot_index == -1:
            slot_source = "default"
        else:
            slot_source = "cli"
        self.get_logger().info(
            "[PLACE_SLOT_INDEX_INIT]\n"
            "place_slot_index=%s\n"
            "source=%s\n"
            "result=OK"
            % (int(self._place_slot_index), slot_source)
        )

    def _call_perception_trigger_service(
        self, client: Any, service_name: str, log_label: str
    ) -> bool:
        if not self._pause_perception_during_execution:
            return True
        wait_sec = float(self._perception_service_wait_sec)
        retries = int(self._perception_service_retries)
        for attempt in range(1, retries + 1):
            if client.wait_for_service(timeout_sec=wait_sec):
                break
            if attempt < retries:
                time.sleep(0.4)
        else:
            self.get_logger().warn(
                "Servicio de percepcion no disponible tras %d intentos: %s "
                "(se mantiene snapshot logico congelado en el ejecutor)"
                % (retries, service_name)
            )
            return False
        req = Trigger.Request()
        future = client.call_async(req)
        spin_timeout = min(wait_sec + 0.25, 0.8)
        rclpy.spin_until_future_complete(self, future, timeout_sec=spin_timeout)
        if not future.done():
            self.get_logger().warn(
                "Timeout llamando %s (%.2fs); continuando con snapshot logico"
                % (service_name, spin_timeout)
            )
            return False
        try:
            result = future.result()
        except Exception as exc:
            self.get_logger().warn("%s fallo: %s" % (log_label, exc))
            return False
        if result is None:
            return False
        self.get_logger().info(
            "%s: success=%s msg=%s"
            % (log_label, str(result.success).lower(), result.message)
        )
        return bool(result.success)

    def _pause_perception_processing(self) -> None:
        if self._skip_pause_service_if_snapshot_locked and self._snapshot_locked:
            self.get_logger().info(
                "[PERCEPTION_PAUSE] omitido (snapshot ya congelado en ejecutor)"
            )
            return
        self._call_perception_trigger_service(
            self._perception_pause_client,
            self._perception_pause_service,
            "[PERCEPTION_PAUSE]",
        )

    def _resume_perception_processing(self) -> None:
        self._call_perception_trigger_service(
            self._perception_resume_client,
            self._perception_resume_service,
            "[PERCEPTION_RESUME]",
        )

    @staticmethod
    def _normalize_execution_mode(raw_mode: str) -> Tuple[str, Dict[str, bool]]:
        """Map execution_mode to a canonical name + boolean phase flags."""
        norm = (raw_mode or "").strip().lower()
        aliases = {
            "": "pick_place",
            "pregrasp_only": "pregrasp",
            "pregrasp": "pregrasp",
            "pregrasp_then_descend": "pregrasp_descend",
            "pregrasp_descend": "pregrasp_descend",
            "pregrasp_descend_close": "pregrasp_descend_close",
            "pregrasp_descend_close_lift": "pick_only",
            "pick": "pick_only",
            "pick_only": "pick_only",
            "pick_place": "pick_place",
            "pick_place_box": "pick_place",
            "full": "pick_place",
            "place": "pick_place",
            "place_debug_scan": "place_debug_scan",
        }
        canonical = aliases.get(norm, norm)
        valid_modes = (
            "pregrasp",
            "pregrasp_descend",
            "pregrasp_descend_close",
            "pick_only",
            "pick_place",
            "place_debug_scan",
        )
        if canonical not in valid_modes:
            valid_raw = sorted((set(valid_modes) | set(aliases.keys())) - {""})
            raise ValueError(
                "execution_mode inválido raw='%s' canonical='%s'. Modos válidos: %s"
                % (raw_mode, canonical, ", ".join(valid_raw))
            )
        flags = {
            "descend": canonical
            in (
                "pregrasp_descend",
                "pregrasp_descend_close",
                "pick_only",
                "pick_place",
            ),
            "close": canonical
            in (
                "pregrasp_descend_close",
                "pick_only",
                "pick_place",
            ),
            "attach": canonical in ("pick_only", "pick_place"),
            "lift": canonical in ("pick_only", "pick_place"),
            "place": canonical == "pick_place",
            "place_debug_scan": canonical == "place_debug_scan",
        }
        return canonical, flags

    def _setup_moveit(self) -> None:
        self._moveit2 = MoveIt2(
            node=self,
            joint_names=panda.joint_names(),
            base_link_name=panda.base_link_name(),
            end_effector_name=panda.end_effector_name(),
            group_name=self._group_name,
        )
        self._moveit2.max_velocity = self._max_vel
        self._moveit2.max_acceleration = self._max_acc
        self._moveit2.planning_time = self._planning_time
        self._moveit2.planner_id = self._planner_id
        self._moveit2.allowed_planning_time = self._allowed_planning_time
        self._moveit2.num_planning_attempts = self._planning_attempts
        try:
            self._moveit2.cartesian_avoid_collisions = bool(
                self._cartesian_avoid_collisions
            )
        except AttributeError:
            self.get_logger().warn(
                "pymoveit2 sin 'cartesian_avoid_collisions'; collision-checking cartesiano no garantizado."
            )
        try:
            self._moveit2.cartesian_fraction_threshold = float(
                self._cartesian_fraction_threshold
            )
        except AttributeError:
            self.get_logger().warn(
                "pymoveit2 sin 'cartesian_fraction_threshold'; no se forzara fraccion minima."
            )

        if self._tf_buffer is None:
            self._tf_buffer = Buffer()
            self._tf_listener = TransformListener(self._tf_buffer, self)

    def _setup_compute_cartesian_path_client(self) -> None:
        if self._compute_cartesian_path_client is not None:
            return
        self._compute_cartesian_path_client = self.create_client(
            GetCartesianPath,
            "compute_cartesian_path",
            qos_profile=QoSProfile(
                durability=QoSDurabilityPolicy.VOLATILE,
                reliability=QoSReliabilityPolicy.RELIABLE,
                history=QoSHistoryPolicy.KEEP_LAST,
                depth=1,
            ),
        )

    def _call_get_cartesian_path_from_joint_state(
        self,
        start_js: Any,
        hand_goal: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
        *,
        candidate_idx: Optional[int] = None,
        max_step: Optional[float] = None,
        jump_threshold: Optional[float] = None,
        avoid_collisions: Optional[bool] = None,
        start_state_source: Optional[str] = None,
        log_audit: bool = True,
    ) -> Tuple[Optional[float], int, Dict[str, Any]]:
        """GetCartesianPath con start_state explícito + auditoría de primer punto."""
        empty_audit: Dict[str, Any] = {
            "requested_start_js": None,
            "returned_first_point_js": None,
            "max_abs_delta_start_vs_first": None,
            "start_state_honored": None,
            "current_js_distance_to_requested_start": None,
            "fraction": None,
            "traj_pts": 0,
            "result": "NOT_EVALUATED",
            "start_state_source": start_state_source,
        }
        if self._moveit2 is None or start_js is None:
            self._last_get_cartesian_path_audit = empty_audit
            return None, 0, empty_audit

        self._setup_compute_cartesian_path_client()
        client = self._compute_cartesian_path_client
        if client is None:
            self._last_get_cartesian_path_audit = empty_audit
            return None, 0, empty_audit

        jump_thr = 0.0
        try:
            jump_thr = float(self._moveit2.cartesian_jump_threshold)
        except (AttributeError, TypeError, ValueError):
            pass
        if jump_threshold is not None:
            jump_thr = float(jump_threshold)
        eef_step = 0.0025
        if max_step is not None:
            eef_step = float(max_step)
        avoid = bool(self._cartesian_avoid_collisions)
        if avoid_collisions is not None:
            avoid = bool(avoid_collisions)

        req = build_get_cartesian_path_request(
            planning_frame=str(self._planning_frame),
            group_name=str(self._group_name),
            link_name=str(self._moveit_target_link),
            start_js=start_js,
            hand_goal=hand_goal,
            hand_quat=quat,
            max_step=float(eef_step),
            jump_threshold=float(jump_thr),
            avoid_collisions=bool(avoid),
        )
        if req is None:
            self._last_get_cartesian_path_audit = empty_audit
            return None, 0, empty_audit

        if not client.wait_for_service(timeout_sec=3.0):
            self.get_logger().warn(
                "Servicio compute_cartesian_path no disponible; "
                "validacion cartesiana paired abortada."
            )
            self._last_get_cartesian_path_audit = empty_audit
            return None, 0, empty_audit

        future = client.call_async(req)
        plan_timeout = max(3.0, float(self._planning_time) + 3.0)
        t_plan = time.monotonic()
        while not future.done() and time.monotonic() - t_plan < plan_timeout:
            rclpy.spin_once(self, timeout_sec=0.05)
        if not future.done():
            self._last_get_cartesian_path_audit = empty_audit
            return None, 0, empty_audit

        response = future.result()
        audit = evaluate_get_cartesian_path_start_state_audit(
            requested_start_js=start_js,
            response=response,
            current_js=self._current_arm_joint_state(),
        )
        audit["start_state_source"] = start_state_source
        audit["eef_step"] = float(eef_step)
        audit["jump_threshold"] = float(jump_thr)
        audit["avoid_collisions"] = bool(avoid)
        audit["link_name"] = str(self._moveit_target_link)
        audit["target_hand_pose"] = tuple(hand_goal)
        self._last_get_cartesian_path_audit = audit
        if log_audit:
            self.get_logger().info(
                format_get_cartesian_path_start_state_audit_log(
                    candidate_idx=candidate_idx,
                    audit=audit,
                    start_state_source=start_state_source,
                )
            )

        fraction = audit.get("fraction")
        traj_pts = int(audit.get("traj_pts", 0))
        if fraction is None:
            return None, traj_pts, audit
        return float(fraction), traj_pts, audit

    def _gripper_ctrl_state_cb(self, msg: JointTrajectoryControllerState) -> None:
        self._last_gripper_ctrl_state = msg

    def _joint_states_cache_cb(self, msg: JointState) -> None:
        self._last_joint_state_msg = msg

    def _read_gripper_finger_positions(self) -> Optional[Tuple[float, float]]:
        st = self._last_gripper_ctrl_state
        if st is not None and st.joint_names and st.actual.positions:
            try:
                names = list(st.joint_names)
                i1 = names.index("panda_finger_joint1")
                i2 = names.index("panda_finger_joint2")
            except ValueError:
                pass
            else:
                pos = list(st.actual.positions)
                if len(pos) > max(i1, i2):
                    return (float(pos[i1]), float(pos[i2]))
        js = self._last_joint_state_msg
        if js is None:
            return None
        name_to = {n: float(p) for n, p in zip(js.name, js.position)}
        if "panda_finger_joint1" not in name_to or "panda_finger_joint2" not in name_to:
            return None
        return (name_to["panda_finger_joint1"], name_to["panda_finger_joint2"])

    def _gripper_fingers_near_width(
        self, width_m: float, pair: Optional[Tuple[float, float]] = None
    ) -> bool:
        p = pair if pair is not None else self._read_gripper_finger_positions()
        if p is None:
            return False
        tol = self._gripper_state_tolerance
        return abs(p[0] - width_m) <= tol and abs(p[1] - width_m) <= tol

    def _wait_gripper_near_width(
        self, width_m: float
    ) -> Tuple[bool, Optional[Tuple[float, float]]]:
        deadline = time.monotonic() + self._gripper_state_timeout_sec
        tol = self._gripper_state_tolerance
        last_pair: Optional[Tuple[float, float]] = None
        while time.monotonic() < deadline:
            last_pair = self._read_gripper_finger_positions()
            if last_pair is not None:
                if (
                    abs(last_pair[0] - width_m) <= tol
                    and abs(last_pair[1] - width_m) <= tol
                ):
                    return True, last_pair
            try:
                rclpy.spin_once(self, timeout_sec=0.05)
            except Exception:
                break
        return False, last_pair

    def _mark_attempt(self) -> None:
        self._attempted_execution = True

    def _set_finished_after_skipped_pipeline(self) -> None:
        """Solo si no se encola snapshot (p. ej. plan_targets None)."""
        if self._execute_once or self._shutdown_when_finished:
            self._finished = True

    def _should_ignore_new_messages(self) -> bool:
        if self._finished:
            if self._execute_once and not self._logged_execute_once_ignore:
                self._logged_execute_once_ignore = True
                self.get_logger().info(
                    "execute_once=true: ya se intento una ejecucion; ignorando nuevos mensajes."
                )
            return True
        return False

    def _should_ignore_vision_updates(self) -> bool:
        if self._pipeline_running or self._snapshot_locked:
            if (
                self._execution_cycle_mode == "snapshot_execute_home"
                and not self._logged_cycle_ignore_updates
            ):
                self._logged_cycle_ignore_updates = True
                self.get_logger().info(
                    "[CYCLE] perception updates ignored during execution"
                )
            return True
        return False

    @staticmethod
    def _snapshot_center_str(candidate: Dict[str, Any]) -> str:
        ctb = candidate.get("chosen_target_center_base")
        if isinstance(ctb, (list, tuple)) and len(ctb) >= 3:
            return "(%.3f,%.3f,%.3f)" % (
                float(ctb[0]),
                float(ctb[1]),
                float(ctb[2]),
            )
        pos = candidate.get("position")
        if isinstance(pos, (list, tuple)) and len(pos) >= 3:
            return "(%.3f,%.3f,%.3f)" % (
                float(pos[0]),
                float(pos[1]),
                float(pos[2]),
            )
        return "n/a"

    def _execute_manual_target(self) -> None:
        candidate = {
            "label": "manual_target",
            "score": 1.0,
            "position": self._manual_target_pos,
            "chosen_target_center_base": self._manual_target_pos,
            "grasp_center_base": self._manual_target_pos,
            "grasp_center_source": "chosen_target_center",
            "approach_position": self._manual_target_pos,
            "top_z_m": self._manual_target_pos[2],
            "grasp_yaw_rad": 0.0,
            "source_frame": self._manual_frame,
        }
        targets = self._compute_pregrasp(candidate)
        if targets is None:
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return
        self._queue_snapshot_execution(candidate, targets, self._manual_frame)

    def _vision_callback(self, msg: String) -> None:
        if self._should_ignore_new_messages() or self._should_ignore_vision_updates():
            return
        if bool(getattr(self, "_clear_table_manual_abort", False)):
            self.get_logger().warning(
                "[CLEAR_TABLE_MANUAL_STEP] vision ignored: bootstrap failed or table complete"
            )
            return

        try:
            payload = json.loads(msg.data)
        except json.JSONDecodeError as exc:
            self.get_logger().warn(f"JSON invalido en /vision_to_executor: {exc}")
            return

        if not isinstance(payload, dict):
            self.get_logger().warn("Mensaje JSON ignorado: se esperaba objeto raiz (dict).")
            return

        detections, source_key = self._get_detection_list(payload)
        if source_key is None:
            self.get_logger().warn("No se encontro lista de objetos (objects/detections/results/items).")
            return

        if not self._first_message_logged:
            self._first_message_logged = True
            self._log_first_payload(payload, detections, source_key)

        self.get_logger().info(f"Lista encontrada en key='{source_key}' con {len(detections)} objetos.")
        self.get_logger().info(f"JSON recibido: {len(detections)} detecciones")

        candidate = self._pick_candidate(detections, payload)
        if candidate is None:
            self.get_logger().warn("Sin detecciones validas para este frame; no se mueve.")
            self._stable_count = 0
            self._stable_label = None
            self._stable_pos = None
            self._stable_yaw_rad = None
            return

        exec_objs = executor_objects_from_payload(payload, detections)
        scene_objs = (
            payload.get("scene_objects")
            if isinstance(payload, dict) and isinstance(payload.get("scene_objects"), list)
            else []
        )
        apply_demo_multiobject_target_pipeline(
            candidate,
            payload=payload if isinstance(payload, dict) else None,
            scene_objects=scene_objs,
            executor_objects=exec_objs,
            logger=self.get_logger(),
        )
        self._enrich_chips_can_runtime_pose_from_gazebo(candidate)
        if isinstance(scene_objs, list) and scene_objs:
            self._invalidate_stale_demo_completed_state(scene_objs)

        label = candidate["label"]
        score = candidate["score"]
        pos = candidate["position"]
        self.get_logger().info(
            "Deteccion candidata: label='%s', score=%.3f, position=(%.3f, %.3f, %.3f)"
            % (label, score, pos[0], pos[1], pos[2])
        )

        stab_yaw, stab_yaw_src = self._get_stability_grasp_yaw(candidate)
        if stab_yaw is not None:
            self.get_logger().info(
                "[STABILITY_YAW_SOURCE] source=%s yaw=%.4f rad (%.1f deg)"
                % (stab_yaw_src, stab_yaw, math.degrees(stab_yaw))
            )
        if not self._update_stability(label, pos, stab_yaw, candidate):
            return

        scene_obstacles = self._build_scene_obstacles_for_candidate(
            payload, candidate, detections
        )
        scene_obstacles = self._finalize_scene_obstacles_for_target(
            payload, candidate, scene_obstacles
        )
        candidate["scene_obstacles"] = scene_obstacles
        self._log_scene_objects_summary(payload, candidate, scene_obstacles)
        present_table_labels = resolve_present_table_labels(
            scene_objects=scene_objs if isinstance(scene_objs, list) else [],
            executor_objects=exec_objs,
            completed_entities=set(self._demo_completed_pick_entities),
            completed_labels=set(self._demo_completed_pick_labels),
        )
        self.get_logger().info(
            "[PRESENT_TABLE_LABELS]\n"
            "labels=%s\n"
            "source=%s\n"
            "completed_labels=%s"
            % (
                sorted(present_table_labels),
                "live_executor" if exec_objs else "scene_objects",
                sorted(self._demo_completed_pick_labels),
            )
        )
        self._apply_sugar_box_demo_scene_02_remaining_equivalent_policy(
            candidate, present_table_labels=present_table_labels
        )

        plan_targets = self._compute_pregrasp(candidate)
        if plan_targets is None:
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return

        if not self._validate_pose_quality_gate(candidate):
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return

        if not self._validate_gripper_width_margin_from_candidate(candidate):
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return

        if not self._validate_geometric_grasp(candidate):
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return

        if self._orientation_debug_only:
            quat_dbg = self._resolve_execution_quaternion(candidate)
            if quat_dbg is None:
                self.get_logger().error(
                    "[ORIENTATION_DEBUG_ONLY] Orientacion invalida o abortada; no se mueve el robot."
                )
            else:
                self.get_logger().info(
                    "[ORIENTATION_DEBUG_ONLY] Yaw calculado y log [YAW_DEBUG] emitido; "
                    "no se encola movimiento."
                )
            self._mark_attempt()
            self._set_finished_after_skipped_pipeline()
            return

        source_frame = str(payload.get("frame_id", self._planning_frame))
        stamp_sec = _to_float(payload.get("stamp_sec"))
        self._queue_snapshot_execution(
            candidate, plan_targets, source_frame, stamp_sec=stamp_sec
        )

    def _queue_snapshot_execution(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        *,
        stamp_sec: Optional[float] = None,
    ) -> None:
        frozen_candidate = copy.deepcopy(candidate)
        frozen_targets = copy.deepcopy(plan_targets)
        if self._scene_id and not frozen_candidate.get("scene_id"):
            frozen_candidate["scene_id"] = str(self._scene_id)
        label = str(frozen_candidate.get("label", ""))
        yaw = _to_float(frozen_candidate.get("grasp_yaw_rad"))
        stamp = float(stamp_sec) if stamp_sec is not None else time.time()
        with self._pipeline_lock:
            if self._pending_snapshot is not None:
                self.get_logger().info(
                    "Ya existe una ejecucion pendiente; se ignora snapshot nuevo."
                )
                return
            self._pending_snapshot = (frozen_candidate, frozen_targets, source_frame)
            self._snapshot_locked = True
            self._logged_cycle_ignore_updates = False
        self._pause_perception_processing()
        if self._execution_cycle_mode == "snapshot_execute_home":
            self.get_logger().info(
                "[CYCLE] snapshot locked label=%s stamp=%.3f yaw=%s center=%s"
                % (
                    label,
                    stamp,
                    "n/a" if yaw is None else "%.3f" % yaw,
                    self._snapshot_center_str(frozen_candidate),
                )
            )
        self.get_logger().info(
            "Snapshot estable encolado para ejecucion sincrona desde main loop."
        )

    def _run_pick_workspace_prelude(self) -> bool:
        if not self._enable_pick_workspace_prelude:
            return True
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                "[PICK_PRELUDE] dry_run o MoveIt no listo; omitiendo preludio articulado."
            )
            return True
        wp = self._pick_workspace_prelude_waypoint
        self.get_logger().info("[PICK_PRELUDE] moving to %s" % wp)
        self.get_logger().info(
            "[PICK_PRELUDE] snapshot was taken before arm entered camera view"
        )
        self._reload_motion_waypoints()
        if not waypoint_is_configured(self._motion_waypoints_data, wp):
            self.get_logger().warn(
                "[PICK_PRELUDE] waypoint '%s' no configurado en YAML; "
                "continuando sin preludio."
                % wp
            )
            return True
        backend = self._pick_workspace_prelude_backend
        ok = False
        if backend == "direct_action":
            traj = JointTrajectory()
            traj.joint_names = list(PANDA_ARM_JOINT_NAMES)
            joints = get_waypoint_joint_positions(self._motion_waypoints_data, wp)
            if joints is None:
                return True
            point = JointTrajectoryPoint()
            point.positions = [float(v) for v in joints]
            point.time_from_start = self._duration_from_seconds(
                self._pick_workspace_prelude_time_sec
            )
            traj.points = [point]
            ok, _, _, _ = self._send_arm_follow_joint_trajectory(traj)
        else:
            ok = self._move_to_joint_waypoint(
                wp,
                velocity_scaling=self._joint_waypoint_vel,
                acceleration_scaling=self._joint_waypoint_acc,
            )
        self.get_logger().info("[PICK_PRELUDE] result=%s" % ("OK" if ok else "FAIL"))
        if ok:
            self._golden_execution_capture_snapshot("pick_workspace_ready_js")
        if not ok and self._abort_if_pick_workspace_prelude_fails:
            return False
        return True

    @staticmethod
    def _is_stale_planning_scene_collision_id(col_id: str) -> bool:
        """IDs de targets/obstáculos de ejecuciones anteriores (no mesa ni Gazebo)."""
        cid = str(col_id or "").strip()
        if not cid or cid == "vision_test_table":
            return False
        if cid.startswith("target_runtime_ycb_"):
            return True
        if cid.startswith("target_"):
            return True
        if cid.startswith("obstacle_"):
            return True
        return False

    def _force_detach_planning_scene_object(self, object_id: str) -> bool:
        oid = str(object_id or "").strip()
        if not oid:
            return False
        try:
            co = CollisionObject()
            co.id = oid
            co.operation = CollisionObject.REMOVE
            attached = AttachedCollisionObject()
            attached.link_name = self._attach_object_link
            attached.object = co
            scene = PlanningScene()
            scene.is_diff = True
            scene.robot_state.is_diff = True
            scene.robot_state.attached_collision_objects = [attached]
            self._planning_scene_pub.publish(scene)
            return True
        except Exception:
            return False

    def _planning_scene_cleanup_on_start(self) -> Tuple[List[str], List[str]]:
        """Quita collision objects/attach stale del PlanningScene; no toca Gazebo."""
        removed_collision: List[str] = []
        detached_ids: List[str] = []
        if self._moveit2 is None or self._dry_run:
            return removed_collision, detached_ids

        stale_ids = sorted(
            {
                str(oid)
                for oid in self._planning_scene_object_ids
                if self._is_stale_planning_scene_collision_id(str(oid))
            }
        )
        for oid in stale_ids:
            self._force_detach_planning_scene_object(oid)
            detached_ids.append(oid)
            self._remove_collision_object(oid)
            removed_collision.append(oid)
            time.sleep(max(0.0, float(self._planning_scene_settle_after_remove_s)))

        extra_detach: List[str] = []
        for raw in (
            self._current_target_collision_id,
            self._last_target_collision_id,
        ):
            oid = str(raw or "").strip()
            if oid and oid not in detached_ids:
                extra_detach.append(oid)
        spec = self._current_target_collision_spec
        if isinstance(spec, dict):
            sid = str(spec.get("id") or "").strip()
            if sid and sid not in extra_detach:
                extra_detach.append(sid)
        for oid in extra_detach:
            if self._force_detach_planning_scene_object(oid):
                if oid not in detached_ids:
                    detached_ids.append(oid)
            if oid in self._planning_scene_object_ids:
                self._remove_collision_object(oid)
                if oid not in removed_collision:
                    removed_collision.append(oid)

        return removed_collision, detached_ids

    def _execution_state_reset_on_start(self) -> None:
        """Limpia estado interno y PlanningScene al iniciar cada pick_place."""
        self.get_logger().info("[EXECUTION_STATE_RESET] begin")
        self._golden_execution_record_init()
        self._preplanned_pick_route = None
        self._stop_gazebo_physical_attach(restore_physics=True)
        if self._current_target_attached:
            self._detach_target_object_after_place()
        self._current_attached_object_id = None
        self._current_target_attached = False
        self._attached_object_recovery_hold = False
        self._attached_object_recovery_mode = ""
        self._current_target_collision_id = None
        self._last_target_collision_id = None
        self._current_target_collision_spec = None
        self._current_target_entity_name = ""
        self._last_gazebo_attach_service_success = False
        self._last_planning_scene_attach_ok = False
        self._last_attach_executed = False
        removed_collision, detached_ids = self._planning_scene_cleanup_on_start()
        self.get_logger().info(
            "[PLANNING_SCENE_CLEANUP_ON_START]\n"
            "removed_collision_ids=%s\n"
            "detached_ids=%s\n"
            "gazebo_models_deleted=false\n"
            "runtime_scene_cleared=false\n"
            "result=OK"
            % (removed_collision, detached_ids)
        )
        self.get_logger().info("[EXECUTION_STATE_RESET] result=OK")

    def _wait_post_prelude_arm_and_tf_stable(self) -> bool:
        if self._dry_run or self._moveit2 is None:
            return True
        timeout = float(self._post_prelude_joint_stable_timeout_sec)
        poll = float(self._post_prelude_joint_stable_poll_sec)
        tol = float(self._post_prelude_joint_stable_tolerance_rad)
        deadline = time.time() + timeout
        prev_js: Optional[JointState] = None
        stable_reads = 0
        while time.time() < deadline:
            cur = self._current_arm_joint_state()
            if cur is None:
                cur = self._last_joint_state_msg
            if cur is not None and prev_js is not None:
                delta = self._joint_state_weighted_distance(cur, prev_js)
                if delta <= tol:
                    stable_reads += 1
                else:
                    stable_reads = 0
                if stable_reads >= 1:
                    break
            prev_js = cur
            time.sleep(poll)
        if not self._wait_tf_ready_for_pick():
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN] TF not stable after pick_workspace_ready"
            )
            return False
        if self._set_start_state_to_current_before_planning:
            self._try_set_start_state_to_current()
        return True

    def _try_pregrasp_ik_plan_from_start_js(
        self,
        *,
        pre_plan: Tuple[float, float, float],
        start_js: Any,
        base_yaw: float,
        variant_label: str,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> Optional[Dict[str, Any]]:
        if self._moveit2 is None:
            return None
        if candidate is not None and self._is_mustard_short_axis_candidate(candidate):
            self._ensure_mustard_axis_mapping(candidate)
            mustard_pick = self._select_best_mustard_yaw_variant(
                candidate,
                base_yaw,
                pre_plan,
                start_js,
                require_plan_ok=True,
            )
            if mustard_pick is None:
                return None
            qname, q, cmd_yaw, ik_sol, _dist, _score, plan_ok = mustard_pick
            return {
                "variant_name": qname,
                "yaw_variant": variant_label or qname,
                "quat": q,
                "commanded_yaw_rad": float(cmd_yaw),
                "ik_ok": ik_sol is not None,
                "plan_ok": bool(plan_ok),
                "ik_joint_state": ik_sol,
            }
        if candidate is not None and self._is_chips_can_cylinder_topdown_candidate(
            candidate
        ):
            return self._pick_chips_can_yaw_free_pregrasp_ik_plan(
                candidate,
                pre_plan,
                start_js,
                base_yaw,
                pregrasp_tcp_z=float(pre_plan[2]),
                variant_label=variant_label,
                require_plan_ok=True,
            )
        if (
            candidate is not None
            and self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate)
        ):
            return self._pick_sugar_box_yaw_free_pregrasp_ik_plan(
                candidate,
                pre_plan,
                start_js,
                base_yaw,
                pregrasp_tcp_z=float(pre_plan[2]),
                variant_label=variant_label,
                require_plan_ok=True,
            )
        ori_tol = float(self._plan_before_prelude_orientation_tolerance)
        ranked = self._ranked_downward_yaw_variants_for_pose(
            base_yaw, pre_plan, start_js
        )
        for qname, q, cmd_yaw, ik_sol, _dist in ranked:
            if ik_sol is None:
                continue
            try:
                pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                traj = self._moveit2.plan(
                    position=list(pre_moveit),
                    quat_xyzw=list(q),
                    frame_id=self._planning_frame,
                    target_link=self._moveit_target_link,
                    start_joint_state=ik_sol,
                    tolerance_orientation=ori_tol,
                )
            except Exception:
                traj = None
            if traj is None:
                continue
            return {
                "variant_name": qname,
                "yaw_variant": variant_label or qname,
                "quat": q,
                "commanded_yaw_rad": float(cmd_yaw),
                "ik_ok": True,
                "plan_ok": True,
            }
        return None

    def _post_prelude_pregrasp_replan(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
    ) -> bool:
        """Revalida pregrasp desde la postura real tras pick_workspace_ready (opción 2)."""
        label = str(candidate.get("label", ""))
        wp = self._pick_workspace_prelude_waypoint
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                "[POST_PRELUDE_PREGRASP_REPLAN] label=%s result=SKIP dry_run_or_no_moveit"
                % label
            )
            return True
        if not self._enable_pick_workspace_prelude:
            return True

        if not self._wait_post_prelude_arm_and_tf_stable():
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN]\n"
                "label=%s\n"
                "start_state_source=current_joint_state_after_prelude\n"
                "waypoint=%s\n"
                "result=FAIL\n"
                "reason=arm_or_tf_not_stable"
                % (label, wp)
            )
            return False

        if (
            bool(candidate.get("_demo_golden_fast_execute"))
            or bool(candidate.get("_chips_can_legacy_success_policy_prevalidated"))
            or bool(candidate.get("_chips_can_legacy_pending_actual_tf_descend"))
            or bool(candidate.get("_pick_route_execute_cached"))
        ):
            candidate["_post_prelude_pregrasp_locked"] = True
            candidate["_pick_route_execute_cached"] = True
            pre_tcp = plan_targets.get("pregrasp_tcp")
            pre_tcp_str = (
                "n/a"
                if not isinstance(pre_tcp, (list, tuple)) or len(pre_tcp) < 3
                else "(%.3f, %.3f, %.3f)"
                % (float(pre_tcp[0]), float(pre_tcp[1]), float(pre_tcp[2]))
            )
            self.get_logger().info(
                "[POST_PRELUDE_PREGRASP_REPLAN]\n"
                "label=%s\n"
                "start_state_source=current_joint_state_after_prelude\n"
                "waypoint=%s\n"
                "pregrasp_tcp=%s\n"
                "yaw_variant=prevalidated_golden\n"
                "ik_ok=skip\n"
                "plan_ok=skip\n"
                "result=OK\n"
                "reason=prevalidated_pick_route_preserved"
                % (label, wp, pre_tcp_str)
            )
            return True

        start_js = self._current_arm_joint_state()
        if start_js is None:
            start_js = self._last_joint_state_msg
        if start_js is None:
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN] label=%s result=FAIL reason=no_start_js"
                % label
            )
            return False

        candidate.pop("_plan_before_motion_validated", None)
        base_cmd_raw = candidate.get("_base_commanded_tcp_yaw_rad")
        if base_cmd_raw is None:
            base_cmd_raw = candidate.get("_final_tcp_yaw_rad")
        try:
            base_yaw = float(base_cmd_raw) if base_cmd_raw is not None else 0.0
        except (TypeError, ValueError):
            base_yaw = 0.0

        self._apply_reachable_pregrasp_resolution(
            candidate=candidate,
            plan_targets=plan_targets,
            source_frame=source_frame,
            base_yaw=base_yaw,
            start_js=start_js,
        )
        if not self._verify_mustard_scanner_aligned_post_reachability_or_abort(
            candidate, plan_targets
        ):
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN] label=%s result=FAIL "
                "reason=mustard_scanner_contract_overwritten_after_verify"
                % label
            )
            return False

        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if not isinstance(pre_tcp, (list, tuple)) or len(pre_tcp) < 3:
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN] label=%s result=FAIL reason=missing_pregrasp"
                % label
            )
            return False
        grasp_z = float(gr_tcp[2]) if isinstance(gr_tcp, (list, tuple)) and len(gr_tcp) >= 3 else float(pre_tcp[2])
        base_pre_xy = (float(pre_tcp[0]), float(pre_tcp[1]))
        base_pre_z = float(pre_tcp[2])

        def _attempt_at_pre_z(
            pre_z: float, attempt_label: str
        ) -> Optional[Dict[str, Any]]:
            pre_try = (base_pre_xy[0], base_pre_xy[1], float(pre_z))
            plan_targets["pregrasp_tcp"] = pre_try
            self._sync_plan_targets_after_pregrasp_update(candidate, plan_targets)
            pre_plan, _ = self._transform_target_to_planning_frame(
                pre_try, source_frame, stage="post_prelude_pregrasp"
            )
            if pre_plan is None:
                return None
            return self._try_pregrasp_ik_plan_from_start_js(
                pre_plan=pre_plan,
                start_js=start_js,
                base_yaw=base_yaw,
                variant_label=attempt_label,
                candidate=candidate,
            )

        attempts_order: List[Tuple[str, float]] = [
            ("top_down_yaw_variants", base_pre_z)
        ]
        if not mustard_scanner_aligned_pregrasp_locked(candidate):
            for dz in self._post_prelude_pregrasp_z_raise_steps_m:
                attempts_order.append(
                    ("pregrasp_tcp_z_plus_%.2f" % float(dz), base_pre_z + float(dz))
                )

        winner: Optional[Dict[str, Any]] = None
        winner_pre_z = float(pre_tcp[2])
        for attempt_label, pre_z in attempts_order:
            if pre_z < grasp_z + 1e-6:
                continue
            hit = _attempt_at_pre_z(pre_z, attempt_label)
            if hit is not None:
                winner = hit
                winner_pre_z = pre_z
                break

        if winner is None:
            safe_tcp = plan_targets.get("safe_pregrasp_tcp")
            if safe_tcp is None:
                obj_safe = candidate.get("object_safe_above_tcp")
                if isinstance(obj_safe, (list, tuple)) and len(obj_safe) >= 3:
                    safe_tcp = (
                        float(obj_safe[0]),
                        float(obj_safe[1]),
                        float(obj_safe[2]),
                    )
            if isinstance(safe_tcp, (list, tuple)) and len(safe_tcp) >= 3:
                safe_plan, _ = self._transform_target_to_planning_frame(
                    safe_tcp, source_frame, stage="post_prelude_safe_above"
                )
                if safe_plan is not None:
                    ranked_safe = self._ranked_downward_yaw_variants_for_pose(
                        base_yaw, safe_plan, start_js
                    )
                    ori_tol = float(self._plan_before_prelude_orientation_tolerance)
                    for qname, q, cmd_yaw, ik_safe, _dist in ranked_safe:
                        if ik_safe is None:
                            continue
                        try:
                            safe_moveit = self._tcp_pose_to_moveit_pose(safe_plan, q)
                            traj_safe = self._moveit2.plan(
                                position=list(safe_moveit),
                                quat_xyzw=list(q),
                                frame_id=self._planning_frame,
                                target_link=self._moveit_target_link,
                                start_joint_state=ik_safe,
                                tolerance_orientation=ori_tol,
                            )
                        except Exception:
                            traj_safe = None
                        if traj_safe is None:
                            continue
                        pre_plan, _ = self._transform_target_to_planning_frame(
                            plan_targets["pregrasp_tcp"],
                            source_frame,
                            stage="post_prelude_safe_to_pre",
                        )
                        if pre_plan is None:
                            continue
                        hit = self._try_pregrasp_ik_plan_from_start_js(
                            pre_plan=pre_plan,
                            start_js=ik_safe,
                            base_yaw=base_yaw,
                            variant_label="safe_above_to_pregrasp",
                        )
                        if hit is not None:
                            winner = hit
                            winner_pre_z = float(plan_targets["pregrasp_tcp"][2])
                            winner["yaw_variant"] = "safe_above_tcp_to_pregrasp"
                            break

        pre_tcp_final = plan_targets.get("pregrasp_tcp")
        pre_tcp_str = (
            "n/a"
            if not isinstance(pre_tcp_final, (list, tuple)) or len(pre_tcp_final) < 3
            else "(%.3f, %.3f, %.3f)"
            % (
                float(pre_tcp_final[0]),
                float(pre_tcp_final[1]),
                float(winner_pre_z if winner else pre_tcp_final[2]),
            )
        )
        if winner is None:
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_REPLAN]\n"
                "label=%s\n"
                "start_state_source=current_joint_state_after_prelude\n"
                "waypoint=%s\n"
                "pregrasp_tcp=%s\n"
                "yaw_variant=n/a\n"
                "ik_ok=false\n"
                "plan_ok=false\n"
                "result=FAIL"
                % (label, wp, pre_tcp_str)
            )
            return False

        win_variant = str(winner.get("variant_name", "post_prelude"))
        win_quat = tuple(winner["quat"])
        win_yaw = float(winner.get("commanded_yaw_rad", base_yaw))
        self._store_plan_before_motion_validated_pregrasp(
            candidate,
            variant_name=win_variant,
            quat=win_quat,
            commanded_yaw_rad=win_yaw,
        )
        if self._is_mustard_short_axis_candidate(candidate):
            candidate["_mustard_post_prelude_yaw_variant"] = win_variant
            candidate["_mustard_post_prelude_commanded_tcp_yaw_rad"] = float(win_yaw)
            candidate["_mustard_post_prelude_quat"] = [
                float(win_quat[0]),
                float(win_quat[1]),
                float(win_quat[2]),
                float(win_quat[3]),
            ]
            self._lock_mustard_yaw_for_execution(
                candidate,
                variant_name=win_variant,
                quat=win_quat,
                commanded_tcp_yaw_rad=win_yaw,
                ik_joint_state=winner.get("ik_joint_state"),
            )
        candidate["_post_prelude_pregrasp_locked"] = True
        self.get_logger().info(
            "[POST_PRELUDE_PREGRASP_REPLAN]\n"
            "label=%s\n"
            "start_state_source=current_joint_state_after_prelude\n"
            "waypoint=%s\n"
            "pregrasp_tcp=%s\n"
            "yaw_variant=%s\n"
            "ik_ok=%s\n"
            "plan_ok=%s\n"
            "result=OK"
            % (
                label,
                wp,
                pre_tcp_str,
                str(winner.get("yaw_variant", winner.get("variant_name", "?"))),
                str(bool(winner.get("ik_ok"))).lower(),
                str(bool(winner.get("plan_ok"))).lower(),
            )
        )
        return True

    def _joint_state_for_waypoint(self, waypoint_name: str) -> Optional[JointState]:
        self._reload_motion_waypoints()
        joints = get_waypoint_joint_positions(self._motion_waypoints_data, waypoint_name)
        if joints is None:
            return None
        js = JointState()
        js.name = list(PANDA_ARM_JOINT_NAMES)
        js.position = [float(v) for v in joints]
        return js

    def _arm_only_joint_state(self, js: Any) -> Optional[JointState]:
        """Extrae panda_joint1..7 en orden fijo; ignora dedos/gripper."""
        if js is None:
            return None
        try:
            names = list(js.name)
            positions = [float(v) for v in js.position]
        except (TypeError, ValueError, AttributeError):
            return None
        pos_map = {str(n): float(p) for n, p in zip(names, positions)}
        out = JointState()
        out.name = list(PANDA_ARM_JOINT_NAMES)
        out.position = []
        for name in PANDA_ARM_JOINT_NAMES:
            if name not in pos_map:
                return None
            out.position.append(float(pos_map[name]))
        return out

    def _current_arm_joint_state(self) -> Optional[JointState]:
        if self._moveit2 is None:
            return None
        js = getattr(self._moveit2, "joint_state", None)
        if js is None or not getattr(js, "position", None):
            return None
        return self._arm_only_joint_state(js)

    def _pregrasp_quaternion_variants(
        self, yaw_rad: float
    ) -> List[Tuple[str, Tuple[float, float, float, float]]]:
        y = float(yaw_rad)
        return [
            ("top_down_yaw", self._downward_yaw_quaternion(y)),
            (
                "top_down_yaw_pi",
                self._downward_yaw_quaternion(self._wrap_to_pi(y + math.pi)),
            ),
        ]

    @staticmethod
    def _commanded_gap_axis_xy_from_tcp_yaw(
        tcp_yaw_rad: float, local_gap_xy: np.ndarray
    ) -> np.ndarray:
        cf = math.cos(float(tcp_yaw_rad))
        sf = math.sin(float(tcp_yaw_rad))
        lx = float(local_gap_xy[0])
        ly = float(local_gap_xy[1])
        out = np.array(
            [cf * lx - sf * ly, sf * lx + cf * ly],
            dtype=np.float64,
        )
        n = float(np.linalg.norm(out))
        if n > 1e-9:
            out = out / n
        return out

    def _joint_state_weighted_distance(self, a: Any, b: Any) -> float:
        a_arm = self._arm_only_joint_state(a)
        b_arm = self._arm_only_joint_state(b)
        if a_arm is None or b_arm is None:
            return float("inf")
        try:
            a_map = {
                n: float(p)
                for n, p in zip(list(a_arm.name), list(a_arm.position))
            }
            b_map = {
                n: float(p)
                for n, p in zip(list(b_arm.name), list(b_arm.position))
            }
        except (TypeError, ValueError, AttributeError):
            return float("inf")
        wrist = ("panda_joint6", "panda_joint7")
        total = 0.0
        for name in PANDA_ARM_JOINT_NAMES:
            if name not in a_map or name not in b_map:
                continue
            delta = self._wrap_to_pi(float(a_map[name]) - float(b_map[name]))
            w = 3.0 if name in wrist else 1.0
            total += w * abs(delta)
        return float(total)

    def _ranked_downward_yaw_variants_for_pose(
        self,
        base_commanded_tcp_yaw: float,
        tcp_pose_planning: Tuple[float, float, float],
        start_js: Any,
    ) -> List[Tuple[str, Tuple[float, float, float, float], float, Any, float]]:
        """Variantes yaw+pi ordenadas por distancia articular (prioriza j6/j7)."""
        phys = float(self._gripper_physical_yaw_correction_rad)
        ranked: List[Tuple[float, str, Tuple[float, float, float, float], float, Any]] = []
        for delta in (0.0, math.pi):
            cmd_yaw = self._wrap_to_pi(float(base_commanded_tcp_yaw) + phys + delta)
            q = self._downward_yaw_quaternion(cmd_yaw)
            name = "top_down_yaw" if abs(delta) < 1e-6 else "top_down_yaw_pi"
            ik_sol = None
            dist = float("inf")
            if self._moveit2 is not None:
                try:
                    moveit_pose = self._tcp_pose_to_moveit_pose(tcp_pose_planning, q)
                    ik_sol = self._moveit2.compute_ik(
                        position=[
                            float(moveit_pose[0]),
                            float(moveit_pose[1]),
                            float(moveit_pose[2]),
                        ],
                        quat_xyzw=[float(q[0]), float(q[1]), float(q[2]), float(q[3])],
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=start_js,
                        wait_for_server_timeout_sec=1.0,
                    )
                except Exception:
                    ik_sol = None
            if ik_sol is not None:
                dist = self._joint_state_weighted_distance(ik_sol, start_js)
            ranked.append((dist, name, q, cmd_yaw, ik_sol))
        ranked.sort(key=lambda item: item[0])
        return [
            (name, q, cmd_yaw, ik_sol, dist)
            for dist, name, q, cmd_yaw, ik_sol in ranked
        ]

    def _chips_can_yaw_from_current_joint7_min_travel(
        self, start_js: Any, phys_corr: float
    ) -> Optional[float]:
        if start_js is None:
            return None
        try:
            names = list(start_js.name)
            positions = [float(v) for v in start_js.position]
        except (TypeError, ValueError, AttributeError):
            return None
        j7_map = {n: p for n, p in zip(names, positions)}
        j7 = j7_map.get("panda_joint7")
        if j7 is None:
            return None
        return self._wrap_to_pi(float(j7) + float(phys_corr))

    def _chips_can_yaw_nearest_to_current_tcp(self, phys_corr: float) -> Optional[float]:
        link = str(self._moveit_target_link or "panda_hand")
        pose = self._link_pose_in_planning_frame(link)
        if pose is None:
            return None
        quat = pose.get("quat")
        if not isinstance(quat, (list, tuple)) or len(quat) < 4:
            return None
        tcp_yaw = self._yaw_rad_from_quaternion_xyzw(
            (
                float(quat[0]),
                float(quat[1]),
                float(quat[2]),
                float(quat[3]),
            )
        )
        return self._wrap_to_pi(float(tcp_yaw) - float(phys_corr))

    def _build_chips_can_yaw_free_candidate_yaws(
        self,
        base_yaw: float,
        start_js: Any,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> List[Tuple[str, float]]:
        del candidate
        phys = float(self._gripper_physical_yaw_correction_rad)
        base = self._wrap_to_pi(float(base_yaw))
        entries: List[Tuple[str, float]] = []
        seen: set = set()

        def _add(name: str, yaw_cmd: float) -> None:
            y = self._wrap_to_pi(float(yaw_cmd))
            key = round(y, 4)
            if key in seen:
                return
            seen.add(key)
            entries.append((str(name), float(y)))

        _add("commanded_yaw", base)
        _add("commanded_yaw_pi", self._wrap_to_pi(base + math.pi))
        _add("top_down_yaw_zero", 0.0)
        _add("top_down_yaw_pi_over_2", math.pi / 2.0)
        _add("top_down_yaw_neg_pi_over_2", -math.pi / 2.0)
        _add("top_down_yaw_pi", math.pi)
        j7_yaw = self._chips_can_yaw_from_current_joint7_min_travel(start_js, phys)
        if j7_yaw is not None:
            _add("yaw_from_current_joint7_min_travel", j7_yaw)
        tcp_yaw = self._chips_can_yaw_nearest_to_current_tcp(phys)
        if tcp_yaw is not None:
            _add("yaw_nearest_to_current_tcp_yaw", tcp_yaw)
        return entries

    def _ranked_chips_can_yaw_free_variants_for_pose(
        self,
        base_commanded_tcp_yaw: float,
        tcp_pose_planning: Tuple[float, float, float],
        start_js: Any,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> List[Tuple[str, Tuple[float, float, float, float], float, Any, float]]:
        phys = float(self._gripper_physical_yaw_correction_rad)
        ranked: List[Tuple[float, str, Tuple[float, float, float, float], float, Any]] = []
        for name, cmd_yaw in self._build_chips_can_yaw_free_candidate_yaws(
            base_commanded_tcp_yaw, start_js, candidate
        ):
            full_cmd = self._wrap_to_pi(float(cmd_yaw) + phys)
            q = self._downward_yaw_quaternion(full_cmd)
            ik_sol = None
            dist = float("inf")
            if self._moveit2 is not None:
                try:
                    moveit_pose = self._tcp_pose_to_moveit_pose(tcp_pose_planning, q)
                    ik_sol = self._moveit2.compute_ik(
                        position=[
                            float(moveit_pose[0]),
                            float(moveit_pose[1]),
                            float(moveit_pose[2]),
                        ],
                        quat_xyzw=[float(q[0]), float(q[1]), float(q[2]), float(q[3])],
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=start_js,
                        wait_for_server_timeout_sec=1.0,
                    )
                except Exception:
                    ik_sol = None
            if ik_sol is not None:
                dist = self._joint_state_weighted_distance(ik_sol, start_js)
            ranked.append((dist, name, q, float(full_cmd), ik_sol))
        ranked.sort(key=lambda item: item[0])
        return [
            (name, q, cmd_yaw, ik_sol, dist)
            for dist, name, q, cmd_yaw, ik_sol in ranked
        ]

    def _build_sugar_box_yaw_free_candidate_yaws(
        self,
        base_yaw: float,
        start_js: Any,
    ) -> List[Tuple[str, float]]:
        phys = float(self._gripper_physical_yaw_correction_rad)
        j7_yaw = self._chips_can_yaw_from_current_joint7_min_travel(start_js, phys)
        tcp_yaw = self._chips_can_yaw_nearest_to_current_tcp(phys)
        return build_yaw_free_candidate_yaws(
            base_yaw,
            joint7_yaw=j7_yaw,
            current_tcp_yaw=tcp_yaw,
        )

    def _ranked_sugar_box_yaw_free_variants_for_pose(
        self,
        base_commanded_tcp_yaw: float,
        tcp_pose_planning: Tuple[float, float, float],
        start_js: Any,
    ) -> List[Tuple[str, Tuple[float, float, float, float], float, Any, float]]:
        phys = float(self._gripper_physical_yaw_correction_rad)
        ranked: List[Tuple[float, str, Tuple[float, float, float, float], float, Any]] = []
        for name, cmd_yaw in self._build_sugar_box_yaw_free_candidate_yaws(
            base_commanded_tcp_yaw, start_js
        ):
            full_cmd = self._wrap_to_pi(float(cmd_yaw) + phys)
            q = self._downward_yaw_quaternion(full_cmd)
            ik_sol = None
            dist = float("inf")
            if self._moveit2 is not None:
                try:
                    hand_pos, hand_q = self._tcp_to_moveit_hand_pose(
                        tcp_pose_planning, q
                    )
                    ik_sol = self._moveit2.compute_ik(
                        position=[
                            float(hand_pos[0]),
                            float(hand_pos[1]),
                            float(hand_pos[2]),
                        ],
                        quat_xyzw=[
                            float(hand_q[0]),
                            float(hand_q[1]),
                            float(hand_q[2]),
                            float(hand_q[3]),
                        ],
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=start_js,
                        wait_for_server_timeout_sec=1.0,
                    )
                except Exception:
                    ik_sol = None
            if ik_sol is not None:
                dist = self._joint_state_weighted_distance(ik_sol, start_js)
            ranked.append((dist, name, q, float(full_cmd), ik_sol))
        ranked.sort(key=lambda item: item[0])
        return [
            (name, q, cmd_yaw, ik_sol, dist)
            for dist, name, q, cmd_yaw, ik_sol in ranked
        ]

    def _log_sugar_box_yaw_free_ik_variant_search(
        self,
        *,
        context: str,
        pregrasp_tcp_z: float,
        variant_name: str,
        candidate_yaw_deg: float,
        ik_ok: bool,
        plan_ok: bool,
        joint_dist: float,
        selected: bool,
        start_state: str = "",
    ) -> None:
        self.get_logger().info(
            "[SUGAR_BOX_YAW_FREE_IK_VARIANT_SEARCH]\n"
            "label=sugar_box\n"
            "context=%s\n"
            "start_state=%s\n"
            "pregrasp_tcp_z=%.4f\n"
            "candidate_yaw_deg=%.2f\n"
            "yaw_variant=%s\n"
            "ik_ok=%s\n"
            "plan_ok=%s\n"
            "joint_dist=%.4f\n"
            "selected=%s"
            % (
                str(context),
                str(start_state or "n/a"),
                float(pregrasp_tcp_z),
                float(candidate_yaw_deg),
                str(variant_name),
                str(bool(ik_ok)).lower(),
                str(bool(plan_ok)).lower(),
                float(joint_dist),
                str(bool(selected)).lower(),
            )
        )

    def _pick_sugar_box_yaw_free_pregrasp_ik_plan(
        self,
        candidate: Dict[str, Any],
        pre_plan: Tuple[float, float, float],
        start_js: Any,
        base_yaw: float,
        *,
        pregrasp_tcp_z: Optional[float] = None,
        variant_label: str = "",
        require_plan_ok: bool = True,
        context: str = "pregrasp",
        start_state_label: str = "",
    ) -> Optional[Dict[str, Any]]:
        if self._moveit2 is None:
            return None
        z_log = (
            float(pregrasp_tcp_z)
            if pregrasp_tcp_z is not None
            else float(pre_plan[2])
        )
        ori_tol = float(self._plan_before_prelude_orientation_tolerance)
        ranked = self._ranked_sugar_box_yaw_free_variants_for_pose(
            base_yaw, pre_plan, start_js
        )
        evaluated: List[Dict[str, Any]] = []
        for qname, q, cmd_yaw, ik_sol, joint_dist in ranked:
            ik_ok = ik_sol is not None
            plan_ok = False
            plan_traj = None
            if ik_ok and require_plan_ok:
                try:
                    pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                    plan_traj = self._moveit2.plan(
                        position=list(pre_moveit),
                        quat_xyzw=list(q),
                        frame_id=self._planning_frame,
                        target_link=self._moveit_target_link,
                        start_joint_state=ik_sol,
                        tolerance_orientation=ori_tol,
                    )
                    plan_ok = plan_traj is not None
                except Exception:
                    plan_ok = False
            elif ik_ok:
                plan_ok = True
            evaluated.append(
                {
                    "variant_name": str(qname),
                    "yaw_variant": variant_label or str(qname),
                    "quat": q,
                    "commanded_yaw_rad": float(cmd_yaw),
                    "ik_ok": bool(ik_ok),
                    "plan_ok": bool(plan_ok),
                    "ik_joint_state": ik_sol,
                    "joint_dist": float(joint_dist),
                    "plan_trajectory": plan_traj,
                }
            )
        best: Optional[Dict[str, Any]] = None
        for item in evaluated:
            if not item["ik_ok"] or not item["plan_ok"]:
                continue
            if context == "direct_pregrasp" and item.get("plan_trajectory") is None:
                continue
            if best is None or float(item["joint_dist"]) + 1e-9 < float(
                best["joint_dist"]
            ):
                best = item
        for item in evaluated:
            self._log_sugar_box_yaw_free_ik_variant_search(
                context=context,
                pregrasp_tcp_z=z_log,
                variant_name=str(item["variant_name"]),
                candidate_yaw_deg=math.degrees(float(item["commanded_yaw_rad"])),
                ik_ok=bool(item["ik_ok"]),
                plan_ok=bool(item["plan_ok"]),
                joint_dist=float(item["joint_dist"]),
                selected=best is not None and item is best,
                start_state=start_state_label,
            )
        return best

