    def _try_sugar_box_direct_pregrasp_pick_route(
        self,
        candidate: Dict[str, Any],
        *,
        snap_str: str,
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        start_js: Any,
        start_state_label: str,
        base_yaw: float,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        plan_log_tag: str,
    ) -> bool:
        pre_z = float(pre_plan[2])
        self.get_logger().info(
            "[SUGAR_BOX_DIRECT_PREGRASP_FROM_WAYPOINT]\n"
            "label=sugar_box\n"
            "start_state=%s\n"
            "pregrasp_tcp=(%.4f, %.4f, %.4f)\n"
            "result=STARTED"
            % (
                start_state_label,
                float(pre_plan[0]),
                float(pre_plan[1]),
                pre_z,
            )
        )
        pick = self._pick_sugar_box_yaw_free_pregrasp_ik_plan(
            candidate,
            pre_plan,
            start_js,
            base_yaw,
            pregrasp_tcp_z=pre_z,
            variant_label="direct_from_pick_workspace_ready",
            require_plan_ok=True,
            context="direct_pregrasp",
            start_state_label=start_state_label,
        )
        if pick is None:
            self.get_logger().info(
                "[SUGAR_BOX_DIRECT_PREGRASP_FROM_WAYPOINT]\n"
                "label=sugar_box\n"
                "start_state=%s\n"
                "result=FAIL\n"
                "reason=no_yaw_free_ik_plan"
                % start_state_label
            )
            return False
        q = pick["quat"]
        ik_pre_sol = pick.get("ik_joint_state")
        if ik_pre_sol is None:
            try:
                pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                ik_pre_sol = self._moveit2.compute_ik(
                    position=[
                        float(pre_moveit[0]),
                        float(pre_moveit[1]),
                        float(pre_moveit[2]),
                    ],
                    quat_xyzw=list(q),
                    ik_link_name=self._moveit_target_link,
                    start_joint_state=start_js,
                    wait_for_server_timeout_sec=1.0,
                )
            except Exception:
                ik_pre_sol = None
        if ik_pre_sol is None:
            self.get_logger().info(
                "[SUGAR_BOX_DIRECT_PREGRASP_FROM_WAYPOINT] result=FAIL reason=no_ik_pregrasp"
            )
            return False
        plan_before_result = "OK_DIRECT_PREGRASP"
        if self._demo_full_pick_route_prevalidation_required(candidate):
            cart_ok, _frac, cart_deferred = (
                self._prevalidate_cartesian_descend_for_pick_route(
                    candidate,
                    pre_plan,
                    gr_plan,
                    q,
                    ik_pre_sol,
                    stage_label="pregrasp_to_grasp",
                )
            )
            if not cart_ok:
                self.get_logger().info(
                    "[SUGAR_BOX_DIRECT_PREGRASP_FROM_WAYPOINT] "
                    "result=FAIL reason=pregrasp_to_grasp_cartesian_fail"
                )
                return False
            plan_before_result = (
                "OK_PREGRASP_PENDING_DESCEND_VALIDATE"
                if cart_deferred
                else "OK_FULL_PICK_ROUTE"
            )
        self._store_plan_before_motion_validated_pregrasp(
            candidate,
            variant_name=str(pick["variant_name"]),
            quat=q,
            commanded_yaw_rad=float(pick["commanded_yaw_rad"]),
            candidate_pregrasp_js=pick.get("ik_joint_state"),
        )
        plan_traj = pick.get("plan_trajectory")
        if plan_traj is not None:
            candidate["_sugar_box_direct_pregrasp_cached_traj"] = plan_traj
        candidate["_sugar_box_selected_route"] = "direct_pregrasp"
        candidate["selected_entry_target"] = "pregrasp_tcp"
        self._store_pregrasp_plan_preflight_status(
            candidate,
            ik_pregrasp="OK",
            plan_pregrasp="OK",
            ik_grasp="SKIP",
            plan_before_result=plan_before_result,
        )
        self._store_preplanned_pick_route(
            candidate,
            plan_targets,
            source_frame,
            pre_plan=pre_plan,
            gr_plan=gr_plan,
            quat=q,
            variant_name=str(pick["variant_name"]),
            safe_pregrasp_enabled=False,
            route_source="sugar_box_direct_pregrasp_from_pick_workspace_ready",
            route="direct_pregrasp",
            selected_entry_target="pregrasp_tcp",
        )
        self._log_pick_route_preplan_selected(
            candidate,
            variant_name=str(pick["variant_name"]),
            pre_plan=pre_plan,
            gr_plan=gr_plan,
            ik_pregrasp="OK",
            plan_pregrasp="OK",
            ik_grasp="SKIP",
            safe_pregrasp_enabled=False,
            result="OK",
        )
        self._log_sugar_box_pick_route_selected(
            route="direct_pregrasp",
            variant_name=str(pick["variant_name"]),
            pregrasp_tcp_z=pre_z,
            start_state=start_state_label,
            safe_pregrasp_enabled=False,
        )
        self.get_logger().info(
            "[%s]\n"
            "label=sugar_box\n"
            "snapshot_center=%s\n"
            "route=direct_pregrasp_from_pick_workspace_ready\n"
            "target_pregrasp=(%.3f, %.3f, %.3f)\n"
            "cartesian_descend_prevalidated=%s\n"
            "result=%s\n"
            "start_state=%s\n"
            "detail=variant=%s z=%.3f"
            % (
                plan_log_tag,
                snap_str,
                pre_plan[0],
                pre_plan[1],
                pre_plan[2],
                str(bool(candidate.get("_cartesian_descend_prevalidated"))).lower(),
                plan_before_result,
                start_state_label,
                str(pick["variant_name"]),
                pre_z,
            )
        )
        return True

    def _ranked_pregrasp_yaw_variants_for_pose(
        self,
        candidate: Optional[Dict[str, Any]],
        base_commanded_tcp_yaw: float,
        tcp_pose_planning: Tuple[float, float, float],
        start_js: Any,
    ) -> List[Tuple[str, Tuple[float, float, float, float], float, Any, float]]:
        if candidate is not None and self._is_chips_can_cylinder_topdown_candidate(
            candidate
        ):
            return self._ranked_chips_can_yaw_free_variants_for_pose(
                base_commanded_tcp_yaw,
                tcp_pose_planning,
                start_js,
                candidate,
            )
        if (
            candidate is not None
            and self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate)
        ):
            return self._ranked_sugar_box_yaw_free_variants_for_pose(
                base_commanded_tcp_yaw, tcp_pose_planning, start_js
            )
        return self._ranked_downward_yaw_variants_for_pose(
            base_commanded_tcp_yaw, tcp_pose_planning, start_js
        )

