    def _pick_chips_can_yaw_free_pregrasp_ik_plan(
        self,
        candidate: Dict[str, Any],
        pre_plan: Tuple[float, float, float],
        start_js: Any,
        base_yaw: float,
        *,
        pregrasp_tcp_z: Optional[float] = None,
        variant_label: str = "",
        require_plan_ok: bool = True,
    ) -> Optional[Dict[str, Any]]:
        if self._moveit2 is None:
            return None
        z_log = (
            float(pregrasp_tcp_z)
            if pregrasp_tcp_z is not None
            else float(pre_plan[2])
        )
        xy = (float(pre_plan[0]), float(pre_plan[1]))
        ori_tol = float(self._plan_before_prelude_orientation_tolerance)
        ranked = self._ranked_chips_can_yaw_free_variants_for_pose(
            base_yaw, pre_plan, start_js, candidate
        )
        evaluated: List[Dict[str, Any]] = []
        for qname, q, cmd_yaw, ik_sol, joint_dist in ranked:
            ik_ok = ik_sol is not None
            plan_ok = False
            if ik_ok and require_plan_ok:
                try:
                    pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                    traj = self._moveit2.plan(
                        position=list(pre_moveit),
                        quat_xyzw=list(q),
                        frame_id=self._planning_frame,
                        target_link=self._moveit_target_link,
                        start_joint_state=ik_sol,
                        tolerance_orientation=ori_tol,
                    )
                    plan_ok = traj is not None
                except Exception:
                    plan_ok = False
            elif ik_ok:
                plan_ok = True
            evaluated.append(
                {
                    "variant_name": str(qname),
                    "yaw_variant": variant_label or str(qname),
                    "quat": q,
                    "commanded_yaw_rad": float(cmd_yaw),
                    "ik_ok": bool(ik_ok),
                    "plan_ok": bool(plan_ok),
                    "ik_joint_state": ik_sol,
                    "joint_dist": float(joint_dist),
                }
            )
        best: Optional[Dict[str, Any]] = None
        for item in evaluated:
            if not item["ik_ok"] or not item["plan_ok"]:
                continue
            if best is None or float(item["joint_dist"]) + 1e-9 < float(
                best["joint_dist"]
            ):
                best = item
        for item in evaluated:
            self._log_chips_can_yaw_free_ik_variant_search(
                candidate,
                xy=xy,
                pregrasp_tcp_z=z_log,
                variant_name=str(item["variant_name"]),
                candidate_yaw_deg=math.degrees(float(item["commanded_yaw_rad"])),
                ik_ok=bool(item["ik_ok"]),
                plan_ok=bool(item["plan_ok"]),
                joint_dist=float(item["joint_dist"]),
                selected=best is not None and item is best,
            )
        return best

    @staticmethod
    def _yaw_rad_from_quaternion_xyzw(
        quat: Tuple[float, float, float, float],
    ) -> float:
        return float(yaw_from_quaternion(quat))

    def _transform_planning_position_to_source_frame(
        self,
        pos_plan: Tuple[float, float, float],
        target_frame: str,
        stage: str = "planning_to_source",
    ) -> Optional[Tuple[float, float, float]]:
        dst = self._effective_place_frame_id(target_frame)
        pos = (float(pos_plan[0]), float(pos_plan[1]), float(pos_plan[2]))
        if dst == self._planning_frame:
            return pos
        if self._tf_buffer is None:
            return None
        pose_in = PoseStamped()
        pose_in.header.frame_id = self._planning_frame
        pose_in.header.stamp = self.get_clock().now().to_msg()
        pose_in.pose.position.x = pos[0]
        pose_in.pose.position.y = pos[1]
        pose_in.pose.position.z = pos[2]
        pose_in.pose.orientation.w = 1.0
        try:
            transformed = self._tf_buffer.transform(
                pose_in,
                dst,
                timeout=rclpy.duration.Duration(seconds=0.5),
            )
            return (
                float(transformed.pose.position.x),
                float(transformed.pose.position.y),
                float(transformed.pose.position.z),
            )
        except Exception as exc:
            self.get_logger().warn(
                "[PLACE_TRANSFORM] planning -> %s stage=%s FAIL: %s"
                % (dst, stage, exc)
            )
            return None

    def _store_plan_before_motion_validated(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        *,
        variant_name: str,
        quat: Tuple[float, float, float, float],
        moveit_hand_pose: Tuple[float, float, float],
        validated_tcp_z_planning: float,
        safe_plan_xy: Tuple[float, float],
    ) -> None:
        validated_tcp_plan = (
            float(safe_plan_xy[0]),
            float(safe_plan_xy[1]),
            float(validated_tcp_z_planning),
        )
        src_tcp = self._transform_planning_position_to_source_frame(
            validated_tcp_plan, source_frame, stage="plan_before_validated_safe"
        )
        if src_tcp is not None:
            base = plan_targets.get("safe_pregrasp_tcp")
            if base is not None:
                plan_targets["safe_pregrasp_tcp"] = (
                    float(src_tcp[0]),
                    float(src_tcp[1]),
                    float(src_tcp[2]),
                )
            else:
                plan_targets["safe_pregrasp_tcp"] = src_tcp

        validated_yaw = self._wrap_to_pi(self._yaw_rad_from_quaternion_xyzw(quat))
        candidate["_plan_before_motion_validated"] = {
            "ok": True,
            "mode": "safe_pregrasp",
            "variant_name": str(variant_name),
            "quat": [float(quat[0]), float(quat[1]), float(quat[2]), float(quat[3])],
            "validated_tcp_z_planning": float(validated_tcp_z_planning),
            "final_yaw_rad": float(validated_yaw),
        }
        candidate["_final_tcp_yaw_rad"] = float(validated_yaw)
        candidate["_execution_quaternion_override"] = [
            float(quat[0]),
            float(quat[1]),
            float(quat[2]),
            float(quat[3]),
        ]

    def _safe_pregrasp_motion_enabled(self) -> bool:
        return bool(self._use_safe_pregrasp and self._enable_safe_pregrasp_stage)

    def _store_plan_before_motion_validated_pregrasp(
        self,
        candidate: Dict[str, Any],
        *,
        variant_name: str,
        quat: Tuple[float, float, float, float],
        commanded_yaw_rad: float,
        candidate_pregrasp_js: Any = None,
    ) -> None:
        """Guarda yaw/quat validados en plan_before (modo pregrasp directo, sin safe local)."""
        yaw = self._wrap_to_pi(float(commanded_yaw_rad))
        validated: Dict[str, Any] = {
            "ok": True,
            "mode": "direct_pregrasp",
            "variant_name": str(variant_name),
            "quat": [float(quat[0]), float(quat[1]), float(quat[2]), float(quat[3])],
            "final_yaw_rad": float(yaw),
        }
        if candidate_pregrasp_js is not None:
            validated["candidate_pregrasp_js"] = candidate_pregrasp_js
            candidate["_paired_pregrasp_validated_js"] = candidate_pregrasp_js
        candidate["_plan_before_motion_validated"] = validated
        candidate["_commanded_tcp_yaw_rad"] = float(yaw)
        candidate["_final_tcp_yaw_rad"] = float(yaw)
        candidate["_execution_quaternion_override"] = [
            float(quat[0]),
            float(quat[1]),
            float(quat[2]),
            float(quat[3]),
        ]

    def _store_pregrasp_plan_preflight_status(
        self,
        candidate: Dict[str, Any],
        *,
        ik_pregrasp: str,
        plan_pregrasp: str,
        ik_grasp: str,
        plan_before_result: str,
    ) -> None:
        candidate["_pregrasp_plan_preflight"] = {
            "ik_pregrasp": str(ik_pregrasp),
            "plan_pregrasp": str(plan_pregrasp),
            "ik_grasp": str(ik_grasp),
            "plan_before_result": str(plan_before_result),
            "grasp_ik_missing_allowed": str(ik_grasp) != "OK",
        }

    def _chips_can_force_safe_pregrasp_stage_active(
        self, candidate: Dict[str, Any]
    ) -> bool:
        if not bool(self._chips_can_force_safe_pregrasp_stage):
            return False
        if not bool(self._enable_safe_pregrasp_stage):
            return False
        return bool(self._is_chips_can_cylinder_topdown_candidate(candidate))

    def _safe_pregrasp_stage_enabled_for_candidate(
        self, candidate: Dict[str, Any]
    ) -> bool:
        if sugar_box_multiobject_use_object_safe_above_stage(candidate):
            return False
        if self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate):
            return True
        return bool(self._enable_safe_pregrasp_stage)

    def _sugar_box_force_safe_pregrasp_when_obstacles_active(
        self, candidate: Dict[str, Any]
    ) -> bool:
        return _sugar_box_force_safe_pregrasp(
            candidate=candidate,
            param_enabled=bool(self._sugar_box_force_safe_pregrasp_when_obstacles),
            min_obstacles=1,
        )

    def _apply_sugar_box_demo_scene_02_remaining_equivalent_policy(
        self,
        candidate: Dict[str, Any],
        *,
        present_table_labels: Optional[Set[str]] = None,
    ) -> None:
        active_obstacle_labels = {
            str(o.get("label", "")).strip().lower()
            for o in (candidate.get("scene_obstacles") or [])
            if isinstance(o, dict) and not bool(o.get("is_target", False))
        }
        if not sugar_box_demo_scene_02_remaining_pick_equivalent(
            label=str(candidate.get("label", "")),
            scene_id=str(self._scene_id or ""),
            completed_labels=set(self._demo_completed_pick_labels),
            active_obstacle_labels=active_obstacle_labels,
            present_table_labels=present_table_labels,
        ):
            return
        candidate["_sugar_box_demo_scene_02_remaining_equivalent"] = True
        apply_sugar_box_demo_scene_02_remaining_equivalent_fields(candidate)
        self.get_logger().info(
            format_sugar_box_demo_scene_02_remaining_equivalent_log(
                scene_id=str(self._scene_id or "demo_scene_02"),
                completed_labels=set(self._demo_completed_pick_labels),
                present_table_labels=present_table_labels,
            )
        )

    def _apply_mustard_obstacle_center_policy_to_scene_object(
        self,
        scene_obj: Dict[str, Any],
        *,
        is_target: bool,
    ) -> Dict[str, Any]:
        merged, log_fields = apply_mustard_obstacle_center_for_planning_scene(
            scene_obj,
            is_target=bool(is_target),
        )
        if log_fields is not None:
            self.get_logger().info(format_mustard_obstacle_center_policy_log(log_fields))
        return merged

    def _sugar_box_use_two_phase_pick_route(self, candidate: Dict[str, Any]) -> bool:
        """HOME solo valida pick_workspace_ready; ruta completa tras el preludio."""
        if not self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate):
            return False
        if not self._enable_pick_workspace_prelude:
            return False
        if self._plan_before_prelude_skip_workspace_prelude:
            return False
        wp = str(self._pick_workspace_prelude_waypoint)
        self._reload_motion_waypoints()
        return waypoint_is_configured(self._motion_waypoints_data, wp)

    def _demo_full_pick_route_prevalidation_required(
        self, candidate: Dict[str, Any]
    ) -> bool:
        label = str(candidate.get("label", "")).strip().lower()
        if self._demo_golden_pick_fast_execute_active(label, candidate=candidate):
            return False
        return _demo_full_pick_route_required(
            candidate=candidate,
            demo_fast_mode=bool(self.get_parameter("demo_fast_mode").value),
            demo_motion_profile_active=self._demo_motion_profile_active(),
            require_param=bool(self._demo_require_full_pick_route_prevalidation),
            chips_can_candidate=self._is_chips_can_cylinder_topdown_candidate(
                candidate
            ),
            demo_authoritative_scene=bool(self._demo_authoritative_scene),
            scene_id=str(self._scene_id or ""),
        )

    def _paired_pregrasp_validation_required(
        self, candidate: Dict[str, Any]
    ) -> bool:
        label = str(candidate.get("label", "")).strip().lower()
        if self._demo_golden_pick_fast_execute_active(label, candidate=candidate):
            return False
        return paired_pregrasp_descend_validation_required(
            candidate=candidate,
            demo_authoritative_scene=bool(self._demo_authoritative_scene),
            scene_id=str(self._scene_id or ""),
        )

    def _reset_demo_completed_state_for_new_session(self) -> None:
        """Borra estado demo persistido solo si demo_reset_completed_state_on_start=true."""
        if not self._demo_persist_completed_objects:
            return
        path = str(self._demo_completed_state_file)
        self._demo_completed_pick_entities.clear()
        self._demo_completed_pick_labels.clear()
        self._deposit_occupied.clear()
        try:
            os.remove(path)
            removed = True
        except FileNotFoundError:
            removed = False
        except OSError as exc:
            self.get_logger().warning(
                "[DEMO_COMPLETED_STATE_RESET] could not remove %s: %s" % (path, exc)
            )
            removed = False
        self.get_logger().info(
            "[DEMO_COMPLETED_STATE_RESET]\n"
            "path=%s\n"
            "file_removed=%s\n"
            "completed_entities=%s\n"
            "completed_labels=%s"
            % (path, str(bool(removed)).lower(), [], [])
        )

    def _load_demo_completed_state_from_file(self) -> None:
        if not self._demo_persist_completed_objects:
            return
        path = str(self._demo_completed_state_file)
        ents, labels, deposits = load_demo_completed_state(path)
        self._demo_completed_pick_entities.update(ents)
        self._demo_completed_pick_labels.update(labels)
        self._deposit_occupied = list(deposits)
        self.get_logger().info(
            "[DEMO_COMPLETED_STATE_LOAD]\n"
            "path=%s\n"
            "completed_entities=%s\n"
            "completed_labels=%s\n"
            "completed_deposits=%s"
            % (path, sorted(ents), sorted(labels), deposits)
        )

    def _bootstrap_clear_table_manual_step_target(self) -> bool:
        """Fija target efectivo desde pick_order antes de recibir /vision_to_executor."""
        explicit = str(self.get_parameter("target_label").value).strip().lower()
        if explicit and explicit not in (
            "clear_table",
            "clear_table_manual",
            "all",
            "*",
        ):
            selected = explicit
            order_index = next(
                (
                    idx
                    for idx, lb in enumerate(self._demo_scene_pick_order)
                    if str(lb).strip().lower() == selected
                ),
                -1,
            )
            reason = "explicit_target_label_param"
        else:
            selected, order_index, reason = resolve_clear_table_manual_step_bootstrap(
                completed_labels=self._demo_completed_pick_labels,
                pick_order=self._demo_scene_pick_order,
            )
        if not selected:
            if reason == "all_completed_or_empty":
                self.get_logger().info(
                    "[CLEAR_TABLE_COMPLETE]\n"
                    "result=OK\n"
                    "scene_id=%s\n"
                    "completed_labels=%s"
                    % (
                        self._scene_id or "n/a",
                        sorted(self._demo_completed_pick_labels),
                    )
                )
            else:
                self.get_logger().error(
                    "[CLEAR_TABLE_MANUAL_STEP]\n"
                    "scene_id=%s\n"
                    "result=FAIL\n"
                    "reason=%s"
                    % (self._scene_id or "n/a", reason)
                )
            self._clear_table_manual_abort = True
            self._clear_table_effective_target_label = ""
            return False
        self._clear_table_effective_target_label = selected
        self._target_label = selected
        self.get_logger().info(
            "[CLEAR_TABLE_MANUAL_STEP]\n"
            "scene_id=%s\n"
            "selected_label=%s\n"
            "selected_order_index=%d\n"
            "completed_labels=%s\n"
            "source=%s\n"
            "result=OK"
            % (
                self._scene_id or "n/a",
                selected,
                int(order_index),
                sorted(self._demo_completed_pick_labels),
                "pick_order" if reason == "pick_order" else reason,
            )
        )
        return True

    def _clear_table_manual_step_active(self) -> bool:
        return bool(
            getattr(self, "_clear_table", False)
            or getattr(self, "_clear_table_manual_step", False)
        )

    def _clear_table_effective_target(self) -> str:
        return str(
            self._clear_table_effective_target_label or self._target_label or ""
        ).strip().lower()

    def _demo_table_objects_for_order_policy(
        self,
        pool: List[Dict[str, Any]],
        payload: Optional[Dict[str, Any]],
        detections: Optional[List[Any]] = None,
    ) -> List[Dict[str, Any]]:
        table_objs: List[Dict[str, Any]] = list(pool)
        exec_objs = [
            o
            for o in executor_objects_from_payload(payload, detections or [])
            if isinstance(o, dict)
        ]
        for o in exec_objs:
            if o not in table_objs:
                table_objs.append(o)
        if isinstance(payload, dict):
            scene_objects = payload.get("scene_objects")
            if isinstance(scene_objects, list):
                for so in scene_objects:
                    if isinstance(so, dict) and so not in table_objs:
                        table_objs.append(so)
        return table_objs

    def _resolve_clear_table_step_target_label(
        self,
        requested_label: str,
        pool: List[Dict[str, Any]],
        payload: Optional[Dict[str, Any]],
        detections: Optional[List[Any]] = None,
    ) -> str:
        table_objs = self._demo_table_objects_for_order_policy(
            pool, payload, detections
        )
        present = collect_present_table_labels(
            table_objs,
            completed_entities=self._demo_completed_pick_entities,
            completed_labels=self._demo_completed_pick_labels,
        )
        self.get_logger().info(
            "[CLEAR_TABLE_OBJECTS]\nlabels=%s" % sorted(present)
        )
        remaining = remaining_table_labels(
            table_objs,
            completed_entities=self._demo_completed_pick_entities,
            completed_labels=self._demo_completed_pick_labels,
        )
        effective_order = discover_effective_pick_order(
            pick_order=self._demo_scene_pick_order,
            present_labels=present,
            completed_labels=self._demo_completed_pick_labels,
        )
        self.get_logger().info(
            "[DEMO_REMAINING_OBJECTS]\n"
            "labels=%s\n"
            "completed_labels=%s"
            % (sorted(remaining), sorted(self._demo_completed_pick_labels))
        )
        self.get_logger().info(
            "[DEMO_PICK_ORDER_DISCOVERY]\n"
            "scene_id=%s\n"
            "configured_order=%s\n"
            "effective_order=%s"
            % (
                self._scene_id or "n/a",
                self._demo_scene_pick_order,
                effective_order,
            )
        )
        selected, reason, skipped = resolve_clear_table_manual_target(
            requested_label,
            present_labels=present,
            completed_labels=self._demo_completed_pick_labels,
            pick_order=self._demo_scene_pick_order,
        )
        for skip_lb in skipped:
            self.get_logger().info(
                "[DEMO_OBJECT_ALREADY_COMPLETED]\n"
                "requested_label=%s\n"
                "skipped_label=%s\n"
                "action=advance_to_next"
                % (str(requested_label or "n/a"), skip_lb)
            )
        if not selected:
            if reason == "all_completed_or_empty":
                self.get_logger().info(
                    "[CLEAR_TABLE_COMPLETE]\n"
                    "result=OK\n"
                    "scene_id=%s\n"
                    "completed_labels=%s"
                    % (
                        self._scene_id or "n/a",
                        sorted(self._demo_completed_pick_labels),
                    )
                )
            else:
                self.get_logger().warning(
                    "[CLEAR_TABLE_MANUAL_STEP] result=SKIP reason=%s (no remaining targets)"
                    % reason
                )
            return ""
        if selected != str(self._clear_table_effective_target_label or "").strip().lower():
            self.get_logger().info(
                "[CLEAR_TABLE_MANUAL_STEP]\n"
                "scene_id=%s\n"
                "selected_label=%s\n"
                "selected_order_index=%d\n"
                "completed_labels=%s\n"
                "source=vision_pick_order\n"
                "result=OK"
                % (
                    self._scene_id or "n/a",
                    selected,
                    next(
                        (
                            idx
                            for idx, lb in enumerate(self._demo_scene_pick_order)
                            if str(lb).strip().lower() == selected
                        ),
                        -1,
                    ),
                    sorted(self._demo_completed_pick_labels),
                )
            )
        self._clear_table_effective_target_label = selected
        self._target_label = selected
        return selected

