    def _cleanup_demo_target_collision_after_place(
        self, candidate: Optional[Dict[str, Any]] = None
    ) -> bool:
        if candidate is None or not isinstance(candidate, dict):
            self.get_logger().info(
                "[DEMO_TARGET_COLLISION_CLEANUP]\n"
                "result=SKIP\n"
                "reason=no_candidate"
            )
            return True
        label = str(candidate.get("label", "")).strip()
        entity = str(
            candidate.get("gt_entity_name")
            or candidate.get("entity_name")
            or self._resolve_target_entity_name(None)
            or ""
        ).strip().split("::")[-1]
        ids: List[str] = []
        spec = self._current_target_collision_spec
        if isinstance(spec, dict):
            sid = str(spec.get("id") or "").strip()
            if sid:
                ids.append(sid)
        for raw in (
            self._current_target_collision_id,
            self._last_target_collision_id,
        ):
            oid = str(raw or "").strip()
            if oid:
                ids.append(oid)
        expanded: List[str] = []
        seen: set = set()
        for oid in ids:
            for variant in (oid, f"{oid}_approach_guard"):
                if variant and variant not in seen:
                    seen.add(variant)
                    expanded.append(variant)
        removed_any = False
        for oid in expanded:
            self._force_detach_planning_scene_object(oid)
            if oid in self._planning_scene_object_ids or oid:
                self._remove_collision_object(oid)
                removed_any = True
        self._current_target_attached = False
        self._current_attached_object_id = None
        self._current_target_collision_id = None
        self._last_target_collision_id = None
        self._current_target_collision_spec = None
        self.get_logger().info(
            "[TARGET_COLLISION_CLEANUP]\n"
            "stage=after_place\n"
            "label=%s\n"
            "entity=%s\n"
            "collision_ids=%s\n"
            "result=%s"
            % (
                label or "n/a",
                entity or "n/a",
                expanded,
                "REMOVED" if removed_any or not expanded else "NONE",
            )
        )
        return True

    def _resolve_demo_effective_target_label(
        self,
        requested_label: str,
        pool: List[Dict[str, Any]],
        payload: Optional[Dict[str, Any]],
        detections: Optional[List[Any]] = None,
    ) -> str:
        if self._clear_table or self._clear_table_manual_step:
            pinned = self._clear_table_effective_target()
            if pinned:
                return pinned
            return self._resolve_clear_table_step_target_label(
                requested_label, pool, payload, detections
            )
        if not self._demo_enable_object_order_policy:
            return str(requested_label or "").strip().lower()
        table_objs = self._demo_table_objects_for_order_policy(
            pool, payload, detections
        )
        present = collect_present_table_labels(
            table_objs,
            completed_entities=self._demo_completed_pick_entities,
            completed_labels=self._demo_completed_pick_labels,
        )
        selected, reason, blocker = resolve_effective_demo_pick_label(
            requested_label,
            present_labels=present,
            completed_entities=self._demo_completed_pick_entities,
            completed_labels=self._demo_completed_pick_labels,
            blocking_rules=self._demo_blocking_rules,
            priority_order=self._demo_object_priority_order,
        )
        req = str(requested_label or "").strip().lower()
        sel = str(selected or req).strip().lower()
        if reason == "already_completed_label":
            self.get_logger().info(
                "[DEMO_OBJECT_ALREADY_COMPLETED]\n"
                "requested_label=%s\n"
                "action=reject_or_fallback"
                % (req or "n/a")
            )
        if reason == "blocker_before_target" and sel != req:
            self.get_logger().info(
                "[DEMO_ORDER_POLICY]\n"
                "requested_label=%s\n"
                "selected_label=%s\n"
                "reason=%s\n"
                "blocker_label=%s"
                % (req or "n/a", sel or "n/a", reason, blocker or "n/a")
            )
        return sel or req

    def _deposit_slot_user_request_from_candidate(
        self, candidate: Optional[Dict[str, Any]] = None
    ) -> Tuple[bool, Optional[int], Optional[str]]:
        if isinstance(candidate, dict):
            if bool(
                candidate.get("place_slot_user_specified")
                or candidate.get("user_requested_place_slot")
            ):
                idx_raw = candidate.get("place_slot_index")
                name = str(
                    candidate.get("place_slot_name")
                    or candidate.get("deposit_slot_name")
                    or ""
                ).strip() or None
                try:
                    idx = int(idx_raw) if idx_raw is not None else None
                except (TypeError, ValueError):
                    idx = None
                return True, idx, name
        if self._place_slot_user_specified:
            idx = (
                int(self._place_slot_index)
                if int(self._place_slot_index) >= 0
                else None
            )
            name = self._place_slot_name or None
            return True, idx, name
        return False, None, None

    def _inject_deposit_slot_request_into_candidate(
        self, candidate: Dict[str, Any]
    ) -> None:
        user_req, idx, name = self._deposit_slot_user_request_from_candidate(
            candidate
        )
        if not user_req and self._place_slot_user_specified:
            user_req = True
            idx = (
                int(self._place_slot_index)
                if int(self._place_slot_index) >= 0
                else None
            )
            name = self._place_slot_name or None
        if user_req:
            candidate["place_slot_user_specified"] = True
            candidate["user_requested_place_slot"] = True
            candidate["_place_slot_request_locked"] = True
            if idx is not None:
                candidate["place_slot_index"] = int(idx)
            if name:
                candidate["place_slot_name"] = str(name)
            self.get_logger().info(
                "[PLACE_SLOT_USER_REQUEST]\n"
                "label=%s\n"
                "slot_index=%s\n"
                "slot_name=%s\n"
                "source=web_api_or_cli"
                % (
                    str(candidate.get("label", "")),
                    "n/a" if idx is None else str(int(idx)),
                    str(name or "n/a"),
                )
            )

    def _demo_place_completion_payload(
        self,
        *,
        place_cand: Optional[Dict[str, Any]] = None,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        pc = dict(place_cand or {})
        base = dict(candidate or {})
        spec = self._current_target_collision_spec or {}
        lb = str(
            pc.get("release_label")
            or pc.get("label")
            or base.get("label")
            or spec.get("label", "")
        ).strip().lower()
        ent = str(
            base.get("gt_entity_name")
            or base.get("entity_name")
            or self._resolve_target_entity_name(None)
            or ""
        ).strip()
        short = ent.split("::")[-1] if ent else ""
        slot_idx = pc.get("place_slot_index", base.get("place_slot_index"))
        try:
            slot_idx = int(slot_idx)
        except (TypeError, ValueError):
            slot_idx = -1
        slot_name = str(
            pc.get("place_slot_label")
            or base.get("place_slot_name")
            or ""
        ).strip()
        dep_x = dep_y = None
        try:
            dep_x = float(pc.get("x", base.get("x")))
            dep_y = float(pc.get("y", base.get("y")))
        except (TypeError, ValueError):
            pass
        if (dep_x is None or dep_y is None) and 0 <= slot_idx < len(
            DEFAULT_PLACE_SLOTS_ORDERED
        ):
            slot_def = DEFAULT_PLACE_SLOTS_ORDERED[slot_idx]
            dep_x = float(slot_def["x"])
            dep_y = float(slot_def["y"])
            if not slot_name:
                slot_name = str(slot_def.get("name", ""))
        release_z = (
            pc.get("selected_release_tcp_z")
            or pc.get("_place_selected_release_tcp_z")
            or pc.get("_final_release_tcp_z")
            or pc.get("release_tcp_z")
            or base.get("selected_release_tcp_z")
            or base.get("_place_selected_release_tcp_z")
            or base.get("_final_release_tcp_z")
            or base.get("release_tcp_z")
        )
        try:
            release_z_f = float(release_z) if release_z is not None else None
        except (TypeError, ValueError):
            release_z_f = None
        return {
            "label": lb,
            "entity_name": ent,
            "gt_entity_name": ent,
            "entity": short or ent,
            "place_slot_index": slot_idx,
            "place_slot_name": slot_name,
            "x": dep_x,
            "y": dep_y,
            "release_tcp_z": release_z_f,
        }

    def _mark_demo_pick_completed(
        self,
        candidate: Optional[Dict[str, Any]] = None,
        *,
        place_cand: Optional[Dict[str, Any]] = None,
    ) -> None:
        payload = self._demo_place_completion_payload(
            place_cand=place_cand,
            candidate=candidate or {},
        )
        ent = str(
            payload.get("gt_entity_name") or payload.get("entity_name") or ""
        ).strip()
        short = ent.split("::")[-1] if ent else ""
        if ent:
            self._demo_completed_pick_entities.add(short)
            self._demo_completed_pick_entities.add(ent)
        lb = str(payload.get("label", "")).strip().lower()
        if lb:
            self._demo_completed_pick_labels.add(lb)
        try:
            slot_idx = int(payload.get("place_slot_index", -1))
        except (TypeError, ValueError):
            slot_idx = -1
        slot_name = str(payload.get("place_slot_name", "")).strip()
        if not slot_name and 0 <= slot_idx < len(DEFAULT_PLACE_SLOTS_ORDERED):
            slot_name = str(DEFAULT_PLACE_SLOTS_ORDERED[slot_idx].get("name", ""))
        dep_x = dep_y = None
        try:
            dep_x = float(payload.get("x"))
            dep_y = float(payload.get("y"))
        except (TypeError, ValueError):
            pass
        release_z = payload.get("release_tcp_z")
        if lb and dep_x is not None and dep_y is not None:
            self._deposit_occupied = [
                d
                for d in self._deposit_occupied
                if str(d.get("label", "")).strip().lower() != lb
            ]
            dep_rec = {
                "label": lb,
                "entity": short or ent or "",
                "slot_name": slot_name,
                "slot_index": slot_idx,
                "slot": slot_idx,
                "x": dep_x,
                "y": dep_y,
            }
            if release_z is not None:
                try:
                    dep_rec["release_tcp_z"] = float(release_z)
                except (TypeError, ValueError):
                    pass
            self._deposit_occupied.append(dep_rec)
        snapshot_cand: Optional[Dict[str, Any]] = None
        if self._pending_snapshot is not None:
            try:
                snapshot_cand = dict(self._pending_snapshot[0])
            except (TypeError, IndexError, ValueError):
                snapshot_cand = None
        candidate_for_cleanup = resolve_candidate_for_cleanup(
            place_cand=place_cand,
            candidate=candidate,
            snapshot_candidate=snapshot_cand,
            current_candidate=getattr(self, "_current_snapshot_candidate", None)
            or getattr(self, "_current_candidate", None),
        )
        if (
            candidate_for_cleanup is None
            and isinstance(self._current_target_collision_spec, dict)
            and self._current_target_collision_spec
        ):
            candidate_for_cleanup = dict(self._current_target_collision_spec)
        self.get_logger().info(
            "[DEMO_PICK_LIFECYCLE]\n"
            "event=placed_completed\n"
            "label=%s\n"
            "entity=%s\n"
            "slot_index=%d\n"
            "slot_name=%s\n"
            "deposit_xy=%s\n"
            "completed_entities=%s\n"
            "completed_labels=%s\n"
            "completed_deposits=%s"
            % (
                lb or "n/a",
                short or ent or "n/a",
                slot_idx,
                slot_name or "n/a",
                "n/a"
                if dep_x is None or dep_y is None
                else "(%.4f, %.4f)" % (float(dep_x), float(dep_y)),
                sorted(self._demo_completed_pick_entities),
                sorted(self._demo_completed_pick_labels),
                list(self._deposit_occupied),
            )
        )
        self._save_demo_completed_state_to_file(label=lb, entity=short or ent)
        if lb == "sugar_box":
            cand_for_golden = candidate_for_cleanup or candidate or {}
            if isinstance(cand_for_golden, dict):
                ok_persist, persist_info = persist_sugar_demo_scene_02_golden_from_success(
                    cand_for_golden,
                    scene_id=str(self._scene_id or ""),
                    place_payload=payload,
                )
                self.get_logger().info(
                    format_sugar_golden_persist_log(
                        result="OK" if ok_persist else "SKIP",
                        path=persist_info if ok_persist else "",
                        reason="" if ok_persist else persist_info,
                    )
                )
        elif lb == "chips_can":
            cand_for_golden = candidate_for_cleanup or candidate or {}
            if isinstance(cand_for_golden, dict):
                ok_persist, persist_info = persist_chips_can_golden_from_success(
                    cand_for_golden,
                    scene_id=str(self._scene_id or ""),
                    place_payload=payload,
                )
                self.get_logger().info(
                    format_chips_can_golden_persist_log(
                        result="OK" if ok_persist else "SKIP",
                        path=persist_info if ok_persist else "",
                        reason="" if ok_persist else persist_info,
                    )
                )
        elif lb == "mustard_bottle":
            cand_for_golden = candidate_for_cleanup or candidate or {}
            if isinstance(cand_for_golden, dict):
                ok_persist, persist_info = persist_mustard_demo_scene_02_golden_from_success(
                    cand_for_golden,
                    scene_id=str(self._scene_id or ""),
                    place_payload=payload,
                )
                self.get_logger().info(
                    format_mustard_golden_persist_log(
                        result="OK" if ok_persist else "SKIP",
                        path=persist_info if ok_persist else "",
                        reason="" if ok_persist else persist_info,
                    )
                )
        self.get_logger().info(
            "[DEMO_TARGET_DONE]\n"
            "label=%s\n"
            "entity=%s\n"
            "slot_index=%d\n"
            "slot_name=%s"
            % (lb or "n/a", short or ent or "n/a", slot_idx, slot_name or "n/a")
        )
        if self._clear_table or self._clear_table_manual_step:
            remaining = [
                lb
                for lb in self._demo_scene_pick_order
                if lb not in self._demo_completed_pick_labels
            ]
            self.get_logger().info(
                "[CLEAR_TABLE_TARGET_DONE]\n"
                "label=%s\n"
                "entity=%s\n"
                "remaining_labels=%s"
                % (lb or "n/a", short or ent or "n/a", remaining)
            )
            if not remaining:
                self._clear_table_manual_abort = True
                self._clear_table_effective_target_label = ""
                self.get_logger().info(
                    "[CLEAR_TABLE_COMPLETE]\n"
                    "result=OK\n"
                    "scene_id=%s\n"
                    "pick_order=%s\n"
                    "completed_labels=%s"
                    % (
                        self._scene_id or "n/a",
                        self._demo_scene_pick_order,
                        sorted(self._demo_completed_pick_labels),
                    )
                )
            else:
                next_label = remaining[0]
                self._clear_table_effective_target_label = next_label
                self._target_label = next_label
                self.get_logger().info(
                    "[CLEAR_TABLE_MANUAL_STEP]\n"
                    "action=advance_next_target\n"
                    "next_label=%s\n"
                    "remaining_labels=%s\n"
                    "completed_labels=%s"
                    % (
                        next_label,
                        remaining,
                        sorted(self._demo_completed_pick_labels),
                    )
                )
        try:
            cleanup_ok = self._cleanup_demo_target_collision_after_place(
                candidate_for_cleanup
            )
            if not cleanup_ok:
                self.get_logger().warning(
                    "[DEMO_TARGET_COLLISION_CLEANUP] result=FAIL "
                    "(demo state already saved)"
                )
        except Exception as exc:
            self.get_logger().warning(
                "[DEMO_TARGET_COLLISION_CLEANUP] result=FAIL exception=%s "
                "(demo state already saved)" % exc
            )

    def _executor_object_should_exclude_from_table_obstacles(
        self, det: Dict[str, Any]
    ) -> bool:
        ent = str(det.get("entity_name") or det.get("gt_entity_name") or "").strip()
        short = ent.split("::")[-1] if ent else ""
        lb = str(det.get("label", "")).strip().lower()
        if self._demo_object_marked_completed(entity=short, label=lb):
            self._log_demo_obstacle_filter_skip(
                label=lb, entity=short, source="vision_executor"
            )
            return True
        excluded = _executor_obj_excluded_obstacle(
            det,
            completed_entities=self._demo_completed_pick_entities,
            completed_labels=self._demo_completed_pick_labels,
        )
        if excluded and (short or lb):
            self._log_demo_obstacle_filter_skip(
                label=lb, entity=short, source="executor_placed_flag"
            )
        return excluded

    def _sugar_box_safe_above_tcp_z(
        self, candidate: Dict[str, Any], top_z: float
    ) -> float:
        clear = float(self._sugar_box_multiobject_safe_clearance_above_top_m)
        return _sugar_nominal_safe_tcp_z(float(top_z), clear)

    def _enforce_sugar_box_safe_tcp_on_plan_targets(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
    ) -> None:
        """Fuente única: safe = top_z + clearance (sin pregrasp+extra)."""
        if not self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate):
            return
        top_z = _to_float(candidate.get("top_z_m"))
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_estimated"))
        if top_z is None:
            return
        safe_z = self._sugar_box_safe_above_tcp_z(candidate, float(top_z))
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        fallback_xy: Optional[Tuple[float, float]] = None
        if isinstance(pre_tcp, (list, tuple)) and len(pre_tcp) >= 2:
            fallback_xy = (float(pre_tcp[0]), float(pre_tcp[1]))
        elif isinstance(gr_tcp, (list, tuple)) and len(gr_tcp) >= 2:
            fallback_xy = (float(gr_tcp[0]), float(gr_tcp[1]))
        if fallback_xy is None:
            return
        object_safe_above_tcp, _source = build_sugar_box_object_safe_above_tcp(
            candidate,
            safe_above_tcp_z=float(safe_z),
            fallback_xy=fallback_xy,
        )
        plan_targets["safe_pregrasp_tcp"] = object_safe_above_tcp
        plan_targets["object_safe_above_tcp"] = object_safe_above_tcp
        candidate["sugar_box_safe_above_tcp_z"] = float(safe_z)
        candidate["sugar_box_multiobject_safe_route"] = True
        candidate["sugar_box_multiobject_safe_route_enabled"] = True
        candidate["selected_entry_target"] = "object_safe_above_tcp"
        candidate["object_safe_above_clearance_m"] = float(
            self._sugar_box_multiobject_safe_clearance_above_top_m
        )
        candidate["object_safe_above_tcp"] = [
            float(object_safe_above_tcp[0]),
            float(object_safe_above_tcp[1]),
            float(object_safe_above_tcp[2]),
        ]

    def _apply_sugar_box_multiobject_safe_pregrasp_policy(
        self,
        candidate: Dict[str, Any],
        seq: Dict[str, Any],
        top_z: float,
    ) -> None:
        if not self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate):
            return
        grasp_tcp = seq.get("grasp_tcp")
        pre_tcp = seq.get("pregrasp_tcp")
        if not isinstance(grasp_tcp, (list, tuple)) or len(grasp_tcp) < 3:
            return
        clear = float(self._sugar_box_multiobject_safe_clearance_above_top_m)
        safe_z = self._sugar_box_safe_above_tcp_z(candidate, float(top_z))
        pre_z = (
            float(pre_tcp[2])
            if isinstance(pre_tcp, (list, tuple)) and len(pre_tcp) >= 3
            else safe_z
        )
        ok, resolved_log = apply_sugar_box_multiobject_safe_route_fields(
            candidate,
            seq,
            safe_above_tcp_z=float(safe_z),
            clearance_above_top_m=clear,
        )
        if not ok:
            self.get_logger().error(resolved_log)
            return
        self.get_logger().info(
            "[SUGAR_BOX_MULTIOBJECT_SAFE_ROUTE]\n"
            "label=sugar_box\n"
            "top_z=%.4f\n"
            "safe_above_tcp_z=%.4f\n"
            "pregrasp_tcp_z=%.4f\n"
            "pregrasp_height_above_top=%.4f\n"
            "clearance_above_top_m=%.4f\n"
            "route=object_safe_above->pregrasp->grasp\n"
            "result=ENABLED"
            % (
                float(top_z),
                float(safe_z),
                pre_z,
                pre_z - float(top_z),
                clear,
            )
        )
        self.get_logger().info(resolved_log)

    def _log_sugar_box_safe_entry_z_search(
        self,
        *,
        candidate_tcp_z: float,
        top_z: float,
        yaw_variant: str,
        ik_ok: bool,
        plan_ok: bool,
        selected: bool,
        reason: str,
        start_state: str = "home/current",
    ) -> None:
        clearance = float(candidate_tcp_z) - float(top_z)
        self.get_logger().info(
            "[SUGAR_BOX_SAFE_ENTRY_Z_SEARCH]\n"
            "start_state=%s\n"
            "candidate_tcp_z=%.4f\n"
            "clearance_above_top=%.4f\n"
            "yaw_variant=%s\n"
            "ik_ok=%s\n"
            "plan_ok=%s\n"
            "selected=%s\n"
            "reason=%s"
            % (
                str(start_state),
                float(candidate_tcp_z),
                clearance,
                str(yaw_variant),
                str(bool(ik_ok)).lower(),
                str(bool(plan_ok)).lower(),
                str(bool(selected)).lower(),
                str(reason),
            )
        )

    def _validate_plan_to_joint_waypoint_from_start(
        self,
        start_js: Any,
        waypoint_name: str,
        *,
        start_state_label: str,
    ) -> bool:
        if self._moveit2 is None:
            return False
        self._reload_motion_waypoints()
        joints = get_waypoint_joint_positions(
            self._motion_waypoints_data, str(waypoint_name)
        )
        if joints is None:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] missing waypoint=%s"
                % str(waypoint_name)
            )
            return False
        try:
            traj = self._moveit2.plan(
                joint_positions=[float(v) for v in joints],
                joint_names=list(PANDA_ARM_JOINT_NAMES),
                start_joint_state=start_js,
            )
        except Exception as exc:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION] waypoint=%s plan_exception=%s"
                % (waypoint_name, exc)
            )
            return False
        ok = traj is not None and bool(getattr(traj, "points", None))
        n_pts = len(traj.points) if ok else 0
        self.get_logger().info(
            "[PLAN_BEFORE_MOTION]\n"
            "phase=prelude_workspace_only\n"
            "start_state=%s\n"
            "target_waypoint=%s\n"
            "trajectory_points=%d\n"
            "result=%s"
            % (
                start_state_label,
                waypoint_name,
                n_pts,
                "OK" if ok and n_pts >= 1 else "FAIL",
            )
        )
        return ok and n_pts >= 1

    def _plan_before_motion_validate_sugar_box_phase1_workspace(
        self,
        candidate: Dict[str, Any],
        *,
        start_js: Any,
        start_state_label: str,
    ) -> bool:
        """Fase 1: solo validar HOME/current -> pick_workspace_ready (sin acercarse al objeto)."""
        candidate["sugar_box_two_phase_pick_route"] = True
        wp = str(self._pick_workspace_prelude_waypoint)
        if not self._enable_pick_workspace_prelude:
            self.get_logger().info(
                "[PLAN_BEFORE_MOTION] sugar_box phase1 SKIP (pick_workspace_prelude disabled)"
            )
            self._store_pregrasp_plan_preflight_status(
                candidate,
                ik_pregrasp="SKIP",
                plan_pregrasp="SKIP",
                ik_grasp="SKIP",
                plan_before_result="OK_PRELUDE_PHASE1",
            )
            return True
        if not waypoint_is_configured(self._motion_waypoints_data, wp):
            self.get_logger().warning(
                "[PLAN_BEFORE_MOTION] waypoint '%s' not configured; phase1 SKIP"
                % wp
            )
            self._store_pregrasp_plan_preflight_status(
                candidate,
                ik_pregrasp="SKIP",
                plan_pregrasp="SKIP",
                ik_grasp="SKIP",
                plan_before_result="OK_PRELUDE_PHASE1",
            )
            return True
        ok = self._validate_plan_to_joint_waypoint_from_start(
            start_js, wp, start_state_label=start_state_label
        )
        if not ok:
            candidate["_plan_before_motion_fail_reason"] = "no_pick_workspace_ready_plan"
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] reason=no_pick_workspace_ready_plan"
            )
            return False
        self._store_pregrasp_plan_preflight_status(
            candidate,
            ik_pregrasp="SKIP",
            plan_pregrasp="OK",
            ik_grasp="SKIP",
            plan_before_result="OK_PRELUDE_PHASE1",
        )
        self.get_logger().info(
            "[PLAN_BEFORE_MOTION]\n"
            "label=sugar_box\n"
            "phase=1_workspace_prelude_only\n"
            "target_waypoint=%s\n"
            "full_pick_route_validation=deferred_after_prelude\n"
            "result=OK_PRELUDE_PHASE1"
            % wp
        )
        return True

    def _post_prelude_validate_sugar_box_pick_route(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
    ) -> bool:
        """Fase 2: validar safe_entry -> pregrasp -> grasp desde pick_workspace_ready."""
        label = str(candidate.get("label", ""))
        wp = str(self._pick_workspace_prelude_waypoint)
        self.get_logger().info(
            "[POST_PRELUDE_PICK_ROUTE_VALIDATE]\n"
            "label=%s\n"
            "start_state=current/pick_workspace_ready\n"
            "waypoint=%s\n"
            "result=STARTED"
            % (label, wp)
        )
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE] dry_run; result=OK"
            )
            return True
        if not self._wait_post_prelude_arm_and_tf_stable():
            self.get_logger().error(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE]\n"
                "result=FAIL\n"
                "reason=arm_or_tf_not_stable"
            )
            return False

        scene_obstacles = candidate.get("scene_obstacles") or []
        if scene_obstacles and self._add_detected_objects_to_scene:
            self._apply_table_collision_if_needed()
            self._add_detected_objects_to_planning_scene(
                scene_obstacles,
                include_target=self._include_target_collision(candidate),
                candidate=candidate,
            )

        start_js = self._current_arm_joint_state()
        start_state_label = "pick_workspace_ready"
        if start_js is None:
            start_js = self._joint_state_for_waypoint(wp)
            start_state_label = "pick_workspace_ready/waypoint_yaml"
        if start_js is None:
            self.get_logger().error(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE] result=FAIL reason=no_start_js"
            )
            return False

        base_cmd_raw = candidate.get("_base_commanded_tcp_yaw_rad")
        if base_cmd_raw is None:
            base_cmd_raw = candidate.get("_final_tcp_yaw_rad")
        try:
            base_yaw = float(base_cmd_raw) if base_cmd_raw is not None else 0.0
        except (TypeError, ValueError):
            base_yaw = 0.0

        self._enforce_sugar_box_safe_tcp_on_plan_targets(candidate, plan_targets)
        pre_tcp = plan_targets.get("pregrasp_tcp")
        safe_tcp = plan_targets.get("safe_pregrasp_tcp")
        if pre_tcp is None or safe_tcp is None:
            self.get_logger().error(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE] result=FAIL reason=missing_targets"
            )
            return False
        pre_plan, _ = self._transform_target_to_planning_frame(
            pre_tcp, source_frame, stage="post_prelude_pre"
        )
        gr_tcp = plan_targets.get("grasp_tcp")
        gr_plan, _ = self._transform_target_to_planning_frame(
            gr_tcp, source_frame, stage="post_prelude_grasp"
        )
        if pre_plan is None or gr_plan is None:
            self.get_logger().error(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE] result=FAIL reason=tf_transform_fail"
            )
            return False

        snap_center = (
            _xyz_from_list(candidate.get("grasp_center_base"))
            or _xyz_from_list(candidate.get("chosen_target_center_base"))
        )
        snap_str = (
            "n/a"
            if snap_center is None
            else "(%.3f,%.3f,%.3f)" % snap_center
        )

        ok = self._plan_before_motion_validate_sugar_box_multiobject_safe_route(
            candidate,
            snap_str=snap_str,
            plan_targets=plan_targets,
            source_frame=source_frame,
            start_js=start_js,
            start_state_label=start_state_label,
            base_yaw=base_yaw,
            pre_plan=pre_plan,
            gr_plan=gr_plan,
            safe_xy_plan=(float(pre_plan[0]), float(pre_plan[1])),
            plan_log_tag="PLAN_AFTER_PRELUDE",
        )
        if ok:
            self.get_logger().info(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE]\n"
                "label=%s\n"
                "start_state=current/pick_workspace_ready\n"
                "cartesian_descend_prevalidated=%s\n"
                "result=OK"
                % (
                    label,
                    str(
                        bool(candidate.get("_cartesian_descend_prevalidated"))
                    ).lower(),
                )
            )
        else:
            self.get_logger().error(
                "[POST_PRELUDE_PICK_ROUTE_VALIDATE]\n"
                "label=%s\n"
                "start_state=current/pick_workspace_ready\n"
                "result=FAIL\n"
                "reason=no_full_route_from_pick_workspace_ready"
                % label
            )
        return ok

    def _log_sugar_box_safe_entry_fail_diag(
        self,
        candidate: Dict[str, Any],
        *,
        top_z: float,
        tried_zs: List[float],
        tried_yaw_variants: List[str],
    ) -> None:
        obstacles = _scene_obstacle_labels_for_log(
            candidate.get("scene_obstacles")
        )
        self.get_logger().error(
            "[SUGAR_BOX_SAFE_ENTRY_FAIL_DIAG]\n"
            "top_z=%.4f\n"
            "tried_zs=%s\n"
            "tried_yaw_variants=%s\n"
            "obstacles=%s\n"
            "reason=no_ik_safe_entry"
            % (
                float(top_z),
                [round(z, 4) for z in tried_zs],
                sorted(set(tried_yaw_variants)),
                obstacles,
            )
        )

    def _plan_before_motion_validate_sugar_box_multiobject_safe_route(
        self,
        candidate: Dict[str, Any],
        *,
        snap_str: str,
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        start_js: Any,
        start_state_label: str,
        base_yaw: float,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        safe_xy_plan: Tuple[float, float],
        plan_log_tag: str = "PLAN_BEFORE_MOTION",
    ) -> bool:
        top_z = _to_float(candidate.get("top_z_m"))
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_estimated"))
        if top_z is None:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] reason=no_safe_entry_ik detail=missing_top_z"
            )
            return False
        top_z = float(top_z)
        self._enforce_sugar_box_safe_tcp_on_plan_targets(candidate, plan_targets)
        z_candidates = _sugar_safe_entry_z_candidates(
            top_z,
            min_clearance_above_top_m=float(
                self._sugar_box_multiobject_min_clearance_above_top_m
            ),
        )
        pregrasp_tcp_z = float(pre_plan[2])
        pre_z_floor = pregrasp_tcp_z + 0.030
        dense: List[float] = []
        if z_candidates:
            hi = float(z_candidates[0])
            lo = max(float(z_candidates[-1]), pre_z_floor)
            z_probe = hi - 0.010
            while z_probe > lo + 1e-4:
                dense.append(round(z_probe, 4))
                z_probe -= 0.010
        seen_z: set = set()
        z_unique: List[float] = []
        for z in z_candidates + dense:
            zr = round(float(z), 4)
            if zr in seen_z:
                continue
            if zr < pre_z_floor - 1e-4:
                continue
            seen_z.add(zr)
            z_unique.append(float(z))

        ori_tol = float(self._plan_before_prelude_orientation_tolerance)
        tried_zs: List[float] = []
        tried_yaw: List[str] = []
        best_detail = ""
        from_prelude = "pick_workspace" in str(start_state_label)
        ik_fail_reason = (
            "no_ik_from_pick_workspace_ready"
            if from_prelude
            else "no_ik_from_home"
        )
        plan_fail_reason = (
            "pick_workspace_to_safe_plan_fail"
            if from_prelude
            else "home_to_safe_plan_fail"
        )

        if from_prelude and not sugar_box_multiobject_use_object_safe_above_stage(
            candidate
        ):
            if self._try_sugar_box_direct_pregrasp_pick_route(
                candidate,
                snap_str=snap_str,
                plan_targets=plan_targets,
                source_frame=source_frame,
                start_js=start_js,
                start_state_label=start_state_label,
                base_yaw=base_yaw,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                plan_log_tag=plan_log_tag,
            ):
                return True
            self.get_logger().info(
                "[SUGAR_BOX_SAFE_ENTRY_FALLBACK]\n"
                "label=sugar_box\n"
                "start_state=%s\n"
                "reason=direct_pregrasp_failed\n"
                "result=TRY_SAFE_ENTRY"
                % start_state_label
            )

        for z_try in z_unique:
            tried_zs.append(float(z_try))
            tcp_try = (
                float(safe_xy_plan[0]),
                float(safe_xy_plan[1]),
                float(z_try),
            )
            ranked = self._ranked_pregrasp_yaw_variants_for_pose(
                candidate, base_yaw, tcp_try, start_js
            )
            for qname, q, _cmd_yaw, ik_sol, joint_dist in ranked:
                tried_yaw.append(str(qname))
                ik_ok = ik_sol is not None
                plan_ok = False
                if not ik_ok:
                    self._log_sugar_box_safe_entry_z_search(
                        candidate_tcp_z=z_try,
                        top_z=top_z,
                        yaw_variant=qname,
                        ik_ok=False,
                        plan_ok=False,
                        selected=False,
                        reason=ik_fail_reason,
                        start_state=start_state_label,
                    )
                    continue
                try:
                    moveit_pose = self._tcp_pose_to_moveit_pose(tcp_try, q)
                except Exception as exc:
                    self._log_sugar_box_safe_entry_z_search(
                        candidate_tcp_z=z_try,
                        top_z=top_z,
                        yaw_variant=qname,
                        ik_ok=True,
                        plan_ok=False,
                        selected=False,
                        reason="tcp_to_moveit_fail:%s" % exc,
                        start_state=start_state_label,
                    )
                    continue
                plan_start_js = ik_sol
                try:
                    traj = self._moveit2.plan(
                        position=list(moveit_pose),
                        quat_xyzw=list(q),
                        frame_id=self._planning_frame,
                        target_link=self._moveit_target_link,
                        start_joint_state=start_js,
                        tolerance_orientation=ori_tol,
                    )
                except Exception:
                    traj = None
                plan_ok = traj is not None
                if not plan_ok:
                    self._log_sugar_box_safe_entry_z_search(
                        candidate_tcp_z=z_try,
                        top_z=top_z,
                        yaw_variant=qname,
                        ik_ok=True,
                        plan_ok=False,
                        selected=False,
                        reason=plan_fail_reason,
                        start_state=start_state_label,
                    )
                    continue
                try:
                    pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                    ik_pre_sol = self._moveit2.compute_ik(
                        position=[
                            float(pre_moveit[0]),
                            float(pre_moveit[1]),
                            float(pre_moveit[2]),
                        ],
                        quat_xyzw=list(q),
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=plan_start_js,
                        wait_for_server_timeout_sec=1.0,
                    )
                except Exception:
                    ik_pre_sol = None
                if ik_pre_sol is None:
                    self._log_sugar_box_safe_entry_z_search(
                        candidate_tcp_z=z_try,
                        top_z=top_z,
                        yaw_variant=qname,
                        ik_ok=True,
                        plan_ok=True,
                        selected=False,
                        reason="no_ik_safe_to_pregrasp",
                        start_state=start_state_label,
                    )
                    continue
                plan_before_result = "OK_SAFE_PREGRASP"
                if self._demo_full_pick_route_prevalidation_required(candidate):
                    safe_entry_plan = (
                        float(tcp_try[0]),
                        float(tcp_try[1]),
                        float(z_try),
                    )
                    if (
                        abs(float(safe_entry_plan[2]) - float(pre_plan[2]))
                        > 1e-3
                    ):
                        safe_frac, _ = self._plan_cartesian_fraction_from_joint_state(
                            plan_start_js, pre_moveit, q
                        )
                        if (
                            safe_frac is None
                            or float(safe_frac) + 1e-6
                            < float(self._cartesian_fraction_threshold)
                        ):
                            self._log_sugar_box_safe_entry_z_search(
                                candidate_tcp_z=z_try,
                                top_z=top_z,
                                yaw_variant=qname,
                                ik_ok=True,
                                plan_ok=True,
                                selected=False,
                                reason="safe_to_pregrasp_cartesian_fail",
                                start_state=start_state_label,
                            )
                            continue
                    cart_ok, _frac, cart_deferred = (
                        self._prevalidate_cartesian_descend_for_pick_route(
                            candidate,
                            pre_plan,
                            gr_plan,
                            q,
                            ik_pre_sol,
                            stage_label="pregrasp_to_grasp",
                        )
                    )
                    if not cart_ok:
                        self._log_sugar_box_safe_entry_z_search(
                            candidate_tcp_z=z_try,
                            top_z=top_z,
                            yaw_variant=qname,
                            ik_ok=True,
                            plan_ok=True,
                            selected=False,
                            reason="pregrasp_to_grasp_cartesian_fail",
                            start_state=start_state_label,
                        )
                        continue
                    plan_before_result = (
                        "OK_PREGRASP_PENDING_DESCEND_VALIDATE"
                        if cart_deferred
                        else "OK_FULL_PICK_ROUTE"
                    )
                self._log_sugar_box_safe_entry_z_search(
                    candidate_tcp_z=z_try,
                    top_z=top_z,
                    yaw_variant=qname,
                    ik_ok=True,
                    plan_ok=True,
                    selected=True,
                    reason="full_pick_route_ok",
                    start_state=start_state_label,
                )
                plan_targets["safe_pregrasp_tcp"] = (
                    float(safe_xy_plan[0]),
                    float(safe_xy_plan[1]),
                    float(z_try),
                )
                candidate["sugar_box_safe_above_tcp_z"] = float(z_try)
                if bool(candidate.get("sugar_box_multiobject_safe_route")):
                    obj_safe = plan_targets.get("object_safe_above_tcp")
                    if isinstance(obj_safe, (list, tuple)) and len(obj_safe) >= 3:
                        candidate["object_safe_above_tcp"] = [
                            float(obj_safe[0]),
                            float(obj_safe[1]),
                            float(obj_safe[2]),
                        ]
                else:
                    candidate["object_safe_above_tcp"] = [
                        float(safe_xy_plan[0]),
                        float(safe_xy_plan[1]),
                        float(z_try),
                    ]
                self._store_plan_before_motion_validated(
                    candidate,
                    plan_targets,
                    source_frame,
                    variant_name=qname,
                    quat=q,
                    moveit_hand_pose=(
                        float(moveit_pose[0]),
                        float(moveit_pose[1]),
                        float(moveit_pose[2]),
                    ),
                    validated_tcp_z_planning=float(z_try),
                    safe_plan_xy=(
                        float(safe_xy_plan[0]),
                        float(safe_xy_plan[1]),
                    ),
                )
                self._store_pregrasp_plan_preflight_status(
                    candidate,
                    ik_pregrasp="OK",
                    plan_pregrasp="OK",
                    ik_grasp="SKIP",
                    plan_before_result=plan_before_result,
                )
                candidate["_sugar_box_selected_route"] = "object_safe_above"
                candidate["selected_entry_target"] = "object_safe_above_tcp"
                self._store_preplanned_pick_route(
                    candidate,
                    plan_targets,
                    source_frame,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    quat=q,
                    variant_name=qname,
                    safe_pregrasp_enabled=True,
                    route_source=(
                        "plan_after_prelude_sugar_box_safe_entry"
                        if plan_log_tag == "PLAN_AFTER_PRELUDE"
                        else "plan_before_motion_sugar_box_safe_entry"
                    ),
                    route="object_safe_above",
                    selected_entry_target="object_safe_above_tcp",
                )
                self._log_pick_route_preplan_selected(
                    candidate,
                    variant_name=qname,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    ik_pregrasp="OK",
                    plan_pregrasp="OK",
                    ik_grasp="SKIP",
                    safe_pregrasp_enabled=True,
                    result="OK",
                )
                self._log_sugar_box_pick_route_selected(
                    route="safe_entry",
                    variant_name=str(qname),
                    pregrasp_tcp_z=float(pre_plan[2]),
                    start_state=start_state_label,
                    safe_pregrasp_enabled=True,
                )
                safe_plan_log = (
                    float(safe_xy_plan[0]),
                    float(safe_xy_plan[1]),
                    float(z_try),
                )
                self.get_logger().info(
                    "[%s]\n"
                    "label=sugar_box\n"
                    "snapshot_center=%s\n"
                    "safe_pregrasp_stage=sugar_box_multiobject\n"
                    "target_safe_pregrasp=(%.3f, %.3f, %.3f)\n"
                    "target_pregrasp=(%.3f, %.3f, %.3f)\n"
                    "target_grasp=(%.3f, %.3f, %.3f)\n"
                    "ik_safe_pregrasp=OK\n"
                    "ik_pregrasp=OK\n"
                    "plan_safe_pregrasp=OK\n"
                    "pregrasp_plan_ok=true\n"
                    "cartesian_descend_prevalidated=%s\n"
                    "result=%s\n"
                    "start_state=%s\n"
                    "detail=variant=%s z=%.3f joint_dist=%.4f"
                    % (
                        plan_log_tag,
                        snap_str,
                        safe_plan_log[0],
                        safe_plan_log[1],
                        safe_plan_log[2],
                        pre_plan[0],
                        pre_plan[1],
                        pre_plan[2],
                        gr_plan[0],
                        gr_plan[1],
                        gr_plan[2],
                        str(
                            bool(candidate.get("_cartesian_descend_prevalidated"))
                        ).lower(),
                        plan_before_result,
                        start_state_label,
                        qname,
                        z_try,
                        joint_dist,
                    )
                )
                return True

        self._log_sugar_box_safe_entry_fail_diag(
            candidate,
            top_z=top_z,
            tried_zs=tried_zs,
            tried_yaw_variants=tried_yaw,
        )
        candidate["_plan_before_motion_fail_reason"] = "no_safe_entry_ik"
        fail_tag = (
            "PLAN_AFTER_PRELUDE_FAIL"
            if plan_log_tag == "PLAN_AFTER_PRELUDE"
            else "PLAN_BEFORE_MOTION_FAIL"
        )
        self.get_logger().error(
            "[%s] reason=no_safe_entry_ik detail=%s"
            % (fail_tag, best_detail or "exhausted_safe_entry_z_search")
        )
        return False

    def _log_chips_can_safe_pregrasp_policy(
        self, candidate: Dict[str, Any], *, reason: str
    ) -> None:
        if not self._is_chips_can_cylinder_topdown_candidate(candidate):
            return
        forced = bool(self._chips_can_force_safe_pregrasp_stage_active(candidate))
        high_forced = bool(self._chips_can_high_pregrasp_policy_active(candidate))
        self.get_logger().info(
            "[CHIPS_CAN_SAFE_PREGRASP_POLICY]\n"
            "label=chips_can\n"
            "strategy=cylinder_topdown\n"
            "enable_safe_pregrasp_stage=%s\n"
            "chips_can_force_safe_pregrasp_stage=%s\n"
            "chips_can_force_high_pregrasp_stage=%s\n"
            "forced_safe_pregrasp=%s\n"
            "forced_high_pregrasp=%s\n"
            "reason=%s\n"
            "result=%s"
            % (
                str(bool(self._enable_safe_pregrasp_stage)).lower(),
                str(bool(self._chips_can_force_safe_pregrasp_stage)).lower(),
                str(bool(self._chips_can_force_high_pregrasp_stage)).lower(),
                str(forced).lower(),
                str(high_forced).lower(),
                str(reason),
                "HIGH_PREGRASP" if high_forced else ("SAFE" if forced else "DISABLED"),
            )
        )

    def _chips_can_demo_scene_02_golden_required(
        self, candidate: Optional[Dict[str, Any]] = None
    ) -> bool:
        from panda_vision.spawn.demo_scene_presets import (
            demo_scene_policy_scene_id_for_preset,
        )

        scene_id = str(self._scene_id or "").strip().lower()
        if candidate is not None:
            label = str(candidate.get("label") or self._target_label or "").strip().lower()
        else:
            label = str(self._target_label or "").strip().lower()
        return (
            demo_scene_policy_scene_id_for_preset(scene_id) == "demo_scene_02"
            and label == "chips_can"
        )

    def _log_chips_can_golden_required_missing(self, reason: str) -> None:
        self.get_logger().error(
            format_chips_can_golden_required_missing_log(
                {
                    "scene_id": str(self._scene_id or ""),
                    "target_label": str(self._target_label or ""),
                    "reason": str(reason),
                }
            )
        )

    def _bootstrap_chips_can_demo_golden(self) -> bool:
        if not self._chips_can_demo_scene_02_golden_required():
            return True
        if self._demo_profile is not None:
            prof_params = dict(self._demo_profile.get("parameters") or {})
            if bool(prof_params.get("chips_can_use_legacy_successful_pick_policy", False)):
                self._chips_can_use_legacy_successful_pick_policy = True
        if self._demo_profile is None:
            self._log_chips_can_golden_required_missing("demo_profile_not_loaded")
            return False
        if not bool(self._chips_can_use_legacy_successful_pick_policy):
            self._log_chips_can_golden_required_missing(
                "chips_can_use_legacy_successful_pick_policy_not_active"
            )
            return False
        yaml_path = self._resolve_demo_golden_candidate_yaml_path()
        golden = load_golden_pick_candidate(yaml_path)
        self.get_logger().info(
            format_golden_candidate_load_log(
                {
                    "path": yaml_path,
                    "scene_id": "demo_scene_02",
                    "target_label": "chips_can",
                    "status": (golden or {}).get("status", ""),
                    "result": "OK" if golden is not None else "FAIL",
                }
            )
        )
        if golden is None:
            self._log_chips_can_golden_required_missing("golden_candidate_file_not_loaded")
            return False
        self._chips_can_demo_golden_payload = golden
        return True

    def _chips_can_legacy_successful_pick_policy_active(
        self, candidate: Dict[str, Any]
    ) -> bool:
        return bool(
            self._is_chips_can_cylinder_topdown_candidate(candidate)
            and bool(getattr(self, "_chips_can_use_legacy_successful_pick_policy", False))
        )

    def _chips_can_high_pregrasp_policy_active(
        self, candidate: Dict[str, Any]
    ) -> bool:
        if self._chips_can_legacy_successful_pick_policy_active(candidate):
            return False
        return bool(
            self._is_chips_can_cylinder_topdown_candidate(candidate)
            and self._chips_can_force_high_pregrasp_stage
        )

    def _resolve_pick_route_preflight_plan_status(
        self, candidate: Dict[str, Any]
    ) -> Dict[str, Any]:
        """Estado de plan pregrasp vs entrada object_high (solo chips_can high_pregrasp)."""
        validated = candidate.get("_plan_before_motion_validated") or {}
        pf = candidate.get("_pregrasp_plan_preflight") or {}
        grasp_ik_required = bool(
            self._grasp_ik_required_before_pregrasp_from_home()
        )
        legacy_pregrasp_plan_ok = (
            bool(validated.get("ok"))
            and str(pf.get("ik_pregrasp")) == "OK"
            and str(pf.get("plan_pregrasp")) == "OK"
        )
        object_high_stage_enabled = bool(
            candidate.get("uses_low_object_high_approach_stage")
        )
        object_high_plan_ok = False
        route_entry_plan_ok = bool(legacy_pregrasp_plan_ok)
        selected_entry_target = "pregrasp_tcp"
        plan_before_result = str(pf.get("plan_before_result", ""))
        plan_pregrasp = str(pf.get("plan_pregrasp", ""))
        ik_pregrasp = str(pf.get("ik_pregrasp", ""))
        ik_grasp = str(pf.get("ik_grasp", ""))

        if self._chips_can_high_pregrasp_policy_active(candidate):
            selected_entry_target = "object_high_pregrasp"
            object_high_plan_ok = bool(
                validated.get("ok")
                and object_high_stage_enabled
                and plan_pregrasp in ("OK", "OK_OBJECT_HIGH")
                and ik_pregrasp in ("OK", "SKIP_HIGH_ENTRY")
                and plan_before_result
                in (
                    "OK_CHIPS_HIGH_PREGRASP",
                    OK_CHIPS_HIGH_ROUTE_PREVALIDATED,
                    OK_CHIPS_HIGH_ROUTE_PENDING_FINAL_DESCEND_VALIDATE,
                    OK_CHIPS_LEGACY_SUCCESS_POLICY,
                    OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND,
                    "OK_CHIPS_ADAPTIVE_ENTRY_PREGRASP",
                    "OK_HIGH_STAGE_ONLY",
                    "PREPLANNED_OK",
                    "OK",
                )
            )
            route_entry_plan_ok = bool(object_high_plan_ok)
            pregrasp_plan_ok = bool(route_entry_plan_ok)
        else:
            pregrasp_plan_ok = bool(legacy_pregrasp_plan_ok)

        full_route_required = self._demo_full_pick_route_prevalidation_required(
            candidate
        )
        cart_fraction = _to_float(candidate.get("_cartesian_descend_fraction"))
        sugar_two_phase = bool(candidate.get("sugar_box_two_phase_pick_route"))
        cart_pending = bool(candidate.get("_cartesian_descend_pending_at_pregrasp"))
        cartesian_prevalidated = bool(candidate.get("_cartesian_descend_prevalidated"))
        preflight_source = ""
        full_pick_route_prevalidated = bool(
            plan_before_result == OK_FULL_PICK_ROUTE_PREVALIDATED
            and cartesian_prevalidated
        )
        chips_high_route_prevalidated = bool(
            plan_before_result == OK_CHIPS_HIGH_ROUTE_PREVALIDATED
            and cartesian_prevalidated
            and bool(candidate.get("_chips_can_high_route_prevalidated"))
        )
        chips_high_route_pending = bool(
            plan_before_result == OK_CHIPS_HIGH_ROUTE_PENDING_FINAL_DESCEND_VALIDATE
            and bool(candidate.get("_chips_can_high_route_pending_final_descend"))
        )
        chips_legacy_pending_actual_tf = bool(
            plan_before_result == OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND
            and bool(candidate.get("_chips_can_legacy_pending_actual_tf_descend"))
        )
        chips_legacy_success_prevalidated = bool(
            plan_before_result == OK_CHIPS_LEGACY_SUCCESS_POLICY
            and bool(candidate.get("_chips_can_legacy_success_policy_prevalidated"))
        )
        object_safe_above_plan_ok = bool(
            candidate.get("_object_safe_above_route_prevalidated")
            or full_pick_route_prevalidated
            or bool(candidate.get("object_safe_above_plan_ok"))
        )
        sugar_defer_pending_descend = bool(
            plan_before_result == "OK_PREGRASP_PENDING_DESCEND_VALIDATE"
            and cart_pending
            and object_safe_above_plan_ok
            and sugar_box_multiobject_use_object_safe_above_stage(candidate)
        )
        if chips_high_route_prevalidated:
            preflight_source = CHIPS_CAN_HIGH_ROUTE_PREFLIGHT_SOURCE
            selected_entry_target = "object_high_pregrasp"
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            object_high_plan_ok = True
            allows_motion = True
            block_reason = CHIPS_CAN_HIGH_ROUTE_PREFLIGHT_SOURCE
        elif chips_high_route_pending:
            preflight_source = CHIPS_CAN_HIGH_ROUTE_PENDING_PREFLIGHT_SOURCE
            selected_entry_target = "object_high_pregrasp"
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            object_high_plan_ok = True
            allows_motion = True
            block_reason = CHIPS_CAN_HIGH_ROUTE_PENDING_PREFLIGHT_SOURCE
        elif chips_legacy_pending_actual_tf:
            preflight_source = CHIPS_CAN_LEGACY_PENDING_ACTUAL_TF_DESCEND_PREFLIGHT_SOURCE
            selected_entry_target = "object_high_pregrasp"
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            object_high_plan_ok = True
            cartesian_prevalidated = False
            cart_pending = True
            allows_motion = True
            block_reason = CHIPS_CAN_LEGACY_PENDING_ACTUAL_TF_DESCEND_PREFLIGHT_SOURCE
        elif chips_legacy_success_prevalidated:
            preflight_source = CHIPS_CAN_LEGACY_SUCCESS_PREFLIGHT_SOURCE
            selected_entry_target = "object_high_pregrasp"
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            object_high_plan_ok = True
            cartesian_prevalidated = True
            allows_motion = True
            block_reason = CHIPS_CAN_LEGACY_SUCCESS_PREFLIGHT_SOURCE
        elif full_pick_route_prevalidated:
            preflight_source = "full_pick_route_prevalidated"
            selected_entry_target = resolve_selected_entry_target(
                candidate, plan_before_result
            )
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            allows_motion = True
            block_reason = "full_pick_route_prevalidated"
        elif sugar_defer_pending_descend:
            preflight_source = SUGAR_BOX_DEFER_FINAL_DESCEND_PREFLIGHT_SOURCE
            selected_entry_target = "object_safe_above_tcp"
            route_entry_plan_ok = True
            pregrasp_plan_ok = True
            object_safe_above_plan_ok = True
            cartesian_prevalidated = False
            cart_pending = True
            allows_motion = True
            block_reason = SUGAR_BOX_DEFER_FINAL_DESCEND_PREFLIGHT_SOURCE
        else:
            if object_safe_above_plan_ok:
                selected_entry_target = resolve_selected_entry_target(
                    candidate, plan_before_result
                )
                route_entry_plan_ok = True
                pregrasp_plan_ok = cartesian_prevalidated
            allows_motion, block_reason = _pick_route_preflight_allows_motion(
                plan_before_result=plan_before_result,
                cartesian_descend_prevalidated=cartesian_prevalidated,
                full_route_required=full_route_required,
                cartesian_fraction=cart_fraction,
                fraction_threshold=float(self._cartesian_fraction_threshold),
                sugar_two_phase_deferred=sugar_two_phase,
                cartesian_descend_pending_at_pregrasp=cart_pending,
                object_safe_above_deferred=bool(
                    candidate.get("object_safe_above_two_phase_pick_route")
                    and plan_before_result
                    in (
                        "OK_OBJECT_SAFE_ABOVE_PRELUDE_PHASE1",
                        "OK_OBJECT_SAFE_ABOVE_DEFERRED",
                    )
                ),
                cartesian_descend_prevalidation_source=str(
                    candidate.get("_cartesian_descend_prevalidation_source") or "moveit"
                ),
                paired_validation_required=self._paired_pregrasp_validation_required(
                    candidate
                ),
                label=str(candidate.get("label") or ""),
                simple_direct_route=bool(candidate.get("_simple_direct_pick_route")),
            )
            if (
                sugar_two_phase
                and plan_before_result in ("OK_PRELUDE_PHASE1",)
                and not bool(candidate.get("object_safe_above_two_phase_pick_route"))
            ):
                pregrasp_plan_ok = True
                route_entry_plan_ok = True
            if (
                cart_pending
                and plan_before_result in ("OK_PREGRASP_PENDING_DESCEND_VALIDATE",)
            ):
                pregrasp_plan_ok = True
                route_entry_plan_ok = True
            if full_route_required and not allows_motion:
                pregrasp_plan_ok = False
                self.get_logger().error(
                    "[EXECUTION_PREFLIGHT] pick_route_blocked reason=%s "
                    "plan_before_result=%s cartesian_prevalidated=%s"
                    % (
                        block_reason,
                        plan_before_result,
                        str(cartesian_prevalidated).lower(),
                    )
                )

        return {
            "pregrasp_plan_ok": pregrasp_plan_ok,
            "route_entry_plan_ok": route_entry_plan_ok,
            "object_high_plan_ok": object_high_plan_ok,
            "legacy_pregrasp_plan_ok": legacy_pregrasp_plan_ok,
            "object_high_stage_enabled": object_high_stage_enabled,
            "selected_entry_target": selected_entry_target,
            "grasp_ik_required_before_pregrasp": grasp_ik_required,
            "ik_grasp": ik_grasp,
            "ik_pregrasp": ik_pregrasp,
            "plan_pregrasp": plan_pregrasp,
            "plan_before_result": plan_before_result,
            "validated_ok": bool(validated.get("ok")),
            "full_pick_route_required": full_route_required,
            "cartesian_descend_prevalidated": cartesian_prevalidated,
            "cartesian_descend_fraction": cart_fraction,
            "pick_route_block_reason": block_reason if full_route_required else "",
            "object_safe_above_plan_ok": object_safe_above_plan_ok,
            "cartesian_prevalidated": cartesian_prevalidated,
            "preflight_source": preflight_source,
            "route_preflight_ok": bool(allows_motion),
            "actual_tf_descend_required": bool(
                candidate.get("_chips_can_legacy_pending_actual_tf_descend")
                or candidate.get("actual_tf_descend_required")
                or sugar_defer_pending_descend
            ),
            "cartesian_descend_pending_at_pregrasp": cart_pending,
            "low_to_grasp_used_as_diagnostic": bool(
                candidate.get("_chips_can_legacy_pending_actual_tf_descend")
            ),
        }

    def _chips_can_height_m(self, candidate: Dict[str, Any]) -> Optional[float]:
        cd = candidate.get("collision_dims")
        if isinstance(cd, dict):
            cyl = cd.get("cylinder")
            if isinstance(cyl, (list, tuple)) and len(cyl) >= 2:
                length_m = _to_float(cyl[1])
                if length_m is not None:
                    return float(length_m)
            box = cd.get("box")
            if isinstance(box, (list, tuple)) and len(box) >= 3:
                height_m = _to_float(box[2])
                if height_m is not None:
                    return float(height_m)
        for key in ("object_height_m", "db_height_m", "effective_height_m", "measured_height_m"):
            height_m = _to_float(candidate.get(key))
            if height_m is not None:
                return float(height_m)
        dims = candidate.get("dims_lwh")
        if isinstance(dims, (list, tuple)) and len(dims) >= 3:
            height_m = _to_float(dims[2])
            if height_m is not None:
                return float(height_m)
        return None

    def _chips_can_geometry_center_z(
        self, candidate: Dict[str, Any], fallback_z: float
    ) -> float:
        for key in ("geometry_center_z",):
            center_z = _to_float(candidate.get(key))
            if center_z is not None:
                return float(center_z)
        pos = candidate.get("position")
        if isinstance(pos, (list, tuple)) and len(pos) >= 3:
            return float(pos[2])
        grasp_center = candidate.get("grasp_center_base")
        if isinstance(grasp_center, (list, tuple)) and len(grasp_center) >= 3:
            return float(grasp_center[2])
        return float(fallback_z)

    def _chips_can_resolve_top_z_m(
        self, candidate: Dict[str, Any], fallback_z: float
    ) -> float:
        top_z = _to_float(candidate.get("top_z_m"))
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_estimated"))
        if top_z is None:
            top_z = _to_float(candidate.get("top_z"))
        height_m = self._chips_can_height_m(candidate)
        center_z = self._chips_can_geometry_center_z(candidate, float(fallback_z))
        if height_m is not None:
            expected_top = float(center_z) + 0.5 * float(height_m)
            if top_z is None:
                if 0.47 <= float(center_z) <= 0.54:
                    # Sin top_z_m explícito: center≈0.51 ya es tapa (demo_scene_02).
                    top_z = float(center_z)
                else:
                    top_z = expected_top
            elif (
                top_z is not None
                and abs(float(top_z) - float(center_z)) < 0.03
                and 0.47 <= float(top_z) <= 0.54
            ):
                # Visión ya reporta la tapa (top_z ≈ center ≈ 0.51 en demo_scene_02).
                top_z = float(top_z)
            elif (
                abs(float(top_z) - float(center_z)) < 0.03
                or float(top_z) < expected_top - 0.02
            ):
                top_z = expected_top
        if top_z is None:
            top_z = float(fallback_z)
        return float(top_z)

    def _apply_chips_can_top_z_correction(self, candidate: Dict[str, Any]) -> float:
        """Corrige top_z cuando el payload confunde centro geométrico con tapa (chips_can)."""
        if not self._is_chips_can_cylinder_topdown_candidate(candidate):
            pos = candidate.get("position")
            fallback = float(pos[2]) if isinstance(pos, (list, tuple)) and len(pos) >= 3 else 0.0
            return _to_float(candidate.get("top_z_m")) or fallback
        pos = candidate.get("position")
        fallback = float(pos[2]) if isinstance(pos, (list, tuple)) and len(pos) >= 3 else 0.0
        raw_top = _to_float(candidate.get("top_z_m"))
        corrected = self._chips_can_resolve_top_z_m(candidate, float(fallback))
        center_z = self._chips_can_geometry_center_z(candidate, float(fallback))
        height_m = self._chips_can_height_m(candidate)
        if raw_top is not None and abs(float(raw_top) - float(corrected)) > 1e-4:
            self.get_logger().info(
                "[CHIPS_CAN_TOP_Z_CORRECTED]\n"
                "geometry_center_z=%.4f\n"
                "height_m=%s\n"
                "raw_top_z_m=%.4f\n"
                "corrected_top_z_m=%.4f\n"
                "result=APPLIED"
                % (
                    float(center_z),
                    "n/a" if height_m is None else "%.4f" % float(height_m),
                    float(raw_top),
                    float(corrected),
                )
            )
        candidate["top_z_m"] = float(corrected)
        return float(corrected)

    def _enrich_mustard_runtime_top_z_sources(
        self, candidate: Dict[str, Any]
    ) -> None:
        """Copia geometría runtime (corners/collision) al candidato mustard."""
        target_entity = str(
            candidate.get("gt_entity_name") or candidate.get("entity_name") or ""
        ).strip().split("::")[-1]
        target_label = str(candidate.get("label", "")).strip().lower()
        corner_keys = (
            "top_face_corners_base",
            "gt_top_face_corners_base",
            "runtime_gt_top_face_corners_base",
            "model_top_face_corners_base",
            "top_corners_base",
        )
        center_keys = (
            "top_face_center_base",
            "gt_top_face_center_base",
            "runtime_gt_top_face_center_base",
        )
        passthrough_keys = (
            "collision_box_pose",
            "collision_dims",
            "collision_dims_moveit",
            "collision_dims_inflated",
            "dims_lwh",
            "semantic_box_center_base",
            "gt_geometry_center_base",
        )

        def _merge_from(src: Dict[str, Any]) -> None:
            if str(src.get("label", "")).strip().lower() != target_label:
                return
            ent = str(src.get("entity_name", "")).strip().split("::")[-1]
            if target_entity and ent and ent != target_entity:
                return
            for key in corner_keys + center_keys + passthrough_keys:
                if candidate.get(key) is None and src.get(key) is not None:
                    candidate[key] = src.get(key)
            corners_top = None
            for key in corner_keys:
                zs = [
                    _to_float(c[2])
                    for c in (src.get(key) or [])
                    if isinstance(c, (list, tuple)) and len(c) >= 3
                ]
                zs = [z for z in zs if z is not None]
                if zs:
                    corners_top = max(zs) if corners_top is None else max(corners_top, max(zs))
            if corners_top is not None and corners_top >= MUSTARD_EXPECTED_MIN_TOP_Z_M:
                candidate["runtime_scene_top_z_m"] = float(corners_top)
                return
            for key in center_keys:
                center = src.get(key)
                if (
                    isinstance(center, (list, tuple))
                    and len(center) >= 3
                    and _to_float(center[2]) is not None
                    and float(center[2]) >= MUSTARD_EXPECTED_MIN_TOP_Z_M
                ):
                    candidate["runtime_scene_top_z_m"] = float(center[2])
                    return

        for obs in candidate.get("scene_obstacles") or []:
            if isinstance(obs, dict) and bool(obs.get("is_target", False)):
                _merge_from(obs)
        for scene_obj in candidate.get("_runtime_scene_objects") or []:
            if isinstance(scene_obj, dict):
                _merge_from(scene_obj)

    def _apply_mustard_top_z_correction(
        self,
        candidate: Dict[str, Any],
        fallback_z: float,
    ) -> float:
        """Top geométrico real para mustard (no cap center / grasp_center z)."""
        if not mustard_tall_object_topdown_active(candidate):
            return _to_float(candidate.get("top_z_m")) or float(fallback_z)
        self._enrich_mustard_runtime_top_z_sources(candidate)
        selected, src, meta = resolve_mustard_geometry_top_z_m(
            candidate,
            table_z_m=float(self._table_z_m),
            fallback_z=float(fallback_z),
            scene_id=str(self._scene_id or ""),
        )
        debug_result = "OK"
        if float(selected) < float(MUSTARD_EXPECTED_MIN_TOP_Z_M):
            debug_result = "FAIL"
            self.get_logger().warning(
                format_mustard_top_z_sanity_log(selected_top_z=float(selected))
            )
        self.get_logger().info(
            format_mustard_top_z_source_debug_log(
                position_z=meta.get("position_z"),
                grasp_center_z=meta.get("grasp_center_z"),
                candidate_top_z_before=meta.get("candidate_top_z_before"),
                runtime_top_z=meta.get("runtime_top_z"),
                runtime_top_z_source=meta.get("runtime_top_z_source"),
                collision_center_z=meta.get("collision_center_z"),
                collision_height_m=meta.get("collision_height_m"),
                collision_top_z=meta.get("collision_top_z"),
                known_sdf_height_m=meta.get("known_sdf_height_m"),
                table_top_z=meta.get("table_top_z"),
                known_sdf_top_z=meta.get("known_sdf_top_z"),
                selected_top_z=float(selected),
                selected_top_z_source=str(src),
                result=debug_result,
            )
        )
        candidate["top_z_m"] = float(selected)
        candidate["_mustard_geometry_top_z_m"] = float(selected)
        candidate["_mustard_top_z_source"] = str(src)
        candidate["_mustard_top_z_meta"] = meta
        return float(selected)

    def _verify_mustard_scanner_aligned_z_contract_or_abort(
        self,
        candidate: Dict[str, Any],
        *,
        top_z: float,
        pregrasp_tcp: Tuple[float, float, float],
        grasp_tcp: Tuple[float, float, float],
    ) -> bool:
        if not mustard_tall_object_topdown_active(candidate):
            return True
        if not self._mustard_demo_scene_depth_search_active(
            str(candidate.get("label", "")),
            str(self._scene_id or ""),
        ):
            return True
        ok, fields = verify_mustard_scanner_aligned_z_contract(
            controller_top_z=float(top_z),
            controller_pregrasp_tcp_z=float(pregrasp_tcp[2]),
            controller_grasp_tcp_z=float(grasp_tcp[2]),
        )
        self.get_logger().info(format_mustard_scanner_aligned_contract_verify_log(fields))
        if ok:
            return True
        self.get_logger().error(
            "[MUSTARD_SCANNER_ALIGNED_CONTRACT_VERIFY]\n"
            "reason=mustard_top_z_not_aligned_with_scanner_contract\n"
            "result=FAIL"
        )
        candidate["_mustard_scanner_contract_abort"] = True
        candidate["_mustard_scanner_contract_fields"] = fields
        return False

    def _chips_can_min_non_contact_tcp_z(
        self, candidate: Dict[str, Any], top_z: float
    ) -> float:
        return float(top_z) + float(
            self._chips_can_min_non_contact_clearance_above_top_m
        )

    def _chips_can_controlled_descend_target_tcp_z(
        self, candidate: Dict[str, Any], top_z: float
    ) -> float:
        low_z = _to_float(candidate.get("chips_can_low_pregrasp_tcp_z"))
        if low_z is None:
            low_z = float(top_z) + float(
                self._chips_can_low_pregrasp_clearance_above_top_m
            )
        return float(low_z)

    def _chips_can_cylinder_axis_xy_from_gazebo_pose(
        self,
        candidate: Dict[str, Any],
        pose: Tuple[float, ...],
    ) -> Tuple[float, float]:
        label = str(candidate.get("label", "chips_can")).strip().lower()
        if len(pose) >= 7:
            quat = (
                float(pose[3]),
                float(pose[4]),
                float(pose[5]),
                float(pose[6]),
            )
        else:
            quat = (0.0, 0.0, 0.0, 1.0)
        sem = semantic_center_from_gazebo_model_origin(
            (float(pose[0]), float(pose[1]), float(pose[2])),
            quat,
            label,
        )
        return float(sem[0]), float(sem[1])

    def _enrich_chips_can_runtime_pose_from_gazebo(
        self, candidate: Dict[str, Any]
    ) -> bool:
        """Sustituye XY (y top_z) del candidato por la pose real del modelo en Gazebo."""
        if not self._is_chips_can_cylinder_topdown_candidate(candidate):
            return False
        if self._dry_run:
            return False
        entity = self._resolve_target_entity_name(candidate)
        pose = self._sample_gazebo_entity_pose(entity, collect_sec=0.15)
        if pose is None or len(pose) < 7:
            self.get_logger().warn(
                "[CHIPS_CAN_RUNTIME_POSE_GAZEBO]\n"
                "entity=%s\n"
                "result=UNAVAILABLE"
                % str(entity or "n/a")
            )
            return False
        label = str(candidate.get("label", "chips_can")).strip().lower()
        quat = (
            float(pose[3]),
            float(pose[4]),
            float(pose[5]),
            float(pose[6]),
        )
        origin = (float(pose[0]), float(pose[1]), float(pose[2]))
        sem = semantic_center_from_gazebo_model_origin(origin, quat, label)
        top_face = top_face_center_from_semantic_center(sem, quat, label)
        gz_x, gz_y, gz_sem_z = float(sem[0]), float(sem[1]), float(sem[2])
        top_z = float(top_face[2])

        prev = self._resolve_grasp_center_base_from_candidate(candidate)
        prev_xy = (
            (float(prev[0]), float(prev[1]))
            if prev is not None
            else (float("nan"), float("nan"))
        )
        shift_xy = math.hypot(gz_x - prev_xy[0], gz_y - prev_xy[1])
        prev_top = _to_float(candidate.get("top_z_m"))
        if prev_top is None:
            prev_top = _to_float(candidate.get("top_z_estimated"))

        candidate["grasp_center_base"] = [gz_x, gz_y, gz_sem_z]
        candidate["chosen_target_center_base"] = [gz_x, gz_y, gz_sem_z]
        candidate["position"] = (gz_x, gz_y, gz_sem_z)
        candidate["top_z_m"] = float(top_z)
        candidate["top_z_estimated"] = float(top_z)
        candidate["grasp_center_source"] = "runtime_gt_cylinder_center"
        candidate["top_face_source"] = "runtime_gt_known_cylinder"
        if not str(candidate.get("yaw_source") or "").strip():
            candidate["yaw_source"] = "runtime_gt_spawn_yaw"
        candidate["supported_for_demo"] = True
        candidate["_chips_can_runtime_pose_gazebo_applied"] = True
        normalize_demo_grasp_sources(candidate)

        self.get_logger().info(
            "[CHIPS_CAN_RUNTIME_POSE_GAZEBO]\n"
            "entity=%s\n"
            "gazebo_origin_xy=(%.4f, %.4f)\n"
            "gazebo_semantic_center_xy=(%.4f, %.4f)\n"
            "previous_center_xy=(%.4f, %.4f)\n"
            "shift_xy_m=%.4f\n"
            "previous_top_z_m=%s\n"
            "runtime_top_z_m=%.4f\n"
            "result=APPLIED"
            % (
                str(entity or "n/a"),
                float(origin[0]),
                float(origin[1]),
                gz_x,
                gz_y,
                prev_xy[0],
                prev_xy[1],
                float(shift_xy),
                "n/a" if prev_top is None else "%.4f" % float(prev_top),
                float(top_z),
            )
        )
        return True

    def _refresh_chips_can_disturbance_snapshot_from_gazebo(
        self,
        candidate: Dict[str, Any],
        *,
        stage: str,
    ) -> bool:
        """Baseline XY tras high_pregrasp para detectar solo deriva local, no HOME vs Gazebo."""
        if not self._is_chips_can_cylinder_topdown_candidate(candidate):
            return False
        entity = self._resolve_target_entity_name(candidate)
        pose = self._sample_gazebo_entity_pose(entity, collect_sec=0.12)
        if pose is None:
            self.get_logger().warn(
                "[CHIPS_CAN_DISTURBANCE_SNAPSHOT_REFRESH]\n"
                "stage=%s\n"
                "entity=%s\n"
                "result=UNAVAILABLE"
                % (str(stage), str(entity or "n/a"))
            )
            return False
        ax, ay = self._chips_can_cylinder_axis_xy_from_gazebo_pose(candidate, pose)
        prev = candidate.get("_chips_can_snapshot_object_xy")
        candidate["_chips_can_snapshot_object_xy"] = [float(ax), float(ay)]
        candidate["_chips_can_snapshot_source"] = str(stage)
        self.get_logger().info(
            "[CHIPS_CAN_DISTURBANCE_SNAPSHOT_REFRESH]\n"
            "stage=%s\n"
            "entity=%s\n"
            "previous_snapshot_xy=%s\n"
            "new_snapshot_xy=(%.4f, %.4f)\n"
            "gazebo_origin_xy=(%.4f, %.4f)\n"
            "result=OK"
            % (
                str(stage),
                str(entity),
                (
                    "n/a"
                    if not isinstance(prev, (list, tuple)) or len(prev) < 2
                    else "(%.4f, %.4f)" % (float(prev[0]), float(prev[1]))
                ),
                float(ax),
                float(ay),
                float(pose[0]),
                float(pose[1]),
            )
        )
        return True

    def _chips_can_guard_tcp_z_non_contact(
        self,
        candidate: Dict[str, Any],
        *,
        requested_tcp_z: float,
        phase: str,
        top_z: Optional[float] = None,
        current_tcp_z: Optional[float] = None,
    ) -> Tuple[float, str]:
        """Clamp/abort TCP Z en fases no-contacto (solo chips_can cylinder_topdown)."""
        if not self._is_chips_can_cylinder_topdown_candidate(candidate):
            return float(requested_tcp_z), "OK"
        if top_z is None:
            top_z = self._chips_can_resolve_top_z_m(
                candidate, float(requested_tcp_z)
            )
        eps = float(self._chips_can_top_clearance_epsilon_m)
        abort_z = float(top_z) + eps
        phase_s = str(phase)
        if phase_s in ("high_to_low_pregrasp", "cartesian_descend_to_grasp"):
            low_target_z = self._chips_can_controlled_descend_target_tcp_z(
                candidate, float(top_z)
            )
            if float(requested_tcp_z) < abort_z - 1e-6:
                self.get_logger().error(
                    "[CHIPS_CAN_TOP_CLEARANCE_VIOLATION]\n"
                    "phase=%s\n"
                    "top_z=%.4f\n"
                    "requested_tcp_z=%.4f\n"
                    "abort_threshold_tcp_z=%.4f\n"
                    "low_target_tcp_z=%.4f\n"
                    "result=BLOCKED"
                    % (
                        phase_s,
                        float(top_z),
                        float(requested_tcp_z),
                        abort_z,
                        float(low_target_z),
                    )
                )
                return float(low_target_z), "BLOCKED"
            self.get_logger().info(
                "[CHIPS_CAN_Z_SAFETY_GUARD]\n"
                "top_z=%.4f\n"
                "current_tcp_z=%s\n"
                "requested_tcp_z=%.4f\n"
                "min_non_contact_tcp_z=%.4f\n"
                "low_target_tcp_z=%.4f\n"
                "phase=%s\n"
                "result=OK_CONTROLLED_DESCEND"
                % (
                    float(top_z),
                    "n/a" if current_tcp_z is None else "%.4f" % float(current_tcp_z),
                    float(requested_tcp_z),
                    self._chips_can_min_non_contact_tcp_z(candidate, float(top_z)),
                    float(low_target_z),
                    phase_s,
                )
            )
            return float(requested_tcp_z), "OK"
        min_z = self._chips_can_min_non_contact_tcp_z(candidate, float(top_z))
        result = "OK"
        guarded = float(requested_tcp_z)
        if float(requested_tcp_z) < abort_z - 1e-6:
            self.get_logger().error(
                "[CHIPS_CAN_TOP_CLEARANCE_VIOLATION]\n"
                "phase=%s\n"
                "top_z=%.4f\n"
                "requested_tcp_z=%.4f\n"
                "abort_threshold_tcp_z=%.4f\n"
                "result=BLOCKED"
                % (str(phase), float(top_z), float(requested_tcp_z), abort_z)
            )
            return float(min_z), "BLOCKED"
        if float(requested_tcp_z) < min_z - 1e-6:
            guarded = float(min_z)
            result = "CLAMPED"
        if current_tcp_z is not None and float(current_tcp_z) < abort_z - 1e-6:
            self.get_logger().error(
                "[CHIPS_CAN_TOP_CLEARANCE_VIOLATION]\n"
                "phase=%s\n"
                "top_z=%.4f\n"
                "current_tcp_z=%.4f\n"
                "abort_threshold_tcp_z=%.4f\n"
                "result=BLOCKED_CURRENT"
                % (str(phase), float(top_z), float(current_tcp_z), abort_z)
            )
            return float(min_z), "BLOCKED"
        self.get_logger().info(
            "[CHIPS_CAN_Z_SAFETY_GUARD]\n"
            "top_z=%.4f\n"
            "current_tcp_z=%s\n"
            "requested_tcp_z=%.4f\n"
            "min_non_contact_tcp_z=%.4f\n"
            "phase=%s\n"
            "result=%s"
            % (
                float(top_z),
                "n/a" if current_tcp_z is None else "%.4f" % float(current_tcp_z),
                float(requested_tcp_z),
                float(min_z),
                str(phase),
                result,
            )
        )
        return guarded, result

    def _apply_chips_can_high_pregrasp_policy(
        self,
        candidate: Dict[str, Any],
        seq: Dict[str, Any],
        top_z: float,
    ) -> None:
        if not self._chips_can_high_pregrasp_policy_active(candidate):
            return
        grasp_tcp = tuple(seq.get("grasp_tcp", (0.0, 0.0, float(top_z))))
        high_clear = float(self._chips_can_high_pregrasp_clearance_above_top_m)
        low_clear = float(self._chips_can_low_pregrasp_clearance_above_top_m)
        high_z = min(float(top_z) + high_clear, float(self._max_target_z))
        low_z = min(float(top_z) + low_clear, float(self._max_target_z))
        low_z = max(low_z, float(grasp_tcp[2]) + 0.010)
        seq["desired_high_pregrasp_tcp"] = (
            float(grasp_tcp[0]),
            float(grasp_tcp[1]),
            float(high_z),
        )
        seq["object_high_pregrasp_tcp"] = tuple(seq["desired_high_pregrasp_tcp"])
        seq["selected_entry_pregrasp_tcp"] = None
        seq["pregrasp_tcp"] = (
            float(grasp_tcp[0]),
            float(grasp_tcp[1]),
            float(low_z),
        )
        seq["uses_low_object_high_approach_stage"] = True
        seq["low_object_high_reason"] = "chips_can_force_high_pregrasp"
        final_descend = max(0.0, float(low_z) - float(grasp_tcp[2]))
        seq["final_descend_m"] = float(final_descend)
        seq["requested_descend_m"] = float(final_descend)
        seq["descend_limit_reason"] = "chips_can_high_to_low_pregrasp"
        candidate["uses_low_object_high_approach_stage"] = True
        candidate["chips_can_desired_high_pregrasp_tcp_z"] = float(high_z)
        candidate["chips_can_high_pregrasp_tcp_z"] = float(high_z)
        candidate["chips_can_selected_entry_pregrasp_tcp_z"] = None
        candidate["chips_can_low_pregrasp_tcp_z"] = float(low_z)
        candidate["chips_can_min_non_contact_tcp_z"] = self._chips_can_min_non_contact_tcp_z(
            candidate, float(top_z)
        )
        candidate["pregrasp_clearance_above_top_m"] = float(low_clear)
        self.get_logger().info(
            "[CHIPS_CAN_HIGH_PREGRASP_POLICY]\n"
            "label=chips_can\n"
            "strategy=cylinder_topdown\n"
            "force_high_pregrasp_stage=true\n"
            "top_z=%.4f\n"
            "desired_high_pregrasp_tcp_z=%.4f\n"
            "low_pregrasp_tcp_z=%.4f\n"
            "selected_entry_pregrasp_tcp_z=n/a\n"
            "high_clearance_above_top_m=%.4f\n"
            "low_clearance_above_top_m=%.4f\n"
            "min_non_contact_clearance_above_top_m=%.4f\n"
            "result=ENABLED"
            % (
                float(top_z),
                float(high_z),
                float(low_z),
                float(high_clear),
                float(low_clear),
                float(self._chips_can_min_non_contact_clearance_above_top_m),
            )
        )
        self.get_logger().info(
            "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
            "entry_moveit_target=object_high_pregrasp\n"
            "desired_high_pregrasp_tcp=(%.3f, %.3f, %.3f)\n"
            "low_pregrasp_tcp=(%.3f, %.3f, %.3f)\n"
            "grasp_tcp=(%.3f, %.3f, %.3f)\n"
            "post_entry_descend=cartesian_high_to_low\n"
            "grasp_descend=cartesian_descend_to_grasp\n"
            "result=PLANNED"
            % (
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(high_z),
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(low_z),
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(grasp_tcp[2]),
            )
        )

    def _apply_chips_can_legacy_successful_pick_policy(
        self,
        candidate: Dict[str, Any],
        seq: Dict[str, Any],
        top_z: float,
    ) -> None:
        if not self._chips_can_legacy_successful_pick_policy_active(candidate):
            return
        grasp_tcp = tuple(seq.get("grasp_tcp", (0.0, 0.0, float(top_z))))
        high_clear = float(self._chips_can_high_pregrasp_clearance_above_top_m)
        pre_h = _to_float(candidate.get("chips_can_legacy_pregrasp_height_above_top_m"))
        if pre_h is None:
            pre_h = float(CHIPS_CAN_LEGACY_PREGRASP_HEIGHT_ABOVE_TOP_M[1])
        depth = self._resolve_chips_can_recommended_grasp_depth_m(candidate)
        if depth <= 0.0:
            depth = float(CHIPS_CAN_LEGACY_GRASP_DEPTH_FROM_TOP_M[2])
        high_z = min(float(top_z) + high_clear, float(self._max_target_z))
        legacy_pre_z = min(
            float(top_z) + float(pre_h),
            float(self._max_target_z),
        )
        legacy_pre_z = max(legacy_pre_z, float(grasp_tcp[2]) + 0.010)
        legacy_gr_z = chips_can_legacy_grasp_tcp_z(
            top_z_m=float(top_z),
            depth_from_top_m=float(depth),
        )
        seq["desired_high_pregrasp_tcp"] = (
            float(grasp_tcp[0]),
            float(grasp_tcp[1]),
            float(high_z),
        )
        seq["object_high_pregrasp_tcp"] = tuple(seq["desired_high_pregrasp_tcp"])
        seq["selected_entry_pregrasp_tcp"] = None
        seq["pregrasp_tcp"] = (
            float(grasp_tcp[0]),
            float(grasp_tcp[1]),
            float(legacy_pre_z),
        )
        seq["grasp_tcp"] = (
            float(grasp_tcp[0]),
            float(grasp_tcp[1]),
            float(legacy_gr_z),
        )
        seq["uses_low_object_high_approach_stage"] = True
        seq["low_object_high_reason"] = "chips_can_legacy_success_policy"
        final_descend = chips_can_legacy_final_descend_m(
            pregrasp_height_above_top_m=float(pre_h),
            depth_from_top_m=float(depth),
        )
        seq["final_descend_m"] = float(final_descend)
        seq["requested_descend_m"] = float(final_descend)
        seq["descend_limit_reason"] = "chips_can_legacy_short_final_descend"
        candidate["uses_low_object_high_approach_stage"] = True
        candidate["chips_can_legacy_success_policy"] = True
        candidate["chips_can_legacy_pregrasp_height_above_top_m"] = float(pre_h)
        candidate["recommended_grasp_depth_from_top_m"] = float(depth)
        candidate["chips_can_desired_high_pregrasp_tcp_z"] = float(high_z)
        candidate["chips_can_high_pregrasp_tcp_z"] = float(high_z)
        candidate["chips_can_low_pregrasp_tcp_z"] = float(legacy_pre_z)
        candidate["pregrasp_clearance_above_top_m"] = float(pre_h)
        self.get_logger().info(
            "[CHIPS_CAN_LEGACY_SUCCESS_POLICY]\n"
            "label=chips_can\n"
            "strategy=cylinder_topdown_legacy\n"
            "top_z=%.4f\n"
            "object_high_tcp_z=%.4f\n"
            "legacy_pregrasp_tcp_z=%.4f\n"
            "legacy_pregrasp_height_above_top_m=%.4f\n"
            "recommended_grasp_depth_from_top_m=%.4f\n"
            "legacy_grasp_tcp_z=%.4f\n"
            "legacy_final_descend_m=%.4f\n"
            "historical_reference=%s\n"
            "result=ENABLED"
            % (
                float(top_z),
                float(high_z),
                float(legacy_pre_z),
                float(pre_h),
                float(depth),
                float(legacy_gr_z),
                float(final_descend),
                str(CHIPS_CAN_LEGACY_HISTORICAL_SUCCESS_REFERENCE),
            )
        )
        self.get_logger().info(
            "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
            "entry_moveit_target=object_high_pregrasp\n"
            "desired_high_pregrasp_tcp=(%.3f, %.3f, %.3f)\n"
            "low_pregrasp_tcp=(%.3f, %.3f, %.3f)\n"
            "grasp_tcp=(%.3f, %.3f, %.3f)\n"
            "post_entry_descend=cartesian_high_to_legacy_low\n"
            "grasp_descend=actual_tf_short_descend\n"
            "result=PLANNED"
            % (
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(high_z),
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(legacy_pre_z),
                float(grasp_tcp[0]),
                float(grasp_tcp[1]),
                float(legacy_gr_z),
            )
        )

    def _try_chips_can_golden_legacy_variant_probe(
        self,
        candidate: Dict[str, Any],
        *,
        top_z: float,
        grasp_xy: Tuple[float, float],
        start_js: Any,
        base_yaw: float,
        entry_plan: Tuple[float, float, float],
        workspace_js: Any,
        target_id: str,
        threshold: float,
    ) -> Optional[Dict[str, Any]]:
        scene_id = str(self._scene_id or "").strip().lower()
        label = str(candidate.get("label") or self._target_label or "").strip().lower()
        if (
            not runtime_uses_demo_scene_02_golden(scene_id)
            or label != "chips_can"
            or not bool(getattr(self, "_chips_can_use_legacy_successful_pick_policy", False))
        ):
            return None
        yaml_path = self._resolve_demo_golden_candidate_yaml_path()
        golden = load_golden_pick_candidate(yaml_path)
        self.get_logger().info(
            format_golden_candidate_load_log(
                {
                    "path": yaml_path,
                    "scene_id": scene_id,
                    "target_label": label,
                    "status": (golden or {}).get("status", ""),
                    "result": "OK" if golden is not None else "FAIL",
                }
            )
        )
        if golden is None:
            return None
        if not (golden.get("legacy") or {}):
            from panda_controller.demo_golden_pick_candidate import (
                PLAN_PREFLIGHT_PICK_ONLY_STATUS,
                enrich_chips_can_legacy_golden_fields,
            )

            if str(golden.get("status", "")).strip().lower() == PLAN_PREFLIGHT_PICK_ONLY_STATUS:
                golden = enrich_chips_can_legacy_golden_fields(
                    golden,
                    grasp_xy=(float(grasp_xy[0]), float(grasp_xy[1])),
                )
        layout_version = str(
            getattr(self, "_demo_layout_version", "")
            or golden.get("layout_version")
            or ""
        ).strip()
        runtime_xy = (float(grasp_xy[0]), float(grasp_xy[1]))
        runtime_scene_yaw, runtime_scene_yaw_source = resolve_runtime_scene_yaw_rad(
            candidate,
            target_label=label,
        )
        runtime_commanded_yaw = float(
            candidate.get("_base_commanded_tcp_yaw_rad") or base_yaw
        )
        compat_ok, compat_reason, _compat_details = validate_golden_candidate_compatibility(
            golden,
            scene_id=scene_id,
            layout_version=layout_version,
            target_label=label,
            runtime_xy=runtime_xy,
            runtime_top_z=float(top_z),
            runtime_scene_yaw_rad=runtime_scene_yaw,
            runtime_scene_yaw_source=runtime_scene_yaw_source,
            runtime_commanded_tcp_yaw_rad=runtime_commanded_yaw,
        )
        if not compat_ok:
            self.get_logger().warning(
                format_golden_candidate_fallback_log(
                    {"reason": "chips_can_golden_%s" % compat_reason}
                )
            )
            return None
        targets = chips_can_golden_legacy_probe_targets(
            golden,
            grasp_xy=grasp_xy,
            top_z_m=float(top_z),
        )
        if targets is None:
            self.get_logger().warning(
                format_golden_candidate_fallback_log(
                    {"reason": "chips_can_golden_missing_legacy_params"}
                )
            )
            return None
        cmd_yaw = float(targets["commanded_tcp_yaw_rad"])
        ranked_h = self._ranked_pregrasp_yaw_variants_for_pose(
            candidate, base_yaw, entry_plan, start_js
        )
        q_match = None
        qname = str(targets["variant_name"])
        joint_dist = 0.0
        best_yaw_delta = float("inf")
        for name, q, yaw, _ik, dist in ranked_h:
            yaw_delta = abs(self._wrap_to_pi(float(yaw) - cmd_yaw))
            if yaw_delta + 1e-9 < best_yaw_delta:
                best_yaw_delta = float(yaw_delta)
                q_match = q
                qname = str(name)
                joint_dist = float(dist)
        if q_match is None:
            q_match = self._downward_yaw_quaternion(cmd_yaw)
            joint_dist = 0.0
        pre_plan = targets["pre_plan"]
        gr_plan = targets["gr_plan"]
        probe = self._probe_chips_can_high_route_yaw_variant(
            candidate,
            workspace_js=workspace_js,
            high_plan=entry_plan,
            pre_plan=pre_plan,
            gr_plan=gr_plan,
            quat=q_match,
            variant_name=qname,
            commanded_yaw_rad=cmd_yaw,
            joint_dist=float(joint_dist),
            target_id=target_id,
            ik_seed_name="pick_workspace_ready",
            plan_start_js=workspace_js,
            top_z_m=float(top_z),
            use_gr_plan_for_final_descend_probe=True,
            legacy_low_to_grasp_diagnostic_only=True,
        )
        probe["pregrasp_height_above_top_m"] = float(targets["pregrasp_height_above_top_m"])
        probe["depth_from_top_m"] = float(targets["depth_from_top_m"])
        probe["entry_tcp"] = targets["entry_tcp"]
        probe["entry_plan"] = entry_plan
        pending_ok = chips_can_legacy_pending_variant_passes(
            probe,
            fraction_threshold=float(threshold),
        )
        legacy_meta = golden.get("legacy") or {}
        self.get_logger().info(
            format_chips_can_golden_legacy_variant_log(
                {
                    "scene_id": scene_id,
                    "target_label": label,
                    "pregrasp_height_above_top_m": float(
                        targets["pregrasp_height_above_top_m"]
                    ),
                    "depth_from_top_m": float(targets["depth_from_top_m"]),
                    "commanded_tcp_yaw_rad": cmd_yaw,
                    "object_high_to_low_fraction": float(
                        targets["object_high_to_low_fraction"]
                    ),
                    "high_to_low_result": str(
                        legacy_meta.get("high_to_low_result", "n/a")
                    ),
                    "result": "OK" if pending_ok else "FAIL",
                }
            )
        )
        if not pending_ok:
            self.get_logger().warning(
                format_golden_candidate_fallback_log(
                    {"reason": "chips_can_golden_probe_revalidate_fail"}
                )
            )
            return None
        apply_golden_runtime_overrides(candidate, golden)
        candidate["_chips_can_golden_legacy_variant"] = True
        candidate["_demo_golden_candidate"] = True
        candidate["_demo_golden_candidate_yaml"] = yaml_path
        return probe

    def _search_chips_can_legacy_success_policy_variants(
        self,
        candidate: Dict[str, Any],
        *,
        top_z: float,
        grasp_xy: Tuple[float, float],
        start_js: Any,
        base_yaw: float,
        source_frame: str,
    ) -> Tuple[Optional[Dict[str, Any]], List[Dict[str, Any]]]:
        if self._moveit2 is None:
            return None, []
        threshold = float(self._cartesian_fraction_threshold)
        gx, gy = float(grasp_xy[0]), float(grasp_xy[1])
        high_clear = float(self._chips_can_high_pregrasp_clearance_above_top_m)
        entry_z = min(float(top_z) + high_clear, float(self._max_target_z))
        entry_tcp = (gx, gy, float(entry_z))
        entry_plan, _ = self._transform_target_to_planning_frame(
            entry_tcp, source_frame, stage="chips_can_legacy_entry_high"
        )
        if entry_plan is None:
            return None, []
        wp = str(self._pick_workspace_prelude_waypoint)
        workspace_js = (
            self._joint_state_for_waypoint(wp)
            if self._enable_pick_workspace_prelude
            and waypoint_is_configured(self._motion_waypoints_data, wp)
            else start_js
        )
        target_id = str(self._current_target_collision_id or "").strip()
        self._ensure_legacy_target_collision_required_for_approach(
            candidate, target_id
        )
        golden_probe = self._try_chips_can_golden_legacy_variant_probe(
            candidate,
            top_z=float(top_z),
            grasp_xy=grasp_xy,
            start_js=start_js,
            base_yaw=float(base_yaw),
            entry_plan=entry_plan,
            workspace_js=workspace_js,
            target_id=target_id,
            threshold=float(threshold),
        )
        if self._chips_can_demo_scene_02_golden_required(candidate):
            self._ensure_legacy_target_collision_required_for_approach(
                candidate, target_id
            )
            if golden_probe is None:
                self._log_chips_can_golden_required_missing(
                    "golden_legacy_variant_probe_failed"
                )
                return None, []
            return golden_probe, [golden_probe]
        if golden_probe is not None:
            self._ensure_legacy_target_collision_required_for_approach(
                candidate, target_id
            )
            return golden_probe, [golden_probe]
        ranked_h = self._ranked_pregrasp_yaw_variants_for_pose(
            candidate, base_yaw, entry_plan, start_js
        )
        all_probes: List[Dict[str, Any]] = []
        for pre_h in CHIPS_CAN_LEGACY_PREGRASP_HEIGHT_ABOVE_TOP_M:
            legacy_pre_z = chips_can_legacy_pregrasp_tcp_z(
                top_z_m=float(top_z),
                pregrasp_height_above_top_m=float(pre_h),
            )
            for depth in CHIPS_CAN_LEGACY_GRASP_DEPTH_FROM_TOP_M:
                gr_z = chips_can_legacy_grasp_tcp_z(
                    top_z_m=float(top_z),
                    depth_from_top_m=float(depth),
                )
                pre_plan = (gx, gy, float(legacy_pre_z))
                gr_plan = (gx, gy, float(gr_z))
                self.get_logger().info(
                    format_chips_can_legacy_success_policy_start_log(
                        {
                            "top_z": float(top_z),
                            "legacy_pregrasp_height_above_top": float(pre_h),
                            "legacy_pregrasp_tcp_z": float(legacy_pre_z),
                            "target_depth_from_top": float(depth),
                            "target_grasp_tcp_z": float(gr_z),
                        }
                    )
                )
                for qname, q, cmd_yaw, _ik_h_sol, joint_dist in ranked_h:
                    probe = self._probe_chips_can_high_route_yaw_variant(
                        candidate,
                        workspace_js=workspace_js,
                        high_plan=entry_plan,
                        pre_plan=pre_plan,
                        gr_plan=gr_plan,
                        quat=q,
                        variant_name=qname,
                        commanded_yaw_rad=float(cmd_yaw),
                        joint_dist=float(joint_dist),
                        target_id=target_id,
                        ik_seed_name="pick_workspace_ready",
                        plan_start_js=workspace_js,
                        top_z_m=float(top_z),
                        use_gr_plan_for_final_descend_probe=True,
                        legacy_low_to_grasp_diagnostic_only=True,
                    )
                    probe["pregrasp_height_above_top_m"] = float(pre_h)
                    probe["depth_from_top_m"] = float(depth)
                    probe["entry_tcp"] = entry_tcp
                    probe["entry_plan"] = entry_plan
                    all_probes.append(probe)
                    pending_ok = chips_can_legacy_pending_variant_passes(
                        probe,
                        fraction_threshold=threshold,
                    )
                    reject_reason = str(probe.get("reject_reason", ""))
                    if pending_ok:
                        display_reason = (
                            reject_reason
                            if reject_reason
                            and "low_to_shallow" not in reject_reason
                            and "low_to_grasp" not in reject_reason
                            else "legacy_pending_actual_tf_descend"
                        )
                    else:
                        display_reason = reject_reason or "legacy_pending_criteria_not_met"
                    self.get_logger().info(
                        format_chips_can_legacy_low_pregrasp_variant_log(
                            {
                                "pregrasp_height_above_top_m": float(pre_h),
                                "depth_from_top_m": float(depth),
                                "yaw_deg": math.degrees(float(cmd_yaw)),
                                "plan_to_pregrasp_ok": bool(
                                    probe.get("object_high_plan_ok")
                                ),
                                "object_high_to_low_fraction": probe.get(
                                    "object_high_to_low_fraction"
                                ),
                                "low_to_grasp_fraction": probe.get(
                                    "low_to_grasp_fraction"
                                ),
                                "low_to_grasp_fraction_used_as_diagnostic": True,
                                "centering_ok": True,
                                "disturbance_ok": True,
                                "result": "OK" if pending_ok else "FAIL",
                                "reject_reason": display_reason,
                            }
                        )
                    )
        selected = select_chips_can_legacy_success_policy_variant(
            all_probes,
            fraction_threshold=threshold,
        )
        self._ensure_legacy_target_collision_required_for_approach(
            candidate, target_id
        )
        return selected, all_probes

    def _apply_chips_can_legacy_pending_actual_tf_preflight(
        self,
        candidate: Dict[str, Any],
        *,
        pick: Dict[str, Any],
        pregrasp_height_above_top_m: float,
        depth_from_top_m: float,
        low_to_grasp_fraction: float,
        object_high_to_low_fraction: float,
    ) -> None:
        candidate["_chips_can_legacy_pending_actual_tf_descend"] = True
        candidate["_chips_can_legacy_success_policy_prevalidated"] = False
        candidate["_chips_can_high_route_prevalidated"] = False
        candidate["_chips_can_high_route_pending_final_descend"] = False
        candidate["_cartesian_descend_pending_at_pregrasp"] = True
        candidate["_cartesian_descend_prevalidated"] = False
        candidate["chips_can_legacy_success_policy"] = True
        candidate["chips_can_legacy_pregrasp_height_above_top_m"] = float(
            pregrasp_height_above_top_m
        )
        candidate["recommended_grasp_depth_from_top_m"] = float(depth_from_top_m)
        candidate["_cartesian_descend_fraction"] = float(low_to_grasp_fraction)
        candidate["chips_can_legacy_object_high_to_low_fraction"] = float(
            object_high_to_low_fraction
        )
        pf = dict(candidate.get("_pick_route_preflight_status") or {})
        pf["plan_before_result"] = OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND
        pf["preflight_source"] = CHIPS_CAN_LEGACY_PENDING_ACTUAL_TF_DESCEND_PREFLIGHT_SOURCE
        pf["cartesian_prevalidated"] = False
        pf["cartesian_descend_prevalidated"] = False
        pf["actual_tf_descend_required"] = True
        pf["object_high_plan_ok"] = True
        pf["route_entry_plan_ok"] = True
        pf["object_high_to_low_cartesian_ok"] = True
        pf["low_to_grasp_cartesian_ok"] = False
        candidate["_pick_route_preflight_status"] = pf
        preflight = dict(candidate.get("_pregrasp_plan_preflight") or {})
        preflight["plan_before_result"] = OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND
        candidate["_pregrasp_plan_preflight"] = preflight
        validated = dict(candidate.get("_plan_before_motion_validated") or {})
        validated["mode"] = "chips_can_legacy_pending_actual_tf_descend"
        candidate["_plan_before_motion_validated"] = validated
        self.get_logger().info(
            format_chips_can_legacy_policy_contract_log(
                {
                    "plan_to_pregrasp_ok": True,
                    "object_high_to_low_fraction": float(object_high_to_low_fraction),
                    "low_to_grasp_fraction": float(low_to_grasp_fraction),
                    "result": OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND,
                }
            )
        )
        self.get_logger().info(
            format_chips_can_legacy_success_policy_selected_log(
                {
                    "pregrasp_height_above_top_m": float(pregrasp_height_above_top_m),
                    "depth_from_top_m": float(depth_from_top_m),
                    "yaw_deg": math.degrees(float(pick.get("commanded_yaw_rad", 0.0))),
                    "object_high_to_low_fraction": float(object_high_to_low_fraction),
                    "cached_js_available": bool(
                        candidate.get("chips_can_legacy_object_high_js") is not None
                        and candidate.get("chips_can_legacy_low_pregrasp_js")
                        is not None
                    ),
                    "low_to_grasp_fraction": float(low_to_grasp_fraction),
                    "low_to_grasp_fraction_used_as_diagnostic": True,
                    "final_descend_m": chips_can_legacy_final_descend_m(
                        pregrasp_height_above_top_m=float(pregrasp_height_above_top_m),
                        depth_from_top_m=float(depth_from_top_m),
                    ),
                    "contract": OK_CHIPS_LEGACY_PENDING_ACTUAL_TF_DESCEND,
                    "result": "OK",
                }
            )
        )

