    def _log_pick_prelude_execution_contract(
        self, candidate: Optional[Dict[str, Any]] = None
    ) -> None:
        route = self._preplanned_pick_route or {}
        selected_entry_target = "pregrasp_tcp"
        if candidate is not None:
            selected_entry_target = str(
                candidate.get("selected_entry_target")
                or route.get("selected_entry_target")
                or "pregrasp_tcp"
            )
        self.get_logger().info(
            "[PICK_PRELUDE_EXECUTION_CONTRACT]\n"
            "route_preplanned=%s\n"
            "allowed_to_plan_after_waypoint=%s\n"
            "safe_pregrasp_enabled=%s\n"
            "selected_entry_target=%s\n"
            "result=OK"
            % (
                str(bool(route.get("validated_before_prelude"))).lower(),
                str(
                    not bool(self._require_full_pick_route_preplanned_before_prelude)
                ).lower(),
                str(bool(route.get("safe_pregrasp_enabled", False))).lower(),
                selected_entry_target,
            )
        )

    def _quick_verify_cached_pregrasp_from_current_state(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        route: Dict[str, Any],
    ) -> bool:
        if self._moveit2 is None:
            return True
        start_js = self._current_arm_joint_state()
        if start_js is None:
            start_js = self._last_joint_state_msg
        if start_js is None:
            return False
        quat_raw = route.get("quat")
        if not isinstance(quat_raw, (list, tuple)) or len(quat_raw) < 4:
            validated = candidate.get("_plan_before_motion_validated") or {}
            quat_raw = validated.get("quat")
        if not isinstance(quat_raw, (list, tuple)) or len(quat_raw) < 4:
            return False
        quat = (
            float(quat_raw[0]),
            float(quat_raw[1]),
            float(quat_raw[2]),
            float(quat_raw[3]),
        )
        uses_high_entry = bool(
            candidate.get("uses_low_object_high_approach_stage")
            or candidate.get("_chips_can_golden_legacy_variant")
            or self._chips_can_legacy_pending_actual_tf_descend_active(candidate)
            or self._chips_can_high_pregrasp_policy_active(candidate)
        )
        if uses_high_entry:
            pre_tcp = plan_targets.get("object_high_pregrasp_tcp")
            verify_stage = "post_prelude_cached_verify_high"
        else:
            pre_tcp = plan_targets.get("pregrasp_tcp")
            verify_stage = "post_prelude_cached_verify"
        if not isinstance(pre_tcp, (list, tuple)) or len(pre_tcp) < 3:
            return False
        pre_plan, _ = self._transform_target_to_planning_frame(
            (float(pre_tcp[0]), float(pre_tcp[1]), float(pre_tcp[2])),
            source_frame,
            stage=verify_stage,
        )
        if pre_plan is None:
            return False
        try:
            pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, quat)
            ik_sol = self._moveit2.compute_ik(
                position=[
                    float(pre_moveit[0]),
                    float(pre_moveit[1]),
                    float(pre_moveit[2]),
                ],
                quat_xyzw=[float(quat[0]), float(quat[1]), float(quat[2]), float(quat[3])],
                ik_link_name=self._moveit_target_link,
                start_joint_state=start_js,
                wait_for_server_timeout_sec=1.0,
            )
        except Exception:
            ik_sol = None
        return ik_sol is not None

    def _post_prelude_execute_cached_pregrasp(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
    ) -> bool:
        """Tras pick_workspace_ready: ejecutar ruta cacheada sin replan ni safe_pregrasp."""
        label = str(candidate.get("label", ""))
        wp = self._pick_workspace_prelude_waypoint
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED] label=%s result=SKIP dry_run_or_no_moveit"
                % label
            )
            return True
        if not self._enable_pick_workspace_prelude:
            return True

        if not self._wait_post_prelude_arm_and_tf_stable():
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED]\n"
                "label=%s\n"
                "waypoint=%s\n"
                "using_cached_route=false\n"
                "result=FAIL\n"
                "reason=arm_or_tf_not_stable"
                % (label, wp)
            )
            return False

        route = self._preplanned_pick_route
        if not isinstance(route, dict) or not bool(route.get("validated_before_prelude")):
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED]\n"
                "label=%s\n"
                "using_cached_route=false\n"
                "result=FAIL\n"
                "reason=missing_preplanned_pick_route"
                % label
            )
            return False

        if not self._refresh_chips_can_yaw_from_current_state(
            candidate, plan_targets, source_frame, route
        ):
            return False

        validated = candidate.get("_plan_before_motion_validated") or {}
        if not bool(validated.get("ok")):
            quat_raw = route.get("quat")
            if isinstance(quat_raw, (list, tuple)) and len(quat_raw) >= 4:
                quat_t = (
                    float(quat_raw[0]),
                    float(quat_raw[1]),
                    float(quat_raw[2]),
                    float(quat_raw[3]),
                )
                yaw = self._wrap_to_pi(self._yaw_rad_from_quaternion_xyzw(quat_t))
                candidate["_plan_before_motion_validated"] = {
                    "ok": True,
                    "mode": "direct_pregrasp",
                    "variant_name": str(route.get("selected_yaw_variant", "cached")),
                    "quat": list(quat_raw),
                    "final_yaw_rad": float(yaw),
                }
                candidate["_commanded_tcp_yaw_rad"] = float(yaw)
                candidate["_final_tcp_yaw_rad"] = float(yaw)
                candidate["_execution_quaternion_override"] = list(quat_raw)

        if not self._quick_verify_cached_pregrasp_from_current_state(
            candidate, plan_targets, source_frame, route
        ):
            self.get_logger().error(
                "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED]\n"
                "label=%s\n"
                "using_cached_route=true\n"
                "safe_pregrasp_enabled=%s\n"
                "selected_yaw_variant=%s\n"
                "pregrasp_tcp=%s\n"
                "result=FAIL\n"
                "reason=cached_pregrasp_not_reachable_from_waypoint"
                % (
                    label,
                    str(bool(route.get("safe_pregrasp_enabled", False))).lower(),
                    str(route.get("selected_yaw_variant", "n/a")),
                    str(route.get("pregrasp_tcp", "n/a")),
                )
            )
            return False

        candidate["_post_prelude_pregrasp_locked"] = True
        candidate["_pick_route_execute_cached"] = True
        self.get_logger().info(
            "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED]\n"
            "using_cached_route=true\n"
            "safe_pregrasp_enabled=%s\n"
            "selected_yaw_variant=%s\n"
            "pregrasp_tcp=%s\n"
            "result=OK"
            % (
                str(bool(route.get("safe_pregrasp_enabled", False))).lower(),
                str(route.get("selected_yaw_variant", "n/a")),
                str(route.get("pregrasp_tcp", "n/a")),
            )
        )
        return True

    def _select_pregrasp_execution_quaternion(
        self,
        candidate: Dict[str, Any],
        pregrasp_tcp_planning: Tuple[float, float, float],
        pregrasp_hand_planning: Tuple[float, float, float],
        fallback_quat: Tuple[float, float, float, float],
    ) -> Tuple[Tuple[float, float, float, float], float]:
        """Elige yaw/quat de pregrasp por IK en la pose TCP real que se ejecutará."""
        fb_yaw = self._yaw_rad_from_quaternion_xyzw(fallback_quat)
        base_cmd = _to_float(candidate.get("_base_commanded_tcp_yaw_rad"))
        if base_cmd is None:
            base_cmd = _to_float(candidate.get("_commanded_tcp_yaw_rad"))
        if base_cmd is None:
            base_cmd = fb_yaw

        stage_mode = (
            "safe_pregrasp_stage"
            if self._safe_pregrasp_motion_enabled()
            else (
                "direct_pregrasp"
                if not self._enable_safe_pregrasp_stage
                else "pregrasp_only"
            )
        )
        phys_corr = float(self._gripper_physical_yaw_correction_rad)

        if self._mustard_yaw_execution_is_locked(candidate):
            locked_quat = self._mustard_locked_execution_quat_tuple(candidate)
            locked_yaw = _to_float(candidate.get("_mustard_locked_commanded_tcp_yaw_rad"))
            locked_var = str(candidate.get("_mustard_locked_yaw_variant", "?"))
            if locked_quat is None or locked_yaw is None:
                self.get_logger().error(
                    "[PREGRASP_YAW_SELECT] mustard yaw lock invalido; abortando"
                )
                candidate["_mustard_yaw_propagation_failed"] = True
                return fallback_quat, float(fb_yaw)
            if not self._mustard_yaw_propagation_check(
                candidate,
                executed_quat=locked_quat,
                executed_yaw=float(locked_yaw),
                executed_variant=locked_var,
            ):
                candidate["_mustard_yaw_propagation_failed"] = True
                return fallback_quat, float(fb_yaw)
            try:
                eval_hand = self._tcp_pose_to_moveit_pose(
                    pregrasp_tcp_planning, locked_quat
                )
            except Exception:
                eval_hand = pregrasp_hand_planning
            self.get_logger().info(
                "[PREGRASP_YAW_SELECT]\n"
                "safe_pregrasp_stage=%s\n"
                "motion_mode=%s\n"
                "selected_variant=%s\n"
                "yaw_source=mustard_locked_post_prelude\n"
                "physical_yaw_correction_rad=%.4f\n"
                "evaluated_tcp=(%.3f, %.3f, %.3f)\n"
                "evaluated_hand=(%.3f, %.3f, %.3f)\n"
                "executed_tcp=(%.3f, %.3f, %.3f)\n"
                "executed_hand=(%.3f, %.3f, %.3f)\n"
                "joint_dist=n/a\n"
                "ik_ok=true\n"
                "commanded_tcp_yaw=%.4f rad (%.1f deg)"
                % (
                    str(self._enable_safe_pregrasp_stage).lower(),
                    stage_mode,
                    locked_var,
                    phys_corr,
                    float(pregrasp_tcp_planning[0]),
                    float(pregrasp_tcp_planning[1]),
                    float(pregrasp_tcp_planning[2]),
                    float(eval_hand[0]),
                    float(eval_hand[1]),
                    float(eval_hand[2]),
                    float(pregrasp_tcp_planning[0]),
                    float(pregrasp_tcp_planning[1]),
                    float(pregrasp_tcp_planning[2]),
                    float(eval_hand[0]),
                    float(eval_hand[1]),
                    float(eval_hand[2]),
                    float(locked_yaw),
                    math.degrees(float(locked_yaw)),
                )
            )
            return locked_quat, float(locked_yaw)

        if self._direct_pregrasp_yaw_execution_is_locked(candidate):
            locked_quat = self._plan_before_locked_execution_quat_tuple(candidate)
            validated = candidate.get("_plan_before_motion_validated") or {}
            locked_yaw = _to_float(validated.get("final_yaw_rad"))
            if locked_yaw is None:
                locked_yaw = _to_float(candidate.get("_commanded_tcp_yaw_rad"))
            locked_var = str(validated.get("variant_name", "plan_before_validated"))
            if locked_quat is None or locked_yaw is None:
                self.get_logger().warning(
                    "[PREGRASP_YAW_SELECT] plan_before yaw lock invalido; fallback"
                )
                return fallback_quat, float(fb_yaw)
            self._lock_direct_pregrasp_yaw_from_plan_before(candidate)
            try:
                eval_hand = self._tcp_pose_to_moveit_pose(
                    pregrasp_tcp_planning, locked_quat
                )
            except Exception:
                eval_hand = pregrasp_hand_planning
            self.get_logger().info(
                "[PREGRASP_YAW_SELECT]\n"
                "safe_pregrasp_stage=%s\n"
                "motion_mode=%s\n"
                "selected_variant=%s\n"
                "yaw_source=plan_before_validated_direct_pregrasp\n"
                "physical_yaw_correction_rad=%.4f\n"
                "evaluated_tcp=(%.3f, %.3f, %.3f)\n"
                "evaluated_hand=(%.3f, %.3f, %.3f)\n"
                "executed_tcp=(%.3f, %.3f, %.3f)\n"
                "executed_hand=(%.3f, %.3f, %.3f)\n"
                "joint_dist=n/a\n"
                "ik_ok=true\n"
                "commanded_tcp_yaw=%.4f rad (%.1f deg)"
                % (
                    str(self._enable_safe_pregrasp_stage).lower(),
                    stage_mode,
                    locked_var,
                    phys_corr,
                    float(pregrasp_tcp_planning[0]),
                    float(pregrasp_tcp_planning[1]),
                    float(pregrasp_tcp_planning[2]),
                    float(eval_hand[0]),
                    float(eval_hand[1]),
                    float(eval_hand[2]),
                    float(pregrasp_tcp_planning[0]),
                    float(pregrasp_tcp_planning[1]),
                    float(pregrasp_tcp_planning[2]),
                    float(eval_hand[0]),
                    float(eval_hand[1]),
                    float(eval_hand[2]),
                    float(locked_yaw),
                    math.degrees(float(locked_yaw)),
                )
            )
            return locked_quat, float(locked_yaw)

        start_js = self._current_arm_joint_state()
        if start_js is None:
            start_js = self._joint_state_for_waypoint("home")
        if self._moveit2 is None or start_js is None:
            return fallback_quat, float(fb_yaw)

        if self._is_mustard_short_axis_candidate(candidate):
            mustard_pick = self._select_best_mustard_yaw_variant(
                candidate,
                float(base_cmd),
                pregrasp_tcp_planning,
                start_js,
                require_plan_ok=False,
            )
            if mustard_pick is not None:
                qname, sel_quat, cmd_yaw, ik_sol, joint_dist, _score, _plan_ok = (
                    mustard_pick
                )
                if ik_sol is not None:
                    candidate["_mustard_locked_ik_joint_state"] = ik_sol
            else:
                ranked = self._ranked_downward_yaw_variants_for_pose(
                    float(base_cmd), pregrasp_tcp_planning, start_js
                )
                if not ranked:
                    self.get_logger().warning(
                        "[PREGRASP_YAW_SELECT] sin variantes IK mustard; fallback"
                    )
                    return fallback_quat, float(fb_yaw)
                qname, sel_quat, cmd_yaw, ik_sol, joint_dist = ranked[0]
        elif self._is_chips_can_gt_cylinder_candidate(candidate):
            ranked = self._ranked_downward_yaw_variants_for_pose(
                float(base_cmd), pregrasp_tcp_planning, start_js
            )
            if not ranked or ranked[0][3] is None:
                self.get_logger().warning(
                    "[PREGRASP_YAW_SELECT] chips_can GT sin variantes IK; fallback quat"
                )
                return fallback_quat, float(fb_yaw)
            qname, sel_quat, cmd_yaw, ik_sol, joint_dist = ranked[0]
        else:
            ranked = self._ranked_downward_yaw_variants_for_pose(
                float(base_cmd), pregrasp_tcp_planning, start_js
            )
            if not ranked:
                self.get_logger().warning(
                    "[PREGRASP_YAW_SELECT] sin variantes IK; usando fallback quat"
                )
                return fallback_quat, float(fb_yaw)
            qname, sel_quat, cmd_yaw, ik_sol, joint_dist = ranked[0]
        ik_ok = ik_sol is not None
        try:
            eval_hand = self._tcp_pose_to_moveit_pose(pregrasp_tcp_planning, sel_quat)
        except Exception:
            eval_hand = pregrasp_hand_planning

        candidate["_commanded_tcp_yaw_rad"] = float(cmd_yaw)
        candidate["_final_tcp_yaw_rad"] = float(cmd_yaw)
        candidate["_execution_quaternion_override"] = [
            float(sel_quat[0]),
            float(sel_quat[1]),
            float(sel_quat[2]),
            float(sel_quat[3]),
        ]
        self.get_logger().info(
            "[PREGRASP_YAW_SELECT]\n"
            "safe_pregrasp_stage=%s\n"
            "motion_mode=%s\n"
            "selected_variant=%s\n"
            "physical_yaw_correction_rad=%.4f\n"
            "evaluated_tcp=(%.3f, %.3f, %.3f)\n"
            "evaluated_hand=(%.3f, %.3f, %.3f)\n"
            "executed_tcp=(%.3f, %.3f, %.3f)\n"
            "executed_hand=(%.3f, %.3f, %.3f)\n"
            "joint_dist=%.4f\n"
            "ik_ok=%s\n"
            "commanded_tcp_yaw=%.4f rad (%.1f deg)"
            % (
                str(self._enable_safe_pregrasp_stage).lower(),
                stage_mode,
                qname,
                phys_corr,
                float(pregrasp_tcp_planning[0]),
                float(pregrasp_tcp_planning[1]),
                float(pregrasp_tcp_planning[2]),
                float(eval_hand[0]),
                float(eval_hand[1]),
                float(eval_hand[2]),
                float(pregrasp_tcp_planning[0]),
                float(pregrasp_tcp_planning[1]),
                float(pregrasp_tcp_planning[2]),
                float(pregrasp_hand_planning[0]),
                float(pregrasp_hand_planning[1]),
                float(pregrasp_hand_planning[2]),
                float(joint_dist),
                str(ik_ok).lower(),
                float(cmd_yaw),
                math.degrees(float(cmd_yaw)),
            )
        )
        return sel_quat, float(cmd_yaw)

    def _grasp_ik_required_before_pregrasp_from_home(self) -> bool:
        """IK al grasp desde HOME solo si el modo lo exige (legacy)."""
        if not bool(self._plan_before_motion_require_grasp_ik_from_home):
            return False
        return bool(self._mode_flags.get("descend"))

    def _log_finger_insertion_policy(
        self, candidate: Dict[str, Any], seq: Dict[str, Any]
    ) -> None:
        palm = candidate.get("palm_clearance_above_top_m")
        palm_s = "n/a" if palm is None else f"{float(palm):.4f}"
        depth_req = candidate.get("recommended_grasp_depth_from_top_m")
        depth_lim = candidate.get("insertion_depth_limit_m")
        self.get_logger().info(
            "[FINGER_INSERTION_POLICY]\n"
            "label=%s\n"
            "strategy=%s\n"
            "top_z=%.3f\n"
            "recommended_grasp_depth_from_top_m=%s\n"
            "insertion_depth_limit_m=%s\n"
            "effective_depth_m=%.4f\n"
            "palm_clearance_above_top_m=%s\n"
            "grasp_tcp_z=%.3f\n"
            "reason=%s"
            % (
                str(candidate.get("label", "")),
                str(candidate.get("grasp_strategy", "")),
                float(seq.get("top_z", 0.0)),
                "n/a" if depth_req is None else f"{float(depth_req):.4f}",
                "n/a" if depth_lim is None else f"{float(depth_lim):.4f}",
                float(seq.get("effective_depth_m", 0.0)),
                palm_s,
                float(seq.get("adjusted_grasp_tcp_z", 0.0)),
                str(seq.get("grasp_z_reason", "label_policy")),
            )
        )

    def _log_descend_limit_policy(
        self, candidate: Dict[str, Any], seq: Dict[str, Any]
    ) -> None:
        label = str(candidate.get("label", ""))
        strategy = str(candidate.get("grasp_strategy", ""))
        self.get_logger().info(
            "[DESCEND_LIMIT_POLICY]\n"
            "label=%s\n"
            "strategy=%s\n"
            "top_z=%.3f\n"
            "requested_grasp_tcp_z=%.3f\n"
            "adjusted_grasp_tcp_z=%.3f\n"
            "desired_descend_m=%.3f\n"
            "min_cartesian_descend_m=%.3f\n"
            "requested_descend_m=%.3f\n"
            "max_cartesian_descend_m=%.3f\n"
            "final_descend_m=%.3f\n"
            "reason=%s"
            % (
                label,
                strategy,
                float(seq.get("top_z", 0.0)),
                float(seq.get("requested_grasp_tcp_z", 0.0)),
                float(seq.get("adjusted_grasp_tcp_z", 0.0)),
                float(seq.get("desired_descend_m", seq.get("requested_descend_m", 0.0))),
                float(seq.get("min_cartesian_descend_m", 0.0)),
                float(seq.get("requested_descend_m", 0.0)),
                float(seq.get("max_cartesian_descend_m", 0.0)),
                float(seq.get("final_descend_m", 0.0)),
                str(seq.get("descend_limit_reason", "label_policy")),
            )
        )

    def _resolve_reachable_pregrasp_for_pick(
        self,
        *,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        base_yaw: float,
        start_js: Any,
    ) -> Dict[str, Any]:
        """Selecciona el pregrasp más bajo alcanzable para el pipeline común."""
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if not isinstance(pre_tcp, (list, tuple)) or not isinstance(gr_tcp, (list, tuple)):
            return {"ok": False, "reason": "missing_plan_targets", "attempts": []}
        if len(pre_tcp) < 3 or len(gr_tcp) < 3:
            return {"ok": False, "reason": "invalid_plan_targets", "attempts": []}

        grasp_tcp = (float(gr_tcp[0]), float(gr_tcp[1]), float(gr_tcp[2]))
        desired_descend = float(
            candidate.get("preferred_cartesian_descend_m", candidate.get("vertical_descend_tcp_m", 0.0))
        )
        min_descend = float(candidate.get("min_cartesian_descend_m", 0.04))
        max_descend = float(candidate.get("max_cartesian_descend_m", max(min_descend, desired_descend)))
        min_descend = max(0.0, min_descend)
        max_descend = max(min_descend, max_descend)
        desired_descend = min(max_descend, max(min_descend, desired_descend))
        step_z = max(0.002, float(candidate.get("pregrasp_reachability_step_z_m", 0.01)))

        if self._is_chips_can_cylinder_topdown_candidate(candidate):
            policy_pre_z = float(pre_tcp[2])
            top_z = float(
                candidate.get("top_z_m")
                or candidate.get("top_z_estimated")
                or grasp_tcp[2]
            )
            floor_z = max(
                policy_pre_z,
                top_z + float(self._chips_can_min_pregrasp_clearance_above_top_m),
                grasp_tcp[2] + min_descend,
            )
            plan_descend = max(0.0, floor_z - grasp_tcp[2])
            desired_descend = max(desired_descend, plan_descend)
            max_descend = max(max_descend, plan_descend)

        desired_pre_z = grasp_tcp[2] + desired_descend
        min_pre_z = max(float(self._min_pregrasp_z), grasp_tcp[2] + min_descend)
        if self._is_chips_can_cylinder_topdown_candidate(candidate):
            min_pre_z = max(min_pre_z, desired_pre_z)
        max_pre_z = min(float(self._max_target_z), grasp_tcp[2] + max_descend + 0.08)
        start_z = max(min_pre_z, desired_pre_z)
        attempts: List[Dict[str, Any]] = []
        selected: Optional[Dict[str, Any]] = None

        chips_can_yaw_free = self._is_chips_can_cylinder_topdown_candidate(candidate)
        z_values: List[float] = []
        if chips_can_yaw_free:
            z_values.append(float(start_z))
            for extra_m in (0.02, 0.04, 0.06, 0.08, 0.10):
                z_try = float(start_z) + float(extra_m)
                if z_try <= max_pre_z + 1e-9 and z_try not in z_values:
                    z_values.append(z_try)
            z_cursor = float(start_z) + float(step_z)
            while z_cursor <= max_pre_z + 1e-9:
                z_round = round(float(z_cursor), 4)
                if all(abs(z_round - float(v)) > 1e-4 for v in z_values):
                    z_values.append(float(z_cursor))
                z_cursor += float(step_z)
        else:
            z_cursor = float(start_z)
            while z_cursor <= max_pre_z + 1e-9:
                z_values.append(float(z_cursor))
                z_cursor += float(step_z)

        if demo_pregrasp_policy_locked(candidate):
            min_pre_z, desired_pre_z, start_z, z_values, _demo_floor_z = (
                apply_demo_locked_pregrasp_z_floor_to_reachability(
                    candidate,
                    min_pre_z=min_pre_z,
                    desired_pre_z=desired_pre_z,
                    start_z=start_z,
                    z_values=z_values,
                )
            )

        if mustard_scanner_aligned_pregrasp_locked(candidate):
            return {
                "ok": True,
                "reason": "mustard_scanner_aligned_skipped",
                "attempts": [],
                "selected_pregrasp_tcp": plan_targets.get("pregrasp_tcp"),
                "selected_pregrasp_plan": None,
                "grasp_tcp": grasp_tcp,
                "old_pregrasp_tcp_z": float(pre_tcp[2]),
                "desired_cartesian_descend_m": desired_descend,
                "final_cartesian_descend_m": float(
                    candidate.get("vertical_descend_tcp_m", 0.0)
                ),
            }

        attempt_idx = 0
        for z in z_values:
            attempt_idx += 1
            pre_tcp_try = (grasp_tcp[0], grasp_tcp[1], float(z))
            pre_plan_try, _ = self._transform_target_to_planning_frame(
                pre_tcp_try, source_frame, stage="pregrasp_reachability"
            )
            hand_z = float("nan") if pre_plan_try is None else float(pre_plan_try[2])
            attempt = {
                "attempt": attempt_idx,
                "pregrasp_tcp_z": float(z),
                "hand_z": hand_z,
                "ik_ok": False,
                "plan_ok": False,
                "reject_reason": "",
            }
            if pre_plan_try is None:
                attempt["reject_reason"] = "tf_transform_fail"
                attempts.append(attempt)
                continue
            if pre_plan_try[2] < self._min_pregrasp_z - 1e-6 or pre_plan_try[2] > self._max_target_z + 1e-6:
                attempt["reject_reason"] = "z_out_of_range"
                attempts.append(attempt)
                continue
            if chips_can_yaw_free:
                pick = self._pick_chips_can_yaw_free_pregrasp_ik_plan(
                    candidate,
                    pre_plan_try,
                    start_js,
                    base_yaw,
                    pregrasp_tcp_z=float(z),
                    variant_label="pregrasp_reachability",
                    require_plan_ok=True,
                )
                if pick is None:
                    attempt["reject_reason"] = "no_ik_or_plan"
                    attempts.append(attempt)
                    continue
                attempt["ik_ok"] = True
                attempt["plan_ok"] = True
                attempt["reject_reason"] = "accepted"
                attempts.append(attempt)
                selected = {
                    "pregrasp_tcp": pre_tcp_try,
                    "pregrasp_plan": pre_plan_try,
                    "reason": "desired_ok" if abs(float(z) - desired_pre_z) <= 1e-6 else "raised_for_ik",
                    "yaw_variant": pick.get("variant_name"),
                    "commanded_yaw_rad": pick.get("commanded_yaw_rad"),
                    "quat": pick.get("quat"),
                }
                break
            ranked = self._ranked_downward_yaw_variants_for_pose(
                base_yaw, pre_plan_try, start_js
            )
            ik_variant = None
            for _qname, q, _cmd, ik_sol, _dist in ranked:
                if ik_sol is not None:
                    ik_variant = (q, ik_sol)
                    break
            if ik_variant is None:
                attempt["reject_reason"] = "no_ik"
                attempts.append(attempt)
                continue
            attempt["ik_ok"] = True
            q, ik_sol = ik_variant
            try:
                pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan_try, q)
                traj = self._moveit2.plan(
                    position=list(pre_moveit),
                    quat_xyzw=list(q),
                    frame_id=self._planning_frame,
                    target_link=self._moveit_target_link,
                    start_joint_state=ik_sol,
                    tolerance_orientation=float(self._plan_before_prelude_orientation_tolerance),
                )
            except Exception:
                traj = None
            if traj is None:
                attempt["reject_reason"] = "plan_fail"
                attempts.append(attempt)
                continue
            attempt["plan_ok"] = True
            attempt["reject_reason"] = "accepted"
            attempts.append(attempt)
            selected = {
                "pregrasp_tcp": pre_tcp_try,
                "pregrasp_plan": pre_plan_try,
                "reason": "desired_ok" if abs(float(z) - desired_pre_z) <= 1e-6 else "raised_for_ik",
            }
            break

        reason = "failed"
        old_pregrasp_tcp_z = float(pre_tcp[2])
        if selected is not None:
            reason = selected["reason"]
            sel_tcp = selected["pregrasp_tcp"]
            plan_targets["pregrasp_tcp"] = sel_tcp
            final_descend = float(sel_tcp[2] - grasp_tcp[2])
            candidate["vertical_descend_tcp_m"] = final_descend
            candidate["effective_approach_distance_m"] = final_descend
            sel_quat = selected.get("quat")
            sel_yaw = selected.get("commanded_yaw_rad")
            if isinstance(sel_quat, (list, tuple)) and len(sel_quat) >= 4:
                candidate["_execution_quaternion_override"] = [
                    float(sel_quat[0]),
                    float(sel_quat[1]),
                    float(sel_quat[2]),
                    float(sel_quat[3]),
                ]
            elif isinstance(sel_quat, tuple) and len(sel_quat) >= 4:
                candidate["_execution_quaternion_override"] = [
                    float(sel_quat[0]),
                    float(sel_quat[1]),
                    float(sel_quat[2]),
                    float(sel_quat[3]),
                ]
            if sel_yaw is not None:
                candidate["_commanded_tcp_yaw_rad"] = float(sel_yaw)
                candidate["_final_tcp_yaw_rad"] = float(sel_yaw)
            sel_variant = selected.get("yaw_variant")
            if sel_variant:
                candidate["_chips_can_pregrasp_yaw_variant"] = str(sel_variant)
        self.get_logger().info(
            "[PREGRASP_REACHABILITY_POLICY]\n"
            "label=%s\n"
            "strategy=%s\n"
            "top_z=%.3f\n"
            "grasp_tcp_z=%.3f\n"
            "desired_descend_m=%.3f\n"
            "min_descend_m=%.3f\n"
            "max_descend_m=%.3f\n"
            "desired_pregrasp_tcp_z=%.3f\n"
            "selected_pregrasp_tcp_z=%.3f\n"
            "final_descend_m=%.3f\n"
            "attempts=%d\n"
            "ik_ok=%s\n"
            "plan_ok=%s\n"
            "reason=%s"
            % (
                str(candidate.get("label", "")),
                str(candidate.get("grasp_strategy", "")),
                float(candidate.get("top_z_m", candidate.get("top_z_estimated", grasp_tcp[2]))),
                grasp_tcp[2],
                desired_descend,
                min_descend,
                max_descend,
                desired_pre_z,
                float(plan_targets["pregrasp_tcp"][2]) if selected is not None else float("nan"),
                float(candidate.get("vertical_descend_tcp_m", 0.0)),
                len(attempts),
                str(any(bool(a.get("ik_ok")) for a in attempts)).lower(),
                str(any(bool(a.get("plan_ok")) for a in attempts)).lower(),
                reason,
            )
        )
        for at in attempts:
            self.get_logger().info(
                "[PREGRASP_REACHABILITY_ATTEMPT]\n"
                "label=%s\n"
                "attempt=%d\n"
                "pregrasp_tcp_z=%.3f\n"
                "hand_z=%.3f\n"
                "ik_ok=%s\n"
                "plan_ok=%s\n"
                "reject_reason=%s"
                % (
                    str(candidate.get("label", "")),
                    int(at["attempt"]),
                    float(at["pregrasp_tcp_z"]),
                    float(at["hand_z"]),
                    str(bool(at["ik_ok"])).lower(),
                    str(bool(at["plan_ok"])).lower(),
                    str(at["reject_reason"]),
                )
            )
        return {
            "ok": selected is not None,
            "reason": reason,
            "attempts": attempts,
            "selected_pregrasp_tcp": plan_targets.get("pregrasp_tcp"),
            "selected_pregrasp_plan": (
                selected.get("pregrasp_plan") if selected is not None else None
            ),
            "grasp_tcp": grasp_tcp,
            "old_pregrasp_tcp_z": old_pregrasp_tcp_z,
            "desired_cartesian_descend_m": desired_descend,
            "final_cartesian_descend_m": float(candidate.get("vertical_descend_tcp_m", 0.0)),
        }

    def _sync_plan_targets_after_pregrasp_update(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
    ) -> None:
        """Propaga pregrasp_tcp seleccionado a targets derivados (safe, object_safe_above)."""
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if not isinstance(pre_tcp, (list, tuple)) or not isinstance(gr_tcp, (list, tuple)):
            return
        if len(pre_tcp) < 3 or len(gr_tcp) < 3:
            return
        final_descend = float(pre_tcp[2] - gr_tcp[2])
        candidate["vertical_descend_tcp_m"] = final_descend
        candidate["effective_approach_distance_m"] = final_descend
        if sync_sugar_box_max_cartesian_descend_after_pregrasp_raise(
            candidate,
            selected_pregrasp_tcp_z=float(pre_tcp[2]),
            grasp_tcp_z=float(gr_tcp[2]),
        ):
            self.get_logger().info(
                "[SUGAR_BOX_PREGRASP_RAISE_MAX_DESCEND_SYNC]\n"
                "selected_pregrasp_tcp_z=%.3f\n"
                "grasp_tcp_z=%.3f\n"
                "required_descend_m=%.3f\n"
                "max_cartesian_descend_m=%.3f\n"
                "result=OK"
                % (
                    float(pre_tcp[2]),
                    float(gr_tcp[2]),
                    final_descend,
                    float(candidate.get("max_cartesian_descend_m") or final_descend),
                )
            )

        if demo_pregrasp_policy_locked(candidate):
            enforce_demo_locked_pregrasp_plan_targets(candidate, plan_targets)
            return

        if mustard_scanner_aligned_pregrasp_locked(candidate):
            enforce_mustard_scanner_aligned_pregrasp_plan_targets(
                candidate, plan_targets
            )
            return

        if not bool(candidate.get("sugar_box_multiobject_safe_route")):
            safe_tcp = plan_targets.get("safe_pregrasp_tcp")
            if isinstance(safe_tcp, (list, tuple)) and len(safe_tcp) >= 3:
                try:
                    safe_extra = float(
                        candidate.get(
                            "safe_pregrasp_extra_above_pregrasp_m",
                            self._safe_pregrasp_extra_above_pregrasp_m,
                        )
                    )
                except (TypeError, ValueError):
                    safe_extra = float(self._safe_pregrasp_extra_above_pregrasp_m)
                min_safe_z = float(pre_tcp[2]) + safe_extra
                if float(safe_tcp[2]) < min_safe_z - 1e-6:
                    plan_targets["safe_pregrasp_tcp"] = (
                        float(safe_tcp[0]),
                        float(safe_tcp[1]),
                        min_safe_z,
                    )

            top_z = _to_float(candidate.get("top_z_m"))
            if top_z is None:
                top_z = _to_float(candidate.get("top_z_estimated"))
            if top_z is not None:
                if (
                    simple_direct_pick_route_eligible_for_candidate(candidate)
                    and not sugar_box_multiobject_full_pick_prevalidate_required(
                        candidate
                    )
                ):
                    candidate["_simple_direct_pick_route"] = True
                    candidate.pop("object_safe_above_tcp", None)
                elif self._is_mustard_short_axis_candidate(candidate):
                    old_obj = candidate.get("object_safe_above_tcp")
                    old_safe_z = (
                        float(old_obj[2])
                        if isinstance(old_obj, (list, tuple)) and len(old_obj) >= 3
                        else None
                    )
                    resolved = resolve_mustard_object_safe_above_tcp_z(
                        top_z_m=float(top_z),
                        selected_pregrasp_tcp_z=float(pre_tcp[2]),
                        old_safe_above_tcp_z=old_safe_z,
                    )
                    object_safe_z = float(resolved["new_safe_above_tcp_z"])
                    candidate["object_safe_above_clearance_m"] = float(
                        resolved["clearance_above_top_m"]
                    )
                    candidate["mustard_object_safe_above_height_policy"] = resolved
                else:
                    try:
                        safe_clear = float(
                            candidate.get("object_safe_above_clearance_m", 0.120)
                        )
                    except (TypeError, ValueError):
                        safe_clear = 0.120
                    object_safe_z = max(
                        float(top_z) + safe_clear, float(pre_tcp[2]) + 0.050
                    )
                if (
                    simple_direct_pick_route_eligible_for_candidate(candidate)
                    and not sugar_box_multiobject_full_pick_prevalidate_required(
                        candidate
                    )
                ):
                    pass
                else:
                    candidate["object_safe_above_tcp"] = [
                        float(pre_tcp[0]),
                        float(pre_tcp[1]),
                        object_safe_z,
                    ]
                if self._is_mustard_short_axis_candidate(candidate):
                    self._log_mustard_object_safe_above_height_policy(
                        candidate,
                        resolved=candidate.get("mustard_object_safe_above_height_policy")
                        or resolve_mustard_object_safe_above_tcp_z(
                            top_z_m=float(top_z),
                            selected_pregrasp_tcp_z=float(pre_tcp[2]),
                        ),
                        ref_quat=None,
                        ik_ok=None,
                        plan_ok=None,
                        result="OK",
                        reason="height_resolved_from_pregrasp_policy",
                    )
        else:
            self._enforce_sugar_box_safe_tcp_on_plan_targets(
                candidate, plan_targets
            )

    def _apply_demo_cracker_descend_limit_if_locked(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
    ) -> None:
        if not demo_pregrasp_policy_locked(candidate):
            return
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if not isinstance(pre_tcp, (list, tuple)) or not isinstance(gr_tcp, (list, tuple)):
            return
        if len(pre_tcp) < 3 or len(gr_tcp) < 3:
            return
        generic_raw = candidate.get("generic_max_cartesian_descend_m")
        if generic_raw is None:
            generic_raw = candidate.get("max_cartesian_descend_m", 0.110)
        try:
            generic_max = float(generic_raw)
        except (TypeError, ValueError):
            generic_max = 0.110
        info = apply_demo_cracker_descend_limit_policy(
            candidate,
            selected_pregrasp_tcp_z=float(pre_tcp[2]),
            grasp_tcp_z=float(gr_tcp[2]),
            generic_max_cartesian_descend_m=generic_max,
            demo_max_cartesian_descend_m=float(
                self._cracker_box_demo_max_cartesian_descend_m
            ),
        )
        self.get_logger().info(
            "[DEMO_CRACKER_DESCEND_LIMIT_POLICY]\n"
            "label=%s\n"
            "selected_pregrasp_tcp_z=%.3f\n"
            "grasp_tcp_z=%.3f\n"
            "required_descend_m=%.3f\n"
            "generic_max_cartesian_descend_m=%.3f\n"
            "demo_max_cartesian_descend_m=%.3f\n"
            "effective_max_cartesian_descend_m=%.3f\n"
            "result=%s"
            % (
                str(info.get("label", "")),
                float(info["selected_pregrasp_tcp_z"]),
                float(info["grasp_tcp_z"]),
                float(info["required_descend_m"]),
                float(info["generic_max_cartesian_descend_m"]),
                float(info["demo_max_cartesian_descend_m"]),
                float(info["effective_max_cartesian_descend_m"]),
                str(info.get("result", "")),
            )
        )

    def _verify_mustard_scanner_aligned_post_reachability_or_abort(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Any],
    ) -> bool:
        if (
            bool(candidate.get("_demo_golden_fast_execute"))
            and isinstance(candidate.get("_mustard_golden_locked_grasp_tcp"), (list, tuple))
        ):
            return True
        if not mustard_scanner_aligned_pregrasp_locked(candidate):
            return True
        enforce_mustard_scanner_aligned_pregrasp_plan_targets(
            candidate, plan_targets
        )
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if not isinstance(pre_tcp, (list, tuple)) or not isinstance(gr_tcp, (list, tuple)):
            return False
        if len(pre_tcp) < 3 or len(gr_tcp) < 3:
            return False
        top_z = _to_float(candidate.get("_mustard_scanner_aligned_locked_top_z_m"))
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_m"))
        ok, fields = verify_mustard_scanner_aligned_post_reachability(
            pregrasp_tcp_z=float(pre_tcp[2]),
            grasp_tcp_z=float(gr_tcp[2]),
            top_z=top_z,
        )
        self.get_logger().info(
            format_mustard_scanner_aligned_post_reachability_verify_log(fields)
        )
        if ok:
            return True
        self.get_logger().error(
            "[MUSTARD_SCANNER_ALIGNED_POST_REACHABILITY_VERIFY]\n"
            "reason=mustard_scanner_contract_overwritten_after_verify\n"
            "result=FAIL"
        )
        candidate["_mustard_scanner_contract_abort"] = True
        candidate["_mustard_scanner_post_reachability_fields"] = fields
        return False

    def _apply_mustard_golden_locked_plan_targets_if_active(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Any],
    ) -> bool:
        """Golden fast: conservar grasp/pregrasp validados (no scanner shallow)."""
        if not bool(candidate.get("_demo_golden_fast_execute")):
            return False
        if str(candidate.get("label", "")).strip().lower() != "mustard_bottle":
            return False
        golden_gr = candidate.get("_mustard_golden_locked_grasp_tcp")
        if not isinstance(golden_gr, (list, tuple)) or len(golden_gr) < 3:
            return False
        plan_targets["grasp_tcp"] = (
            float(golden_gr[0]),
            float(golden_gr[1]),
            float(golden_gr[2]),
        )
        golden_pre = candidate.get("_mustard_golden_locked_pregrasp_tcp")
        if isinstance(golden_pre, (list, tuple)) and len(golden_pre) >= 3:
            plan_targets["pregrasp_tcp"] = (
                float(golden_pre[0]),
                float(golden_pre[1]),
                float(golden_pre[2]),
            )
        top_z = candidate.get("top_z_m")
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_estimated"))
        if top_z is not None:
            candidate["recommended_grasp_depth_from_top_m"] = max(
                float(self._mustard_min_required_depth_from_top_m),
                float(top_z) - float(golden_gr[2]),
            )
        candidate["_mustard_nominal_grasp_tcp_z_m"] = float(golden_gr[2])
        candidate["_runtime_grasp_tcp_z"] = float(golden_gr[2])
        return True

    def _apply_reachable_pregrasp_resolution(
        self,
        *,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
        base_yaw: float,
        start_js: Any,
    ) -> Dict[str, Any]:
        """Ejecuta reachability y aplica el pregrasp seleccionado al flujo operativo."""
        if mustard_scanner_aligned_pregrasp_locked(candidate):
            lock_ok, lock_reason, _selected_z, _expected_z = (
                enforce_mustard_scanner_aligned_pregrasp_plan_targets(
                    candidate, plan_targets
                )
            )
            if not lock_ok:
                self.get_logger().error(
                    "[MUSTARD_SCANNER_ALIGNED_PREGRASP_LOCK]\n"
                    "reason=%s\n"
                    "result=FAIL"
                    % str(lock_reason)
                )
                return {
                    "ok": False,
                    "reason": str(lock_reason),
                    "attempts": [],
                    "old_pregrasp_tcp_z": float("nan"),
                }
            self.get_logger().info(
                "[MUSTARD_SCANNER_ALIGNED_PREGRASP_LOCK]\n"
                "pregrasp_tcp_z=%.4f\n"
                "grasp_tcp_z=%.4f\n"
                "reachability_policy=skipped\n"
                "result=LOCKED"
                % (
                    float(plan_targets["pregrasp_tcp"][2]),
                    float(plan_targets["grasp_tcp"][2]),
                )
            )
            if not self._verify_mustard_scanner_aligned_post_reachability_or_abort(
                candidate, plan_targets
            ):
                return {
                    "ok": False,
                    "reason": "mustard_scanner_contract_overwritten_after_verify",
                    "attempts": [],
                    "old_pregrasp_tcp_z": float(
                        plan_targets["pregrasp_tcp"][2]
                    ),
                }
            return {
                "ok": True,
                "reason": "mustard_scanner_aligned_locked",
                "attempts": [],
                "selected_pregrasp_tcp": plan_targets.get("pregrasp_tcp"),
                "old_pregrasp_tcp_z": float(plan_targets["pregrasp_tcp"][2]),
            }

        pre_before = plan_targets.get("pregrasp_tcp")
        old_z = (
            float(pre_before[2])
            if isinstance(pre_before, (list, tuple)) and len(pre_before) >= 3
            else float("nan")
        )
        result = self._resolve_reachable_pregrasp_for_pick(
            candidate=candidate,
            plan_targets=plan_targets,
            source_frame=source_frame,
            base_yaw=base_yaw,
            start_js=start_js,
        )
        if demo_pregrasp_policy_locked(candidate):
            lock_ok, lock_reason, selected_z, demo_z = (
                enforce_demo_locked_pregrasp_plan_targets(candidate, plan_targets)
            )
            if not lock_ok:
                self.get_logger().error(
                    "[DEMO_PREGRASP_POLICY_VIOLATION]\n"
                    "label=%s\n"
                    "demo_pregrasp_tcp_z=%.3f\n"
                    "selected_pregrasp_tcp_z=%.3f\n"
                    "result=FAIL\n"
                    "reason=%s"
                    % (
                        str(candidate.get("label", "")),
                        float(demo_z) if demo_z is not None else float("nan"),
                        float(selected_z) if selected_z is not None else float("nan"),
                        lock_reason,
                    )
                )
                return {
                    "ok": False,
                    "reason": lock_reason,
                    "attempts": result.get("attempts") or [],
                    "old_pregrasp_tcp_z": old_z,
                }
            sel_tcp = plan_targets.get("pregrasp_tcp")
            sel_z = (
                float(sel_tcp[2])
                if isinstance(sel_tcp, (list, tuple)) and len(sel_tcp) >= 3
                else float("nan")
            )
            self.get_logger().info(
                "[DEMO_PREGRASP_POLICY_LOCK]\n"
                "label=%s\n"
                "demo_pregrasp_tcp_z=%.3f\n"
                "selected_pregrasp_tcp_z=%.3f\n"
                "result=LOCKED"
                % (
                    str(candidate.get("label", "")),
                    float(demo_z) if demo_z is not None else float("nan"),
                    sel_z,
                )
            )

        if not bool(result.get("ok")):
            return result

        self._sync_plan_targets_after_pregrasp_update(candidate, plan_targets)
        self._enforce_sugar_box_safe_tcp_on_plan_targets(candidate, plan_targets)
        if demo_pregrasp_policy_locked(candidate):
            enforce_demo_locked_pregrasp_plan_targets(candidate, plan_targets)
            self._apply_demo_cracker_descend_limit_if_locked(candidate, plan_targets)
        sel_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if (
            isinstance(sel_tcp, (list, tuple))
            and isinstance(gr_tcp, (list, tuple))
            and len(sel_tcp) >= 3
            and len(gr_tcp) >= 3
            and any(bool(a.get("plan_ok")) for a in (result.get("attempts") or []))
        ):
            self.get_logger().info(
                "[PREGRASP_REACHABILITY_APPLIED]\n"
                "label=%s\n"
                "old_pregrasp_tcp_z=%.3f\n"
                "selected_pregrasp_tcp_z=%.3f\n"
                "grasp_tcp_z=%.3f\n"
                "effective_descend_m=%.3f\n"
                "reason=%s"
                % (
                    str(candidate.get("label", "")),
                    float(result.get("old_pregrasp_tcp_z", old_z)),
                    float(sel_tcp[2]),
                    float(gr_tcp[2]),
                    float(candidate.get("vertical_descend_tcp_m", 0.0)),
                    str(result.get("reason", "")),
                )
            )
        if not self._verify_mustard_scanner_aligned_post_reachability_or_abort(
            candidate, plan_targets
        ):
            return {
                "ok": False,
                "reason": "mustard_scanner_contract_overwritten_after_verify",
                "attempts": result.get("attempts") or [],
                "old_pregrasp_tcp_z": old_z,
            }
        return result

    def _log_low_object_approach_stage(
        self,
        candidate: Dict[str, Any],
        seq: Dict[str, Any],
        pregrasp_tcp: Tuple[float, float, float],
        grasp_tcp: Tuple[float, float, float],
    ) -> None:
        high = seq.get("object_high_pregrasp_tcp")
        self.get_logger().info(
            "[LOW_OBJECT_APPROACH_STAGE]\n"
            "label=%s\n"
            "strategy=%s\n"
            "using_high_stage=%s\n"
            "object_high_tcp=%s\n"
            "pregrasp_tcp=(%.3f, %.3f, %.3f)\n"
            "grasp_tcp=(%.3f, %.3f, %.3f)\n"
            "reason=%s"
            % (
                str(candidate.get("label", "")),
                str(candidate.get("grasp_strategy", "")),
                str(bool(seq.get("uses_low_object_high_approach_stage"))).lower(),
                (
                    "n/a"
                    if high is None
                    else "(%.3f, %.3f, %.3f)"
                    % (float(high[0]), float(high[1]), float(high[2]))
                ),
                pregrasp_tcp[0],
                pregrasp_tcp[1],
                pregrasp_tcp[2],
                grasp_tcp[0],
                grasp_tcp[1],
                grasp_tcp[2],
                str(seq.get("low_object_high_reason", "low_object_or_edge_grasp")),
            )
        )

    def _effective_descend_vel_acc(
        self, candidate: Dict[str, Any]
    ) -> Tuple[float, float]:
        v, a, source = descend_speed_from_candidate(
            candidate, self._descend_vel, self._descend_acc
        )
        self.get_logger().info(
            "[DESCEND_SPEED_POLICY]\n"
            "label=%s\n"
            "descend_velocity_scaling=%.4f\n"
            "descend_acceleration_scaling=%.4f\n"
            "source=%s"
            % (
                str(candidate.get("label", "")),
                float(v),
                float(a),
                source,
            )
        )
        return float(v), float(a)

    def _shift_tcp_xy(
        self,
        tcp: Tuple[float, float, float],
        dx: float,
        dy: float,
    ) -> Tuple[float, float, float]:
        return (float(tcp[0]) + float(dx), float(tcp[1]) + float(dy), float(tcp[2]))

    def _execute_pregrasp_with_staging(
        self,
        *,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        pregrasp_moveit: Tuple[float, float, float, float, float, float, float],
        quat: Tuple[float, float, float, float],
        dx: float,
        dy: float,
        move_stage_fn: Any,
        candidate_idx: int,
    ) -> bool:
        """Tras pick_workspace_ready: opcional object_high → pregrasp operativo."""
        uses_high = bool(candidate.get("uses_low_object_high_approach_stage"))
        high_tcp = plan_targets.get("object_high_pregrasp_tcp")
        pre_tcp_req = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        pre_ok = False
        if uses_high and high_tcp is not None:
            self.get_logger().info(
                "[LOW_OBJECT_STAGE_DECISION]\n"
                "label=%s\n"
                "strategy=%s\n"
                "object_high_tcp=(%.3f, %.3f, %.3f)\n"
                "pregrasp_tcp_requested=%s\n"
                "pregrasp_tcp_for_moveit=%s\n"
                "grasp_tcp=%s\n"
                "pregrasp_low_has_ik=false\n"
                "selected_plan_target=object_high\n"
                "reason=low_pregrasp_no_ik_use_object_high"
                % (
                    str(candidate.get("label", "")),
                    str(candidate.get("grasp_strategy", "")),
                    float(high_tcp[0]),
                    float(high_tcp[1]),
                    float(high_tcp[2]),
                    (
                        "n/a"
                        if pre_tcp_req is None
                        else "(%.3f, %.3f, %.3f)"
                        % (
                            float(pre_tcp_req[0]),
                            float(pre_tcp_req[1]),
                            float(pre_tcp_req[2]),
                        )
                    ),
                    "n/a (high-stage-cartesian-route)",
                    (
                        "n/a"
                        if gr_tcp is None
                        else "(%.3f, %.3f, %.3f)"
                        % (float(gr_tcp[0]), float(gr_tcp[1]), float(gr_tcp[2]))
                    ),
                )
            )
        if uses_high and high_tcp is not None:
            high_shifted = self._shift_tcp_xy(high_tcp, dx, dy)
            high_moveit = self._tcp_pose_to_moveit_pose(high_shifted, quat)
            self.get_logger().info(
                "[LOW_OBJECT_OBJECT_HIGH_TARGET]\n"
                "tcp=(%.3f, %.3f, %.3f)\n"
                "moveit_hand=(%.3f, %.3f, %.3f)\n"
                "result=PLANNING"
                % (
                    float(high_shifted[0]),
                    float(high_shifted[1]),
                    float(high_shifted[2]),
                    float(high_moveit[0]),
                    float(high_moveit[1]),
                    float(high_moveit[2]),
                )
            )
            self.get_logger().info(
                "Movimiento pick_workspace -> object_high_pregrasp (candidato %d)."
                % candidate_idx
            )
            if not move_stage_fn(
                "object_high_pregrasp",
                high_moveit,
                self._pregrasp_vel,
                self._pregrasp_acc,
                quat_override=quat,
            ):
                self.get_logger().error(
                    "[GRASP_CANDIDATE] idx=%d: object_high_pregrasp FAIL."
                    % candidate_idx
                )
                self.get_logger().info(
                    "[LOW_OBJECT_OBJECT_HIGH_TARGET]\n"
                    "tcp=(%.3f, %.3f, %.3f)\n"
                    "moveit_hand=(%.3f, %.3f, %.3f)\n"
                    "result=FAIL"
                    % (
                        float(high_shifted[0]),
                        float(high_shifted[1]),
                        float(high_shifted[2]),
                        float(high_moveit[0]),
                        float(high_moveit[1]),
                        float(high_moveit[2]),
                    )
                )
                return False
            self.get_logger().info(
                "object_high_pregrasp (candidato %d): OK" % candidate_idx
            )
            self.get_logger().info(
                "[LOW_OBJECT_OBJECT_HIGH_TARGET]\n"
                "tcp=(%.3f, %.3f, %.3f)\n"
                "moveit_hand=(%.3f, %.3f, %.3f)\n"
                "result=OK"
                % (
                    float(high_shifted[0]),
                    float(high_shifted[1]),
                    float(high_shifted[2]),
                    float(high_moveit[0]),
                    float(high_moveit[1]),
                    float(high_moveit[2]),
                )
            )
            if self._chips_can_high_pregrasp_policy_active(
                candidate
            ) or self._chips_can_legacy_pending_actual_tf_descend_active(candidate):
                self._refresh_chips_can_disturbance_snapshot_from_gazebo(
                    candidate, stage="after_object_high_pregrasp"
                )
            legacy_pending = self._chips_can_legacy_pending_actual_tf_descend_active(
                candidate
            )
            chips_high_policy = self._chips_can_high_pregrasp_policy_active(candidate)
            if (legacy_pending or chips_high_policy) and pre_tcp_req is not None:
                if legacy_pending:
                    if not self._execute_chips_can_legacy_high_to_low_pregrasp(
                        candidate=candidate,
                        high_shifted=high_shifted,
                        pre_tcp_req=pre_tcp_req,
                        quat=quat,
                        dx=dx,
                        dy=dy,
                    ):
                        return False
                    return True
                low_shifted = self._shift_tcp_xy(pre_tcp_req, dx, dy)
                top_z = self._chips_can_resolve_top_z_m(
                    candidate, float(low_shifted[2])
                )
                guarded_z, guard_result = self._chips_can_guard_tcp_z_non_contact(
                    candidate,
                    requested_tcp_z=float(low_shifted[2]),
                    phase="high_to_low_pregrasp",
                    top_z=float(top_z),
                )
                if guard_result == "BLOCKED":
                    return False
                low_shifted = (
                    float(low_shifted[0]),
                    float(low_shifted[1]),
                    float(guarded_z),
                )
                tcp_now = self._tcp_position_in_planning_frame()
                if tcp_now is not None:
                    low_shifted = (
                        float(tcp_now[0]),
                        float(tcp_now[1]),
                        float(low_shifted[2]),
                    )
                low_moveit = self._tcp_pose_to_moveit_pose(low_shifted, quat)
                self.get_logger().info(
                    "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
                    "stage=cartesian_high_to_low\n"
                    "high_tcp_z=%.4f\n"
                    "low_tcp_z=%.4f\n"
                    "result=EXECUTING"
                    % (float(high_shifted[2]), float(low_shifted[2]))
                )
                if not self._execute_monitored_moveit_stage(
                    "chips_can_high_to_low_pregrasp",
                    low_moveit,
                    self._pregrasp_vel,
                    self._pregrasp_acc,
                    quat,
                    requested_tcp_z=float(low_shifted[2]),
                    cartesian=bool(
                        self._chips_can_descend_use_cartesian_effective()
                    ),
                ):
                    self.get_logger().error(
                        "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
                        "stage=cartesian_high_to_low\n"
                        "result=FAIL"
                    )
                    return False
                self.get_logger().info(
                    "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
                    "stage=cartesian_high_to_low\n"
                    "high_tcp_z=%.4f\n"
                    "low_tcp_z=%.4f\n"
                    "result=OK"
                    % (float(high_shifted[2]), float(low_shifted[2]))
                )
                if not self._cache_chips_can_low_pregrasp_state_after_high_to_low(
                    candidate,
                    expected_tcp=(
                        float(low_shifted[0]),
                        float(low_shifted[1]),
                        float(low_shifted[2]),
                    ),
                ):
                    self.get_logger().error(
                        "[CHIPS_CAN_HIGH_PREGRASP_ROUTE]\n"
                        "stage=cartesian_high_to_low\n"
                        "result=FAIL\n"
                        "reason=low_pregrasp_state_cache_failed"
                    )
                    return False
                self._refresh_chips_can_disturbance_snapshot_from_gazebo(
                    candidate, stage="after_high_to_low_pregrasp"
                )
                return True
            if legacy_pending:
                self.get_logger().error(
                    "[LOW_OBJECT_STAGE_EXECUTION_BUG]\n"
                    "using_high_stage=true\n"
                    "legacy_pending_actual_tf_descend=true\n"
                    "pregrasp_tcp=%s\n"
                    "reason=missing_pregrasp_tcp_for_legacy_high_to_low"
                    % (
                        "n/a"
                        if pre_tcp_req is None
                        else "(%.3f, %.3f, %.3f)"
                        % (
                            float(pre_tcp_req[0]),
                            float(pre_tcp_req[1]),
                            float(pre_tcp_req[2]),
                        )
                    )
                )
                self.get_logger().error(
                    "[PICK_ABORT_SAFE] reason=chips_can_legacy_high_to_low_execution_failed"
                )
                return False
            return True
        if uses_high:
            self.get_logger().warn(
                "[LOW_OBJECT_STAGE_EXECUTION_BUG]\n"
                "using_high_stage=true\n"
                "attempted_legacy_pregrasp=true\n"
                "pregrasp_tcp=%s\n"
                "object_high_tcp=%s"
                % (
                    "n/a"
                    if pre_tcp_req is None
                    else "(%.3f, %.3f, %.3f)"
                    % (
                        float(pre_tcp_req[0]),
                        float(pre_tcp_req[1]),
                        float(pre_tcp_req[2]),
                    ),
                    "n/a",
                )
            )
        pre_ok = bool(
            move_stage_fn(
                "pregrasp",
                pregrasp_moveit,
                self._pregrasp_vel,
                self._pregrasp_acc,
                quat_override=quat,
            )
        )
        if pre_ok:
            return True
        if high_tcp is None or uses_high:
            return False
        self.get_logger().warn(
            "[PREGRASP_PLAN_FALLBACK]\n"
            "reason=pregrasp_from_workspace_failed\n"
            "fallback=object_high_stage\n"
            "result=attempting"
        )
        high_shifted = self._shift_tcp_xy(high_tcp, dx, dy)
        high_moveit = self._tcp_pose_to_moveit_pose(high_shifted, quat)
        if not move_stage_fn(
            "object_high_pregrasp",
            high_moveit,
            self._pregrasp_vel,
            self._pregrasp_acc,
            quat_override=quat,
        ):
            self.get_logger().error(
                "[PREGRASP_PLAN_FALLBACK]\n"
                "reason=pregrasp_from_workspace_failed\n"
                "fallback=object_high_stage\n"
                "result=FAIL_high"
            )
            return False
        pre_ok = bool(
            move_stage_fn(
                "pregrasp",
                pregrasp_moveit,
                self._pregrasp_vel,
                self._pregrasp_acc,
                quat_override=quat,
            )
        )
        self.get_logger().info(
            "[PREGRASP_PLAN_FALLBACK]\n"
            "reason=pregrasp_from_workspace_failed\n"
            "fallback=object_high_stage\n"
            "result=%s"
            % ("OK" if pre_ok else "FAIL_pregrasp")
        )
        return pre_ok

    def _plan_before_motion_validate_direct_pregrasp(
        self,
        candidate: Dict[str, Any],
        *,
        snap_str: str,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        start_js: Any,
        start_state_label: str,
        base_yaw: float,
        plan_targets: Optional[Dict[str, Tuple[float, float, float]]] = None,
        source_frame: str = "",
    ) -> bool:
        """Valida IK/plan hacia pregrasp (y grasp si aplica) sin etapa safe_pregrasp local."""
        ik_pre = "SKIP"
        plan_pre = "SKIP"
        ik_gr = "SKIP"
        best_detail = ""
        grasp_ik_required = self._grasp_ik_required_before_pregrasp_from_home()
        ori_tol = float(self._plan_before_prelude_orientation_tolerance)
        high_tcp = (
            plan_targets.get("object_high_pregrasp_tcp")
            if plan_targets is not None
            else None
        )
        uses_high_stage = bool(candidate.get("uses_low_object_high_approach_stage"))

        if high_tcp is not None and uses_high_stage and source_frame:
            if self._chips_can_demo_scene_02_golden_required(candidate):
                if not self._chips_can_demo_golden_ready:
                    self._log_chips_can_golden_required_missing(
                        "demo_golden_not_ready_before_plan_before_motion"
                    )
                    return False
                if not self._chips_can_legacy_successful_pick_policy_active(candidate):
                    self._log_chips_can_golden_required_missing(
                        "legacy_policy_not_active_for_demo_golden"
                    )
                    return False
                return self._plan_before_motion_validate_chips_can_legacy_success_policy(
                    candidate,
                    snap_str=snap_str,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    start_js=start_js,
                    start_state_label=start_state_label,
                    base_yaw=base_yaw,
                    plan_targets=plan_targets,
                    source_frame=source_frame,
                )
            if self._chips_can_legacy_successful_pick_policy_active(candidate):
                return self._plan_before_motion_validate_chips_can_legacy_success_policy(
                    candidate,
                    snap_str=snap_str,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    start_js=start_js,
                    start_state_label=start_state_label,
                    base_yaw=base_yaw,
                    plan_targets=plan_targets,
                    source_frame=source_frame,
                )
            if self._chips_can_high_pregrasp_policy_active(candidate):
                top_z = self._chips_can_resolve_top_z_m(
                    candidate, float(pre_plan[2])
                )
                grasp_xy = (float(pre_plan[0]), float(pre_plan[1]))
                pick = self._search_chips_can_adaptive_entry_pregrasp(
                    candidate,
                    top_z=float(top_z),
                    grasp_xy=grasp_xy,
                    gr_plan=gr_plan,
                    pre_plan=pre_plan,
                    start_js=start_js,
                    base_yaw=base_yaw,
                    source_frame=source_frame,
                )
                if pick is not None and plan_targets is not None:
                    qname = str(pick["variant_name"])
                    q = pick["quat"]
                    cmd_yaw = float(pick["commanded_yaw_rad"])
                    joint_dist = float(pick["joint_dist"])
                    ik_gr = str(pick.get("ik_grasp", "FAIL"))
                    entry_tcp, high_plan = self._apply_chips_can_selected_entry_pregrasp(
                        candidate, plan_targets, pick
                    )
                    return self._prevalidate_chips_can_high_route_before_motion(
                        candidate,
                        plan_targets=plan_targets,
                        source_frame=source_frame,
                        snap_str=snap_str,
                        pre_plan=pre_plan,
                        gr_plan=gr_plan,
                        high_plan=high_plan,
                        start_js=start_js,
                        start_state_label=start_state_label,
                        pick=pick,
                    )
                if self._try_setup_chips_can_high_route_pending_final_descend(
                    candidate,
                    plan_targets=plan_targets,
                    source_frame=source_frame,
                    snap_str=snap_str,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    start_js=start_js,
                    start_state_label=start_state_label,
                ):
                    return True
                self.get_logger().error(
                    "[PLAN_BEFORE_MOTION_FAIL]\n"
                    "label=chips_can\n"
                    "reason=no_yaw_variant_full_route_ok\n"
                    "top_z=%.4f\n"
                    "low_pregrasp_tcp_z=%.4f"
                    % (float(top_z), float(pre_plan[2]))
                )
                return False
            else:
                high_plan, _ = self._transform_target_to_planning_frame(
                    high_tcp, source_frame, stage="plan_before_object_high"
                )
                if high_plan is not None:
                    ranked_h = self._ranked_downward_yaw_variants_for_pose(
                        base_yaw, high_plan, start_js
                    )
                    for qname, q, cmd_yaw, ik_h_sol, joint_dist in ranked_h:
                        if ik_h_sol is None:
                            continue
                        try:
                            high_moveit = self._tcp_pose_to_moveit_pose(
                                high_plan, q
                            )
                            traj_h = self._moveit2.plan(
                                position=list(high_moveit),
                                quat_xyzw=list(q),
                                frame_id=self._planning_frame,
                                target_link=self._moveit_target_link,
                                start_joint_state=ik_h_sol,
                                tolerance_orientation=ori_tol,
                            )
                        except Exception:
                            traj_h = None
                        if traj_h is None:
                            continue
                        try:
                            gr_moveit = self._tcp_pose_to_moveit_pose(gr_plan, q)
                            ik_gr_sol = self._moveit2.compute_ik(
                                position=[
                                    float(gr_moveit[0]),
                                    float(gr_moveit[1]),
                                    float(gr_moveit[2]),
                                ],
                                quat_xyzw=[
                                    float(q[0]),
                                    float(q[1]),
                                    float(q[2]),
                                    float(q[3]),
                                ],
                                ik_link_name=self._moveit_target_link,
                                start_joint_state=ik_h_sol,
                                wait_for_server_timeout_sec=1.0,
                            )
                            ik_gr = "OK" if ik_gr_sol is not None else "FAIL"
                        except Exception:
                            ik_gr = "FAIL"
                        self._store_plan_before_motion_validated_pregrasp(
                            candidate,
                            variant_name=qname,
                            quat=q,
                            commanded_yaw_rad=float(cmd_yaw),
                        )
                        if plan_targets is not None and source_frame:
                            self._store_pregrasp_plan_preflight_status(
                                candidate,
                                ik_pregrasp="SKIP_HIGH_ENTRY",
                                plan_pregrasp="OK_OBJECT_HIGH",
                                ik_grasp=ik_gr,
                                plan_before_result="OK_HIGH_STAGE_ONLY",
                            )
                            self._store_preplanned_pick_route(
                                candidate,
                                plan_targets,
                                source_frame,
                                pre_plan=pre_plan,
                                gr_plan=gr_plan,
                                quat=q,
                                variant_name=qname,
                                safe_pregrasp_enabled=False,
                                route_source="plan_before_motion_object_high",
                            )
                        self.get_logger().info(
                            "[PLAN_BEFORE_MOTION]\n"
                            "result=OK_HIGH_STAGE_ONLY\n"
                            "detail=variant=%s high_joint_dist=%.4f"
                            % (qname, joint_dist)
                        )
                        return True
                    self.get_logger().warning(
                        "[PREGRASP_PLAN_FALLBACK]\n"
                        "reason=pregrasp_from_home_failed\n"
                        "fallback=object_high_stage\n"
                        "result=FAIL"
                    )

        if self._is_chips_can_cylinder_topdown_candidate(candidate):
            pre_z_log = float(pre_plan[2])
            if plan_targets is not None:
                pre_tcp_src = plan_targets.get("pregrasp_tcp")
                if isinstance(pre_tcp_src, (list, tuple)) and len(pre_tcp_src) >= 3:
                    pre_z_log = float(pre_tcp_src[2])
            pick = self._pick_chips_can_yaw_free_pregrasp_ik_plan(
                candidate,
                pre_plan,
                start_js,
                base_yaw,
                pregrasp_tcp_z=pre_z_log,
                variant_label="plan_before_motion",
                require_plan_ok=True,
            )
            if pick is not None:
                ranked = [
                    (
                        str(pick["variant_name"]),
                        pick["quat"],
                        float(pick["commanded_yaw_rad"]),
                        pick["ik_joint_state"],
                        float(pick["joint_dist"]),
                    )
                ]
            else:
                ranked = []
                ik_pre = "FAIL"
                plan_pre = "FAIL"
        else:
            ranked = self._ranked_downward_yaw_variants_for_pose(
                base_yaw, pre_plan, start_js
            )
        for qname, q, _cmd_yaw, ik_pre_sol, joint_dist in ranked:
            try:
                pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
            except Exception as exc:
                best_detail = "tcp_to_moveit_fail:%s" % exc
                continue
            if ik_pre_sol is None:
                ik_pre = "FAIL"
                continue
            ik_pre = "OK"
            plan_start_js = ik_pre_sol if ik_pre_sol is not None else start_js
            try:
                traj = self._moveit2.plan(
                    position=list(pre_moveit),
                    quat_xyzw=list(q),
                    frame_id=self._planning_frame,
                    target_link=self._moveit_target_link,
                    start_joint_state=plan_start_js,
                    tolerance_orientation=ori_tol,
                )
            except Exception as exc:
                traj = None
                best_detail = "plan_exception:%s" % exc
            if traj is None:
                plan_pre = "FAIL"
                continue
            plan_pre = "OK"
            try:
                gr_moveit = self._tcp_pose_to_moveit_pose(gr_plan, q)
                pos_gr = [
                    float(gr_moveit[0]),
                    float(gr_moveit[1]),
                    float(gr_moveit[2]),
                ]
                quat_gr = [
                    float(q[0]),
                    float(q[1]),
                    float(q[2]),
                    float(q[3]),
                ]
                ik_gr_sol = self._moveit2.compute_ik(
                    position=pos_gr,
                    quat_xyzw=quat_gr,
                    ik_link_name=self._moveit_target_link,
                    start_joint_state=plan_start_js,
                    wait_for_server_timeout_sec=1.0,
                )
                ik_gr = "OK" if ik_gr_sol is not None else "FAIL"
            except Exception:
                ik_gr = "FAIL"
            if grasp_ik_required and ik_gr != "OK":
                best_detail = "variant=%s grasp_ik_fail" % qname
                continue
            if ik_gr != "OK":
                self.get_logger().warning(
                    "[PLAN_BEFORE_MOTION] ik_grasp=FAIL (grasp por descenso cartesiano "
                    "desde pregrasp; grasp_ik_required_before_pregrasp=false)"
                )
            best_detail = "variant=%s direct_pregrasp joint_dist=%.4f" % (
                qname,
                joint_dist,
            )
            motion_result = "OK" if ik_gr == "OK" else "OK_PREGRASP_ONLY"
            if self._demo_full_pick_route_prevalidation_required(candidate):
                pregrasp_end_js = (
                    self._joint_state_from_plan_trajectory(traj) or ik_pre_sol
                )
                cart_ok, _frac, cart_deferred = (
                    self._prevalidate_cartesian_descend_for_pick_route(
                        candidate,
                        pre_plan,
                        gr_plan,
                        q,
                        pregrasp_end_js,
                        stage_label="pregrasp_to_grasp",
                        pregrasp_plan_traj=traj,
                    )
                )
                if not cart_ok:
                    best_detail = "variant=%s cartesian_descend_prevalidate_fail" % qname
                    continue
                if cart_deferred:
                    motion_result = "OK_PREGRASP_PENDING_DESCEND_VALIDATE"
                else:
                    motion_result = "OK_FULL_PICK_ROUTE"
            self._store_plan_before_motion_validated_pregrasp(
                candidate,
                variant_name=qname,
                quat=q,
                commanded_yaw_rad=float(_cmd_yaw),
            )
            self._store_pregrasp_plan_preflight_status(
                candidate,
                ik_pregrasp=ik_pre,
                plan_pregrasp=plan_pre,
                ik_grasp=ik_gr,
                plan_before_result=motion_result,
            )
            if plan_targets is not None and source_frame:
                self._store_preplanned_pick_route(
                    candidate,
                    plan_targets,
                    source_frame,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    quat=q,
                    variant_name=qname,
                    safe_pregrasp_enabled=False,
                    route_source="plan_before_motion_direct_pregrasp",
                )
            self._log_pick_route_preplan_selected(
                candidate,
                variant_name=qname,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                ik_pregrasp=ik_pre,
                plan_pregrasp=plan_pre,
                ik_grasp=ik_gr,
                safe_pregrasp_enabled=False,
                result="OK",
            )
            self.get_logger().info(
                "[PLAN_BEFORE_MOTION]\n"
                "snapshot_center=%s\n"
                "safe_pregrasp_stage=disabled\n"
                "target_pregrasp=(%.3f, %.3f, %.3f)\n"
                "target_grasp=(%.3f, %.3f, %.3f)\n"
                "ik_pregrasp=%s\n"
                "plan_pregrasp=%s\n"
                "ik_grasp=%s\n"
                "grasp_ik_required_before_pregrasp=%s\n"
                "result=%s\n"
                "pregrasp_plan_ok=true\n"
                "motion_authorized=false\n"
                "motion_authorization_source=EXECUTION_PREFLIGHT\n"
                "start_state=%s\n"
                "detail=%s"
                % (
                    snap_str,
                    pre_plan[0],
                    pre_plan[1],
                    pre_plan[2],
                    gr_plan[0],
                    gr_plan[1],
                    gr_plan[2],
                    ik_pre,
                    plan_pre,
                    ik_gr,
                    str(grasp_ik_required).lower(),
                    motion_result,
                    start_state_label,
                    best_detail,
                )
            )
            return True

        if (
            high_tcp is not None
            and bool(candidate.get("uses_low_object_high_approach_stage"))
            and source_frame
        ):
            high_plan, _ = self._transform_target_to_planning_frame(
                high_tcp, source_frame, stage="plan_before_object_high"
            )
            if high_plan is not None:
                self.get_logger().warning(
                    "[PREGRASP_PLAN_FALLBACK]\n"
                    "reason=pregrasp_from_home_failed\n"
                    "fallback=object_high_stage\n"
                    "result=attempting_legacy"
                )
                ranked_h = self._ranked_downward_yaw_variants_for_pose(
                    base_yaw, high_plan, start_js
                )
                for qname, q, _cmd_yaw, ik_h_sol, joint_dist in ranked_h:
                    if ik_h_sol is None:
                        continue
                    try:
                        high_moveit = self._tcp_pose_to_moveit_pose(high_plan, q)
                        traj_h = self._moveit2.plan(
                            position=list(high_moveit),
                            quat_xyzw=list(q),
                            frame_id=self._planning_frame,
                            target_link=self._moveit_target_link,
                            start_joint_state=ik_h_sol,
                            tolerance_orientation=ori_tol,
                        )
                    except Exception:
                        traj_h = None
                    if traj_h is None:
                        continue
                    try:
                        pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                        ik_pre_sol = self._moveit2.compute_ik(
                            position=[
                                float(pre_moveit[0]),
                                float(pre_moveit[1]),
                                float(pre_moveit[2]),
                            ],
                            quat_xyzw=[
                                float(q[0]),
                                float(q[1]),
                                float(q[2]),
                                float(q[3]),
                            ],
                            ik_link_name=self._moveit_target_link,
                            start_joint_state=ik_h_sol,
                            wait_for_server_timeout_sec=1.0,
                        )
                    except Exception:
                        ik_pre_sol = None
                    if ik_pre_sol is None:
                        continue
                    self._store_plan_before_motion_validated_pregrasp(
                        candidate,
                        variant_name=qname,
                        quat=q,
                        commanded_yaw_rad=float(_cmd_yaw),
                    )
                    self.get_logger().info(
                        "[PREGRASP_PLAN_FALLBACK]\n"
                        "reason=pregrasp_from_home_failed\n"
                        "fallback=object_high_stage\n"
                        "result=OK\n"
                        "detail=variant=%s high_joint_dist=%.4f"
                        % (qname, joint_dist)
                    )
                    self.get_logger().info(
                        "[PLAN_BEFORE_MOTION]\n"
                        "snapshot_center=%s\n"
                        "safe_pregrasp_stage=disabled\n"
                        "object_high_stage=enabled\n"
                        "target_object_high=(%.3f, %.3f, %.3f)\n"
                        "target_pregrasp=(%.3f, %.3f, %.3f)\n"
                        "result=OK_HIGH_THEN_PREGRASP"
                        % (
                            snap_str,
                            high_plan[0],
                            high_plan[1],
                            high_plan[2],
                            pre_plan[0],
                            pre_plan[1],
                            pre_plan[2],
                        )
                    )
                    return True
                self.get_logger().error(
                    "[PREGRASP_PLAN_FALLBACK]\n"
                    "reason=pregrasp_from_home_failed\n"
                    "fallback=object_high_stage\n"
                    "result=FAIL"
                )

        self.get_logger().error(
            "[PLAN_BEFORE_MOTION]\n"
            "snapshot_center=%s\n"
            "safe_pregrasp_stage=disabled\n"
            "target_pregrasp=(%.3f, %.3f, %.3f)\n"
            "target_grasp=(%.3f, %.3f, %.3f)\n"
            "ik_pregrasp=%s\n"
            "plan_pregrasp=%s\n"
            "ik_grasp=%s\n"
            "grasp_ik_required_before_pregrasp=%s\n"
            "result=FAIL\n"
            "start_state=%s\n"
            "detail=%s"
            % (
                snap_str,
                pre_plan[0],
                pre_plan[1],
                pre_plan[2],
                gr_plan[0],
                gr_plan[1],
                gr_plan[2],
                ik_pre,
                plan_pre,
                ik_gr,
                str(grasp_ik_required).lower(),
                start_state_label,
                best_detail or "exhausted_variants",
            )
        )
        return False

    def _shifted_tcp_from_plan_targets(
        self,
        plan_targets: Dict[str, Tuple[float, float, float]],
        key: str,
        dx: float,
        dy: float,
    ) -> Optional[Tuple[float, float, float]]:
        raw = plan_targets.get(key)
        if not isinstance(raw, (list, tuple)) or len(raw) < 3:
            return None
        return self._shift_pose_xy(
            (float(raw[0]), float(raw[1]), float(raw[2])), dx, dy
        )

    @staticmethod
    def _quaternion_angle_deg(
        q_a: Tuple[float, float, float, float],
        q_b: Tuple[float, float, float, float],
    ) -> float:
        a = np.array([float(q_a[0]), float(q_a[1]), float(q_a[2]), float(q_a[3])])
        b = np.array([float(q_b[0]), float(q_b[1]), float(q_b[2]), float(q_b[3])])
        na = float(np.linalg.norm(a))
        nb = float(np.linalg.norm(b))
        if na < 1e-9 or nb < 1e-9:
            return 180.0
        a = a / na
        b = b / nb
        dot = float(abs(np.dot(a, b)))
        dot = min(1.0, dot)
        return math.degrees(2.0 * math.acos(dot))

    def _link_pose_in_planning_frame(
        self, link: str
    ) -> Optional[Dict[str, Any]]:
        self._ensure_tf_buffer()
        if self._tf_buffer is None:
            return None
        try:
            tf_msg = self._tf_buffer.lookup_transform(
                self._planning_frame,
                link,
                rclpy.time.Time(),
                timeout=rclpy.duration.Duration(
                    seconds=float(self._gripper_axis_tf_wait_timeout_sec)
                ),
            )
            t = tf_msg.transform.translation
            q = tf_msg.transform.rotation
            return {
                "position": (
                    float(t.x),
                    float(t.y),
                    float(t.z),
                ),
                "quat": (
                    float(q.x),
                    float(q.y),
                    float(q.z),
                    float(q.w),
                ),
            }
        except Exception:
            return None

    def _lock_chips_can_yaw_free_descend_orientation(
        self,
        candidate: Dict[str, Any],
        original_target_quat: Tuple[float, float, float, float],
    ) -> Optional[Dict[str, Any]]:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        if hand_pose is None:
            self.get_logger().error(
                "[CHIPS_CAN_YAW_FREE_DESCEND_ORIENTATION_LOCK] FAIL: no TF for %s"
                % hand_link
            )
            return None

        hand_pos = hand_pose["position"]
        hand_quat = hand_pose["quat"]
        tcp_pos: Optional[Tuple[float, float, float]] = None
        tcp_quat: Optional[Tuple[float, float, float, float]] = None
        if self._use_grasp_tcp:
            tcp_pose = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if tcp_pose is not None:
                tcp_pos = tcp_pose["position"]
                tcp_quat = tcp_pose["quat"]

        ref_quat = tcp_quat if tcp_quat is not None else hand_quat
        z_axis = self._unit_z_from_quaternion_xyzw(ref_quat)
        z_norm = float(np.linalg.norm(z_axis))
        if z_norm > 1e-9:
            z_axis = z_axis / z_norm
        top_down_dot = float(-z_axis[2])
        top_down_orientation_ok = top_down_dot >= 0.85
        tilt_deg = math.degrees(math.acos(max(-1.0, min(1.0, top_down_dot))))

        center_metrics = self._compute_chips_can_gt_cylinder_centering_metrics(
            candidate
        )
        if center_metrics is None:
            center_metrics = self._compute_gripper_centering_metrics(candidate)
        centering_ok = False
        if center_metrics is not None:
            if self._is_chips_can_gt_cylinder_candidate(candidate):
                centering_ok = self._chips_can_gt_cylinder_centering_within_thresholds(
                    center_metrics
                )
            else:
                centering_ok = self._gripper_centering_within_thresholds(
                    center_metrics
                )

        gripper_open_ok = self._gripper_fingers_near_width(
            self._cap_open_joint_value(
                self._raw_effective_open_joint(), "chips_can_pre_descend_open_check"
            )
        )
        lock_ok = bool(top_down_orientation_ok and centering_ok and gripper_open_ok)
        self.get_logger().info(
            "[CHIPS_CAN_YAW_FREE_DESCEND_ORIENTATION_LOCK]\n"
            "label=chips_can\n"
            "strategy=cylinder_topdown\n"
            "skip_gap_axis_check=true\n"
            "reason=yaw_free_cylinder_gt_centered\n"
            "top_down_orientation_ok=%s\n"
            "top_down_dot=%.4f\n"
            "tilt_from_vertical_deg=%.2f\n"
            "centering_ok=%s\n"
            "gripper_open_ok=%s\n"
            "result=%s"
            % (
                str(top_down_orientation_ok).lower(),
                top_down_dot,
                tilt_deg,
                str(centering_ok).lower(),
                str(gripper_open_ok).lower(),
                "OK" if lock_ok else "FAIL",
            )
        )
        if not lock_ok:
            return None

        angular_delta = self._quaternion_angle_deg(hand_quat, original_target_quat)
        locked = {
            "current_hand_position": hand_pos,
            "current_hand_quat": hand_quat,
            "current_tcp_position": tcp_pos,
            "current_tcp_quat": tcp_quat,
            "locked_hand_quat": hand_quat,
            "original_target_quat": original_target_quat,
            "angular_delta_from_original_deg": angular_delta,
        }
        candidate["_descend_orientation_lock"] = {
            "current_hand_position": list(hand_pos),
            "current_hand_quat": list(hand_quat),
            "locked_hand_quat": list(hand_quat),
        }
        return locked

    def _sugar_box_runtime_wrist_metrics(
        self,
        candidate: Dict[str, Any],
        validated_hand_quat: Tuple[float, float, float, float],
    ) -> Optional[Dict[str, float]]:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        if hand_pose is None:
            return None
        hand_quat = hand_pose["quat"]
        ref_quat = hand_quat
        if self._use_grasp_tcp:
            tcp_pose = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if tcp_pose is not None:
                ref_quat = tcp_pose["quat"]
        z_axis = self._unit_z_from_quaternion_xyzw(ref_quat)
        z_norm = float(np.linalg.norm(z_axis))
        if z_norm > 1e-9:
            z_axis = z_axis / z_norm
        top_down_dot = float(-z_axis[2])
        tilt_deg = math.degrees(math.acos(max(-1.0, min(1.0, top_down_dot))))
        orient_err = float(
            self._quaternion_angle_deg(hand_quat, validated_hand_quat)
        )
        j6_deg = float("nan")
        current_js = self._current_arm_joint_state()
        if current_js is not None:
            try:
                names = list(current_js.name)
                positions = [float(v) for v in current_js.position]
                j6_map = {n: p for n, p in zip(names, positions)}
                if "panda_joint6" in j6_map:
                    j6_deg = math.degrees(float(j6_map["panda_joint6"]))
            except (TypeError, ValueError, AttributeError):
                pass
        return {
            "top_down_dot": top_down_dot,
            "tilt_from_vertical_deg": tilt_deg,
            "hand_orientation_error_deg": orient_err,
            "panda_joint6_deg": j6_deg,
        }

    def _sugar_box_strict_wrist_orientation_ok(
        self,
        metrics: Optional[Dict[str, float]],
    ) -> bool:
        if metrics is None:
            return False
        return bool(
            float(metrics["top_down_dot"])
            >= float(self._sugar_box_strict_top_down_dot)
            and float(metrics["hand_orientation_error_deg"])
            <= float(self._sugar_box_strict_hand_orientation_tol_deg)
        )

    @staticmethod
    def _sugar_box_pregrasp_variant_rank_key(variant: Dict[str, Any]) -> Tuple[float, float, float]:
        orient = float(variant.get("hand_orientation_error_deg", 1e9))
        top_down = -float(variant.get("plan_top_down_dot", 0.0))
        joint = float(variant.get("joint_dist", 1e9))
        return (orient, top_down, joint)

    def _lock_sugar_box_validated_descend_orientation(
        self,
        candidate: Dict[str, Any],
        original_target_quat: Tuple[float, float, float, float],
    ) -> Optional[Dict[str, Any]]:
        validated_quat = (
            self._plan_before_locked_execution_quat_tuple(candidate)
            or original_target_quat
        )
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        if hand_pose is None:
            self.get_logger().error(
                "[SUGAR_BOX_DESCEND_ORIENTATION_LOCK] FAIL: no TF for %s"
                % hand_link
            )
            return None

        hand_pos = hand_pose["position"]
        hand_quat = hand_pose["quat"]
        tcp_pos: Optional[Tuple[float, float, float]] = None
        tcp_quat: Optional[Tuple[float, float, float, float]] = None
        if self._use_grasp_tcp:
            tcp_pose = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if tcp_pose is not None:
                tcp_pos = tcp_pose["position"]
                tcp_quat = tcp_pose["quat"]

        metrics = self._sugar_box_runtime_wrist_metrics(candidate, validated_quat)
        use_gap_lock = sugar_box_use_gap_aligned_descend_orientation_lock(candidate)
        gap_angle_err = float("nan")
        if use_gap_lock:
            gap_metrics = self._gripper_gap_alignment_metrics(candidate)
            if gap_metrics is not None:
                gap_angle_err = float(gap_metrics["angle_error_deg"])
            wrist_ok = sugar_box_descend_wrist_ok_with_gap_lock(
                top_down_dot=float(metrics["top_down_dot"]) if metrics else -1.0,
                gap_angle_error_deg=gap_angle_err,
                strict_top_down_dot=float(self._sugar_box_strict_top_down_dot),
                gap_target_angle_deg=float(self._gripper_gap_verify_target_angle_deg),
            )
            centering_check = "gap_aligned_after_joint7"
        else:
            wrist_ok = self._sugar_box_strict_wrist_orientation_ok(metrics)
            centering_check = "skipped_plan_before_validated"
        gripper_open_ok = self._gripper_fingers_near_width(
            self._cap_open_joint_value(
                self._raw_effective_open_joint(), "sugar_box_pre_descend_open_check"
            )
        )
        lock_ok = bool(wrist_ok and gripper_open_ok)
        self.get_logger().info(
            "[SUGAR_BOX_DESCEND_ORIENTATION_LOCK]\n"
            "label=sugar_box\n"
            "strategy=top_down_short_axis\n"
            "orientation_lock_mode=%s\n"
            "validated_quat=(%.4f, %.4f, %.4f, %.4f)\n"
            "strict_top_down_dot_min=%.4f\n"
            "strict_hand_orientation_tol_deg=%.2f\n"
            "top_down_dot=%s\n"
            "tilt_from_vertical_deg=%s\n"
            "hand_orientation_error_deg=%s\n"
            "gap_angle_error_deg=%s\n"
            "panda_joint6_deg=%s\n"
            "wrist_orientation_ok=%s\n"
            "gripper_open_ok=%s\n"
            "centering_check=%s\n"
            "result=%s"
            % (
                "gap_aligned_after_joint7" if use_gap_lock else "plan_before_validated",
                float(validated_quat[0]),
                float(validated_quat[1]),
                float(validated_quat[2]),
                float(validated_quat[3]),
                float(self._sugar_box_strict_top_down_dot),
                float(self._sugar_box_strict_hand_orientation_tol_deg),
                "n/a"
                if metrics is None
                else "%.4f" % float(metrics["top_down_dot"]),
                "n/a"
                if metrics is None
                else "%.2f" % float(metrics["tilt_from_vertical_deg"]),
                "n/a"
                if metrics is None
                else "%.2f" % float(metrics["hand_orientation_error_deg"]),
                "n/a"
                if use_gap_lock and math.isnan(gap_angle_err)
                else ("%.2f" % gap_angle_err if use_gap_lock else "n/a"),
                "n/a"
                if metrics is None
                else "%.2f" % float(metrics["panda_joint6_deg"]),
                str(wrist_ok).lower(),
                str(gripper_open_ok).lower(),
                centering_check,
                "OK" if lock_ok else "FAIL",
            )
        )
        if not lock_ok:
            return None

        lock_quat = hand_quat if use_gap_lock else validated_quat
        angular_delta = self._quaternion_angle_deg(hand_quat, validated_quat)
        locked = {
            "current_hand_position": hand_pos,
            "current_hand_quat": hand_quat,
            "current_tcp_position": tcp_pos,
            "current_tcp_quat": tcp_quat,
            "locked_hand_quat": lock_quat,
            "original_target_quat": validated_quat,
            "angular_delta_from_original_deg": angular_delta,
        }
        candidate["_descend_orientation_lock"] = {
            "current_hand_position": list(hand_pos),
            "current_hand_quat": list(hand_quat),
            "locked_hand_quat": list(lock_quat),
        }
        return locked

    @staticmethod
    def _unit_z_from_quaternion_xyzw(
        quat: Tuple[float, float, float, float],
    ) -> np.ndarray:
        x, y, z, w = (float(quat[0]), float(quat[1]), float(quat[2]), float(quat[3]))
        return np.array(
            [
                2.0 * (x * z + w * y),
                2.0 * (y * z - w * x),
                1.0 - 2.0 * (x * x + y * y),
            ],
            dtype=np.float64,
        )

    def _lock_descend_orientation_from_current_tf(
        self,
        candidate: Dict[str, Any],
        original_target_quat: Tuple[float, float, float, float],
    ) -> Optional[Dict[str, Any]]:
        if sugar_box_direct_pregrasp_yaw_locked(candidate):
            return self._lock_sugar_box_validated_descend_orientation(
                candidate, original_target_quat
            )
        if (
            self._chips_can_skip_gripper_gap_alignment(candidate)
            and self._is_chips_can_gt_cylinder_candidate(candidate)
        ):
            return self._lock_chips_can_yaw_free_descend_orientation(
                candidate, original_target_quat
            )
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        if hand_pose is None:
            self.get_logger().error(
                "[DESCEND_ORIENTATION_LOCK] FAIL: no TF for %s in %s"
                % (hand_link, self._planning_frame)
            )
            return None

        hand_pos = hand_pose["position"]
        hand_quat = hand_pose["quat"]
        tcp_pos: Optional[Tuple[float, float, float]] = None
        tcp_quat: Optional[Tuple[float, float, float, float]] = None
        if self._use_grasp_tcp:
            tcp_pose = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if tcp_pose is not None:
                tcp_pos = tcp_pose["position"]
                tcp_quat = tcp_pose["quat"]

        angular_delta = self._quaternion_angle_deg(hand_quat, original_target_quat)
        gap_metrics = self._gripper_gap_alignment_metrics(candidate)
        angle_err = (
            float(gap_metrics["angle_error_deg"])
            if gap_metrics is not None
            else float("nan")
        )
        target_deg = float(self._gripper_gap_verify_target_angle_deg)
        hard_max_deg = float(self._gripper_gap_verify_max_angle_deg)
        observed_str = "n/a"
        desired_str = "n/a"
        dot_raw = float("nan")
        flip_target_used = "n/a"
        if gap_metrics is not None:
            obs = gap_metrics["observed"]
            des = gap_metrics["desired"]
            observed_str = "(%.4f, %.4f)" % (float(obs[0]), float(obs[1]))
            desired_str = "(%.4f, %.4f)" % (float(des[0]), float(des[1]))
            dot_raw = float(np.dot(obs, des))
            tgt = gap_metrics.get("target")
            if isinstance(tgt, np.ndarray):
                flip_target_used = (
                    "desired"
                    if float(np.dot(tgt, des)) >= float(np.dot(-tgt, des))
                    else "negated_desired"
                )

        lock_ok = gap_metrics is not None and angle_err <= target_deg
        self.get_logger().info(
            "[DESCEND_ORIENTATION_LOCK]\n"
            "source=current_tf_after_yaw_and_centering\n"
            "current_hand_quat=(%.4f, %.4f, %.4f, %.4f)\n"
            "current_hand_position=(%.4f, %.4f, %.4f)\n"
            "current_tcp_quat=%s\n"
            "current_tcp_position=%s\n"
            "original_target_quat=(%.4f, %.4f, %.4f, %.4f)\n"
            "angular_delta_from_original_deg=%.2f\n"
            "observed_gap_axis_xy=%s\n"
            "desired_object_gap_axis_xy=%s\n"
            "dot_raw=%s\n"
            "flip_target_used=%s\n"
            "angle_error_deg=%s\n"
            "target_angle_deg=%.2f\n"
            "hard_max_angle_deg=%.2f\n"
            "orientation_allow_axis_flip_equivalence=%s\n"
            "result=%s"
            % (
                hand_quat[0],
                hand_quat[1],
                hand_quat[2],
                hand_quat[3],
                hand_pos[0],
                hand_pos[1],
                hand_pos[2],
                "n/a"
                if tcp_quat is None
                else "(%.4f, %.4f, %.4f, %.4f)"
                % tcp_quat,
                "n/a"
                if tcp_pos is None
                else "(%.4f, %.4f, %.4f)" % tcp_pos,
                original_target_quat[0],
                original_target_quat[1],
                original_target_quat[2],
                original_target_quat[3],
                angular_delta,
                observed_str,
                desired_str,
                "n/a" if gap_metrics is None else "%.4f" % dot_raw,
                flip_target_used,
                "n/a" if gap_metrics is None else "%.2f" % angle_err,
                target_deg,
                hard_max_deg,
                str(self._orientation_allow_axis_flip).lower(),
                "OK" if lock_ok else "FAIL",
            )
        )
        if not lock_ok:
            if gap_metrics is not None and angle_err > hard_max_deg:
                self.get_logger().error(
                    "[DESCEND_ORIENTATION_LOCK] FAIL: angle_error_deg=%.2f > hard_max=%.2f"
                    % (angle_err, hard_max_deg)
                )
            return None

        locked = {
            "current_hand_position": hand_pos,
            "current_hand_quat": hand_quat,
            "current_tcp_position": tcp_pos,
            "current_tcp_quat": tcp_quat,
            "locked_hand_quat": hand_quat,
            "original_target_quat": original_target_quat,
            "angular_delta_from_original_deg": angular_delta,
        }
        candidate["_descend_orientation_lock"] = {
            "current_hand_position": list(hand_pos),
            "current_hand_quat": list(hand_quat),
            "locked_hand_quat": list(hand_quat),
        }
        return locked

    def _build_descend_moveit_goal_locked(
        self,
        orientation_lock: Dict[str, Any],
        target_tcp: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
    ) -> Tuple[Tuple[float, float, float], Tuple[float, float, float, float]]:
        hand_quat = orientation_lock["locked_hand_quat"]
        hand_xyz = hand_goal_from_tcp_target(
            orientation_lock,
            target_tcp,
            quat,
            use_grasp_tcp=bool(self._use_grasp_tcp),
            tcp_to_moveit=self._tcp_pose_to_moveit_pose,
        )
        return hand_xyz, (
            float(hand_quat[0]),
            float(hand_quat[1]),
            float(hand_quat[2]),
            float(hand_quat[3]),
        )

    def _guard_descend_tcp_hand_goal(
        self,
        orientation_lock: Dict[str, Any],
        target_tcp: Tuple[float, float, float],
        descend_hand_goal: Tuple[float, float, float],
        *,
        label: str = "",
        expected_grasp_tcp_z: Optional[float] = None,
        tolerance_m: float = 0.01,
    ) -> bool:
        tcp_pos = orientation_lock.get("current_tcp_position")
        hand_pos = orientation_lock["current_hand_position"]
        if not isinstance(tcp_pos, (list, tuple)) or len(tcp_pos) < 3:
            tcp_pos = self._tcp_position_in_planning_frame()
        if tcp_pos is None:
            self.get_logger().error(
                "[DESCEND_TCP_HAND_MISMATCH]\n"
                "label=%s\n"
                "result=FAIL\n"
                "reason=no_current_tcp"
                % (str(label),)
            )
            return False
        exp_grasp_z = (
            float(expected_grasp_tcp_z)
            if expected_grasp_tcp_z is not None
            else float(target_tcp[2])
        )
        sem_ok, sem_reason, tcp_dz, hand_dz = descend_goal_semantic_check(
            float(tcp_pos[2]),
            float(target_tcp[2]),
            exp_grasp_z,
            float(hand_pos[2]),
            float(descend_hand_goal[2]),
        )
        self.get_logger().info(
            "[DESCEND_GOAL_SEMANTIC_CHECK]\n"
            "label=%s\n"
            "current_tcp_z=%.4f\n"
            "target_tcp_z=%.4f\n"
            "expected_grasp_tcp_z=%.4f\n"
            "current_hand_z=%.4f\n"
            "target_hand_z=%.4f\n"
            "tcp_delta_z=%.4f\n"
            "hand_delta_z=%.4f\n"
            "result=%s\n"
            "reason=%s"
            % (
                str(label),
                float(tcp_pos[2]),
                float(target_tcp[2]),
                float(exp_grasp_z),
                float(hand_pos[2]),
                float(descend_hand_goal[2]),
                float(tcp_dz),
                float(hand_dz),
                "OK" if sem_ok else "FAIL",
                sem_reason,
            )
        )
        if not sem_ok:
            self.get_logger().error(
                "[DESCEND_TCP_HAND_MISMATCH]\n"
                "label=%s\n"
                "reason=%s\n"
                "current_tcp_z=%.4f\n"
                "target_tcp_z=%.4f\n"
                "expected_grasp_tcp_z=%.4f\n"
                "current_hand_z=%.4f\n"
                "descend_hand_goal_z=%.4f\n"
                "tcp_delta_z=%.4f\n"
                "hand_delta_z=%.4f\n"
                "result=FAIL"
                % (
                    str(label),
                    sem_reason,
                    float(tcp_pos[2]),
                    float(target_tcp[2]),
                    float(exp_grasp_z),
                    float(hand_pos[2]),
                    float(descend_hand_goal[2]),
                    float(tcp_dz),
                    float(hand_dz),
                )
            )
            return False
        ok, expected_dz, actual_dz = descend_tcp_hand_delta_mismatch(
            float(tcp_pos[2]),
            float(target_tcp[2]),
            float(hand_pos[2]),
            float(descend_hand_goal[2]),
            tolerance_m=float(tolerance_m),
        )
        if ok:
            return True
        self.get_logger().error(
            "[DESCEND_TCP_HAND_MISMATCH]\n"
            "label=%s\n"
            "reason=hand_delta_mismatch_tcp_delta\n"
            "expected_tcp_delta_z=%.4f\n"
            "actual_hand_delta_z=%.4f\n"
            "current_tcp_z=%.4f\n"
            "target_tcp_z=%.4f\n"
            "current_hand_z=%.4f\n"
            "descend_hand_goal_z=%.4f\n"
            "use_grasp_tcp=%s\n"
            "grasp_tcp_frame=%s\n"
            "moveit_target_link=%s\n"
            "result=FAIL"
            % (
                str(label),
                float(expected_dz),
                float(actual_dz),
                float(tcp_pos[2]),
                float(target_tcp[2]),
                float(hand_pos[2]),
                float(descend_hand_goal[2]),
                str(bool(self._use_grasp_tcp)).lower(),
                self._grasp_tcp_frame,
                self._moveit_target_link,
            )
        )
        return False

    def _log_cartesian_descent_route_locked(
        self,
        candidate: Dict[str, Any],
        orientation_lock: Dict[str, Any],
        target_tcp: Tuple[float, float, float],
        descend_hand_goal: Tuple[float, float, float],
        *,
        route: str = "single_segment",
        reason: str = "label_policy",
    ) -> None:
        tcp_pos = orientation_lock.get("current_tcp_position")
        hand_pos = orientation_lock["current_hand_position"]
        if not isinstance(tcp_pos, (list, tuple)) or len(tcp_pos) < 3:
            tcp_pos = self._tcp_position_in_planning_frame()
        tcp_dz = (
            abs(float(tcp_pos[2]) - float(target_tcp[2]))
            if tcp_pos is not None
            else float("nan")
        )
        hand_dz = abs(float(hand_pos[2]) - float(descend_hand_goal[2]))
        tcp_from = (
            "n/a"
            if tcp_pos is None
            else "(%.4f, %.4f, %.4f)" % (float(tcp_pos[0]), float(tcp_pos[1]), float(tcp_pos[2]))
        )
        self.get_logger().info(
            "[CARTESIAN_DESCENT_ROUTE]\n"
            "label=%s\n"
            "route=%s\n"
            "current_tcp=%s\n"
            "target_tcp=(%.4f, %.4f, %.4f)\n"
            "current_hand=(%.4f, %.4f, %.4f)\n"
            "target_hand=(%.4f, %.4f, %.4f)\n"
            "tcp_delta_z=%.4f\n"
            "hand_delta_z=%.4f\n"
            "velocity_scaling=%.4f\n"
            "reason=%s"
            % (
                str(candidate.get("label", "")),
                str(route),
                tcp_from,
                float(target_tcp[0]),
                float(target_tcp[1]),
                float(target_tcp[2]),
                float(hand_pos[0]),
                float(hand_pos[1]),
                float(hand_pos[2]),
                float(descend_hand_goal[0]),
                float(descend_hand_goal[1]),
                float(descend_hand_goal[2]),
                float(tcp_dz),
                float(hand_dz),
                float(candidate.get("descend_velocity_scaling", self._descend_vel)),
                str(reason),
            )
        )

    def _pre_descend_tcp_ok(self, candidate: Dict[str, Any]) -> bool:
        pre_tcp = None
        route = self._preplanned_pick_route or {}
        if isinstance(route, dict):
            pre_tcp = route.get("pregrasp_tcp")
        if pre_tcp is None:
            return True
        current_tcp = self._tcp_position_in_planning_frame()
        tcp_err = self._tcp_xyz_error_m(current_tcp, pre_tcp)
        threshold = float(DEFAULT_PREGRASP_TCP_ERROR_THRESHOLD_M)
        if bool(candidate.get("_sugar_box_skip_joint7_axis_correction")):
            threshold = max(threshold, 0.020)
        return bool(
            tcp_err is not None
            and float(tcp_err) + 1e-9 < threshold
        )

    def _chips_can_legacy_micro_descend_inter_segment_active(
        self,
        candidate: Dict[str, Any],
        depth_plan: Dict[str, Any],
    ) -> bool:
        if not self._chips_can_legacy_pending_actual_tf_descend_active(candidate):
            return False
        segments = depth_plan.get("segments") or []
        return len(segments) > 1

    def _verify_chips_can_micro_descend_inter_segment(
        self,
        candidate: Dict[str, Any],
        *,
        step_idx: int,
        segment_target_z: float,
        start_tcp_z: float,
        next_target_z: float,
        lock_xy: Tuple[float, float],
    ) -> Tuple[bool, str]:
        skip_gap = self._chips_can_skip_gripper_gap_alignment(candidate)
        if skip_gap:
            gap_ok = True
        else:
            gap_ok = self._verify_gripper_gap_axis_after_pregrasp_pose(
                candidate,
                grasp_center_base=self._resolve_grasp_center_base_from_candidate(
                    candidate
                ),
            )
        top_down_ok, centering_ok, gripper_open_ok = (
            self._chips_can_yaw_free_descend_gate_flags(candidate)
        )
        orientation_ok = bool(top_down_ok and gripper_open_ok)
        tcp = self._tcp_position_in_planning_frame()
        actual_z = float(tcp[2]) if tcp is not None else None
        tol = float(self._chips_can_descend_tcp_z_tolerance_m)
        drift_xy_m: Optional[float] = None
        xy_drift_ok = False
        if tcp is not None:
            drift_xy_m = _chips_xy_drift_m(
                lock_xy, (float(tcp[0]), float(tcp[1]))
            )
            xy_drift_ok = _chips_xy_drift_ok(
                drift_xy_m, float(self._chips_can_descend_max_xy_drift_m)
            )
        segment_tcp_ok = (
            actual_z is not None
            and float(actual_z) - float(segment_target_z) <= tol + 1e-9
        )
        z_progress_ok = bool(segment_tcp_ok)
        if actual_z is not None:
            progress_m = float(start_tcp_z) - float(actual_z)
            needed_drop = max(0.0, float(start_tcp_z) - float(segment_target_z))
            if needed_drop > 1e-4:
                z_progress_ok = bool(
                    progress_m + 1e-6
                    >= float(self._chips_can_descend_min_progress_m)
                    or segment_tcp_ok
                )
        overall_ok = bool(
            gap_ok
            and centering_ok
            and xy_drift_ok
            and z_progress_ok
            and orientation_ok
            and gripper_open_ok
        )
        if overall_ok:
            fail_reason = "inter_segment_verify_ok"
        elif not centering_ok:
            fail_reason = "centering_fail"
        elif not xy_drift_ok:
            fail_reason = "xy_drift_fail"
        elif not z_progress_ok or not segment_tcp_ok:
            fail_reason = "tcp_progress_fail"
        elif not gripper_open_ok or not top_down_ok:
            fail_reason = "gripper_open_fail"
        elif not gap_ok:
            fail_reason = "gap_fail"
        else:
            fail_reason = "inter_segment_verify_fail"
        self.get_logger().info(
            format_chips_can_micro_descend_inter_segment_verify_log(
                {
                    "step_idx": int(step_idx),
                    "actual_tcp_z": actual_z,
                    "previous_target_tcp_z": float(segment_target_z),
                    "next_target_tcp_z": float(next_target_z),
                    "z_progress_ok": bool(z_progress_ok),
                    "xy_drift_ok": bool(xy_drift_ok),
                    "centering_ok": bool(centering_ok),
                    "gripper_open_ok": bool(gripper_open_ok),
                    "gap_ok": bool(gap_ok),
                    "segment_tcp_ok": bool(segment_tcp_ok),
                    "tcp_ok_mode": "segment_progress_not_pregrasp",
                    "result": "OK" if overall_ok else "FAIL",
                    "reason": fail_reason,
                }
            )
        )
        return bool(overall_ok), str(fail_reason)

    def _pre_descend_gripper_reverify(self, candidate: Dict[str, Any]) -> bool:
        skip_gap = self._chips_can_skip_gripper_gap_alignment(candidate)
        gap_ok_phys, center_ok_phys, joint_limits_ok = (
            self._pregrasp_execution_physical_verify_ok(candidate)
        )
        tcp_ok = self._pre_descend_tcp_ok(candidate)
        if skip_gap:
            gap_ok = True
        else:
            gap_ok = self._verify_gripper_gap_axis_after_pregrasp_pose(
                candidate,
                grasp_center_base=self._resolve_grasp_center_base_from_candidate(
                    candidate
                ),
            )
        center_metrics: Optional[Dict[str, Any]] = None
        if self._is_chips_can_gt_cylinder_candidate(candidate):
            center_metrics = self._compute_chips_can_gt_cylinder_centering_metrics(
                candidate
            )
        if center_metrics is None:
            center_metrics = self._compute_gripper_centering_metrics(candidate)
        if center_metrics is not None:
            center_metrics = self._normalize_centering_metrics_dict(center_metrics)
            if self._is_chips_can_gt_cylinder_candidate(candidate):
                tc = center_metrics.get("target_center")
                if tc is not None and hasattr(tc, "__len__") and len(tc) >= 2:
                    candidate["_chips_can_target_axis_center_xy"] = [
                        float(tc[0]),
                        float(tc[1]),
                    ]

        center_ok = False
        log_ok = True
        if center_metrics is None:
            if skip_gap and bool(
                candidate.get("_chips_can_gt_centering_verified_at_pregrasp")
            ):
                center_ok = True
                self.get_logger().info(
                    "[PRE_DESCEND_GRIPPER_REVERIFY] center metrics unavailable; "
                    "using prior GT centering OK at pregrasp"
                )
            else:
                self.get_logger().error(
                    "[GRIPPER_CENTERING_VERIFY] pre-descend FAIL: no TF center"
                )
                return False
        elif self._is_chips_can_gt_cylinder_candidate(candidate):
            center_ok = self._chips_can_gt_cylinder_centering_within_thresholds(
                center_metrics
            )
            log_ok = self._log_chips_can_gt_cylinder_centering_verify(
                center_metrics, "OK" if center_ok else "FAIL"
            )
            if not log_ok and center_ok and skip_gap:
                self.get_logger().info(
                    "[PRE_DESCEND_GRIPPER_REVERIFY] GT centering log UNAVAILABLE; "
                    "continuing with center_ok=true"
                )
        else:
            center_ok = self._gripper_centering_within_thresholds(center_metrics)
            self._log_gripper_centering_verify(
                center_metrics, "OK" if center_ok else "FAIL"
            )

        gap_for_joint7 = bool(gap_ok and gap_ok_phys)
        center_for_joint7 = bool(center_ok and center_ok_phys)
        joint7_ok, joint7_action, joint7_reason = (
            self._verify_validated_joint7_runtime_match(
                candidate,
                gap_ok=gap_for_joint7,
                centering_ok=center_for_joint7,
                joint_limits_ok=joint_limits_ok,
                tcp_ok=tcp_ok,
            )
        )
        joint7_mismatch_ignored = bool(
            joint7_ok and joint7_action == "ALLOW_PHYSICAL_GAP_OK"
        )
        overall_ok = bool(
            joint7_ok and gap_ok and center_ok and tcp_ok and joint_limits_ok
        )
        reverify_reason = joint7_reason if overall_ok else "pre_descend_gripper_fail"
        if overall_ok and joint7_mismatch_ignored:
            reverify_reason = "physical_gap_ok_after_axis_correction"
        self.get_logger().info(
            format_pre_descend_gripper_reverify_log(
                gap_ok=bool(gap_ok and gap_ok_phys),
                centering_ok=bool(center_ok and center_ok_phys),
                tcp_ok=tcp_ok,
                joint7_mismatch_ignored=joint7_mismatch_ignored,
                reason=reverify_reason,
                result="OK" if overall_ok else "FAIL",
            )
        )
        if not overall_ok:
            self.get_logger().error(
                "[PRE_DESCEND_GRIPPER_REVERIFY] FAIL gap_ok=%s center_ok=%s tcp_ok=%s joint7_ok=%s"
                % (
                    str(gap_ok).lower(),
                    str(center_ok).lower(),
                    str(tcp_ok).lower(),
                    str(joint7_ok).lower(),
                )
            )
        return overall_ok

    def _post_descend_gripper_verify(self, candidate: Dict[str, Any]) -> bool:
        skip_gap = self._chips_can_skip_gripper_gap_alignment(candidate)
        gap_metrics = None if skip_gap else self._gripper_gap_alignment_metrics(candidate)
        center_metrics = self._compute_gripper_centering_metrics(candidate)
        angle_err = (
            float(gap_metrics["angle_error_deg"])
            if gap_metrics is not None
            else float("inf")
        )
        center_xy = (
            float(center_metrics["error_xy_m"])
            if center_metrics is not None
            else float("inf")
        )
        target_deg = float(self._gripper_gap_verify_target_angle_deg)
        gap_ok = skip_gap or (
            gap_metrics is not None and angle_err <= target_deg
        )
        center_ok = (
            center_metrics is not None
            and self._gripper_centering_within_thresholds(center_metrics)
        )
        ok = bool(gap_ok and center_ok)
        self.get_logger().info(
            "[POST_DESCEND_GRIPPER_VERIFY]\n"
            "angle_error_deg=%.2f\n"
            "center_error_xy_m=%.4f\n"
            "center_error_closing_axis_m=%s\n"
            "target_angle_deg=%.2f\n"
            "result=%s"
            % (
                angle_err,
                center_xy,
                "n/a"
                if center_metrics is None
                else "%.4f"
                % float(center_metrics["error_closing_axis_m"]),
                target_deg,
                "OK" if ok else "FAIL",
            )
        )
        if not ok:
            self.get_logger().error(
                "[POST_DESCEND_GRIPPER_VERIFY] orientación/centrado degradados tras "
                "descenso; no se cierra gripper"
            )
        return ok

    def _lock_lift_orientation_from_current_tf(
        self,
        original_lift_quat: Tuple[float, float, float, float],
    ) -> Optional[Dict[str, Any]]:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        if hand_pose is None:
            self.get_logger().error(
                "[LIFT_ORIENTATION_LOCK] FAIL: no TF for %s in %s"
                % (hand_link, self._planning_frame)
            )
            return None

        hand_pos = hand_pose["position"]
        hand_quat = hand_pose["quat"]
        tcp_pos: Optional[Tuple[float, float, float]] = None
        tcp_quat: Optional[Tuple[float, float, float, float]] = None
        if self._use_grasp_tcp:
            tcp_pose = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if tcp_pose is not None:
                tcp_pos = tcp_pose["position"]
                tcp_quat = tcp_pose["quat"]

        angular_delta = self._quaternion_angle_deg(hand_quat, original_lift_quat)
        self.get_logger().info(
            "[LIFT_ORIENTATION_LOCK]\n"
            "source=current_tf_after_close_and_attach\n"
            "current_hand_position=(%.4f, %.4f, %.4f)\n"
            "current_hand_quat=(%.4f, %.4f, %.4f, %.4f)\n"
            "current_tcp_position=%s\n"
            "current_tcp_quat=%s\n"
            "original_lift_quat=(%.4f, %.4f, %.4f, %.4f)\n"
            "angular_delta_from_original_deg=%.2f\n"
            "lift_use_current_xy_from_tf=%s\n"
            "result=OK"
            % (
                hand_pos[0],
                hand_pos[1],
                hand_pos[2],
                hand_quat[0],
                hand_quat[1],
                hand_quat[2],
                hand_quat[3],
                "n/a"
                if tcp_pos is None
                else "(%.4f, %.4f, %.4f)" % tcp_pos,
                "n/a"
                if tcp_quat is None
                else "(%.4f, %.4f, %.4f, %.4f)" % tcp_quat,
                original_lift_quat[0],
                original_lift_quat[1],
                original_lift_quat[2],
                original_lift_quat[3],
                angular_delta,
                str(self._lift_use_current_xy_from_tf).lower(),
            )
        )
        locked = {
            "current_hand_position": hand_pos,
            "current_hand_quat": hand_quat,
            "current_tcp_position": tcp_pos,
            "current_tcp_quat": tcp_quat,
            "locked_hand_quat": hand_quat,
            "original_lift_quat": original_lift_quat,
            "angular_delta_from_original_deg": angular_delta,
        }
        return locked

    def _build_lift_moveit_goal_locked(
        self,
        orientation_lock: Dict[str, Any],
        legacy_lift_moveit: Tuple[float, float, float],
        use_current_xy: bool,
        lift_distance_m: Optional[float] = None,
    ) -> Tuple[Tuple[float, float, float], Tuple[float, float, float, float]]:
        hand_pos = orientation_lock["current_hand_position"]
        hand_quat = orientation_lock["locked_hand_quat"]
        if use_current_xy:
            lx = float(hand_pos[0])
            ly = float(hand_pos[1])
        else:
            lx = float(legacy_lift_moveit[0])
            ly = float(legacy_lift_moveit[1])
        lift_dist = (
            float(lift_distance_m)
            if lift_distance_m is not None
            else float(self._lift_distance_m)
        )
        lz = float(hand_pos[2]) + lift_dist
        return (
            (lx, ly, lz),
            (
                float(hand_quat[0]),
                float(hand_quat[1]),
                float(hand_quat[2]),
                float(hand_quat[3]),
            ),
        )

    def _cartesian_lift_precheck(
        self,
        orientation_lock: Dict[str, Any],
        lift_hand_goal: Tuple[float, float, float],
        *,
        target_attached: bool,
        locked_orientation_used: bool,
    ) -> bool:
        hand_pos = orientation_lock["current_hand_position"]
        delta_z = float(lift_hand_goal[2]) - float(hand_pos[2])
        ok = bool(locked_orientation_used and delta_z > 1e-4)
        result = "OK" if ok else "FAIL"
        self.get_logger().info(
            "[CARTESIAN_LIFT_PRECHECK]\n"
            "from_current_state=true\n"
            "orientation_source=current_tf_locked\n"
            "locked_orientation_used=%s\n"
            "current_hand=(%.4f, %.4f, %.4f)\n"
            "lift_hand_goal=(%.4f, %.4f, %.4f)\n"
            "delta_z=%.4f\n"
            "lift_distance_m=%.4f\n"
            "target_attached=%s\n"
            "result=%s"
            % (
                str(bool(locked_orientation_used)).lower(),
                float(hand_pos[0]),
                float(hand_pos[1]),
                float(hand_pos[2]),
                float(lift_hand_goal[0]),
                float(lift_hand_goal[1]),
                float(lift_hand_goal[2]),
                delta_z,
                self._lift_distance_m,
                str(bool(target_attached)).lower(),
                result,
            )
        )
        return ok

    def _log_cartesian_lift_plan_fail(
        self,
        *,
        fraction: Optional[float],
        trajectory_points: int,
        motion_pending: bool,
        reason: str,
    ) -> None:
        self.get_logger().error(
            "[CARTESIAN_LIFT_PLAN_FAIL]\n"
            "fraction=%s\n"
            "trajectory_points=%d\n"
            "motion_pending=%s\n"
            "reason=%s\n"
            "result=FAIL"
            % (
                "n/a" if fraction is None else "%.5f" % float(fraction),
                int(trajectory_points),
                str(bool(motion_pending)).lower(),
                str(reason),
            )
        )

    def _log_cartesian_lift_execute(
        self,
        ok: bool,
        *,
        timed_out: bool = False,
        fraction: Optional[float] = None,
        trajectory_points: int = 0,
        execution_requested: bool = False,
        wait_result: bool = False,
        hand_delta_z: Optional[float] = None,
        min_delta_z_required: Optional[float] = None,
    ) -> None:
        final_tcp = self._tcp_position_in_planning_frame()
        if final_tcp is None:
            final_str = "n/a"
        else:
            final_str = "(%.4f, %.4f, %.4f)" % final_tcp
        if fraction is None:
            fraction = self._read_cartesian_fraction()
        self.get_logger().info(
            "[CARTESIAN_LIFT_EXECUTE]\n"
            "result=%s\n"
            "timed_out=%s\n"
            "fraction=%s\n"
            "trajectory_points=%d\n"
            "execution_requested=%s\n"
            "wait_result=%s\n"
            "hand_delta_z=%s\n"
            "min_delta_z_required=%s\n"
            "final_tcp=%s"
            % (
                "OK" if ok else "FAIL",
                str(bool(timed_out)).lower(),
                "n/a" if fraction is None else "%.3f" % float(fraction),
                int(trajectory_points),
                str(bool(execution_requested)).lower(),
                str(bool(wait_result)).lower(),
                "n/a"
                if hand_delta_z is None
                else "%.4f" % float(hand_delta_z),
                "n/a"
                if min_delta_z_required is None
                else "%.4f" % float(min_delta_z_required),
                final_str,
            )
        )

    def _cartesian_lift_micro_step_valid(
        self,
        *,
        fraction: Optional[float],
        trajectory_points: int,
        execution_requested: bool,
        wait_result: bool,
        hand_delta_z: float,
        min_delta_z_required: float,
    ) -> Tuple[bool, str]:
        """Validación estricta solo para micropasos chips_can (plan_async propio)."""
        threshold = float(self._cartesian_fraction_threshold)
        if fraction is None or float(fraction) + 1e-6 < threshold:
            return False, "plan_fraction_below_threshold"
        if int(trajectory_points) < 2:
            return False, "trajectory_empty"
        if not execution_requested:
            return False, "execution_not_requested"
        if not wait_result:
            return False, "wait_until_executed_false"
        if float(hand_delta_z) + 1e-6 < float(min_delta_z_required):
            return False, "hand_delta_z_insufficient"
        return True, "executed"

    def _generic_cartesian_lift_observation_ok(
        self,
        *,
        action_wait_ok: bool,
        hand_delta_z: float,
        min_delta_z_required: float,
        attached_flag: bool,
        orientation_ok: bool,
        motion_pending_after_plan: Optional[bool] = None,
    ) -> bool:
        """
        Lift genérico (cracker_box, sugar_box, mustard_bottle): MoveIt2 a menudo no
        expone fraction/trajectory_points en move_to_pose; validar por ejecución y TF.
        """
        if not bool(attached_flag) or not bool(orientation_ok):
            return False
        if float(hand_delta_z) + 1e-6 >= float(min_delta_z_required):
            return True
        if motion_pending_after_plan is False and not bool(action_wait_ok):
            return False
        return bool(action_wait_ok) and float(hand_delta_z) + 1e-6 >= float(
            min_delta_z_required
        )

    def _plan_and_execute_cartesian_lift_step(
        self,
        stage: str,
        hand_pose: Tuple[float, float, float],
        vel: float,
        acc: float,
        quat: Tuple[float, float, float, float],
        *,
        avoid_collisions: Optional[bool] = None,
        fraction_threshold_override: Optional[float] = None,
    ) -> Tuple[bool, Dict[str, Any]]:
        """Planifica/ejecuta un tramo cartesiano de lift; devuelve (ok, métricas)."""
        metrics: Dict[str, Any] = {
            "fraction": None,
            "trajectory_points": 0,
            "execution_requested": False,
            "wait_result": False,
            "reason": "",
        }
        if self._moveit2 is None:
            metrics["reason"] = "moveit_not_initialized"
            return False, metrics
        if not self._ensure_moveit_idle_before_stage():
            metrics["reason"] = "prior_motion_still_pending"
            return False, metrics
        if self._stop_before_planning:
            try:
                self._moveit2.cancel_execution()
            except Exception:
                pass
        self._moveit2.max_velocity = float(vel)
        self._moveit2.max_acceleration = float(acc)
        if self._set_start_state_to_current_before_planning:
            self._try_set_start_state_to_current()
        avoid_val = (
            bool(avoid_collisions)
            if avoid_collisions is not None
            else bool(self._cartesian_avoid_collisions)
        )
        try:
            self._moveit2.cartesian_avoid_collisions = avoid_val
        except AttributeError:
            pass
        future = self._moveit2.plan_async(
            position=list(hand_pose),
            quat_xyzw=list(quat),
            frame_id=self._planning_frame,
            target_link=self._moveit_target_link,
            cartesian=True,
            max_step=0.0025,
        )
        if future is None:
            metrics["reason"] = "plan_future_none"
            return False, metrics
        plan_timeout = max(3.0, float(self._planning_time) + 3.0)
        t_plan = time.monotonic()
        while not future.done() and time.monotonic() - t_plan < plan_timeout:
            rclpy.spin_once(self, timeout_sec=0.05)
        if not future.done():
            metrics["reason"] = "plan_timeout"
            return False, metrics
        res = future.result()
        traj = None
        fraction_threshold = float(self._cartesian_fraction_threshold)
        if fraction_threshold_override is not None:
            fraction_threshold = float(fraction_threshold_override)
        if res is not None:
            metrics["fraction"] = float(res.fraction)
            try:
                setattr(
                    self._moveit2,
                    "last_cartesian_fraction",
                    float(res.fraction),
                )
            except Exception:
                pass
            if (
                int(res.error_code.val) == int(MoveItErrorCodes.SUCCESS)
                and float(res.fraction) + 1e-6 >= fraction_threshold
                and res.solution is not None
                and res.solution.joint_trajectory is not None
            ):
                traj = res.solution.joint_trajectory
        else:
            metrics["reason"] = "cartesian_null_response"
        metrics["trajectory_points"] = (
            len(traj.points) if traj is not None and traj.points else 0
        )
        if traj is None or metrics["trajectory_points"] < 2:
            metrics["reason"] = metrics["reason"] or "trajectory_empty"
            self._log_cartesian_lift_plan_fail(
                fraction=metrics["fraction"],
                trajectory_points=int(metrics["trajectory_points"]),
                motion_pending=self._moveit2_motion_pending(),
                reason=str(metrics["reason"]),
            )
            return False, metrics
        self._moveit2.execute(traj)
        metrics["execution_requested"] = self._moveit2_motion_pending()
        if not metrics["execution_requested"]:
            metrics["reason"] = "execution_not_requested"
            self._log_cartesian_lift_plan_fail(
                fraction=metrics["fraction"],
                trajectory_points=int(metrics["trajectory_points"]),
                motion_pending=False,
                reason=str(metrics["reason"]),
            )
            return False, metrics
        metrics["wait_result"] = bool(self._moveit2.wait_until_executed())
        if not metrics["wait_result"]:
            metrics["reason"] = "wait_until_executed_false"
            return False, metrics
        metrics["reason"] = "executed"
        return True, metrics

    def _chips_can_lift_policy_enabled(self, candidate: Optional[Dict[str, Any]]) -> bool:
        return bool(
            isinstance(candidate, dict)
            and self._chips_can_lift_relax_collisions
            and self._is_chips_can_cylinder_topdown_candidate(candidate)
        )

    def _chips_can_lift_avoid_collisions_for_step(
        self, candidate: Optional[Dict[str, Any]]
    ) -> Optional[bool]:
        if not self._chips_can_lift_policy_enabled(candidate):
            return None
        return bool(self._chips_can_lift_avoid_collisions)

    def _log_chips_can_lift_policy(
        self,
        candidate: Dict[str, Any],
        *,
        start_hand_z: float,
        target_hand_z: float,
    ) -> None:
        avoid = self._chips_can_lift_avoid_collisions_for_step(candidate)
        self.get_logger().info(
            "[CHIPS_CAN_LIFT_POLICY]\n"
            "label=chips_can\n"
            "strategy=cylinder_topdown\n"
            "mode=cartesian_pure_z_relaxed_collision\n"
            "avoid_collisions=%s\n"
            "reason=attached_contact_lift_expected_collision\n"
            "lift_distance_m=%.4f\n"
            "start_hand_z=%.4f\n"
            "target_hand_z=%.4f\n"
            "micro_step_m=%.4f\n"
            "policy_enabled=true"
            % (
                str(bool(avoid)).lower() if avoid is not None else "global",
                float(self._lift_distance_m),
                float(start_hand_z),
                float(target_hand_z),
                float(self._chips_can_cartesian_lift_max_step_m),
            )
        )

    def _log_chips_can_micro_lift_route_step(
        self,
        *,
        step_idx: int,
        from_hand_z: float,
        to_hand_z: float,
        avoid_collisions: Optional[bool],
        fraction: Optional[float],
        result: str,
        lock_xy: Optional[Tuple[float, float]] = None,
    ) -> None:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_pose = self._link_pose_in_planning_frame(hand_link)
        actual_z = (
            float(hand_pose["position"][2]) if hand_pose is not None else float("nan")
        )
        delta_z = float("nan")
        if hand_pose is not None:
            delta_z = float(actual_z) - float(from_hand_z)
        drift_s = "n/a"
        if hand_pose is not None and lock_xy is not None:
            drift_s = "%.4f" % _chips_xy_drift_m(
                lock_xy,
                (float(hand_pose["position"][0]), float(hand_pose["position"][1])),
            )
        avoid_s = (
            "global"
            if avoid_collisions is None
            else str(bool(avoid_collisions)).lower()
        )
        self.get_logger().info(
            "[CHIPS_CAN_MICRO_LIFT_ROUTE]\n"
            "step_idx=%d\n"
            "from_hand_z=%.4f\n"
            "to_hand_z=%.4f\n"
            "avoid_collisions=%s\n"
            "fraction=%s\n"
            "actual_hand_z_after=%s\n"
            "delta_z=%s\n"
            "xy_drift=%s\n"
            "result=%s"
            % (
                int(step_idx),
                float(from_hand_z),
                float(to_hand_z),
                avoid_s,
                "n/a" if fraction is None else "%.5f" % float(fraction),
                "n/a" if math.isnan(actual_z) else "%.4f" % float(actual_z),
                "n/a" if math.isnan(delta_z) else "%.4f" % float(delta_z),
                drift_s,
                str(result),
            )
        )

    def _chips_can_manual_safety_gate_after_lift_step(
        self,
        candidate: Dict[str, Any],
        *,
        lock_xy: Tuple[float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        z_before: float,
        requested_hand_z: float,
        stage: str,
        min_step_delta_z: float,
    ) -> bool:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_after = self._link_pose_in_planning_frame(hand_link)
        top_down_ok, centering_ok, _gripper_open_ok = (
            self._chips_can_yaw_free_descend_gate_flags(candidate)
        )
        orientation_ok = True
        if hand_after is not None:
            orient_deg = self._quaternion_angle_deg(
                hand_after["quat"], lift_quat_locked
            )
            orientation_ok = orient_deg <= float(
                self._gripper_gap_verify_target_angle_deg
            )
        xy_drift_ok = False
        drift_xy_m = float("nan")
        actual_z = float("nan")
        if hand_after is not None:
            actual_z = float(hand_after["position"][2])
            drift_xy_m = _chips_xy_drift_m(
                lock_xy,
                (float(hand_after["position"][0]), float(hand_after["position"][1])),
            )
            xy_drift_ok = _chips_xy_drift_ok(
                drift_xy_m, float(self._chips_can_descend_max_xy_drift_m)
            )
        progress_m = float(actual_z) - float(z_before) if hand_after is not None else 0.0
        needed_rise = max(0.0, float(requested_hand_z) - float(z_before))
        z_progress_ok = True
        if needed_rise > 1e-4:
            z_progress_ok = progress_m + 1e-6 >= float(min_step_delta_z)
        table_clearance_ok = True
        attached_ok = bool(self._current_target_attached)
        gate_ok = bool(
            xy_drift_ok
            and z_progress_ok
            and orientation_ok
            and centering_ok
            and table_clearance_ok
            and attached_ok
        )
        self.get_logger().info(
            "[CHIPS_CAN_MANUAL_SAFETY_GATE]\n"
            "stage=%s\n"
            "table_clearance_ok=%s\n"
            "xy_drift_ok=%s\n"
            "xy_drift_m=%s\n"
            "z_progress_ok=%s\n"
            "orientation_ok=%s\n"
            "centering_ok=%s\n"
            "attached_flag_ok=%s\n"
            "result=%s"
            % (
                str(stage),
                str(bool(table_clearance_ok)).lower(),
                str(bool(xy_drift_ok)).lower(),
                "n/a" if math.isnan(drift_xy_m) else "%.4f" % float(drift_xy_m),
                str(bool(z_progress_ok)).lower(),
                str(bool(orientation_ok)).lower(),
                str(bool(centering_ok)).lower(),
                str(bool(attached_ok)).lower(),
                "OK" if gate_ok else "FAIL",
            )
        )
        return gate_ok

    def _chips_can_execute_one_lift_micro_step(
        self,
        candidate: Dict[str, Any],
        stage: str,
        *,
        hand_xy: Tuple[float, float],
        requested_hand_z: float,
        lift_quat: Tuple[float, float, float, float],
        lift_vel: float,
        lift_acc: float,
        z_before: float,
        min_step_delta_z: float,
        lock_xy: Tuple[float, float],
        avoid_collisions: Optional[bool],
    ) -> bool:
        hand_goal = (
            float(hand_xy[0]),
            float(hand_xy[1]),
            float(requested_hand_z),
        )
        step_ok, _metrics = self._plan_and_execute_cartesian_lift_step(
            stage,
            hand_goal,
            float(lift_vel),
            float(lift_acc),
            lift_quat,
            avoid_collisions=avoid_collisions,
        )
        if not step_ok:
            return False
        if not self._chips_can_manual_safety_gate_after_lift_step(
            candidate,
            lock_xy=lock_xy,
            lift_quat_locked=lift_quat,
            z_before=float(z_before),
            requested_hand_z=float(requested_hand_z),
            stage=stage,
            min_step_delta_z=float(min_step_delta_z),
        ):
            return False
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        if hand_after is None:
            return False
        actual_z = float(hand_after["position"][2])
        tol = float(self._chips_can_descend_tcp_z_tolerance_m)
        if actual_z + tol < float(requested_hand_z):
            self.get_logger().error(
                "[CHIPS_CAN_LIFT_Z_REACHED] stage=%s result=FAIL "
                "reason=hand_z_below_request actual=%.4f req=%.4f"
                % (stage, actual_z, float(requested_hand_z))
            )
            return False
        return True

    def _execute_chips_can_cartesian_lift(
        self,
        candidate: Dict[str, Any],
        lift_lock: Dict[str, Any],
        lift_hand_goal: Tuple[float, float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        *,
        target_attached: bool,
    ) -> bool:
        if not target_attached or not self._current_target_attached:
            self.get_logger().error(
                "[CHIPS_CAN_LIFT_POLICY] result=FAIL reason=attached_flag_false"
            )
            return False
        hand_pos = lift_lock["current_hand_position"]
        z_start = float(hand_pos[2])
        z_target = float(lift_hand_goal[2])
        if z_target <= z_start + 1e-4:
            self.get_logger().error(
                "[CHIPS_CAN_LIFT_POLICY] result=FAIL reason=non_positive_lift_delta"
            )
            return False
        self._log_chips_can_lift_policy(
            candidate, start_hand_z=z_start, target_hand_z=z_target
        )
        lock_xy = (float(hand_pos[0]), float(hand_pos[1]))
        hand_xy = lock_xy
        avoid = self._chips_can_lift_avoid_collisions_for_step(candidate)
        max_step = float(self._chips_can_cartesian_lift_max_step_m)
        waypoints = build_chips_can_lift_hand_z_waypoints(
            z_start, z_target, max_step_m=max_step, min_step_m=0.010
        )
        min_delta = 0.040
        try:
            min_delta = float(candidate.get("post_lift_min_delta_z_m") or min_delta)
        except (TypeError, ValueError):
            min_delta = 0.040
        min_step_delta = min(
            float(max_step) * 0.5,
            float(min_delta) / max(1, len(waypoints)),
        )
        z_prev = z_start
        for step_idx, z_step in enumerate(waypoints):
            stage = "chips_can_lift_micro_%d" % (step_idx + 1)
            if not self._chips_can_execute_one_lift_micro_step(
                candidate,
                stage,
                hand_xy=hand_xy,
                requested_hand_z=float(z_step),
                lift_quat=lift_quat_locked,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=float(min_step_delta),
                lock_xy=lock_xy,
                avoid_collisions=avoid,
            ):
                self._log_chips_can_micro_lift_route_step(
                    step_idx=step_idx,
                    from_hand_z=z_prev,
                    to_hand_z=float(z_step),
                    avoid_collisions=avoid,
                    fraction=self._read_cartesian_fraction(),
                    result="FAIL",
                    lock_xy=lock_xy,
                )
                return False
            self._log_chips_can_micro_lift_route_step(
                step_idx=step_idx,
                from_hand_z=z_prev,
                to_hand_z=float(z_step),
                avoid_collisions=avoid,
                fraction=self._read_cartesian_fraction(),
                result="OK",
                lock_xy=lock_xy,
            )
            z_prev = float(z_step)
            hand_mid = self._link_pose_in_planning_frame(
                str(self._moveit_target_link or "panda_hand")
            )
            if hand_mid is not None:
                hand_xy = (
                    float(hand_mid["position"][0]),
                    float(hand_mid["position"][1]),
                )
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        hand_delta_z = (
            float(hand_after["position"][2]) - float(z_start)
            if hand_after is not None
            else 0.0
        )
        lift_ok = hand_after is not None and hand_delta_z + 1e-6 >= float(min_delta)
        self._log_cartesian_lift_execute(
            lift_ok,
            fraction=self._read_cartesian_fraction(),
            trajectory_points=2 if lift_ok else 0,
            execution_requested=bool(lift_ok),
            wait_result=bool(lift_ok),
            hand_delta_z=float(hand_delta_z),
            min_delta_z_required=float(min_delta),
        )
        if not lift_ok:
            self.get_logger().error(
                "[CHIPS_CAN_LIFT_POLICY] aggregate result=FAIL reason=hand_delta_z_insufficient "
                "hand_delta_z=%.4f min=%.4f"
                % (float(hand_delta_z), float(min_delta))
            )
        return bool(lift_ok)

    def _sugar_box_lift_policy_enabled(self, candidate: Optional[Dict[str, Any]]) -> bool:
        return bool(
            isinstance(candidate, dict)
            and self._sugar_box_lift_fallback_enabled
            and str(candidate.get("label", "")).strip().lower() == "sugar_box"
        )

    def _mustard_attached_transport_policy_enabled(
        self, candidate: Optional[Dict[str, Any]]
    ) -> bool:
        return self._mustard_lift_policy_enabled(candidate)

    def _mustard_attached_transport_cartesian_overrides(
        self, candidate: Dict[str, Any], stage: str
    ) -> Tuple[Optional[bool], Optional[float]]:
        label = str(candidate.get("label", "")).strip().lower()
        sid = str(candidate.get("scene_id") or self._scene_id or "")
        if stage in ("carry_safe_height", "transport_entry_safe"):
            if label == "sugar_box" and sugar_box_hold_gripper_frozen_after_grasp(
                label=label, scene_id=sid
            ):
                return False, float(self._mustard_transport_cartesian_fraction_threshold)
            if bool(candidate.get("_demo_golden_fast_execute")):
                return True, float(GOLDEN_FAST_CARRY_CARTESIAN_FRACTION)
        if not self._mustard_attached_transport_policy_enabled(candidate):
            return None, None
        if stage not in ("carry_safe_height", "transport_entry_safe"):
            return None, None
        return (
            bool(self._mustard_transport_avoid_collisions),
            float(self._mustard_transport_cartesian_fraction_threshold),
        )

    def _attached_carry_safe_height_joint_fallback_enabled(
        self, candidate: Dict[str, Any]
    ) -> bool:
        if self._mustard_attached_transport_policy_enabled(candidate):
            return True
        if not isinstance(candidate, dict):
            return False
        label = str(candidate.get("label", "")).strip().lower()
        sid = str(candidate.get("scene_id") or self._scene_id or "")
        return self._sugar_box_lift_policy_enabled(candidate) and (
            sugar_box_hold_gripper_frozen_after_grasp(label=label, scene_id=sid)
        )

    def _resolve_attached_transport_locked_quat(
        self,
        fallback_quat: Tuple[float, float, float, float],
    ) -> Tuple[float, float, float, float]:
        transport_lock = self._lock_lift_orientation_from_current_tf(fallback_quat)
        if transport_lock is None:
            return fallback_quat
        locked = transport_lock.get("locked_hand_quat")
        if not isinstance(locked, (list, tuple)) or len(locked) < 4:
            return fallback_quat
        return (
            float(locked[0]),
            float(locked[1]),
            float(locked[2]),
            float(locked[3]),
        )

    def _execute_mustard_carry_safe_height_raise(
        self,
        candidate: Dict[str, Any],
        *,
        current_hand: Tuple[float, float, float],
        target_hand_z: float,
        transport_quat: Tuple[float, float, float, float],
        move_stage: Any,
    ) -> bool:
        raise_pose = (
            float(current_hand[0]),
            float(current_hand[1]),
            float(target_hand_z),
        )
        avoid, frac = self._mustard_attached_transport_cartesian_overrides(
            candidate, "carry_safe_height"
        )
        ok_raise = bool(
            move_stage(
                "carry_safe_height",
                raise_pose,
                self._lift_vel,
                self._lift_acc,
                quat_override=transport_quat,
                avoid_collisions_override=avoid,
                fraction_threshold_override=frac,
            )
        )
        if ok_raise:
            return True
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        z_start = (
            float(hand_after["position"][2])
            if hand_after is not None
            else float(current_hand[2])
        )
        z_target = float(target_hand_z)
        if z_target <= z_start + 0.005:
            return z_target <= z_start + 0.010
        lock_xy = (
            float(hand_after["position"][0]),
            float(hand_after["position"][1]),
        ) if hand_after is not None else (
            float(current_hand[0]),
            float(current_hand[1]),
        )
        self.get_logger().info(
            "[MUSTARD_CARRY_SAFE_HEIGHT_FALLBACK]\n"
            "start_hand_z=%.4f\n"
            "target_hand_z=%.4f\n"
            "result=PENDING"
            % (float(z_start), float(z_target))
        )
        waypoints = _mustard_build_lift_waypoints(
            z_start,
            z_target,
            max_step_m=float(self._mustard_cartesian_lift_max_step_m),
            min_step_m=0.010,
        )
        z_prev = float(z_start)
        hand_xy = lock_xy
        for step_idx, z_step in enumerate(waypoints):
            if not self._mustard_execute_one_lift_micro_step(
                candidate,
                "mustard_carry_safe_height_%d" % (int(step_idx) + 1),
                hand_xy=hand_xy,
                requested_hand_z=float(z_step),
                lift_quat=transport_quat,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=0.015,
                lock_xy=lock_xy,
                avoid_collisions=False,
            ):
                self.get_logger().error(
                    "[MUSTARD_CARRY_SAFE_HEIGHT_FALLBACK] result=FAIL"
                )
                return False
            z_prev, hand_xy = self._sugar_box_sync_hand_state_after_lift_step(
                z_prev, hand_xy
            )
        self.get_logger().info(
            "[MUSTARD_CARRY_SAFE_HEIGHT_FALLBACK]\n"
            "start_hand_z=%.4f\n"
            "after_hand_z=%.4f\n"
            "target_hand_z=%.4f\n"
            "result=OK"
            % (float(z_start), float(z_prev), float(z_target))
        )
        return True

    def _mustard_lift_policy_enabled(self, candidate: Optional[Dict[str, Any]]) -> bool:
        return bool(
            isinstance(candidate, dict)
            and self._mustard_lift_fallback_enabled
            and str(candidate.get("label", "")).strip().lower() == "mustard_bottle"
            and str(candidate.get("grasp_strategy", "")).strip()
            == "tall_object_topdown"
        )

    def _mustard_lift_fallback_prerequisites_ok(
        self, candidate: Dict[str, Any]
    ) -> Tuple[bool, str]:
        if not bool(self._last_grasp_contact_strict_pass):
            return False, "contact_not_ok"
        if not bool(self._current_target_attached):
            return False, "attach_not_ok"
        return True, "ok"

    def _sugar_box_lift_fallback_prerequisites_ok(
        self, candidate: Dict[str, Any]
    ) -> Tuple[bool, str]:
        if not bool(self._last_grasp_contact_strict_pass):
            return False, "contact_not_ok"
        if not bool(self._current_target_attached):
            return False, "attach_not_ok"
        if sugar_box_lift_centering_prerequisite_required(candidate):
            center_metrics = self._compute_gripper_centering_metrics(candidate)
            center_ok = (
                center_metrics is not None
                and self._gripper_centering_within_thresholds(center_metrics)
            )
            if not center_ok:
                return False, "centering_not_ok"
        if sugar_box_lift_gap_prerequisite_required(candidate):
            gap_metrics = self._gripper_gap_alignment_metrics(candidate)
            gap_ok = gap_metrics is not None and float(
                gap_metrics["angle_error_deg"]
            ) <= float(self._gripper_gap_verify_target_angle_deg) + 1e-6
            if not gap_ok:
                return False, "gap_not_ok"
        return True, "ok"

    def _log_sugar_box_micro_lift_route_step(
        self,
        *,
        step_idx: int,
        phase: str,
        from_hand_z: float,
        to_hand_z: float,
        avoid_collisions: bool,
        fraction: Optional[float],
        result: str,
        lock_xy: Tuple[float, float],
    ) -> None:
        hand_pose = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        actual_z = (
            float(hand_pose["position"][2]) if hand_pose is not None else float("nan")
        )
        delta_z = float("nan")
        drift_s = "n/a"
        if hand_pose is not None:
            delta_z = float(actual_z) - float(from_hand_z)
            drift_s = "%.4f" % _chips_xy_drift_m(
                lock_xy,
                (float(hand_pose["position"][0]), float(hand_pose["position"][1])),
            )
        self.get_logger().info(
            "[SUGAR_BOX_MICRO_LIFT_ROUTE]\n"
            "step_idx=%d\n"
            "phase=%s\n"
            "from_hand_z=%.4f\n"
            "to_hand_z=%.4f\n"
            "avoid_collisions=%s\n"
            "fraction=%s\n"
            "actual_hand_z_after=%s\n"
            "delta_z=%s\n"
            "xy_drift=%s\n"
            "result=%s"
            % (
                int(step_idx),
                str(phase),
                float(from_hand_z),
                float(to_hand_z),
                str(bool(avoid_collisions)).lower(),
                "n/a" if fraction is None else "%.5f" % float(fraction),
                "n/a" if math.isnan(actual_z) else "%.4f" % float(actual_z),
                "n/a" if math.isnan(delta_z) else "%.4f" % float(delta_z),
                drift_s,
                str(result),
            )
        )

    def _sugar_box_manual_safety_gate_after_lift_step(
        self,
        candidate: Dict[str, Any],
        *,
        lock_xy: Tuple[float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        z_before: float,
        requested_hand_z: float,
        stage: str,
        min_step_delta_z: float,
    ) -> bool:
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        center_metrics = self._compute_gripper_centering_metrics(candidate)
        centering_ok = (
            center_metrics is not None
            and self._gripper_centering_within_thresholds(center_metrics)
        )
        orientation_ok = True
        if hand_after is not None:
            orient_deg = self._quaternion_angle_deg(
                hand_after["quat"], lift_quat_locked
            )
            orientation_ok = orient_deg <= float(
                self._gripper_gap_verify_target_angle_deg
            )
        xy_drift_ok = False
        drift_xy_m = float("nan")
        actual_z = float("nan")
        if hand_after is not None:
            actual_z = float(hand_after["position"][2])
            drift_xy_m = _chips_xy_drift_m(
                lock_xy,
                (float(hand_after["position"][0]), float(hand_after["position"][1])),
            )
            xy_drift_ok = _chips_xy_drift_ok(
                drift_xy_m, float(sugar_box_lift_xy_drift_tolerance_m())
            )
        progress_m = float(actual_z) - float(z_before) if hand_after is not None else 0.0
        needed_rise = max(0.0, float(requested_hand_z) - float(z_before))
        min_progress_m = float(min_step_delta_z)
        tolerance_m = float(self._sugar_box_lift_z_progress_tolerance_m)
        requested_progress_m = (
            float(needed_rise) if needed_rise > 1e-4 else float(min_progress_m)
        )
        z_progress_ok = True
        if needed_rise > 1e-4:
            z_progress_ok = sugar_box_z_progress_ok(
                progress_m,
                min_progress_m,
                tolerance_m=tolerance_m,
            )
        attached_ok = bool(self._current_target_attached)
        gate_ok = bool(
            xy_drift_ok
            and z_progress_ok
            and orientation_ok
            and centering_ok
            and attached_ok
        )
        self.get_logger().info(
            "[SUGAR_BOX_MANUAL_SAFETY_GATE]\n"
            "stage=%s\n"
            "requested_progress_m=%.4f\n"
            "actual_progress_m=%.4f\n"
            "min_progress_m=%.4f\n"
            "tolerance_m=%.4f\n"
            "z_progress_ok=%s\n"
            "xy_drift_ok=%s\n"
            "xy_drift_m=%s\n"
            "orientation_ok=%s\n"
            "centering_ok=%s\n"
            "attached_flag_ok=%s\n"
            "gripper_opened=false\n"
            "result=%s"
            % (
                str(stage),
                float(requested_progress_m),
                float(progress_m),
                float(min_progress_m),
                float(tolerance_m),
                str(bool(z_progress_ok)).lower(),
                str(bool(xy_drift_ok)).lower(),
                "n/a" if math.isnan(drift_xy_m) else "%.4f" % float(drift_xy_m),
                str(bool(orientation_ok)).lower(),
                str(bool(centering_ok)).lower(),
                str(bool(attached_ok)).lower(),
                "OK" if gate_ok else "FAIL",
            )
        )
        return gate_ok

    def _sugar_box_sync_hand_state_after_lift_step(
        self,
        z_prev: float,
        hand_xy: Tuple[float, float],
    ) -> Tuple[float, Tuple[float, float]]:
        hand_mid = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        if hand_mid is None:
            return float(z_prev), hand_xy
        return (
            float(hand_mid["position"][2]),
            (
                float(hand_mid["position"][0]),
                float(hand_mid["position"][1]),
            ),
        )

    def _sugar_box_execute_one_lift_micro_step(
        self,
        candidate: Dict[str, Any],
        stage: str,
        *,
        hand_xy: Tuple[float, float],
        requested_hand_z: float,
        lift_quat: Tuple[float, float, float, float],
        lift_vel: float,
        lift_acc: float,
        z_before: float,
        min_step_delta_z: float,
        lock_xy: Tuple[float, float],
        avoid_collisions: bool,
    ) -> bool:
        hand_goal = (
            float(hand_xy[0]),
            float(hand_xy[1]),
            float(requested_hand_z),
        )
        step_ok, _metrics = self._plan_and_execute_cartesian_lift_step(
            stage,
            hand_goal,
            float(lift_vel),
            float(lift_acc),
            lift_quat,
            avoid_collisions=avoid_collisions,
        )
        if not step_ok:
            return False
        return self._sugar_box_manual_safety_gate_after_lift_step(
            candidate,
            lock_xy=lock_xy,
            lift_quat_locked=lift_quat,
            z_before=float(z_before),
            requested_hand_z=float(requested_hand_z),
            stage=stage,
            min_step_delta_z=float(min_step_delta_z),
        )

    def _execute_sugar_box_cartesian_lift_fallback(
        self,
        candidate: Dict[str, Any],
        lift_lock: Dict[str, Any],
        lift_hand_goal: Tuple[float, float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        *,
        target_attached: bool,
    ) -> bool:
        prereq_ok, prereq_reason = self._sugar_box_lift_fallback_prerequisites_ok(
            candidate
        )
        self.get_logger().info(
            "[SUGAR_BOX_LIFT_FALLBACK_START]\n"
            "label=sugar_box\n"
            "target_attached=%s\n"
            "contact_ok=%s\n"
            "prerequisites=%s\n"
            "skip_gap_prerequisite=%s\n"
            "skip_centering_prerequisite=%s\n"
            "reason=%s"
            % (
                str(bool(target_attached)).lower(),
                str(bool(self._last_grasp_contact_strict_pass)).lower(),
                "OK" if prereq_ok else "FAIL",
                str(
                    not sugar_box_lift_gap_prerequisite_required(candidate)
                ).lower(),
                str(
                    not sugar_box_lift_centering_prerequisite_required(candidate)
                ).lower(),
                prereq_reason,
            )
        )
        if not prereq_ok or not target_attached:
            self.get_logger().error(
                "[SUGAR_BOX_LIFT_FALLBACK_RESULT] result=FAIL reason=%s"
                % prereq_reason
            )
            return False
        hand_pos = lift_lock["current_hand_position"]
        z_start = float(hand_pos[2])
        z_target = float(lift_hand_goal[2])
        if z_target <= z_start + 1e-4:
            self.get_logger().error(
                "[SUGAR_BOX_LIFT_FALLBACK_RESULT] result=FAIL reason=non_positive_lift_delta"
            )
            return False
        lock_xy = (float(hand_pos[0]), float(hand_pos[1]))
        hand_xy = lock_xy
        micro_rise = float(self._sugar_box_lift_first_micro_rise_m)
        min_micro = float(self._sugar_box_lift_min_micro_progress_m)
        z_micro = min(z_start + micro_rise, z_target)
        avoid = bool(self._sugar_box_lift_avoid_collisions)
        candidate["_sugar_box_lift_fallback_used"] = True
        z_prev = z_start
        step_idx = 0
        if z_micro > z_prev + 1e-4:
            if not self._sugar_box_execute_one_lift_micro_step(
                candidate,
                "sugar_box_lift_micro_initial",
                hand_xy=hand_xy,
                requested_hand_z=float(z_micro),
                lift_quat=lift_quat_locked,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=float(min_micro),
                lock_xy=lock_xy,
                avoid_collisions=False,
            ):
                self._log_sugar_box_micro_lift_route_step(
                    step_idx=0,
                    phase="initial_micro",
                    from_hand_z=z_prev,
                    to_hand_z=float(z_micro),
                    avoid_collisions=False,
                    fraction=self._read_cartesian_fraction(),
                    result="FAIL",
                    lock_xy=lock_xy,
                )
                self.get_logger().error(
                    "[SUGAR_BOX_LIFT_FALLBACK_RESULT] result=FAIL reason=initial_micro_lift_failed"
                )
                return False
            self._log_sugar_box_micro_lift_route_step(
                step_idx=0,
                phase="initial_micro",
                from_hand_z=z_prev,
                to_hand_z=float(z_micro),
                avoid_collisions=False,
                fraction=self._read_cartesian_fraction(),
                result="OK",
                lock_xy=lock_xy,
            )
            z_prev, hand_xy = self._sugar_box_sync_hand_state_after_lift_step(
                z_prev, hand_xy
            )
            step_idx = 1
        max_step = float(self._sugar_box_cartesian_lift_max_step_m)
        waypoints = build_chips_can_lift_hand_z_waypoints(
            z_prev, z_target, max_step_m=max_step, min_step_m=0.010
        )
        min_delta = 0.040
        try:
            min_delta = float(candidate.get("post_lift_min_delta_z_m") or min_delta)
        except (TypeError, ValueError):
            min_delta = 0.040
        min_step_delta = min(
            float(max_step) * 0.5,
            float(min_delta) / max(1, len(waypoints) + 1),
        )
        for z_step in waypoints:
            stage = "sugar_box_lift_micro_%d" % (step_idx + 1)
            if not self._sugar_box_execute_one_lift_micro_step(
                candidate,
                stage,
                hand_xy=hand_xy,
                requested_hand_z=float(z_step),
                lift_quat=lift_quat_locked,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=float(min_step_delta),
                lock_xy=lock_xy,
                avoid_collisions=avoid,
            ):
                self._log_sugar_box_micro_lift_route_step(
                    step_idx=step_idx,
                    phase="segment",
                    from_hand_z=z_prev,
                    to_hand_z=float(z_step),
                    avoid_collisions=avoid,
                    fraction=self._read_cartesian_fraction(),
                    result="FAIL",
                    lock_xy=lock_xy,
                )
                self.get_logger().error(
                    "[SUGAR_BOX_LIFT_FALLBACK_RESULT] result=FAIL reason=segment_lift_failed"
                )
                return False
            self._log_sugar_box_micro_lift_route_step(
                step_idx=step_idx,
                phase="segment",
                from_hand_z=z_prev,
                to_hand_z=float(z_step),
                avoid_collisions=avoid,
                fraction=self._read_cartesian_fraction(),
                result="OK",
                lock_xy=lock_xy,
            )
            z_prev, hand_xy = self._sugar_box_sync_hand_state_after_lift_step(
                z_prev, hand_xy
            )
            step_idx += 1
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        hand_delta_z = (
            float(hand_after["position"][2]) - float(z_start)
            if hand_after is not None
            else 0.0
        )
        lift_ok = hand_after is not None and hand_delta_z + 1e-6 >= float(min_delta)
        self._log_cartesian_lift_execute(
            lift_ok,
            fraction=self._read_cartesian_fraction(),
            trajectory_points=2 if lift_ok else 0,
            execution_requested=bool(lift_ok),
            wait_result=bool(lift_ok),
            hand_delta_z=float(hand_delta_z),
            min_delta_z_required=float(min_delta),
        )
        self.get_logger().info(
            "[SUGAR_BOX_LIFT_FALLBACK_RESULT]\n"
            "hand_delta_z=%.4f\n"
            "min_delta_z_required=%.4f\n"
            "result=%s"
            % (
                float(hand_delta_z),
                float(min_delta),
                "OK" if lift_ok else "FAIL",
            )
        )
        return bool(lift_ok)

    def _mustard_lift_hand_delta_from(self, z_start: float) -> float:
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        if hand_after is None:
            return 0.0
        return float(hand_after["position"][2]) - float(z_start)

    def _mustard_execute_one_lift_micro_step(
        self,
        candidate: Dict[str, Any],
        stage: str,
        *,
        hand_xy: Tuple[float, float],
        requested_hand_z: float,
        lift_quat: Tuple[float, float, float, float],
        lift_vel: float,
        lift_acc: float,
        z_before: float,
        min_step_delta_z: float,
        lock_xy: Tuple[float, float],
        avoid_collisions: bool,
    ) -> bool:
        hand_goal = (
            float(hand_xy[0]),
            float(hand_xy[1]),
            float(requested_hand_z),
        )
        step_ok = False
        attempts = (
            (
                bool(avoid_collisions),
                float(self._mustard_lift_cartesian_fraction_threshold),
            ),
            (
                False,
                float(self._mustard_lift_cartesian_retry_fraction_threshold),
            ),
        )
        for attempt_idx, (avoid, frac_thr) in enumerate(attempts):
            step_ok, _metrics = self._plan_and_execute_cartesian_lift_step(
                stage if attempt_idx == 0 else "%s_retry%d" % (stage, attempt_idx),
                hand_goal,
                float(lift_vel),
                float(lift_acc),
                lift_quat,
                avoid_collisions=avoid,
                fraction_threshold_override=frac_thr,
            )
            if step_ok:
                break
        if not step_ok:
            rise_m = max(0.0, float(requested_hand_z) - float(z_before))
            rise_m = min(float(rise_m), float(self._mustard_cartesian_lift_max_step_m))
            if rise_m > 0.004 and self._safe_joint_retreat_vertical_from_current(
                lift_quat,
                rise_m=float(rise_m),
                candidate=candidate,
            ):
                self.get_logger().info(
                    "[MUSTARD_LIFT_JOINT_FALLBACK]\n"
                    "stage=%s\n"
                    "rise_m=%.4f\n"
                    "result=OK"
                    % (str(stage), float(rise_m))
                )
                step_ok = True
        if not step_ok:
            return False
        return self._mustard_manual_safety_gate_after_lift_step(
            candidate,
            lock_xy=lock_xy,
            lift_quat_locked=lift_quat,
            z_before=float(z_before),
            requested_hand_z=float(requested_hand_z),
            stage=stage,
            min_step_delta_z=float(min_step_delta_z),
        )

    def _mustard_manual_safety_gate_after_lift_step(
        self,
        candidate: Dict[str, Any],
        *,
        lock_xy: Tuple[float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        z_before: float,
        requested_hand_z: float,
        stage: str,
        min_step_delta_z: float,
    ) -> bool:
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        center_metrics = self._compute_gripper_centering_metrics(candidate)
        centering_ok = (
            center_metrics is not None
            and self._gripper_centering_within_thresholds(center_metrics)
        )
        orientation_ok = True
        if hand_after is not None:
            orient_deg = self._quaternion_angle_deg(
                hand_after["quat"], lift_quat_locked
            )
            orientation_ok = orient_deg <= float(
                self._gripper_gap_verify_target_angle_deg
            )
        xy_drift_ok = False
        drift_xy_m = float("nan")
        actual_z = float("nan")
        if hand_after is not None:
            actual_z = float(hand_after["position"][2])
            drift_xy_m = _chips_xy_drift_m(
                lock_xy,
                (float(hand_after["position"][0]), float(hand_after["position"][1])),
            )
            xy_drift_ok = _chips_xy_drift_ok(
                drift_xy_m, float(mustard_lift_xy_drift_tolerance_m())
            )
        progress_m = float(actual_z) - float(z_before) if hand_after is not None else 0.0
        needed_rise = max(0.0, float(requested_hand_z) - float(z_before))
        min_progress_m = float(min_step_delta_z)
        tolerance_m = float(self._mustard_lift_z_progress_tolerance_m)
        requested_progress_m = (
            float(needed_rise) if needed_rise > 1e-4 else float(min_progress_m)
        )
        z_progress_ok = True
        if needed_rise > 1e-4:
            z_progress_ok = sugar_box_z_progress_ok(
                progress_m,
                min_progress_m,
                tolerance_m=tolerance_m,
            )
        attached_ok = bool(self._current_target_attached)
        relaxed = mustard_operational_lift_relaxed_safety(candidate)
        gate_ok = bool(
            xy_drift_ok
            and z_progress_ok
            and orientation_ok
            and attached_ok
            and (centering_ok or relaxed)
        )
        if relaxed and hand_after is not None and progress_m > 0.002 and attached_ok:
            if not gate_ok:
                self.get_logger().warning(
                    "[MUSTARD_MANUAL_SAFETY_GATE] warn_only operational_pick; "
                    "continuing lift (stage=%s progress_m=%.4f)"
                    % (str(stage), float(progress_m))
                )
            gate_ok = True
        self.get_logger().info(
            "[MUSTARD_MANUAL_SAFETY_GATE]\n"
            "stage=%s\n"
            "requested_progress_m=%.4f\n"
            "actual_progress_m=%.4f\n"
            "min_progress_m=%.4f\n"
            "tolerance_m=%.4f\n"
            "z_progress_ok=%s\n"
            "xy_drift_ok=%s\n"
            "xy_drift_m=%s\n"
            "orientation_ok=%s\n"
            "centering_ok=%s\n"
            "attached_flag_ok=%s\n"
            "result=%s"
            % (
                str(stage),
                float(requested_progress_m),
                float(progress_m),
                float(min_progress_m),
                float(tolerance_m),
                str(bool(z_progress_ok)).lower(),
                str(bool(xy_drift_ok)).lower(),
                "n/a" if math.isnan(drift_xy_m) else "%.4f" % float(drift_xy_m),
                str(bool(orientation_ok)).lower(),
                str(bool(centering_ok)).lower(),
                str(bool(attached_ok)).lower(),
                "OK" if gate_ok else "FAIL",
            )
        )
        return gate_ok

    def _execute_mustard_cartesian_lift_fallback(
        self,
        candidate: Dict[str, Any],
        lift_lock: Dict[str, Any],
        lift_hand_goal: Tuple[float, float, float],
        lift_quat_locked: Tuple[float, float, float, float],
        *,
        target_attached: bool,
    ) -> bool:
        prereq_ok, prereq_reason = self._mustard_lift_fallback_prerequisites_ok(
            candidate
        )
        self.get_logger().info(
            "[MUSTARD_LIFT_FALLBACK_START]\n"
            "label=mustard_bottle\n"
            "target_attached=%s\n"
            "contact_ok=%s\n"
            "prerequisites=%s\n"
            "reason=%s"
            % (
                str(bool(target_attached)).lower(),
                str(bool(self._last_grasp_contact_strict_pass)).lower(),
                "OK" if prereq_ok else "FAIL",
                prereq_reason,
            )
        )
        if not prereq_ok or not target_attached:
            self.get_logger().error(
                "[MUSTARD_LIFT_FALLBACK_RESULT] result=FAIL reason=%s"
                % prereq_reason
            )
            return False
        hand_pos = lift_lock["current_hand_position"]
        z_start = float(hand_pos[2])
        z_target = float(lift_hand_goal[2])
        if z_target <= z_start + 1e-4:
            self.get_logger().error(
                "[MUSTARD_LIFT_FALLBACK_RESULT] result=FAIL reason=non_positive_lift_delta"
            )
            return False
        lock_xy = (float(hand_pos[0]), float(hand_pos[1]))
        hand_xy = lock_xy
        micro_rise = float(self._mustard_lift_first_micro_rise_m)
        min_micro = float(self._mustard_lift_min_micro_progress_m)
        z_micro = min(z_start + micro_rise, z_target)
        avoid = bool(self._mustard_lift_avoid_collisions)
        candidate["_mustard_lift_fallback_used"] = True
        z_prev = z_start
        step_idx = 0
        if z_micro > z_prev + 1e-4:
            if not self._mustard_execute_one_lift_micro_step(
                candidate,
                "mustard_lift_micro_initial",
                hand_xy=hand_xy,
                requested_hand_z=float(z_micro),
                lift_quat=lift_quat_locked,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=float(min_micro),
                lock_xy=lock_xy,
                avoid_collisions=False,
            ):
                self.get_logger().error(
                    "[MUSTARD_LIFT_FALLBACK_RESULT] result=FAIL reason=initial_micro_lift_failed"
                )
                return False
            z_prev, hand_xy = self._sugar_box_sync_hand_state_after_lift_step(
                z_prev, hand_xy
            )
            step_idx = 1
        max_step = float(self._mustard_cartesian_lift_max_step_m)
        waypoints = _mustard_build_lift_waypoints(
            z_prev, z_target, max_step_m=max_step, min_step_m=0.010
        )
        min_delta = 0.040
        try:
            min_delta = float(candidate.get("post_lift_min_delta_z_m") or min_delta)
        except (TypeError, ValueError):
            min_delta = 0.040
        min_step_delta = min(
            float(max_step) * 0.5,
            float(min_delta) / max(1, len(waypoints) + 1),
        )
        for z_step in waypoints:
            stage = "mustard_lift_micro_%d" % (step_idx + 1)
            if not self._mustard_execute_one_lift_micro_step(
                candidate,
                stage,
                hand_xy=hand_xy,
                requested_hand_z=float(z_step),
                lift_quat=lift_quat_locked,
                lift_vel=float(self._lift_vel),
                lift_acc=float(self._lift_acc),
                z_before=float(z_prev),
                min_step_delta_z=float(min_step_delta),
                lock_xy=lock_xy,
                avoid_collisions=avoid,
            ):
                hand_delta_z = self._mustard_lift_hand_delta_from(z_start)
                if (
                    mustard_operational_lift_relaxed_safety(candidate)
                    and hand_delta_z + 1e-6 >= float(min_delta)
                ):
                    self.get_logger().warning(
                        "[MUSTARD_LIFT_FALLBACK] segment=%s failed but aggregate "
                        "hand_delta_z=%.4f >= min=%.4f; accepting lift"
                        % (stage, float(hand_delta_z), float(min_delta))
                    )
                    break
                self.get_logger().error(
                    "[MUSTARD_LIFT_FALLBACK_RESULT] result=FAIL reason=segment_lift_failed"
                )
                return False
            z_prev, hand_xy = self._sugar_box_sync_hand_state_after_lift_step(
                z_prev, hand_xy
            )
            step_idx += 1
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        hand_delta_z = (
            float(hand_after["position"][2]) - float(z_start)
            if hand_after is not None
            else 0.0
        )
        lift_ok = hand_after is not None and hand_delta_z + 1e-6 >= float(min_delta)
        self._log_cartesian_lift_execute(
            lift_ok,
            fraction=self._read_cartesian_fraction(),
            trajectory_points=2 if lift_ok else 0,
            execution_requested=bool(lift_ok),
            wait_result=bool(lift_ok),
            hand_delta_z=float(hand_delta_z),
            min_delta_z_required=float(min_delta),
        )
        self.get_logger().info(
            "[MUSTARD_LIFT_FALLBACK_RESULT]\n"
            "hand_delta_z=%.4f\n"
            "min_delta_z_required=%.4f\n"
            "avoid_collisions=%s\n"
            "result=%s"
            % (
                float(hand_delta_z),
                float(min_delta),
                str(bool(avoid)).lower(),
                "OK" if lift_ok else "FAIL",
            )
        )
        return bool(lift_ok)

    def _safe_micro_retreat_vertical_from_current_tf(
        self,
        quat: Tuple[float, float, float, float],
        *,
        rise_m: float = 0.06,
    ) -> bool:
        """Subida corta desde TF actual antes de retreat/HOME (postura baja)."""
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_now = self._link_pose_in_planning_frame(hand_link)
        if hand_now is None or self._moveit2 is None:
            return False
        z0 = float(hand_now["position"][2])
        hand_quat = (
            float(hand_now["quat"][0]),
            float(hand_now["quat"][1]),
            float(hand_now["quat"][2]),
            float(hand_now["quat"][3]),
        )
        goal = (
            float(hand_now["position"][0]),
            float(hand_now["position"][1]),
            float(z0) + float(rise_m),
        )
        ok, _metrics = self._plan_and_execute_cartesian_lift_step(
            "safe_micro_retreat_vertical",
            goal,
            float(self._lift_vel),
            float(self._lift_acc),
            hand_quat,
            avoid_collisions=False,
        )
        hand_after = self._link_pose_in_planning_frame(hand_link)
        progress = (
            float(hand_after["position"][2]) - z0 if hand_after is not None else 0.0
        )
        self.get_logger().info(
            "[SAFE_MICRO_RETREAT_VERTICAL]\n"
            "rise_requested_m=%.4f\n"
            "hand_delta_z=%.4f\n"
            "avoid_collisions=false\n"
            "result=%s"
            % (float(rise_m), float(progress), "OK" if ok else "FAIL")
        )
        return bool(ok) and progress + 1e-6 >= 0.03

    def _safe_joint_retreat_vertical_from_current(
        self,
        quat: Tuple[float, float, float, float],
        *,
        rise_m: float = 0.10,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> bool:
        """Retiro vertical por IK→joint goal (evita OMPL pregrasp desde pose baja)."""
        start_js = self._current_arm_joint_state()
        if start_js is None or self._moveit2 is None:
            return False
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_now = self._link_pose_in_planning_frame(hand_link)
        if hand_now is None:
            return False
        z0 = float(hand_now["position"][2])
        hand_quat = (
            float(hand_now["quat"][0]),
            float(hand_now["quat"][1]),
            float(hand_now["quat"][2]),
            float(hand_now["quat"][3]),
        )
        target_hand = (
            float(hand_now["position"][0]),
            float(hand_now["position"][1]),
            float(z0) + float(rise_m),
        )
        ik_sol = None
        try:
            ik_sol = self._moveit2.compute_ik(
                position=list(target_hand),
                quat_xyzw=list(hand_quat),
                ik_link_name=hand_link,
                start_joint_state=start_js,
                wait_for_server_timeout_sec=1.5,
            )
        except Exception:
            ik_sol = None
        if ik_sol is None and self._use_grasp_tcp:
            try:
                tcp_now = self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            except Exception:
                tcp_now = None
            if tcp_now is not None:
                target_tcp = (
                    float(tcp_now["position"][0]),
                    float(tcp_now["position"][1]),
                    float(tcp_now["position"][2]) + float(rise_m),
                )
                ik_sol = self._try_compute_ik_grasp_tcp(
                    target_tcp, quat, start_js, candidate=candidate
                )
        if ik_sol is None:
            self.get_logger().warning(
                "[SAFE_JOINT_RETREAT_VERTICAL]\n"
                "rise_requested_m=%.4f\n"
                "result=FAIL\n"
                "reason=no_ik_for_vertical_retreat"
                % float(rise_m)
            )
            return False
        goal_pos = self._arm_positions_from_joint_state(ik_sol)
        start_pos = self._arm_positions_from_joint_state(start_js)
        max_delta = max(
            abs(float(g) - float(s)) for g, s in zip(goal_pos, start_pos)
        )
        motion_t = max(0.8, min(2.5, 0.6 + 1.2 * float(max_delta)))
        ok = self._move_arm_to_joint_positions(goal_pos, motion_time_sec=motion_t)
        hand_after = self._link_pose_in_planning_frame(hand_link)
        progress = (
            float(hand_after["position"][2]) - z0 if hand_after is not None else 0.0
        )
        self.get_logger().info(
            "[SAFE_JOINT_RETREAT_VERTICAL]\n"
            "rise_requested_m=%.4f\n"
            "hand_delta_z=%.4f\n"
            "motion_time_sec=%.2f\n"
            "result=%s"
            % (
                float(rise_m),
                float(progress),
                float(motion_t),
                "OK" if ok and progress + 1e-6 >= 0.04 else "FAIL",
            )
        )
        return bool(ok) and progress + 1e-6 >= 0.04

    def _moveit2_motion_pending(self) -> bool:
        if self._moveit2 is None:
            return False
        return bool(
            getattr(self._moveit2, "_MoveIt2__is_motion_requested", False)
            or getattr(self._moveit2, "_MoveIt2__is_executing", False)
        )

    def _wait_cartesian_lift_executed(self) -> Tuple[bool, bool]:
        """Espera ejecución MoveIt del lift con timeout. Devuelve (ok, timed_out)."""
        if self._moveit2 is None:
            return False, False
        timeout_sec = float(self._cartesian_lift_wait_timeout_sec)
        self.get_logger().info(
            "[CARTESIAN_LIFT_ACTION_GOAL_SENT]\n"
            "timeout_sec=%.1f"
            % timeout_sec
        )
        t0 = time.monotonic()
        timed_out = False
        motion_started = False
        while self._moveit2_motion_pending():
            motion_started = True
            if time.monotonic() - t0 > timeout_sec:
                timed_out = True
                try:
                    self._moveit2.cancel_execution()
                except Exception:
                    pass
                break
            rclpy.spin_once(self, timeout_sec=0.05)
        if not motion_started:
            self.get_logger().error(
                "[CARTESIAN_LIFT_ACTION_RESULT]\n"
                "result=FAIL\n"
                "reason=lift_motion_not_started\n"
                "elapsed_sec=%.2f"
                % (time.monotonic() - t0)
            )
            return False, False
        ok = bool(getattr(self._moveit2, "motion_suceeded", False)) and not timed_out
        self.get_logger().info(
            "[CARTESIAN_LIFT_ACTION_RESULT]\n"
            "result=%s\n"
            "elapsed_sec=%.2f"
            % ("OK" if ok else "FAIL", time.monotonic() - t0)
        )
        if timed_out:
            self.get_logger().error(
                "[CARTESIAN_LIFT_TIMEOUT]\n"
                "timeout_sec=%.1f\n"
                "result=FAIL"
                % timeout_sec
            )
        return ok, timed_out

    def _mustard_operational_lift_relaxed_for(
        self, candidate: Optional[Dict[str, Any]] = None
    ) -> bool:
        c: Dict[str, Any] = dict(candidate or {})
        if not str(c.get("label") or "").strip():
            c["label"] = str(getattr(self, "_target_label", "") or "")
        if not str(c.get("scene_id") or "").strip():
            c["scene_id"] = str(getattr(self, "_scene_id", "") or "")
        return mustard_operational_lift_relaxed_safety(c)

    def _post_lift_verify(
        self,
        lift_lock_before: Dict[str, Any],
        lift_quat_locked: Tuple[float, float, float, float],
        attached_object_id: Optional[str],
        candidate: Optional[Dict[str, Any]] = None,
    ) -> bool:
        effective_attached_object_id = str(
            attached_object_id or self._current_attached_object_id or ""
        ).strip()
        object_entity = self._resolve_target_entity_name(candidate)
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        tcp_after = (
            self._link_pose_in_planning_frame(self._grasp_tcp_frame)
            if self._use_grasp_tcp
            else None
        )
        pos_before = lift_lock_before["current_hand_position"]
        orient_deg = float("inf")
        delta_z = float("nan")
        if hand_after is not None:
            pos_after = hand_after["position"]
            delta_z = float(pos_after[2]) - float(pos_before[2])
            orient_deg = self._quaternion_angle_deg(
                hand_after["quat"], lift_quat_locked
            )
        target_deg = float(self._gripper_gap_verify_target_angle_deg)
        min_delta = 0.040
        if isinstance(candidate, dict):
            try:
                min_delta = float(candidate.get("post_lift_min_delta_z_m") or min_delta)
            except (TypeError, ValueError):
                min_delta = 0.040
        attached_flag = bool(self._current_target_attached)
        mustard_topdown = (
            isinstance(candidate, dict)
            and mustard_requires_gazebo_lift_verification(candidate)
        )
        ok = (
            hand_after is not None
            and delta_z > float(min_delta)
            and orient_deg <= target_deg
            and attached_flag
        )
        follower_active = self._gazebo_attach_mode == "continuous_set_pose_follow"
        object_z_before = (
            float(self._last_known_object_z_before_lift)
            if self._last_known_object_z_before_lift is not None
            else float("nan")
        )
        semantic_z_before = (
            float(self._last_known_semantic_center_z_before_lift)
            if self._last_known_semantic_center_z_before_lift is not None
            else float("nan")
        )
        desired_z_before = (
            float(self._last_known_desired_origin_z_before_lift)
            if self._last_known_desired_origin_z_before_lift is not None
            else float("nan")
        )
        object_z_source = "post_attach_cache"
        track_after = self._gazebo_verify_set_pose_tracking(
            object_entity, candidate=candidate, collect_sec=0.20
        )
        object_z_after = float(track_after.get("readback_origin_z", float("nan")))
        if math.isnan(object_z_after) and object_entity:
            pose_after = self._sample_gazebo_entity_pose(
                object_entity, collect_sec=0.45
            )
            if pose_after is not None:
                object_z_after = float(pose_after[2])
                object_z_source = "post_lift_pose_readback"
        semantic_z_after = float(track_after.get("semantic_center_z", float("nan")))
        desired_z_after = float(track_after.get("desired_origin_z", float("nan")))
        tracking_error_after = float(track_after.get("tracking_error_z", float("nan")))
        object_delta_z = float("nan")
        semantic_delta_z = float("nan")
        desired_delta_z = float("nan")
        if not math.isnan(object_z_before) and not math.isnan(object_z_after):
            object_delta_z = float(object_z_after - object_z_before)
        if not math.isnan(semantic_z_before) and not math.isnan(semantic_z_after):
            semantic_delta_z = float(semantic_z_after - semantic_z_before)
        if not math.isnan(desired_z_before) and not math.isnan(desired_z_after):
            desired_delta_z = float(desired_z_after - desired_z_before)
        readback_available = not math.isnan(object_z_after)
        min_object_delta = float(min_delta)
        object_pose_ok = (
            not math.isnan(object_delta_z) and object_delta_z >= min_object_delta
        )
        semantic_pose_ok = (
            not math.isnan(semantic_delta_z)
            and semantic_delta_z >= min_object_delta
        )
        desired_pose_ok = (
            not math.isnan(desired_delta_z)
            and desired_delta_z >= min_object_delta * 0.85
        )
        tracking_ok_after = bool(track_after.get("ok"))
        hand_lift_ok = hand_after is not None and delta_z >= float(min_delta)
        mustard_needs_gz_lift = bool(
            mustard_topdown and mustard_requires_gazebo_lift_verification(candidate)
        )
        mustard_op_lift = bool(
            isinstance(candidate, dict)
            and str(candidate.get("label", "")).strip().lower() == "mustard_bottle"
            and self._mustard_operational_lift_relaxed_for(candidate)
        )
        if follower_active and hand_lift_ok and tracking_ok_after:
            if mustard_needs_gz_lift and not (
                object_pose_ok or semantic_pose_ok or desired_pose_ok
            ):
                verify_reason = "mustard_follower_tracking_without_object_lift"
                verify_result = "FAIL"
                ok = False
            else:
                verify_reason = "follower_hand_lift_and_set_pose_tracking_ok"
                verify_result = "OK"
        elif semantic_pose_ok or object_pose_ok or desired_pose_ok:
            verify_reason = (
                "semantic_center_lifted"
                if semantic_pose_ok
                else (
                    "desired_origin_lifted"
                    if desired_pose_ok
                    else "object_origin_lifted"
                )
            )
            verify_result = "OK"
        elif follower_active and hand_lift_ok:
            if mustard_needs_gz_lift:
                verify_reason = "mustard_physical_lift_not_verified"
                verify_result = "FAIL"
                ok = False
            else:
                verify_reason = "follower_active_hand_lift_readback_inconclusive"
                verify_result = "OK"
        elif hand_lift_ok and not readback_available:
            if mustard_topdown and not follower_active:
                verify_reason = "mustard_physical_lift_not_verified"
                verify_result = "FAIL"
                ok = False
            else:
                verify_reason = "hand_lift_ok_gazebo_readback_unavailable"
                verify_result = "VERIFY_UNAVAILABLE"
        elif hand_after is None or abs(float(delta_z)) < 1e-4:
            verify_reason = "lift_motion_not_executed"
            verify_result = "FAIL"
            ok = False
        elif not hand_lift_ok:
            verify_reason = "lift_no_hand_progress"
            verify_result = "FAIL"
            ok = False
        else:
            verify_reason = "object_did_not_follow_gripper"
            verify_result = "FAIL"
            ok = False
        if verify_result == "OK":
            ok = bool(
                hand_lift_ok
                and orient_deg <= target_deg
                and attached_flag
            )
        elif verify_result == "VERIFY_UNAVAILABLE" and hand_lift_ok and attached_flag:
            if mustard_topdown and not follower_active:
                ok = False
                verify_result = "FAIL"
                verify_reason = "mustard_physical_lift_not_verified"
            else:
                ok = True
        if mustard_needs_gz_lift or mustard_op_lift:
            friction_ok, friction_reason = evaluate_mustard_friction_lift_verify(
                hand_lift_ok=bool(hand_lift_ok),
                attached_flag=bool(attached_flag),
                contact_strict_pass=bool(self._last_grasp_contact_strict_pass),
                orient_ok=bool(orient_deg <= target_deg),
                object_delta_z=float(object_delta_z),
                hand_delta_z=float(delta_z) if not math.isnan(delta_z) else float("nan"),
                min_delta=float(min_delta),
                readback_available=bool(readback_available),
            )
            if friction_ok:
                ok = True
                verify_result = "OK"
                verify_reason = friction_reason
            elif (
                mustard_op_lift
                and not readback_available
                and hand_lift_ok
                and attached_flag
                and orient_deg <= target_deg
                and bool(self._last_grasp_contact_strict_pass)
            ):
                ok = True
                verify_result = "OK"
                verify_reason = "mustard_operational_hand_lift_proxy_ok"
            else:
                ok = False
                verify_result = "FAIL"
                verify_reason = friction_reason
        self.get_logger().info(
            "[POST_LIFT_VERIFY_INPUT]\n"
            "attached_object_id=%s\n"
            "target_attached=%s\n"
            "gazebo_lift_verify_result=%s\n"
            "lift_delta_z_observed=%.4f\n"
            "orientation_preserved_deg=%.2f"
            % (
                effective_attached_object_id or "n/a",
                str(bool(self._current_target_attached)).lower(),
                verify_result,
                delta_z,
                orient_deg,
            )
        )
        self.get_logger().info(
            "[GAZEBO_OBJECT_LIFT_VERIFY]\n"
            "label=%s\n"
            "entity_name=%s\n"
            "object_z_before_lift=%s\n"
            "object_z_before_source=%s\n"
            "semantic_z_before_lift=%s\n"
            "desired_origin_z_before_lift=%s\n"
            "object_z_after_lift=%s\n"
            "semantic_z_after_lift=%s\n"
            "desired_origin_z_after_lift=%s\n"
            "delta_object_z=%s\n"
            "delta_semantic_z=%s\n"
            "delta_desired_origin_z=%s\n"
            "set_pose_tracking_error_after=%s\n"
            "hand_delta_z=%s\n"
            "follower_active=%s\n"
            "tcp_z_before_lift=%s\n"
            "tcp_z_after_lift=%s\n"
            "attached_flag=%s\n"
            "min_delta_z_required=%.4f\n"
            "result=%s\n"
            "reason=%s"
            % (
                "n/a" if not isinstance(candidate, dict) else str(candidate.get("label", "")),
                object_entity or "n/a",
                "n/a" if math.isnan(object_z_before) else "%.4f" % object_z_before,
                object_z_source,
                "n/a" if math.isnan(semantic_z_before) else "%.4f" % semantic_z_before,
                "n/a" if math.isnan(desired_z_before) else "%.4f" % desired_z_before,
                "n/a" if math.isnan(object_z_after) else "%.4f" % object_z_after,
                "n/a" if math.isnan(semantic_z_after) else "%.4f" % semantic_z_after,
                "n/a" if math.isnan(desired_z_after) else "%.4f" % desired_z_after,
                "n/a" if math.isnan(object_delta_z) else "%.4f" % object_delta_z,
                "n/a" if math.isnan(semantic_delta_z) else "%.4f" % semantic_delta_z,
                "n/a" if math.isnan(desired_delta_z) else "%.4f" % desired_delta_z,
                "n/a"
                if math.isnan(tracking_error_after)
                else "%.4f" % tracking_error_after,
                "n/a" if math.isnan(delta_z) else "%.4f" % delta_z,
                str(follower_active).lower(),
                "n/a" if hand_after is None else "%.4f" % float(pos_before[2]),
                "n/a"
                if hand_after is None
                else "%.4f" % float(hand_after["position"][2]),
                str(attached_flag).lower(),
                float(min_delta),
                verify_result,
                verify_reason,
            )
        )
        self.get_logger().info(
            "[POST_LIFT_VERIFY]\n"
            "current_hand_position=%s\n"
            "current_tcp_position=%s\n"
            "lift_delta_z_observed=%.4f\n"
            "orientation_preserved_deg=%.2f\n"
            "target_angle_deg=%.2f\n"
            "attached_object_id=%s\n"
            "target_attached=%s\n"
            "result=%s"
            % (
                "n/a"
                if hand_after is None
                else "(%.4f, %.4f, %.4f)" % hand_after["position"],
                "n/a"
                if tcp_after is None
                else "(%.4f, %.4f, %.4f)" % tcp_after["position"],
                delta_z,
                orient_deg,
                target_deg,
                effective_attached_object_id or "n/a",
                str(bool(self._current_target_attached)).lower(),
                "OK" if ok else ("VERIFY_UNAVAILABLE" if verify_result == "VERIFY_UNAVAILABLE" else "FAIL"),
            )
        )
        if verify_result == "VERIFY_UNAVAILABLE" and ok:
            self.get_logger().warn(
                "[POST_LIFT_VERIFY] readback Gazebo intermitente; se acepta por ΔZ TCP y follower=%s."
                % self._gazebo_attach_mode
            )
        elif not ok:
            self.get_logger().error(
                "[POST_LIFT_VERIFY] lift no preservó orientación o ΔZ insuficiente"
            )
        return ok

    def _execute_pick_lift_stage(
        self,
        lift_moveit: Tuple[float, float, float],
        original_quat: Tuple[float, float, float, float],
        move_stage_fn: Any,
        *,
        target_attached: bool,
        attached_object_id: Optional[str],
        candidate: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if not self._lock_lift_orientation_to_current_tf:
            lift_ok = bool(
                move_stage_fn(
                    "lift",
                    lift_moveit,
                    self._lift_vel,
                    self._lift_acc,
                    quat_override=original_quat,
                )
            )
            if lift_ok:
                self._log_cartesian_lift_execute(lift_ok)
            return lift_ok

        lift_lock = self._lock_lift_orientation_from_current_tf(original_quat)
        if lift_lock is None:
            if self._lock_lift_orientation_allow_legacy_on_tf_fail:
                self.get_logger().warning(
                    "[LIFT_ORIENTATION_LOCK] TF FAIL; legacy lift con quat planificada"
                )
                lift_ok = bool(
                    move_stage_fn(
                        "lift",
                        lift_moveit,
                        self._lift_vel,
                        self._lift_acc,
                        quat_override=original_quat,
                    )
                )
                if lift_ok:
                    self._log_cartesian_lift_execute(lift_ok)
                return lift_ok
            return False

        lift_dist = self._resolve_pick_lift_m_for_candidate(candidate)
        lift_hand_goal, lift_quat_locked = self._build_lift_moveit_goal_locked(
            lift_lock,
            lift_moveit,
            bool(self._lift_use_current_xy_from_tf),
            lift_distance_m=lift_dist,
        )
        if not self._cartesian_lift_precheck(
            lift_lock,
            lift_hand_goal,
            target_attached=target_attached,
            locked_orientation_used=True,
        ):
            return False

        self.get_logger().info(
            "Lift cartesiano: hand_goal=(%.4f, %.4f, %.4f) quat_locked=(%.4f, %.4f, %.4f, %.4f) "
            "(solo ΔZ, orientación TF tras attach)"
            % (
                lift_hand_goal[0],
                lift_hand_goal[1],
                lift_hand_goal[2],
                lift_quat_locked[0],
                lift_quat_locked[1],
                lift_quat_locked[2],
                lift_quat_locked[3],
            )
        )
        self.get_logger().info(
            "[ATTACHED_OBJECT_STATE_BEFORE_LIFT]\n"
            "current_attached_object_id=%s\n"
            "planning_scene_object_id=%s\n"
            "gazebo_entity_name=%s\n"
            "target_attached=%s"
            % (
                str(self._current_attached_object_id or "n/a"),
                str(attached_object_id or self._current_target_collision_id or "n/a"),
                self._resolve_target_entity_name(candidate) or "n/a",
                str(bool(self._current_target_attached)).lower(),
            )
        )
        if isinstance(candidate, dict) and mustard_requires_gazebo_lift_verification(
            candidate
        ):
            ent = self._resolve_target_entity_name(candidate)
            pre_lift_pose = self._sample_gazebo_entity_pose(
                ent, collect_sec=0.15, cache_as_pre_lift=True
            )
            if pre_lift_pose is not None:
                self._last_known_object_z_before_lift = float(pre_lift_pose[2])
                self.get_logger().info(
                    "[GAZEBO_PRE_LIFT_POSE_SAMPLE]\n"
                    "entity_name=%s\n"
                    "object_z_before_lift=%.4f\n"
                    "result=OK"
                    % (ent or "n/a", float(pre_lift_pose[2]))
                )
        hand_z_before = float(lift_lock["current_hand_position"][2])
        min_delta = 0.040
        if isinstance(candidate, dict):
            try:
                min_delta = float(candidate.get("post_lift_min_delta_z_m") or min_delta)
            except (TypeError, ValueError):
                min_delta = 0.040

        if (
            isinstance(candidate, dict)
            and self._chips_can_lift_policy_enabled(candidate)
        ):
            lift_ok = self._execute_chips_can_cartesian_lift(
                candidate,
                lift_lock,
                lift_hand_goal,
                lift_quat_locked,
                target_attached=target_attached,
            )
            if not lift_ok:
                return False
            return self._post_lift_verify(
                lift_lock, lift_quat_locked, attached_object_id, candidate
            )

        if (
            isinstance(candidate, dict)
            and self._sugar_box_lift_policy_enabled(candidate)
        ):
            lift_ok = self._execute_sugar_box_cartesian_lift_fallback(
                candidate,
                lift_lock,
                lift_hand_goal,
                lift_quat_locked,
                target_attached=target_attached,
            )
            if not lift_ok:
                return False
            return self._post_lift_verify(
                lift_lock, lift_quat_locked, attached_object_id, candidate
            )

        if (
            isinstance(candidate, dict)
            and self._mustard_lift_policy_enabled(candidate)
        ):
            lift_ok = self._execute_mustard_cartesian_lift_fallback(
                candidate,
                lift_lock,
                lift_hand_goal,
                lift_quat_locked,
                target_attached=target_attached,
            )
            if not lift_ok:
                return False
            return self._post_lift_verify(
                lift_lock, lift_quat_locked, attached_object_id, candidate
            )

        action_wait_ok = bool(
            move_stage_fn(
                "lift",
                lift_hand_goal,
                self._lift_vel,
                self._lift_acc,
                quat_override=lift_quat_locked,
            )
        )
        hand_after = self._link_pose_in_planning_frame(
            str(self._moveit_target_link or "panda_hand")
        )
        hand_delta_z = (
            float(hand_after["position"][2]) - hand_z_before
            if hand_after is not None
            else 0.0
        )
        orient_ok = True
        if hand_after is not None:
            orient_deg = self._quaternion_angle_deg(
                hand_after["quat"], lift_quat_locked
            )
            orient_ok = orient_deg <= float(self._gripper_gap_verify_target_angle_deg)
        motion_after_plan = getattr(
            self, "_last_lift_motion_pending_after_plan", None
        )
        lift_ok = self._generic_cartesian_lift_observation_ok(
            action_wait_ok=bool(
                action_wait_ok
                or getattr(self, "_last_generic_lift_action_wait_ok", False)
            ),
            hand_delta_z=float(hand_delta_z),
            min_delta_z_required=float(min_delta),
            attached_flag=bool(self._current_target_attached),
            orientation_ok=bool(orient_ok),
            motion_pending_after_plan=motion_after_plan,
        )
        fraction = self._read_cartesian_fraction()
        self._log_cartesian_lift_execute(
            lift_ok,
            fraction=fraction,
            hand_delta_z=float(hand_delta_z),
            min_delta_z_required=float(min_delta),
            execution_requested=bool(action_wait_ok),
            wait_result=bool(
                action_wait_ok
                or getattr(self, "_last_generic_lift_action_wait_ok", False)
            ),
        )
        fraction_low = (
            fraction is not None
            and float(fraction) + 1e-6 < float(self._cartesian_fraction_threshold)
        )
        if (
            not lift_ok
            and isinstance(candidate, dict)
            and self._sugar_box_lift_policy_enabled(candidate)
            and (fraction_low or not bool(action_wait_ok))
        ):
            lift_ok = self._execute_sugar_box_cartesian_lift_fallback(
                candidate,
                lift_lock,
                lift_hand_goal,
                lift_quat_locked,
                target_attached=target_attached,
            )
        if not lift_ok:
            return False
        return self._post_lift_verify(
            lift_lock, lift_quat_locked, attached_object_id, candidate
        )

    _CARTESIAN_PREVALIDATE_START_TCP_TOL_M = 0.02

    def _joint_state_from_plan_trajectory(self, traj: Any) -> Optional[JointState]:
        if traj is None:
            return None
        points = getattr(traj, "points", None)
        if not points:
            return None
        pt = points[-1]
        pos = getattr(pt, "positions", None)
        if not pos:
            return None
        js = JointState()
        names = getattr(traj, "joint_names", None)
        js.name = list(names) if names else list(PANDA_ARM_JOINT_NAMES)
        js.position = [float(v) for v in pos]
        return js

    def _fk_link_position_from_joint_state(
        self, joint_state: Any, link_name: str
    ) -> Optional[Tuple[float, float, float]]:
        if self._moveit2 is None or joint_state is None:
            return None
        link = str(link_name or "").strip()
        if not link:
            return None
        try:
            future = self._moveit2.compute_fk_async(
                joint_state,
                fk_link_names=[link],
            )
        except Exception:
            return None
        if future is None:
            return None
        t0 = time.monotonic()
        while not future.done() and time.monotonic() - t0 < 2.0:
            rclpy.spin_once(self, timeout_sec=0.05)
        if not future.done():
            return None
        poses = self._moveit2.get_compute_fk_result(
            future, fk_link_names=[link]
        )
        if poses is None:
            return None
        if isinstance(poses, list):
            if not poses:
                return None
            pose_stamped = poses[0]
        else:
            pose_stamped = poses
        p = pose_stamped.pose.position
        return (float(p.x), float(p.y), float(p.z))

    def _fk_tcp_position_from_joint_state(
        self, joint_state: Any
    ) -> Optional[Tuple[float, float, float]]:
        if bool(self._use_grasp_tcp):
            return self._fk_link_position_from_joint_state(
                joint_state, str(self._grasp_tcp_frame)
            )
        return self._fk_link_position_from_joint_state(
            joint_state, str(self._moveit_target_link)
        )

    def _fk_hand_position_from_joint_state(
        self, joint_state: Any
    ) -> Optional[Tuple[float, float, float]]:
        return self._fk_link_position_from_joint_state(
            joint_state, str(self._moveit_target_link)
        )

    @staticmethod
    def _tcp_xyz_error_m(
        a: Optional[Tuple[float, float, float]],
        b: Tuple[float, float, float],
    ) -> Optional[float]:
        if a is None:
            return None
        return float(
            math.sqrt(
                (float(a[0]) - float(b[0])) ** 2
                + (float(a[1]) - float(b[1])) ** 2
                + (float(a[2]) - float(b[2])) ** 2
            )
        )

    def _store_pending_cartesian_descend_validation(
        self,
        candidate: Dict[str, Any],
        *,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
    ) -> None:
        candidate["_cartesian_descend_pending_at_pregrasp"] = True
        candidate["_cartesian_descend_prevalidated"] = False
        candidate["_pregrasp_cartesian_validate_pre_plan"] = [
            float(pre_plan[0]),
            float(pre_plan[1]),
            float(pre_plan[2]),
        ]
        candidate["_pregrasp_cartesian_validate_gr_plan"] = [
            float(gr_plan[0]),
            float(gr_plan[1]),
            float(gr_plan[2]),
        ]
        candidate["_pregrasp_cartesian_validate_quat"] = [float(q) for q in quat]

    def _plan_cartesian_fraction_from_joint_state(
        self,
        start_js: Any,
        hand_goal: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
        *,
        candidate_idx: Optional[int] = None,
        start_state_source: Optional[str] = None,
        max_step: Optional[float] = None,
        jump_threshold: Optional[float] = None,
        avoid_collisions: Optional[bool] = None,
        log_audit: bool = True,
    ) -> Tuple[Optional[float], int]:
        fraction, traj_pts, _audit = self._call_get_cartesian_path_from_joint_state(
            start_js,
            hand_goal,
            quat,
            candidate_idx=candidate_idx,
            start_state_source=start_state_source,
            max_step=max_step,
            jump_threshold=jump_threshold,
            avoid_collisions=avoid_collisions,
            log_audit=log_audit,
        )
        return fraction, traj_pts

    def _prevalidate_cartesian_descend_for_pick_route(
        self,
        candidate: Dict[str, Any],
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
        pregrasp_js: Any,
        *,
        stage_label: str = "pregrasp_to_grasp",
        pregrasp_plan_traj: Any = None,
    ) -> Tuple[bool, float, bool]:
        """
        Prevalida descenso cartesiano. Si el brazo no está en pregrasp (HOME/workspace),
        difiere la validación a POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE.
        Returns: (route_ok, fraction, deferred)
        """
        threshold = float(self._cartesian_fraction_threshold)
        tol = float(self._CARTESIAN_PREVALIDATE_START_TCP_TOL_M)
        label = str(candidate.get("label", ""))
        gr_moveit = self._tcp_pose_to_moveit_pose(gr_plan, quat)

        cart_js = (
            self._joint_state_from_plan_trajectory(pregrasp_plan_traj) or pregrasp_js
        )
        start_state_label = (
            "pregrasp_plan_end"
            if pregrasp_plan_traj is not None
            and self._joint_state_from_plan_trajectory(pregrasp_plan_traj) is not None
            else "pregrasp_ik"
        )

        current_tcp = self._tcp_position_in_planning_frame()
        fk_tcp = self._fk_tcp_position_from_joint_state(cart_js)
        current_err = self._tcp_xyz_error_m(current_tcp, pre_plan)
        start_err = self._tcp_xyz_error_m(fk_tcp, pre_plan)

        defer = (
            current_err is not None
            and float(current_err) > tol
        ) or start_err is None

        if defer:
            self._store_pending_cartesian_descend_validation(
                candidate, pre_plan=pre_plan, gr_plan=gr_plan, quat=quat
            )
            candidate["_cartesian_descend_fraction"] = 0.0
            candidate["_cartesian_descend_prevalidate_stage"] = str(stage_label)
            self.get_logger().info(
                "[CARTESIAN_DESCEND_PREVALIDATE]\n"
                "label=%s\n"
                "stage=%s\n"
                "start_state=%s\n"
                "current_tcp=%s\n"
                "expected_start_tcp=(%.4f, %.4f, %.4f)\n"
                "start_tcp_error=%s\n"
                "fk_start_tcp=%s\n"
                "result=SKIPPED_PENDING_AT_PREGRASP\n"
                "reason=current_state_not_at_pregrasp"
                % (
                    label,
                    stage_label,
                    start_state_label,
                    "n/a"
                    if current_tcp is None
                    else "(%.4f, %.4f, %.4f)"
                    % (current_tcp[0], current_tcp[1], current_tcp[2]),
                    float(pre_plan[0]),
                    float(pre_plan[1]),
                    float(pre_plan[2]),
                    "n/a" if current_err is None else "%.4f" % float(current_err),
                    "n/a"
                    if fk_tcp is None
                    else "(%.4f, %.4f, %.4f)"
                    % (fk_tcp[0], fk_tcp[1], fk_tcp[2]),
                )
            )
            self.get_logger().info(
                "[PLAN_BEFORE_MOTION]\n"
                "label=%s\n"
                "stage=%s\n"
                "pregrasp_plan_ok=true\n"
                "cartesian_descend_prevalidated=false\n"
                "cartesian_descend_pending_at_pregrasp=true\n"
                "result=OK_PREGRASP_PENDING_DESCEND_VALIDATE"
                % (label, stage_label)
            )
            return True, 0.0, True

        fraction, traj_pts = self._plan_cartesian_fraction_from_joint_state(
            cart_js, gr_moveit, quat
        )
        ok = (
            fraction is not None
            and float(fraction) + 1e-6 >= threshold
            and int(traj_pts) >= 2
        )
        candidate["_cartesian_descend_pending_at_pregrasp"] = False
        candidate["_cartesian_descend_prevalidated"] = bool(ok)
        candidate["_cartesian_descend_fraction"] = (
            float(fraction) if fraction is not None else 0.0
        )
        candidate["_cartesian_descend_prevalidate_stage"] = str(stage_label)
        obstacles = _scene_obstacle_labels_for_log(
            candidate.get("scene_obstacles")
        )
        self.get_logger().info(
            "[CARTESIAN_DESCEND_PREVALIDATE]\n"
            "label=%s\n"
            "stage=%s\n"
            "start_state=%s\n"
            "current_tcp=%s\n"
            "expected_start_tcp=(%.4f, %.4f, %.4f)\n"
            "start_tcp_error=%s\n"
            "fk_start_tcp=%s\n"
            "cartesian_descend_fraction=%s\n"
            "cartesian_fraction_threshold=%.2f\n"
            "result=%s"
            % (
                label,
                stage_label,
                start_state_label,
                "n/a"
                if current_tcp is None
                else "(%.4f, %.4f, %.4f)"
                % (current_tcp[0], current_tcp[1], current_tcp[2]),
                float(pre_plan[0]),
                float(pre_plan[1]),
                float(pre_plan[2]),
                "n/a" if start_err is None else "%.4f" % float(start_err),
                "n/a"
                if fk_tcp is None
                else "(%.4f, %.4f, %.4f)"
                % (fk_tcp[0], fk_tcp[1], fk_tcp[2]),
                "n/a" if fraction is None else "%.5f" % float(fraction),
                threshold,
                "OK" if ok else "FAIL",
            )
        )
        self.get_logger().info(
            "[PLAN_BEFORE_MOTION]\n"
            "label=%s\n"
            "stage=%s\n"
            "pregrasp_plan_ok=true\n"
            "cartesian_descend_prevalidated=%s\n"
            "cartesian_descend_fraction=%s\n"
            "cartesian_fraction_threshold=%.2f\n"
            "trajectory_points=%d\n"
            "obstacles_considered=%s\n"
            "result=%s"
            % (
                label,
                stage_label,
                str(bool(ok)).lower(),
                "n/a" if fraction is None else "%.5f" % float(fraction),
                threshold,
                int(traj_pts),
                obstacles,
                "OK_FULL_PICK_ROUTE" if ok else "FAIL_CARTESIAN_DESCEND",
            )
        )
        if not ok:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] reason=cartesian_descend_not_prevalidated "
                "stage=%s fraction=%s threshold=%.2f"
                % (
                    stage_label,
                    "n/a" if fraction is None else "%.5f" % float(fraction),
                    threshold,
                )
            )
            self._log_cartesian_descend_fail_diag(
                candidate,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                quat=quat,
                pregrasp_js=cart_js,
                fraction=fraction,
                stage_label=stage_label,
            )
        return bool(ok), float(fraction) if fraction is not None else 0.0, False

    def _try_sugar_box_cartesian_descend_validate_fallback(
        self,
        candidate: Dict[str, Any],
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
        *,
        fraction: float,
        threshold: float,
        start_js: Any,
        orientation_lock: Optional[Dict[str, Any]] = None,
        descend_quat: Optional[Tuple[float, float, float, float]] = None,
    ) -> Tuple[bool, float, Tuple[float, float, float]]:
        """Reintenta validación con grasp_tcp_z más alto si fraction ∈ [soft_min, threshold)."""
        label = str(candidate.get("label", "")).strip().lower()
        if label != "sugar_box":
            return False, float(fraction), gr_plan
        if not bool(self._sugar_box_cartesian_descend_fallback_enabled):
            return False, float(fraction), gr_plan
        if not sugar_box_cartesian_soft_fail_eligible(
            fraction,
            threshold,
            soft_min_fraction=float(self._sugar_box_cartesian_soft_fail_min_fraction),
        ):
            return False, float(fraction), gr_plan
        if not self._pre_descend_gripper_reverify(candidate):
            self.get_logger().error(
                "[SUGAR_BOX_CARTESIAN_DESCEND_FALLBACK]\n"
                "fraction=%.5f\n"
                "threshold=%.2f\n"
                "result=FAIL\n"
                "reason=centering_or_gap_not_ok"
                % (float(fraction), float(threshold))
            )
            return False, float(fraction), gr_plan

        z_steps = list(self._sugar_box_cartesian_fallback_z_raise_steps_m or [])
        candidates_z = build_sugar_box_cartesian_fallback_grasp_z_candidates(
            float(pre_plan[2]),
            float(gr_plan[2]),
            float(fraction),
            float(threshold),
            z_raise_steps_m=z_steps,
        )
        best_frac = float(fraction)
        best_gr = gr_plan
        plan_quat = (
            descend_quat
            if descend_quat is not None
            else quat
        )
        for idx, grasp_z in enumerate(candidates_z):
            if float(grasp_z) >= float(pre_plan[2]) - 1e-4:
                continue
            trial_gr = apply_grasp_tcp_z_to_plan(gr_plan, grasp_z)
            if orientation_lock is not None and descend_quat is not None:
                trial_frac, trial_pts = self._plan_sugar_box_locked_descend_fraction(
                    start_js,
                    orientation_lock,
                    float(grasp_z),
                    plan_quat,
                    log_audit=False,
                )
            else:
                gr_moveit = self._tcp_pose_to_moveit_pose(trial_gr, quat)
                trial_frac, trial_pts = self._plan_cartesian_fraction_from_joint_state(
                    start_js, gr_moveit, quat
                )
            trial_ok = sugar_box_cartesian_fallback_accept(
                trial_frac, threshold, traj_points=int(trial_pts)
            )
            self.get_logger().info(
                "[SUGAR_BOX_CARTESIAN_DESCEND_FALLBACK]\n"
                "attempt=%d\n"
                "nominal_grasp_z=%.4f\n"
                "trial_grasp_z=%.4f\n"
                "fraction=%s\n"
                "trajectory_points=%d\n"
                "result=%s"
                % (
                    int(idx) + 1,
                    float(gr_plan[2]),
                    float(grasp_z),
                    "n/a" if trial_frac is None else "%.5f" % float(trial_frac),
                    int(trial_pts),
                    "OK" if trial_ok else "FAIL",
                )
            )
            if trial_frac is not None and float(trial_frac) > best_frac:
                best_frac = float(trial_frac)
                best_gr = trial_gr
            if trial_ok:
                candidate["_sugar_box_cartesian_descend_fallback_used"] = True
                candidate["_sugar_box_cartesian_descend_fallback_attempt"] = int(idx) + 1
                candidate["_pregrasp_cartesian_validate_gr_plan"] = list(trial_gr)
                top_z = _to_float(candidate.get("top_z_m"))
                if top_z is not None:
                    depth_new = max(0.0, float(top_z) - float(grasp_z))
                    old_depth = _to_float(
                        candidate.get("recommended_grasp_depth_from_top_m")
                    )
                    candidate["recommended_grasp_depth_from_top_m"] = float(depth_new)
                    self.get_logger().info(
                        "[SUGAR_BOX_CARTESIAN_DESCEND_FALLBACK]\n"
                        "route=reduced_grasp_depth\n"
                        "recommended_grasp_depth_from_top_m=%.4f\n"
                        "previous_depth=%s"
                        % (
                            float(depth_new),
                            "n/a"
                            if old_depth is None
                            else "%.4f" % float(old_depth),
                        )
                    )
                return True, float(trial_frac), trial_gr

        self.get_logger().error(
            "[SUGAR_BOX_CARTESIAN_DESCEND_FALLBACK]\n"
            "fraction=%.5f\n"
            "best_fraction=%.5f\n"
            "threshold=%.2f\n"
            "attempts=%d\n"
            "result=FAIL\n"
            "reason=all_reduced_grasp_z_candidates_failed"
            % (
                float(fraction),
                float(best_frac),
                float(threshold),
                len(candidates_z),
            )
        )
        return False, float(best_frac), best_gr

    def _joint_state_at_locked_hand_pose(
        self,
        start_js: Any,
        hand_goal: Tuple[float, float, float],
        hand_quat: Tuple[float, float, float, float],
    ) -> Any:
        if self._moveit2 is None or start_js is None:
            return None
        try:
            return self._moveit2.compute_ik(
                position=[
                    float(hand_goal[0]),
                    float(hand_goal[1]),
                    float(hand_goal[2]),
                ],
                quat_xyzw=[
                    float(hand_quat[0]),
                    float(hand_quat[1]),
                    float(hand_quat[2]),
                    float(hand_quat[3]),
                ],
                ik_link_name=self._moveit_target_link,
                start_joint_state=start_js,
                wait_for_server_timeout_sec=1.0,
            )
        except Exception:
            return None

    def _plan_sugar_box_locked_descend_fraction(
        self,
        start_js: Any,
        orientation_lock: Dict[str, Any],
        target_tcp_z: float,
        hand_quat: Tuple[float, float, float, float],
        *,
        log_audit: bool = True,
    ) -> Tuple[Optional[float], int]:
        tcp_pos = orientation_lock.get("current_tcp_position")
        if not isinstance(tcp_pos, (list, tuple)) or len(tcp_pos) < 3:
            tcp_pos = orientation_lock.get("current_hand_position")
        target_tcp = (
            float(tcp_pos[0]),
            float(tcp_pos[1]),
            float(target_tcp_z),
        )
        hand_goal = self._sugar_box_guarded_ik_hand_goal_for_tcp_target(
            orientation_lock, target_tcp, hand_quat
        )
        return self._plan_cartesian_fraction_from_joint_state(
            start_js,
            hand_goal,
            hand_quat,
            log_audit=log_audit,
        )

    def _validate_sugar_box_segmented_locked_descend(
        self,
        start_js: Any,
        orientation_lock: Dict[str, Any],
        hand_quat: Tuple[float, float, float, float],
        waypoints_tcp_z: List[float],
        *,
        threshold: float,
        tcp_xy: Tuple[float, float],
    ) -> Tuple[bool, float, Tuple[float, float, float]]:
        js = start_js
        lock = dict(orientation_lock)
        tcp_x, tcp_y = float(tcp_xy[0]), float(tcp_xy[1])
        min_frac = 1.0
        final_z = float(waypoints_tcp_z[-1]) if waypoints_tcp_z else 0.0
        for wp_z in waypoints_tcp_z:
            frac, pts = self._plan_sugar_box_locked_descend_fraction(
                js, lock, float(wp_z), hand_quat, log_audit=False
            )
            seg_ok = sugar_box_cartesian_fallback_accept(
                frac, threshold, traj_points=int(pts)
            )
            self.get_logger().info(
                "[SUGAR_BOX_DESCEND_SEGMENT_VALIDATE]\n"
                "target_tcp_z=%.4f\n"
                "fraction=%s\n"
                "trajectory_points=%d\n"
                "result=%s"
                % (
                    float(wp_z),
                    "n/a" if frac is None else "%.5f" % float(frac),
                    int(pts),
                    "OK" if seg_ok else "FAIL",
                )
            )
            if not seg_ok:
                return False, min_frac, (tcp_x, tcp_y, float(wp_z))
            if frac is not None:
                min_frac = min(min_frac, float(frac))
            hand_goal = self._sugar_box_guarded_ik_hand_goal_for_tcp_target(
                lock,
                (tcp_x, tcp_y, float(wp_z)),
                hand_quat,
            )
            js_next = self._joint_state_at_locked_hand_pose(js, hand_goal, hand_quat)
            if js_next is None:
                return False, min_frac, (tcp_x, tcp_y, float(wp_z))
            js = js_next
            lock["current_tcp_position"] = [tcp_x, tcp_y, float(wp_z)]
            lock["current_hand_position"] = [
                float(hand_goal[0]),
                float(hand_goal[1]),
                float(hand_goal[2]),
            ]
            final_z = float(wp_z)
        return True, float(min_frac), (tcp_x, tcp_y, float(final_z))

    def _execute_sugar_box_segmented_locked_descend(
        self,
        candidate: Dict[str, Any],
        orientation_lock: Dict[str, Any],
        hand_quat: Tuple[float, float, float, float],
        move_stage_fn: Any,
        descend_vel: float,
        descend_acc: float,
    ) -> bool:
        waypoints = list(
            candidate.get("_sugar_box_descend_segment_waypoints_tcp_z") or []
        )
        if not waypoints:
            return False
        lock = dict(orientation_lock)
        tcp_pos = lock.get("current_tcp_position") or lock["current_hand_position"]
        tcp_x, tcp_y = float(tcp_pos[0]), float(tcp_pos[1])
        all_ok = True
        for wp_z in waypoints:
            hand_goal = self._sugar_box_guarded_ik_hand_goal_for_tcp_target(
                lock,
                (tcp_x, tcp_y, float(wp_z)),
                hand_quat,
            )
            seg_ok = bool(
                move_stage_fn(
                    "descend",
                    hand_goal,
                    descend_vel,
                    descend_acc,
                    quat_override=hand_quat,
                )
            )
            self.get_logger().info(
                "[SUGAR_BOX_DESCEND_SEGMENT_EXECUTE]\n"
                "target_tcp_z=%.4f\n"
                "result=%s"
                % (float(wp_z), "OK" if seg_ok else "FAIL")
            )
            if not seg_ok:
                all_ok = False
                break
            lock["current_tcp_position"] = [tcp_x, tcp_y, float(wp_z)]
            lock["current_hand_position"] = [
                float(hand_goal[0]),
                float(hand_goal[1]),
                float(hand_goal[2]),
            ]
        return bool(all_ok)

    def _sugar_box_guarded_ik_descend_policy_active(
        self, candidate: Dict[str, Any]
    ) -> bool:
        scene_id = str(candidate.get("scene_id") or self._scene_id or "")
        return sugar_box_guarded_ik_descend_eligible(
            label=str(candidate.get("label", "")),
            scene_id=scene_id,
            multiobject_safe_route=bool(
                candidate.get("sugar_box_multiobject_safe_route")
                or sugar_box_multiobject_final_descend_target_removal_required(
                    candidate
                )
            ),
        )

    def _fk_link_pose_from_joint_state(
        self, joint_state: Any, link_name: str
    ) -> Optional[Dict[str, Any]]:
        if self._moveit2 is None or joint_state is None:
            return None
        link = str(link_name or "").strip()
        if not link:
            return None
        try:
            future = self._moveit2.compute_fk_async(
                joint_state,
                fk_link_names=[link],
            )
        except Exception:
            return None
        if future is None:
            return None
        t0 = time.monotonic()
        while not future.done() and time.monotonic() - t0 < 2.0:
            rclpy.spin_once(self, timeout_sec=0.05)
        if not future.done():
            return None
        poses = self._moveit2.get_compute_fk_result(
            future, fk_link_names=[link]
        )
        if poses is None:
            return None
        pose_stamped = poses[0] if isinstance(poses, list) else poses
        p = pose_stamped.pose.position
        q = pose_stamped.pose.orientation
        return {
            "position": (float(p.x), float(p.y), float(p.z)),
            "quat": (
                float(q.x),
                float(q.y),
                float(q.z),
                float(q.w),
            ),
        }

    def _refresh_sugar_box_guarded_ik_orientation_lock(
        self,
        orientation_lock: Dict[str, Any],
        *,
        tcp_pos: Tuple[float, float, float],
    ) -> Optional[Dict[str, Any]]:
        hand_link = str(self._moveit_target_link or "panda_hand")
        hand_tf = self._link_pose_in_planning_frame(hand_link)
        if hand_tf is None:
            return None
        current_hand = hand_tf["position"]
        current_tcp = tcp_pos
        if bool(self._use_grasp_tcp):
            tcp_tf = self._link_pose_in_planning_frame(str(self._grasp_tcp_frame))
            if tcp_tf is not None:
                current_tcp = tcp_tf["position"]
        lock = dict(orientation_lock)
        lock["current_hand_position"] = list(current_hand)
        lock["current_tcp_position"] = list(current_tcp)
        lock["locked_hand_quat"] = list(hand_tf["quat"])
        return lock

    def _sugar_box_guarded_ik_hand_goal_for_tcp_target(
        self,
        lock: Dict[str, Any],
        target_tcp: Tuple[float, float, float],
        hand_quat: Tuple[float, float, float, float],
        *,
        candidate: Optional[Dict[str, Any]] = None,
    ) -> Tuple[float, float, float]:
        if bool(self._use_grasp_tcp):
            hand_pos, _hand_q = self._tcp_to_moveit_hand_pose(
                target_tcp, hand_quat, candidate=candidate
            )
            return hand_pos
        hand_pos = lock["current_hand_position"]
        tcp_pos = lock.get("current_tcp_position") or hand_pos
        return build_sugar_box_locked_descend_hand_goal(
            lock,
            float(target_tcp[2]),
            target_tcp_xy=(float(target_tcp[0]), float(target_tcp[1])),
        )

    def _validate_sugar_box_guarded_ik_descend_plan(
        self,
        candidate: Dict[str, Any],
        orientation_lock: Dict[str, Any],
        hand_quat: Tuple[float, float, float, float],
        *,
        start_js: Any,
        tcp_pos: Tuple[float, float, float],
        nominal_grasp_tcp_z: float,
    ) -> Tuple[bool, float, List[List[float]]]:
        if self._moveit2 is None or start_js is None:
            return False, float(nominal_grasp_tcp_z), []
        hand_link = str(self._moveit_target_link or "panda_hand")
        lock = self._refresh_sugar_box_guarded_ik_orientation_lock(
            orientation_lock, tcp_pos=tcp_pos
        )
        if lock is None:
            return False, float(nominal_grasp_tcp_z), []
        current_hand = lock["current_hand_position"]
        current_tcp = lock["current_tcp_position"]
        hand_minus_tcp_z = float(current_hand[2]) - float(current_tcp[2])
        ref_xy = (float(current_tcp[0]), float(current_tcp[1]))
        final_candidates = build_sugar_box_guarded_ik_final_z_candidates(
            float(nominal_grasp_tcp_z)
        )
        self.get_logger().info(
            format_sugar_box_guarded_ik_descend_start_log(
                {
                    "current_tcp_z": float(current_tcp[2]),
                    "target_tcp_z": float(nominal_grasp_tcp_z),
                }
            )
        )
        for final_z in final_candidates:
            z_steps = build_sugar_box_guarded_ik_z_waypoints(
                float(current_tcp[2]), float(final_z)
            )
            js_seed = start_js
            step_lock = dict(lock)
            joint_chain: List[List[float]] = []
            chain_ok = True
            for step_idx, target_z in enumerate(z_steps, start=1):
                target_tcp = (ref_xy[0], ref_xy[1], float(target_z))
                hand_goal = self._sugar_box_guarded_ik_hand_goal_for_tcp_target(
                    step_lock, target_tcp, hand_quat
                )
                if sugar_box_guarded_ik_tcp_z_used_as_hand_z(
                    current_hand_z=float(current_hand[2]),
                    current_tcp_z=float(current_tcp[2]),
                    target_hand_z=float(hand_goal[2]),
                    target_tcp_z=float(target_z),
                ):
                    self.get_logger().error(format_sugar_box_guarded_ik_frame_bug_log())
                    return False, float(nominal_grasp_tcp_z), []
                self.get_logger().info(
                    format_sugar_box_guarded_ik_descend_step_target_log(
                        {
                            "moveit_target_link": hand_link,
                            "current_tcp_z": float(current_tcp[2]),
                            "current_hand_z": float(current_hand[2]),
                            "target_tcp_z": float(target_z),
                            "target_hand_z": float(hand_goal[2]),
                            "hand_minus_tcp_z": float(hand_minus_tcp_z),
                            "quat_source": "current_tf_after_joint7",
                        }
                    )
                )
                try:
                    ik_js = self._moveit2.compute_ik(
                        position=[
                            float(hand_goal[0]),
                            float(hand_goal[1]),
                            float(hand_goal[2]),
                        ],
                        quat_xyzw=[
                            float(hand_quat[0]),
                            float(hand_quat[1]),
                            float(hand_quat[2]),
                            float(hand_quat[3]),
                        ],
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=js_seed,
                        wait_for_server_timeout_sec=2.0,
                    )
                except Exception:
                    ik_js = None
                ik_ok = ik_js is not None
                fk_tcp = None
                orient_err = None
                xy_err = None
                z_err = None
                step_result = "FAIL"
                if ik_ok:
                    fk_tcp = self._fk_tcp_position_from_joint_state(ik_js)
                    fk_hand = self._fk_link_pose_from_joint_state(ik_js, hand_link)
                    if fk_tcp is not None and fk_hand is not None:
                        orient_err = self._quaternion_angle_deg(
                            fk_hand["quat"], hand_quat
                        )
                        step_ok, xy_err, z_err, orient_err = (
                            evaluate_sugar_box_guarded_ik_fk_step(
                                fk_tcp=fk_tcp,
                                target_tcp_z=float(target_z),
                                reference_tcp_xy=ref_xy,
                                orientation_error_deg=float(orient_err),
                            )
                        )
                        step_result = "OK" if step_ok else "FAIL"
                        if step_ok:
                            jv = self._joint_values_7d_from_any(
                                ik_js, context="sugar_box_guarded_ik_descend"
                            )
                            if jv is None:
                                step_ok = False
                                step_result = "FAIL"
                            else:
                                joint_chain.append([float(v) for v in jv])
                                js_seed = ik_js
                                step_lock["current_tcp_position"] = [
                                    ref_xy[0],
                                    ref_xy[1],
                                    float(target_z),
                                ]
                                step_lock["current_hand_position"] = [
                                    float(hand_goal[0]),
                                    float(hand_goal[1]),
                                    float(hand_goal[2]),
                                ]
                        chain_ok = bool(step_ok)
                    else:
                        chain_ok = False
                else:
                    chain_ok = False
                self.get_logger().info(
                    format_sugar_box_guarded_ik_descend_step_log(
                        {
                            "step": "%d/%d" % (step_idx, len(z_steps)),
                            "target_tcp_z": float(target_z),
                            "ik_ok": ik_ok,
                            "fk_tcp": fk_tcp,
                            "xy_error": xy_err,
                            "z_error": z_err,
                            "orientation_error_deg": orient_err,
                            "result": step_result,
                        }
                    )
                )
                if not chain_ok:
                    break
            if chain_ok and joint_chain:
                candidate["_sugar_box_guarded_ik_descend_joint_waypoints"] = (
                    joint_chain
                )
                candidate["_sugar_box_guarded_ik_descend_target_tcp_z"] = float(
                    final_z
                )
                candidate["_sugar_box_guarded_ik_descend_reference_tcp_xy"] = list(
                    ref_xy
                )
                return True, float(final_z), joint_chain
        return False, float(nominal_grasp_tcp_z), []

    def _execute_sugar_box_guarded_ik_descend(
        self,
        candidate: Dict[str, Any],
        *,
        descend_vel: float,
        descend_acc: float,
    ) -> bool:
        joint_chain = candidate.get("_sugar_box_guarded_ik_descend_joint_waypoints")
        target_z = _to_float(candidate.get("_sugar_box_guarded_ik_descend_target_tcp_z"))
        if not isinstance(joint_chain, list) or not joint_chain or target_z is None:
            return False
        seg_time = max(
            0.8,
            min(
                2.5,
                float(descend_vel) * 8.0 if float(descend_vel) > 0 else 1.5,
            ),
        )
        traj = JointTrajectory()
        traj.joint_names = list(PANDA_ARM_JOINT_NAMES)
        points: List[JointTrajectoryPoint] = []
        t_acc = 0.0
        for joints in joint_chain:
            if not isinstance(joints, (list, tuple)) or len(joints) < 7:
                continue
            pt = JointTrajectoryPoint()
            pt.positions = [float(v) for v in joints[:7]]
            t_acc += float(seg_time)
            pt.time_from_start = self._duration_from_seconds(t_acc)
            points.append(pt)
        if not points:
            return False
        traj.points = points
        self.get_logger().info(
            format_sugar_box_guarded_ik_descend_execute_log(
                {
                    "steps": len(points),
                    "target_tcp_z": float(target_z),
                    "result": "PENDING",
                }
            )
        )
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                format_sugar_box_guarded_ik_descend_execute_log(
                    {
                        "steps": len(points),
                        "target_tcp_z": float(target_z),
                        "result": "OK",
                    }
                )
            )
            return True
        ok, _status, _code, _err = self._send_arm_follow_joint_trajectory(traj)
        self.get_logger().info(
            format_sugar_box_guarded_ik_descend_execute_log(
                {
                    "steps": len(points),
                    "target_tcp_z": float(target_z),
                    "result": "OK" if ok else "FAIL",
                }
            )
        )
        return bool(ok)

    def _verify_sugar_box_guarded_ik_descend_after_motion(
        self, candidate: Dict[str, Any]
    ) -> bool:
        target_z = _to_float(candidate.get("_sugar_box_guarded_ik_descend_target_tcp_z"))
        actual_tcp = self._tcp_position_in_planning_frame()
        if target_z is None or actual_tcp is None:
            return False
        actual_z = float(actual_tcp[2])
        z_ok = actual_z <= float(target_z) + 0.003 + 1e-9
        top_z = _to_float(candidate.get("top_z_m"))
        depth_below_top = (
            None if top_z is None else float(top_z) - float(actual_z)
        )
        verify_ok = bool(z_ok)
        self.get_logger().info(
            format_sugar_box_guarded_ik_descend_verify_log(
                {
                    "actual_tcp_z": actual_z,
                    "target_tcp_z": float(target_z),
                    "depth_below_top": depth_below_top,
                    "result": "OK" if verify_ok else "FAIL",
                }
            )
        )
        if not verify_ok:
            return False
        return True

    def _execute_sugar_box_micro_descend_ik_stepwise(
        self,
        candidate: Dict[str, Any],
        orientation_lock: Dict[str, Any],
        descend_quat_locked: Tuple[float, float, float, float],
        *,
        descend_vel: float,
        descend_acc: float,
        backend: str,
    ) -> bool:
        """Ejecuta el microdescenso por waypoints de joints (sin compute_cartesian_path).

        Recalcula/valida la secuencia IK stepwise desde el estado REAL actual;
        si no es posible recomputar, usa los waypoints validados en cache.
        """
        micro_m = _to_float(candidate.get("_sugar_box_micro_descend_m")) or 0.0
        req_tcp_z = _to_float(candidate.get("_sugar_box_micro_descend_target_tcp_z"))
        joint_waypoints: List[List[float]] = []
        if micro_m > 1e-6 and self._moveit2 is not None:
            aligned_js = self._current_arm_joint_state()
            lock = (
                self._build_sugar_box_orientation_lock_from_joint_state(
                    aligned_js, fallback_hand_quat=descend_quat_locked
                )
                if aligned_js is not None
                else None
            )
            if lock is not None:
                hand_quat = tuple(
                    float(v)
                    for v in (lock.get("locked_hand_quat") or descend_quat_locked)
                )
                tcp_lock = lock.get("current_tcp_position")
                target_center = self._resolve_grasp_center_base_from_candidate(
                    candidate
                )
                if target_center is not None:
                    target_xy = (float(target_center[0]), float(target_center[1]))
                elif isinstance(tcp_lock, (list, tuple)) and len(tcp_lock) >= 2:
                    target_xy = (float(tcp_lock[0]), float(tcp_lock[1]))
                else:
                    target_xy = (0.0, 0.0)
                top_z = _to_float(candidate.get("top_z_m"))
                min_table_clear = max(float(self._min_tcp_clearance_m), 0.015)
                step_dz = (
                    float(self._sugar_box_micro_descend_ik_step_dz_m)
                    if backend == "ik_stepwise"
                    else max(float(micro_m), 1.0)
                )
                diag: Dict[str, Any] = {}
                record = self._run_sugar_box_micro_descend_ik_stepwise(
                    aligned_js=aligned_js,
                    orientation_lock=lock,
                    hand_quat=hand_quat,
                    target_center_xy=target_xy,
                    top_z=top_z,
                    requested_micro_descend_m=float(micro_m),
                    step_dz_m=step_dz,
                    min_table_clear=min_table_clear,
                    candidate_id=int(candidate.get("variant_index") or 0),
                    backend=str(backend),
                    cartesian_fraction=None,
                    cartesian_fallback_used=True,
                    diag=diag,
                )
                if record is not None and record.get("joint_waypoints"):
                    joint_waypoints = [
                        [float(v) for v in wp]
                        for wp in record["joint_waypoints"]
                        if isinstance(wp, (list, tuple)) and len(wp) >= 7
                    ]
                    if record.get("final_tcp_z") is not None:
                        req_tcp_z = float(record["final_tcp_z"])
        if not joint_waypoints:
            cached = candidate.get("_sugar_box_micro_descend_joint_waypoints")
            if isinstance(cached, list):
                joint_waypoints = [
                    [float(v) for v in wp]
                    for wp in cached
                    if isinstance(wp, (list, tuple)) and len(wp) >= 7
                ]
        steps = len(joint_waypoints)
        if steps == 0:
            self.get_logger().error(
                format_sugar_box_micro_descend_execute_log(
                    {
                        "backend": str(backend),
                        "steps": 0,
                        "selected_micro_descend_m": micro_m,
                        "final_tcp_z": req_tcp_z,
                        "result": "FAIL",
                    }
                )
            )
            return False
        # Velocidad baja para el tramo final de contacto.
        seg_time = max(
            1.0,
            min(2.5, float(descend_vel) * 10.0 if float(descend_vel) > 0 else 1.5),
        )
        traj = JointTrajectory()
        traj.joint_names = list(PANDA_ARM_JOINT_NAMES)
        points: List[JointTrajectoryPoint] = []
        t_acc = 0.0
        for joints in joint_waypoints:
            pt = JointTrajectoryPoint()
            pt.positions = [float(v) for v in joints[:7]]
            t_acc += float(seg_time)
            pt.time_from_start = self._duration_from_seconds(t_acc)
            points.append(pt)
        traj.points = points
        self.get_logger().info(
            format_sugar_box_micro_descend_execute_log(
                {
                    "backend": str(backend),
                    "steps": steps,
                    "selected_micro_descend_m": micro_m,
                    "final_tcp_z": req_tcp_z,
                    "result": "PENDING",
                }
            )
        )
        if self._dry_run or self._moveit2 is None:
            self.get_logger().info(
                format_sugar_box_micro_descend_execute_log(
                    {
                        "backend": str(backend),
                        "steps": steps,
                        "selected_micro_descend_m": micro_m,
                        "final_tcp_z": req_tcp_z,
                        "result": "OK",
                    }
                )
            )
            return True
        ok, _status, _code, _err = self._send_arm_follow_joint_trajectory(traj)
        self.get_logger().info(
            format_sugar_box_micro_descend_execute_log(
                {
                    "backend": str(backend),
                    "steps": steps,
                    "selected_micro_descend_m": micro_m,
                    "final_tcp_z": req_tcp_z,
                    "result": "OK" if ok else "FAIL",
                }
            )
        )
        return bool(ok)

    def _validate_sugar_box_locked_post_pregrasp_cartesian_descend(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        quat: Tuple[float, float, float, float],
        *,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        dx: float = 0.0,
        dy: float = 0.0,
    ) -> bool:
        """Valida descenso cartesiano sugar_box multiobjeto con orientación TF real."""
        label = str(candidate.get("label", ""))
        threshold = float(self._cartesian_fraction_threshold)
        tol = float(self._CARTESIAN_PREVALIDATE_START_TCP_TOL_M)
        start_js = self._current_arm_joint_state()
        current_tcp = self._tcp_position_in_planning_frame()
        current_err = self._tcp_xyz_error_m(current_tcp, pre_plan)

        if current_err is not None and float(current_err) > tol:
            self.get_logger().error(
                "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
                "label=%s\n"
                "orientation_source=current_tf_after_joint7\n"
                "current_orientation_locked=false\n"
                "start_tcp_error=%.4f\n"
                "fraction=n/a\n"
                "result=FAIL\n"
                "reason=not_at_pregrasp_tcp"
                % (label, float(current_err))
            )
            return False

        orientation_lock = self._lock_descend_orientation_from_current_tf(
            candidate, quat
        )
        if orientation_lock is None:
            self.get_logger().error(
                "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
                "label=%s\n"
                "orientation_source=current_tf_after_joint7\n"
                "current_orientation_locked=false\n"
                "fraction=n/a\n"
                "result=FAIL\n"
                "reason=descend_orientation_lock_failed"
                % label
            )
            return False

        hand_quat = orientation_lock["locked_hand_quat"]
        tcp_pos_raw = orientation_lock.get("current_tcp_position")
        if not isinstance(tcp_pos_raw, (list, tuple)) or len(tcp_pos_raw) < 3:
            tcp_pos_raw = current_tcp
        if tcp_pos_raw is None:
            return False
        tcp_pos = (
            float(tcp_pos_raw[0]),
            float(tcp_pos_raw[1]),
            float(tcp_pos_raw[2]),
        )
        selected_grasp_z = float(gr_plan[2])
        target_tcp = build_sugar_box_locked_descend_target_tcp(
            tcp_pos, selected_grasp_z
        )
        gr_plan = target_tcp
        old_yaw = self._wrap_to_pi(self._yaw_rad_from_quaternion_xyzw(quat))
        hand_yaw = self._wrap_to_pi(
            self._yaw_rad_from_quaternion_xyzw(
                (
                    float(hand_quat[0]),
                    float(hand_quat[1]),
                    float(hand_quat[2]),
                    float(hand_quat[3]),
                )
            )
        )
        orient_delta = quaternion_yaw_delta_deg(quat, hand_quat)
        self.get_logger().info(
            format_sugar_box_descend_orientation_lock_log(
                {
                    "old_candidate_yaw_rad": old_yaw,
                    "current_hand_yaw_rad": hand_yaw,
                    "orientation_delta_deg": orient_delta,
                    "current_tcp": list(tcp_pos),
                    "target_tcp": list(target_tcp),
                    "selected_grasp_tcp_z": selected_grasp_z,
                    "result": "OK",
                }
            )
        )

        target_collision_removed_for_descend = (
            self._prepare_planning_scene_for_post_pregrasp_descend_validate(
                candidate, self._current_target_collision_id
            )
        )
        if not target_collision_removed_for_descend:
            self.get_logger().error(
                "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
                "label=%s\n"
                "target_collision_removed_for_descend=false\n"
                "fraction=n/a\n"
                "result=FAIL\n"
                "reason=target_collision_removal_failed_before_descend_validate"
                % label
            )
            return False

        candidate["_post_pregrasp_descend_orientation_source"] = (
            "current_tf_after_joint7"
        )
        candidate["_post_pregrasp_descend_orientation_locked"] = True
        candidate["_descend_orientation_lock"] = {
            "current_hand_position": list(
                orientation_lock["current_hand_position"]
            ),
            "current_hand_quat": list(hand_quat),
            "locked_hand_quat": list(hand_quat),
            "current_tcp_position": list(tcp_pos),
        }

        fraction, traj_pts = self._plan_sugar_box_locked_descend_fraction(
            start_js, orientation_lock, selected_grasp_z, hand_quat
        )
        ok = sugar_box_cartesian_fallback_accept(
            fraction, threshold, traj_points=int(traj_pts)
        )
        fallback_used = False
        segmented_used = False
        guarded_ik_used = False
        if (
            not ok
            and bool(self._sugar_box_cartesian_descend_fallback_enabled)
        ):
            fb_ok, fb_frac, gr_plan = (
                self._try_sugar_box_cartesian_descend_validate_fallback(
                    candidate,
                    (float(tcp_pos[0]), float(tcp_pos[1]), float(tcp_pos[2])),
                    gr_plan,
                    quat,
                    fraction=float(fraction) if fraction is not None else 0.0,
                    threshold=float(threshold),
                    start_js=start_js,
                    orientation_lock=orientation_lock,
                    descend_quat=hand_quat,
                )
            )
            if fb_ok:
                ok = True
                fraction = float(fb_frac)
                fallback_used = True
                _, traj_pts = self._plan_sugar_box_locked_descend_fraction(
                    start_js,
                    orientation_lock,
                    float(gr_plan[2]),
                    hand_quat,
                )

        partial_micro_ok = False
        if not ok and start_js is not None:
            for dz in SUGAR_BOX_DESCEND_MICROSTEP_DZ_M:
                target_z = float(tcp_pos[2]) - float(dz)
                if target_z < selected_grasp_z - 1e-4:
                    continue
                mf, mp = self._plan_sugar_box_locked_descend_fraction(
                    start_js,
                    orientation_lock,
                    target_z,
                    hand_quat,
                    log_audit=False,
                )
                m_ok = sugar_box_cartesian_fallback_accept(
                    mf, threshold, traj_points=int(mp)
                )
                if m_ok:
                    partial_micro_ok = True
                self.get_logger().info(
                    format_sugar_box_descend_microstep_diag_log(
                        {
                            "dz": float(dz),
                            "target_tcp_z": float(target_z),
                            "fraction": mf,
                            "trajectory_points": int(mp),
                            "result": "OK" if m_ok else "FAIL",
                        }
                    )
                )

            if partial_micro_ok or (
                fraction is not None and float(fraction) <= 1e-6
            ):
                waypoints = build_sugar_box_segment_descent_waypoints(
                    float(tcp_pos[2]), selected_grasp_z
                )
                seg_ok, seg_frac, seg_gr = (
                    self._validate_sugar_box_segmented_locked_descend(
                        start_js,
                        orientation_lock,
                        hand_quat,
                        waypoints,
                        threshold=threshold,
                        tcp_xy=(float(tcp_pos[0]), float(tcp_pos[1])),
                    )
                )
                if seg_ok:
                    ok = True
                    fraction = float(seg_frac)
                    gr_plan = seg_gr
                    segmented_used = True
                    candidate["_sugar_box_descend_use_segmented"] = True
                    candidate["_sugar_box_descend_segment_waypoints_tcp_z"] = (
                        list(waypoints)
                    )
                    _, traj_pts = self._plan_sugar_box_locked_descend_fraction(
                        start_js,
                        orientation_lock,
                        float(gr_plan[2]),
                        hand_quat,
                        log_audit=False,
                    )

        if (
            not ok
            and start_js is not None
            and self._sugar_box_guarded_ik_descend_policy_active(candidate)
        ):
            ik_ok, final_z, _joint_chain = (
                self._validate_sugar_box_guarded_ik_descend_plan(
                    candidate,
                    orientation_lock,
                    (
                        float(hand_quat[0]),
                        float(hand_quat[1]),
                        float(hand_quat[2]),
                        float(hand_quat[3]),
                    ),
                    start_js=start_js,
                    tcp_pos=tcp_pos,
                    nominal_grasp_tcp_z=float(selected_grasp_z),
                )
            )
            if ik_ok:
                ok = True
                guarded_ik_used = True
                selected_grasp_z = float(final_z)
                gr_plan = (
                    float(tcp_pos[0]),
                    float(tcp_pos[1]),
                    float(final_z),
                )
                candidate["_sugar_box_guarded_ik_descend_validated"] = True
                candidate["_cartesian_descend_prevalidation_source"] = (
                    "guarded_ik_after_joint7"
                )

        if not ok and start_js is not None:
            self._log_sugar_box_post_pregrasp_descend_collision_diag(
                candidate,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                quat=(
                    float(hand_quat[0]),
                    float(hand_quat[1]),
                    float(hand_quat[2]),
                    float(hand_quat[3]),
                ),
                orientation_lock=orientation_lock,
                hand_quat=(
                    float(hand_quat[0]),
                    float(hand_quat[1]),
                    float(hand_quat[2]),
                    float(hand_quat[3]),
                ),
                start_js=start_js,
                without_target_fraction=(
                    float(fraction) if fraction is not None else None
                ),
            )

        if ok and isinstance(plan_targets.get("grasp_tcp"), (list, tuple)):
            plan_targets["grasp_tcp"] = (
                float(gr_plan[0]),
                float(gr_plan[1]),
                float(gr_plan[2]),
            )
            candidate["_pregrasp_cartesian_validate_gr_plan"] = list(gr_plan)

        candidate["_cartesian_descend_pending_at_pregrasp"] = False
        candidate["_cartesian_descend_prevalidated"] = bool(ok)
        candidate["_cartesian_descend_fraction"] = (
            float(fraction) if fraction is not None else 0.0
        )
        self.get_logger().info(
            "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
            "label=%s\n"
            "orientation_source=current_tf_after_joint7\n"
            "current_orientation_locked=true\n"
            "current_tcp=(%.4f, %.4f, %.4f)\n"
            "pregrasp_tcp=(%.4f, %.4f, %.4f)\n"
            "grasp_tcp=(%.4f, %.4f, %.4f)\n"
            "target_collision_removed_for_descend=%s\n"
            "fraction=%s\n"
            "cartesian_fraction_threshold=%.2f\n"
            "trajectory_points=%d\n"
            "sugar_box_fallback=%s\n"
            "sugar_box_segmented=%s\n"
            "sugar_box_guarded_ik=%s\n"
            "result=%s"
            % (
                label,
                float(tcp_pos[0]),
                float(tcp_pos[1]),
                float(tcp_pos[2]),
                pre_plan[0],
                pre_plan[1],
                pre_plan[2],
                gr_plan[0],
                gr_plan[1],
                gr_plan[2],
                str(bool(target_collision_removed_for_descend)).lower(),
                "n/a" if fraction is None else "%.5f" % float(fraction),
                threshold,
                int(traj_pts),
                str(bool(fallback_used)).lower(),
                str(bool(segmented_used)).lower(),
                str(bool(guarded_ik_used)).lower(),
                "OK" if ok else "FAIL",
            )
        )
        if not ok and target_collision_removed_for_descend:
            self._prepare_planning_scene_for_post_pregrasp_descend_validate(
                candidate, self._current_target_collision_id
            )
        return bool(ok)

    def _validate_cartesian_descend_at_actual_pregrasp(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        quat: Tuple[float, float, float, float],
        *,
        dx: float = 0.0,
        dy: float = 0.0,
    ) -> bool:
        """Valida descenso cartesiano desde el TCP/joints reales en pregrasp."""
        if (
            self._is_chips_can_cylinder_topdown_candidate(candidate)
            and bool(candidate.get("_chips_can_high_route_pending_final_descend"))
        ):
            return self._validate_chips_can_final_descend_from_actual_low_pregrasp(
                candidate, plan_targets, quat, dx=dx, dy=dy
            )
        if self._is_chips_can_cylinder_topdown_candidate(candidate):
            return True
        if not bool(candidate.get("_cartesian_descend_pending_at_pregrasp")):
            return bool(candidate.get("_cartesian_descend_prevalidated"))

        label = str(candidate.get("label", ""))
        pre_raw = candidate.get("_pregrasp_cartesian_validate_pre_plan")
        gr_raw = candidate.get("_pregrasp_cartesian_validate_gr_plan")
        if isinstance(pre_raw, (list, tuple)) and len(pre_raw) >= 3:
            pre_plan = (
                float(pre_raw[0]) + float(dx),
                float(pre_raw[1]) + float(dy),
                float(pre_raw[2]),
            )
        else:
            pre_tcp = plan_targets.get("pregrasp_tcp")
            if not isinstance(pre_tcp, (list, tuple)) or len(pre_tcp) < 3:
                return False
            pre_plan = (
                float(pre_tcp[0]) + float(dx),
                float(pre_tcp[1]) + float(dy),
                float(pre_tcp[2]),
            )
        if isinstance(gr_raw, (list, tuple)) and len(gr_raw) >= 3:
            gr_plan = (
                float(gr_raw[0]) + float(dx),
                float(gr_raw[1]) + float(dy),
                float(gr_raw[2]),
            )
        else:
            gr_tcp = plan_targets.get("grasp_tcp")
            if not isinstance(gr_tcp, (list, tuple)) or len(gr_tcp) < 3:
                return False
            gr_plan = (
                float(gr_tcp[0]) + float(dx),
                float(gr_tcp[1]) + float(dy),
                float(gr_tcp[2]),
            )

        scene_obstacles = candidate.get("scene_obstacles") or []
        target_collision_removed_for_descend = False
        removal_required = sugar_box_multiobject_final_descend_target_removal_required(
            candidate
        )
        if removal_required:
            return self._validate_sugar_box_locked_post_pregrasp_cartesian_descend(
                candidate,
                plan_targets,
                quat,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                dx=dx,
                dy=dy,
            )
        elif scene_obstacles and self._add_detected_objects_to_scene:
            self._apply_table_collision_if_needed()
            self._add_detected_objects_to_planning_scene(
                scene_obstacles,
                include_target=self._include_target_collision(candidate),
                candidate=candidate,
            )

        start_js = self._current_arm_joint_state()
        current_tcp = self._tcp_position_in_planning_frame()
        current_err = self._tcp_xyz_error_m(current_tcp, pre_plan)
        threshold = float(self._cartesian_fraction_threshold)
        tol = float(self._CARTESIAN_PREVALIDATE_START_TCP_TOL_M)

        if current_err is not None and float(current_err) > tol:
            self.get_logger().error(
                "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
                "label=%s\n"
                "current_tcp=%s\n"
                "pregrasp_tcp=(%.4f, %.4f, %.4f)\n"
                "grasp_tcp=(%.4f, %.4f, %.4f)\n"
                "start_tcp_error=%.4f\n"
                "fraction=n/a\n"
                "result=FAIL\n"
                "reason=not_at_pregrasp_tcp"
                % (
                    label,
                    "n/a"
                    if current_tcp is None
                    else "(%.4f, %.4f, %.4f)"
                    % (current_tcp[0], current_tcp[1], current_tcp[2]),
                    pre_plan[0],
                    pre_plan[1],
                    pre_plan[2],
                    gr_plan[0],
                    gr_plan[1],
                    gr_plan[2],
                    float(current_err),
                )
            )
            return False

        gr_moveit = self._tcp_pose_to_moveit_pose(gr_plan, quat)
        fraction, traj_pts = self._plan_cartesian_fraction_from_joint_state(
            start_js, gr_moveit, quat
        )
        ok = sugar_box_cartesian_fallback_accept(
            fraction, threshold, traj_points=int(traj_pts)
        )
        fallback_used = False
        if (
            not ok
            and str(label).strip().lower() == "sugar_box"
            and bool(self._sugar_box_cartesian_descend_fallback_enabled)
        ):
            fb_ok, fb_frac, gr_plan = self._try_sugar_box_cartesian_descend_validate_fallback(
                candidate,
                pre_plan,
                gr_plan,
                quat,
                fraction=float(fraction) if fraction is not None else 0.0,
                threshold=float(threshold),
                start_js=start_js,
            )
            if fb_ok:
                ok = True
                fraction = float(fb_frac)
                fallback_used = True
                _, traj_pts = self._plan_cartesian_fraction_from_joint_state(
                    start_js,
                    self._tcp_pose_to_moveit_pose(gr_plan, quat),
                    quat,
                )
                if isinstance(plan_targets.get("grasp_tcp"), (list, tuple)):
                    plan_targets["grasp_tcp"] = (
                        float(gr_plan[0]),
                        float(gr_plan[1]),
                        float(gr_plan[2]),
                    )
        if (
            not ok
            and removal_required
            and start_js is not None
        ):
            self._log_sugar_box_post_pregrasp_descend_collision_diag(
                candidate,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                quat=quat,
                start_js=start_js,
                without_target_fraction=(
                    float(fraction) if fraction is not None else None
                ),
            )
        candidate["_cartesian_descend_pending_at_pregrasp"] = False
        candidate["_cartesian_descend_prevalidated"] = bool(ok)
        candidate["_cartesian_descend_fraction"] = (
            float(fraction) if fraction is not None else 0.0
        )
        self.get_logger().info(
            "[POST_PREGRASP_CARTESIAN_DESCEND_VALIDATE]\n"
            "label=%s\n"
            "current_tcp=%s\n"
            "pregrasp_tcp=(%.4f, %.4f, %.4f)\n"
            "grasp_tcp=(%.4f, %.4f, %.4f)\n"
            "target_collision_removed_for_descend=%s\n"
            "fraction=%s\n"
            "cartesian_fraction_threshold=%.2f\n"
            "trajectory_points=%d\n"
            "sugar_box_fallback=%s\n"
            "result=%s"
            % (
                label,
                "n/a"
                if current_tcp is None
                else "(%.4f, %.4f, %.4f)"
                % (current_tcp[0], current_tcp[1], current_tcp[2]),
                pre_plan[0],
                pre_plan[1],
                pre_plan[2],
                gr_plan[0],
                gr_plan[1],
                gr_plan[2],
                str(bool(target_collision_removed_for_descend)).lower(),
                "n/a" if fraction is None else "%.5f" % float(fraction),
                threshold,
                int(traj_pts),
                str(bool(fallback_used)).lower(),
                "OK" if ok else "FAIL",
            )
        )
        return bool(ok)

    def _log_cartesian_descend_fail_diag(
        self,
        candidate: Dict[str, Any],
        *,
        pre_plan: Tuple[float, float, float],
        gr_plan: Tuple[float, float, float],
        quat: Tuple[float, float, float, float],
        pregrasp_js: Any,
        fraction: Optional[float],
        stage_label: str,
    ) -> None:
        if self._moveit2 is None or pregrasp_js is None:
            return
        label = str(candidate.get("label", ""))
        threshold = float(self._cartesian_fraction_threshold)
        tcp = self._tcp_position_in_planning_frame()
        current_tcp = (
            "n/a"
            if tcp is None
            else "(%.4f, %.4f, %.4f)" % (float(tcp[0]), float(tcp[1]), float(tcp[2]))
        )
        requested_tcp = "(%.4f, %.4f, %.4f)" % (
            float(gr_plan[0]),
            float(gr_plan[1]),
            float(gr_plan[2]),
        )
        last_reachable_z = "n/a"
        if fraction is not None and fraction > 1e-6:
            interp_z = float(pre_plan[2]) + float(fraction) * (
                float(gr_plan[2]) - float(pre_plan[2])
            )
            last_reachable_z = "%.4f" % interp_z
        obstacles = _scene_obstacle_labels_for_log(
            candidate.get("scene_obstacles")
        )
        likely = "unknown"
        probe_lines: List[str] = []
        scene_obs = [
            o
            for o in (candidate.get("scene_obstacles") or [])
            if isinstance(o, dict) and not bool(o.get("is_target", False))
        ]
        gr_moveit = self._tcp_pose_to_moveit_pose(gr_plan, quat)
        cases: List[Tuple[str, List[Dict[str, Any]]]] = [("all_obstacles", scene_obs)]
        if scene_obs:
            for drop in scene_obs:
                lb = str(drop.get("label", "obj"))
                kept = [o for o in scene_obs if o is not drop]
                cases.append(("without_%s" % lb, kept))
            cases.append(("without_all_obstacles", []))
        for case_name, kept in cases:
            if self._add_detected_objects_to_scene:
                self._apply_table_collision_if_needed()
                self._add_detected_objects_to_planning_scene(
                    kept,
                    include_target=self._include_target_collision(candidate),
                    candidate=candidate,
                )
            frac, _ = self._plan_cartesian_fraction_from_joint_state(
                pregrasp_js, gr_moveit, quat
            )
            probe_lines.append(
                "%s:fraction=%s"
                % (case_name, "n/a" if frac is None else "%.5f" % float(frac))
            )
            if frac is not None and float(frac) + 1e-6 >= threshold:
                if case_name.startswith("without_") and case_name != "without_all_obstacles":
                    likely = case_name.replace("without_", "")
                elif case_name == "without_all_obstacles":
                    likely = "self_collision_or_kinematics"
        self.get_logger().error(
            "[CARTESIAN_DESCEND_FAIL_DIAG]\n"
            "label=%s\n"
            "stage=%s\n"
            "obstacles=%s\n"
            "fraction=%s\n"
            "threshold=%.2f\n"
            "current_tcp=%s\n"
            "requested_tcp=%s\n"
            "pregrasp_tcp=(%.4f, %.4f, %.4f)\n"
            "last_reachable_tcp_z=%s\n"
            "offline_obstacle_probes=%s\n"
            "likely_blocking_obstacle=%s"
            % (
                label,
                stage_label,
                obstacles,
                "n/a" if fraction is None else "%.5f" % float(fraction),
                threshold,
                current_tcp,
                requested_tcp,
                float(pre_plan[0]),
                float(pre_plan[1]),
                float(pre_plan[2]),
                last_reachable_z,
                "; ".join(probe_lines),
                likely,
            )
        )

    def _cartesian_descend_precheck(
        self,
        plan_targets: Dict[str, Tuple[float, float, float]],
        dx: float,
        dy: float,
        *,
        yaw_verified: bool,
        centering_verified: bool,
        target_collision_removed: bool,
        locked_orientation_used: bool = False,
        orientation_source: str = "original_target_quat",
        descend_hand_goal: Optional[Tuple[float, float, float]] = None,
        descend_delta_z_m: Optional[float] = None,
    ) -> bool:
        pre_tcp = self._shifted_tcp_from_plan_targets(
            plan_targets, "pregrasp_tcp", dx, dy
        )
        gr_tcp = self._shifted_tcp_from_plan_targets(plan_targets, "grasp_tcp", dx, dy)
        result = "FAIL"
        ok = False
        delta_z = float("nan")
        if pre_tcp is not None and gr_tcp is not None:
            if descend_delta_z_m is not None:
                delta_z = float(descend_delta_z_m)
            elif descend_delta_z_m is not None:
                delta_z = float(descend_delta_z_m)
            elif descend_hand_goal is not None:
                delta_z = abs(float(gr_tcp[2]) - float(pre_tcp[2]))
            else:
                delta_z = float(pre_tcp[2]) - float(gr_tcp[2])
            ok = (
                bool(yaw_verified)
                and bool(centering_verified)
                and bool(locked_orientation_used)
                and delta_z > 1e-4
            )
            result = "OK" if ok else "FAIL"
        self.get_logger().info(
            "[CARTESIAN_DESCEND_PRECHECK]\n"
            "from_current_state=true\n"
            "orientation_source=%s\n"
            "locked_orientation_used=%s\n"
            "descend_hand_goal=%s\n"
            "pregrasp_tcp=%s\n"
            "grasp_tcp=%s\n"
            "delta_z=%.4f\n"
            "yaw_verified=%s\n"
            "centering_verified=%s\n"
            "target_collision_removed=%s\n"
            "result=%s"
            % (
                orientation_source,
                str(bool(locked_orientation_used)).lower(),
                "n/a"
                if descend_hand_goal is None
                else "(%.4f, %.4f, %.4f)" % descend_hand_goal,
                "n/a"
                if pre_tcp is None
                else "(%.4f, %.4f, %.4f)" % pre_tcp,
                "n/a"
                if gr_tcp is None
                else "(%.4f, %.4f, %.4f)" % gr_tcp,
                delta_z,
                str(bool(yaw_verified)).lower(),
                str(bool(centering_verified)).lower(),
                str(bool(target_collision_removed)).lower(),
                result,
            )
        )
        return ok

    def _log_cartesian_descend_execute(
        self,
        ok: bool,
        *,
        label: str = "",
        requested_tcp_z: Optional[float] = None,
        actual_tcp_z: Optional[float] = None,
        depth_gate_ok: Optional[bool] = None,
    ) -> None:
        fraction = self._read_cartesian_fraction()
        final_tcp = self._tcp_position_in_planning_frame()
        if final_tcp is None:
            final_str = "n/a"
        else:
            final_str = "(%.4f, %.4f, %.4f)" % final_tcp
        if actual_tcp_z is None and final_tcp is not None:
            actual_tcp_z = float(final_tcp[2])
        result = "OK" if ok else "FAIL"
        if (
            ok
            and requested_tcp_z is not None
            and actual_tcp_z is not None
            and abs(float(actual_tcp_z) - float(requested_tcp_z))
            > float(self._chips_can_descend_tcp_z_tolerance_m) + 1e-6
        ):
            result = "OK_BUT_TARGET_NOT_REACHED"
        if depth_gate_ok is False and label == "chips_can":
            if result == "OK":
                result = "OK_BUT_TARGET_NOT_REACHED"
        self.get_logger().info(
            "[CARTESIAN_DESCEND_EXECUTE]\n"
            "label=%s\n"
            "result=%s\n"
            "fraction=%s\n"
            "requested_tcp_z=%s\n"
            "actual_tcp_z=%s\n"
            "depth_gate_ok=%s\n"
            "final_tcp=%s"
            % (
                label or "n/a",
                result,
                "n/a" if fraction is None else "%.3f" % fraction,
                "n/a"
                if requested_tcp_z is None
                else "%.4f" % float(requested_tcp_z),
                "n/a"
                if actual_tcp_z is None
                else "%.4f" % float(actual_tcp_z),
                "n/a"
                if depth_gate_ok is None
                else str(bool(depth_gate_ok)).lower(),
                final_str,
            )
        )

    def _plan_before_motion_validate(
        self,
        candidate: Dict[str, Any],
        plan_targets: Dict[str, Tuple[float, float, float]],
        source_frame: str,
    ) -> bool:
        """Valida IK/plan desde HOME antes de mover el brazo (safe o pregrasp directo)."""
        if self._golden_execution_required_contract_active():
            self._golden_execution_contract_violation("PLAN_BEFORE_MOTION")
            return False
        if self._moveit2 is None or self._dry_run:
            return True
        if not self._wait_tf_ready_for_pick():
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] TF no listo para pick después de timeout"
            )
            return False

        self._reload_motion_waypoints()
        start_state_label = "home/current"
        start_js = self._current_arm_joint_state()
        if start_js is None:
            home_js = self._joint_state_for_waypoint("home")
            if home_js is not None:
                start_js = home_js
                start_state_label = "home/waypoint_yaml"
        if start_js is None:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] no joint start state (HOME)"
            )
            return False

        if self._set_start_state_to_current_before_planning:
            self._try_set_start_state_to_current()

        quat = self._resolve_execution_quaternion(candidate)
        if quat is None:
            self.get_logger().error("[PLAN_BEFORE_MOTION_FAIL] invalid quaternion")
            return False

        snap_center = (
            _xyz_from_list(candidate.get("grasp_center_base"))
            or _xyz_from_list(candidate.get("chosen_target_center_base"))
            or _xyz_from_list(candidate.get("position"))
        )
        snap_str = (
            "n/a"
            if snap_center is None
            else "(%.3f,%.3f,%.3f)" % snap_center
        )

        safe_tcp = plan_targets.get("safe_pregrasp_tcp")
        pre_tcp = plan_targets.get("pregrasp_tcp")
        gr_tcp = plan_targets.get("grasp_tcp")
        if pre_tcp is None or gr_tcp is None:
            self.get_logger().error("[PLAN_BEFORE_MOTION_FAIL] missing plan targets")
            return False
        safe_for_candidate_early = self._safe_pregrasp_stage_enabled_for_candidate(
            candidate
        )
        if safe_for_candidate_early and safe_tcp is None:
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] missing safe_pregrasp_tcp plan target"
            )
            return False

        base_cmd_raw = candidate.get("_base_commanded_tcp_yaw_rad")
        if base_cmd_raw is None:
            base_cmd_raw = candidate.get("_final_tcp_yaw_rad")
        try:
            base_yaw = float(base_cmd_raw) if base_cmd_raw is not None else 0.0
        except (TypeError, ValueError):
            base_yaw = 0.0

        if self._demo_golden_pick_fast_execute_active(
            label=str(candidate.get("label", "")),
            candidate=candidate,
        ):
            if self._apply_demo_golden_pick_fast_execute_plan_before_motion(
                candidate,
                plan_targets,
                source_frame,
                snap_str=snap_str,
                base_yaw=base_yaw,
            ):
                self.get_logger().info(
                    "[DEMO_LOW_RESOURCE_MODE]\n"
                    "label=%s\n"
                    "moveit_prevalidate=skipped\n"
                    "reachability_search=skipped\n"
                    "planning_scene_prevalidate=deferred_to_execution\n"
                    "reason=golden_fast_execute"
                    % str(candidate.get("label", ""))
                )
                return True
            self.get_logger().warning(
                "[GOLDEN_FAST_EXECUTE] compat/load failed; "
                "continuando con prevalidación normal"
            )

        label_for_routing = str(
            candidate.get("label", "") or self._target_label or ""
        ).strip().lower()
        if (
            label_for_routing == "chips_can"
            and self._chips_can_legacy_successful_pick_policy_active(candidate)
            and bool(getattr(self, "_chips_can_demo_golden_ready", False))
        ):
            golden = getattr(self, "_chips_can_demo_golden_payload", None)
            if not isinstance(golden, dict):
                golden = load_golden_pick_candidate(
                    self._resolve_demo_golden_candidate_yaml_path()
                )
            if isinstance(golden, dict):
                apply_golden_plan_targets(plan_targets, golden)
                apply_golden_runtime_overrides(candidate, golden)
            pre_tcp = plan_targets.get("pregrasp_tcp")
            gr_tcp = plan_targets.get("grasp_tcp")
            if pre_tcp is not None and gr_tcp is not None:
                pre_plan, _ = self._transform_target_to_planning_frame(
                    pre_tcp, source_frame, stage="plan_before_pre_chips_legacy"
                )
                gr_plan, _ = self._transform_target_to_planning_frame(
                    gr_tcp, source_frame, stage="plan_before_gr_chips_legacy"
                )
                if pre_plan is not None and gr_plan is not None:
                    legacy_ok = (
                        self._plan_before_motion_validate_chips_can_legacy_success_policy(
                            candidate,
                            snap_str=snap_str,
                            pre_plan=pre_plan,
                            gr_plan=gr_plan,
                            start_js=start_js,
                            start_state_label=start_state_label,
                            base_yaw=base_yaw,
                            plan_targets=plan_targets,
                            source_frame=source_frame,
                        )
                    )
                    if legacy_ok:
                        return True
                    fail_reason = str(
                        candidate.get("_plan_before_motion_fail_reason")
                        or "chips_can_legacy_plan_before_motion_failed"
                    )
                    self.get_logger().error(
                        "[PLAN_BEFORE_MOTION_FAIL] reason=%s; el robot no se moverá."
                        % fail_reason
                    )
                    return False

        self._ensure_pick_prevalidate_planning_scene(candidate)

        reach_result = self._apply_reachable_pregrasp_resolution(
            candidate=candidate,
            plan_targets=plan_targets,
            source_frame=source_frame,
            base_yaw=base_yaw,
            start_js=start_js,
        )
        if not bool(reach_result.get("ok", True)):
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] reason=%s"
                % str(reach_result.get("reason", "pregrasp_reachability_fail"))
            )
            return False
        if not self._verify_mustard_scanner_aligned_post_reachability_or_abort(
            candidate, plan_targets
        ):
            self.get_logger().error(
                "[PLAN_BEFORE_MOTION_FAIL] reason=mustard_scanner_contract_overwritten_after_verify"
            )
            return False
        pre_tcp = plan_targets.get("pregrasp_tcp")
        safe_tcp = plan_targets.get("safe_pregrasp_tcp")
        self._enforce_sugar_box_safe_tcp_on_plan_targets(candidate, plan_targets)
        pre_tcp = plan_targets.get("pregrasp_tcp")
        safe_tcp = plan_targets.get("safe_pregrasp_tcp")

        safe_plan: Optional[Tuple[float, float, float]] = None
        if safe_for_candidate_early and safe_tcp is not None:
            safe_plan, _ = self._transform_target_to_planning_frame(
                safe_tcp, source_frame, stage="plan_before_safe"
            )
        pre_plan, _ = self._transform_target_to_planning_frame(
            pre_tcp, source_frame, stage="plan_before_pre"
        )
        gr_plan, _ = self._transform_target_to_planning_frame(
            gr_tcp, source_frame, stage="plan_before_grasp"
        )
        if pre_plan is None or gr_plan is None:
            self.get_logger().error("[PLAN_BEFORE_MOTION_FAIL] TF to planning failed")
            return False
        if safe_plan is None and safe_for_candidate_early:
            self.get_logger().error("[PLAN_BEFORE_MOTION_FAIL] TF to planning failed")
            return False

        candidate["_pregrasp_tcp_planning"] = [
            float(pre_plan[0]),
            float(pre_plan[1]),
            float(pre_plan[2]),
        ]

        safe_for_candidate = self._safe_pregrasp_stage_enabled_for_candidate(candidate)
        self._log_pick_route_preplan_start(
            candidate, safe_pregrasp_enabled=safe_for_candidate
        )
        self._log_chips_can_safe_pregrasp_policy(
            candidate, reason="direct_pregrasp_validated_before_motion"
        )

        if not safe_for_candidate:
            if sugar_box_multiobject_full_pick_prevalidate_required(candidate):
                self.get_logger().info(
                    "[SUGAR_BOX_MULTIOBJECT_FULL_PICK_ROUTE_PREVALIDATE_START]\n"
                    "label=sugar_box\n"
                    "route=home->pick_workspace_ready->object_safe_above->pregrasp->grasp\n"
                    "result=START"
                )
                candidate.pop("_simple_direct_pick_route", None)
                candidate["_sugar_box_selected_route"] = "object_safe_above"
                candidate["selected_entry_target"] = "object_safe_above_tcp"
                return self._prevalidate_full_pick_route_before_motion(
                    candidate,
                    plan_targets=plan_targets,
                    source_frame=source_frame,
                    snap_str=snap_str,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    start_js=start_js,
                    start_state_label=start_state_label,
                    base_yaw=base_yaw,
                )
            if simple_direct_pick_route_prevalidate_required(
                candidate,
                enable_pick_workspace_prelude=self._enable_pick_workspace_prelude,
                plan_before_prelude_skip_workspace_prelude=(
                    self._plan_before_prelude_skip_workspace_prelude
                ),
            ):
                self.get_logger().info(
                    "[SAFE_PREGRASP_STAGE] disabled; simple direct pick route "
                    "(pick_workspace_ready->pregrasp->vertical_descend, no high object_safe_above)"
                )
                return self._prevalidate_simple_direct_pick_route_before_motion(
                    candidate,
                    plan_targets=plan_targets,
                    source_frame=source_frame,
                    snap_str=snap_str,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    start_js=start_js,
                    start_state_label=start_state_label,
                    base_yaw=base_yaw,
                )
            if self._object_safe_above_stage_required(candidate, plan_targets):
                self.get_logger().info(
                    "[SAFE_PREGRASP_STAGE] disabled; object_safe_above route required "
                    "(multiobject + target collision + close pregrasp)"
                )
                if (
                    self._enable_pick_workspace_prelude
                    and not self._plan_before_prelude_skip_workspace_prelude
                ):
                    return self._prevalidate_full_pick_route_before_motion(
                        candidate,
                        plan_targets=plan_targets,
                        source_frame=source_frame,
                        snap_str=snap_str,
                        pre_plan=pre_plan,
                        gr_plan=gr_plan,
                        start_js=start_js,
                        start_state_label=start_state_label,
                        base_yaw=base_yaw,
                    )
                self.get_logger().error(
                    "[PLAN_BEFORE_MOTION_FAIL] reason=pick_workspace_prelude_required "
                    "detail=object_safe_above_route"
                )
                candidate["_plan_before_motion_fail_reason"] = (
                    "pick_workspace_prelude_required"
                )
                return False
            self.get_logger().info(
                "[SAFE_PREGRASP_STAGE] disabled; plan_before_motion validates "
                "pregrasp directly (no local safe_pregrasp plan)"
            )
            return self._plan_before_motion_validate_direct_pregrasp(
                candidate,
                snap_str=snap_str,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                start_js=start_js,
                start_state_label=start_state_label,
                base_yaw=base_yaw,
                plan_targets=plan_targets,
                source_frame=source_frame,
            )

        if self._sugar_box_force_safe_pregrasp_when_obstacles_active(candidate):
            if safe_plan is None:
                self.get_logger().error(
                    "[PLAN_BEFORE_MOTION_FAIL] reason=no_safe_entry_ik "
                    "detail=missing_safe_plan_tf"
                )
                return False
            if self._sugar_box_use_two_phase_pick_route(candidate):
                return self._plan_before_motion_validate_sugar_box_phase1_workspace(
                    candidate,
                    start_js=start_js,
                    start_state_label=start_state_label,
                )
            return self._plan_before_motion_validate_sugar_box_multiobject_safe_route(
                candidate,
                snap_str=snap_str,
                plan_targets=plan_targets,
                source_frame=source_frame,
                start_js=start_js,
                start_state_label=start_state_label,
                base_yaw=base_yaw,
                pre_plan=pre_plan,
                gr_plan=gr_plan,
                safe_xy_plan=(float(safe_plan[0]), float(safe_plan[1])),
            )

        top_z = candidate.get("top_z_m")
        if top_z is None:
            top_z = _to_float(candidate.get("top_z_estimated"))
        pregrasp_tcp_z = float(pre_tcp[2])
        z_candidates = [float(safe_plan[2])]
        z_candidates.extend(
            self._safe_pregrasp_tcp_z_fallback_values(
                plan_targets,
                float(top_z) if top_z is not None else pregrasp_tcp_z,
                pregrasp_tcp_z,
            )
        )
        seen_z: set = set()
        z_unique: List[float] = []
        for z in z_candidates:
            zr = round(float(z), 4)
            if zr not in seen_z:
                seen_z.add(zr)
                z_unique.append(float(z))

        ik_safe = "SKIP"
        ik_pre = "SKIP"
        plan_safe = "SKIP"
        best_detail = ""
        ori_tol = float(self._plan_before_prelude_orientation_tolerance)

        for z_try in z_unique:
            tcp_try = (float(safe_plan[0]), float(safe_plan[1]), float(z_try))
            ranked = self._ranked_pregrasp_yaw_variants_for_pose(
                candidate, base_yaw, tcp_try, start_js
            )
            for qname, q, cmd_yaw, ik_sol, joint_dist in ranked:
                try:
                    moveit_pose = self._tcp_pose_to_moveit_pose(tcp_try, q)
                except Exception as exc:
                    best_detail = "tcp_to_moveit_fail:%s" % exc
                    continue
                try:
                    pos_ik = [
                        float(moveit_pose[0]),
                        float(moveit_pose[1]),
                        float(moveit_pose[2]),
                    ]
                    quat_ik = [
                        float(q[0]),
                        float(q[1]),
                        float(q[2]),
                        float(q[3]),
                    ]
                    self.get_logger().info(
                        "[IK_CHECK] target_link=%s position=(%.3f, %.3f, %.3f) "
                        "quat=(%.4f, %.4f, %.4f, %.4f) stage=safe_pregrasp "
                        "variant=%s joint_dist=%.4f"
                        % (
                            str(self._moveit_target_link),
                            pos_ik[0],
                            pos_ik[1],
                            pos_ik[2],
                            quat_ik[0],
                            quat_ik[1],
                            quat_ik[2],
                            quat_ik[3],
                            qname,
                            joint_dist,
                        )
                    )
                except Exception:
                    pass
                if ik_sol is None:
                    ik_safe = "FAIL"
                    continue
                ik_safe = "OK"
                plan_start_js = ik_sol if ik_sol is not None else start_js
                try:
                    traj = self._moveit2.plan(
                        position=list(moveit_pose),
                        quat_xyzw=list(q),
                        frame_id=self._planning_frame,
                        target_link=self._moveit_target_link,
                        start_joint_state=plan_start_js,
                        tolerance_orientation=ori_tol,
                    )
                except Exception as exc:
                    traj = None
                    best_detail = "plan_exception:%s" % exc
                if traj is None:
                    plan_safe = "FAIL"
                    continue
                plan_safe = "OK"
                try:
                    pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                    pos_pre = [
                        float(pre_moveit[0]),
                        float(pre_moveit[1]),
                        float(pre_moveit[2]),
                    ]
                    quat_pre = [
                        float(q[0]),
                        float(q[1]),
                        float(q[2]),
                        float(q[3]),
                    ]
                    self.get_logger().info(
                        "[IK_CHECK] target_link=%s position=(%.3f, %.3f, %.3f) "
                        "quat=(%.4f, %.4f, %.4f, %.4f) stage=pregrasp"
                        % (
                            str(self._moveit_target_link),
                            pos_pre[0],
                            pos_pre[1],
                            pos_pre[2],
                            quat_pre[0],
                            quat_pre[1],
                            quat_pre[2],
                            quat_pre[3],
                        )
                    )
                    ik_pre_sol = self._moveit2.compute_ik(
                        position=pos_pre,
                        quat_xyzw=quat_pre,
                        ik_link_name=self._moveit_target_link,
                        start_joint_state=plan_start_js,
                        wait_for_server_timeout_sec=1.0,
                    )
                    ik_pre = "OK" if ik_pre_sol is not None else "FAIL"
                except Exception:
                    ik_pre = "FAIL"
                if ik_pre != "OK" or ik_pre_sol is None:
                    continue
                plan_before_result = "OK_SAFE_PREGRASP"
                if self._demo_full_pick_route_prevalidation_required(candidate):
                    if abs(float(safe_plan[2]) - float(pre_plan[2])) > 1e-3:
                        pre_moveit = self._tcp_pose_to_moveit_pose(pre_plan, q)
                        safe_frac, _ = self._plan_cartesian_fraction_from_joint_state(
                            plan_start_js, pre_moveit, q
                        )
                        if (
                            safe_frac is None
                            or float(safe_frac) + 1e-6
                            < float(self._cartesian_fraction_threshold)
                        ):
                            best_detail = (
                                "variant=%s safe_to_pregrasp_cartesian_fail"
                                % qname
                            )
                            continue
                    cart_ok, _frac, cart_deferred = (
                        self._prevalidate_cartesian_descend_for_pick_route(
                            candidate,
                            pre_plan,
                            gr_plan,
                            q,
                            ik_pre_sol,
                            stage_label="pregrasp_to_grasp",
                        )
                    )
                    if not cart_ok:
                        best_detail = (
                            "variant=%s cartesian_descend_prevalidate_fail" % qname
                        )
                        continue
                    plan_before_result = (
                        "OK_PREGRASP_PENDING_DESCEND_VALIDATE"
                        if cart_deferred
                        else "OK_FULL_PICK_ROUTE"
                    )
                best_detail = "variant=%s z=%.3f joint_dist=%.4f" % (
                    qname,
                    z_try,
                    joint_dist,
                )
                self._store_plan_before_motion_validated(
                    candidate,
                    plan_targets,
                    source_frame,
                    variant_name=qname,
                    quat=q,
                    moveit_hand_pose=(
                        float(moveit_pose[0]),
                        float(moveit_pose[1]),
                        float(moveit_pose[2]),
                    ),
                    validated_tcp_z_planning=float(z_try),
                    safe_plan_xy=(float(safe_plan[0]), float(safe_plan[1])),
                )
                self._store_pregrasp_plan_preflight_status(
                    candidate,
                    ik_pregrasp=ik_pre,
                    plan_pregrasp=plan_safe,
                    ik_grasp="SKIP",
                    plan_before_result=plan_before_result,
                )
                self._store_preplanned_pick_route(
                    candidate,
                    plan_targets,
                    source_frame,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    quat=q,
                    variant_name=qname,
                    safe_pregrasp_enabled=True,
                    route_source="plan_before_motion_safe_pregrasp",
                )
                self._log_pick_route_preplan_selected(
                    candidate,
                    variant_name=qname,
                    pre_plan=pre_plan,
                    gr_plan=gr_plan,
                    ik_pregrasp=ik_pre,
                    plan_pregrasp=plan_safe,
                    ik_grasp="SKIP",
                    safe_pregrasp_enabled=True,
                    result="OK",
                )
                self.get_logger().info(
                    "[PLAN_BEFORE_MOTION]\n"
                    "snapshot_center=%s\n"
                    "target_safe_pregrasp=(%.3f, %.3f, %.3f)\n"
                    "target_pregrasp=(%.3f, %.3f, %.3f)\n"
                    "target_grasp=(%.3f, %.3f, %.3f)\n"
                    "ik_safe_pregrasp=%s\n"
                    "ik_pregrasp=%s\n"
                    "plan_safe_pregrasp=%s\n"
                    "pregrasp_plan_ok=true\n"
                    "motion_authorized=false\n"
                    "motion_authorization_source=EXECUTION_PREFLIGHT\n"
                    "start_state=%s\n"
                    "detail=%s"
                    % (
                        snap_str,
                        moveit_pose[0],
                        moveit_pose[1],
                        moveit_pose[2],
                        pre_plan[0],
                        pre_plan[1],
                        pre_plan[2],
                        gr_plan[0],
                        gr_plan[1],
                        gr_plan[2],
                        ik_safe,
                        ik_pre,
                        plan_safe,
                        start_state_label,
                        best_detail,
                    )
                )
                return True

        self.get_logger().error(
            "[PLAN_BEFORE_MOTION]\n"
            "snapshot_center=%s\n"
            "target_safe_pregrasp=(%.3f, %.3f, %.3f)\n"
            "target_pregrasp=(%.3f, %.3f, %.3f)\n"
            "target_grasp=(%.3f, %.3f, %.3f)\n"
            "ik_safe_pregrasp=%s\n"
            "ik_pregrasp=%s\n"
            "plan_safe_pregrasp=%s\n"
            "start_state=%s\n"
            "detail=%s"
            % (
                snap_str,
                safe_plan[0],
                safe_plan[1],
                safe_plan[2],
                pre_plan[0],
                pre_plan[1],
                pre_plan[2],
                gr_plan[0],
                gr_plan[1],
                gr_plan[2],
                ik_safe,
                ik_pre,
                plan_safe,
                start_state_label,
                best_detail or "exhausted_variants",
            )
        )
        return False

    def _log_mode_explain_pregrasp(self) -> None:
        if self._execution_mode_canonical != "pregrasp":
            return
        self.get_logger().info(
            "[MODE_EXPLAIN] execution_mode=pregrasp only moves to pregrasp and "
            "opens gripper; it will not descend/close/attach/lift."
        )
        if self._return_home_after_execution:
            self.get_logger().info(
                "[MODE_EXPLAIN] return_home_after_execution=true so robot will "
                "return HOME after visual pregrasp."
            )
        else:
            self.get_logger().info(
                "[MODE_EXPLAIN] return_home_after_execution=false so robot will "
                "stay at pregrasp (no automatic return HOME)."
            )

    def _finalize_execution_cycle(self) -> None:
        if self._execution_cycle_mode == "snapshot_execute_home":
            home_return_ok = True
            attempted_home_return = False
            already_home_after_place = bool(self._already_returned_home_after_place)
            home_ok_after_place = bool(self._home_return_ok_after_place)
            if already_home_after_place and home_ok_after_place:
                self.get_logger().info(
                    "[CYCLE] execution finished; home already reached by post-place return; perception resumed"
                )
            elif already_home_after_place and not home_ok_after_place:
                self.get_logger().error(
                    "[CYCLE] execution finished; post-place return failed; skipping duplicate HOME attempt"
                )
            elif self._return_home_after_execution and not self._dry_run:
                if bool(getattr(self, "_attached_object_recovery_hold", False)):
                    self.get_logger().info(
                        "[CYCLE] execution finished; attached object recovery hold active; "
                        "skipping MOVE_HOME"
                    )
                else:
                    self.get_logger().info("[CYCLE] execution finished; returning HOME")
            else:
                self.get_logger().info(
                    "[CYCLE] execution finished; staying at current pose because "
                    "return_home_after_execution=false"
                )
            if (
                self._execution_mode_canonical == "pregrasp"
                and self._return_home_after_execution
            ):
                self._log_mode_explain_pregrasp()
            if (
                not already_home_after_place
                and self._return_home_after_execution
                and not self._dry_run
                and not bool(getattr(self, "_attached_object_recovery_hold", False))
            ):
                if self._moveit2 is not None:
                    attempted_home_return = True
                    self.get_logger().info(
                        "[CYCLE] returning home before unlocking perception"
                    )
                    home_return_ok = bool(self._move_home_now(dry_run=False))
                    if home_return_ok:
                        self.get_logger().info(
                            "[CYCLE] home reached; perception resumed"
                        )
                    else:
                        self.get_logger().error(
                            "[HOME_FAILED]\n"
                            "attempts=%d\n"
                            "reason=move_home_failed\n"
                            "perception_resumed=false"
                            % max(
                                1, int(self._return_home_after_place_planning_attempts)
                            )
                        )
                else:
                    attempted_home_return = True
                    home_return_ok = False
                    self.get_logger().warning(
                        "[CYCLE] MoveIt no disponible; no se puede volver a home."
                    )
            should_resume = bool(self._resume_perception_after_home)
            if already_home_after_place and not home_ok_after_place:
                should_resume = False
            if attempted_home_return and not home_return_ok:
                should_resume = False
            if should_resume:
                self._resume_perception_processing()
            elif already_home_after_place and not home_ok_after_place:
                self.get_logger().error(
                    "[CYCLE] perception_resumed=false (post-place HOME failed)"
                )
            elif attempted_home_return and not home_return_ok:
                self.get_logger().error(
                    "[CYCLE] perception_resumed=false (HOME not reached)"
                )
            self.get_logger().info(
                "[CYCLE] perception unlocked; ready for next snapshot"
            )
        else:
            self._resume_perception_processing()

    def run_pending_snapshot_once(self) -> None:
        with self._pipeline_lock:
            if self._pipeline_running:
                return
            if self._pending_snapshot is None:
                return
            job = self._pending_snapshot
            self._pending_snapshot = None
            self._pipeline_running = True

        try:
            candidate, plan_targets, source_frame = job
            self._inject_deposit_slot_request_into_candidate(candidate)
            if self._enrich_chips_can_runtime_pose_from_gazebo(candidate):
                refreshed_targets = self._compute_pregrasp(candidate)
                if refreshed_targets is not None:
                    plan_targets = refreshed_targets
            self._execution_state_reset_on_start()
            if self._candidate_benchmark_mode_active():
                self._use_golden_execution_candidate = False
                self._require_golden_execution_candidate = False
                self._paired_grid_accept_first_valid = False
                if self._candidate_benchmark_record_golden:
                    self._golden_execution_record = True
            golden_decision = self._golden_execution_mode_lock_and_validate(candidate)
            if self._golden_execution_scope_active() and self._use_golden_execution_candidate:
                golden_flow_result = self._handle_golden_execution_flow(
                    candidate,
                    plan_targets,
                    source_frame,
                    decision=golden_decision,
                )
                if golden_flow_result in ("EXECUTED_OK", "EXECUTED_FAIL", "ABORTED"):
                    return
            if self._plan_before_prelude:
                if not self._plan_before_motion_validate(
                    candidate, plan_targets, source_frame
                ):
                    fail_reason = str(
                        candidate.get("_plan_before_motion_fail_reason")
                        or "no_valid_ik_plan_from_home"
                    )
                    self.get_logger().error(
                        "[PLAN_BEFORE_MOTION_FAIL] reason=%s; el robot no se moverá."
                        % fail_reason
                    )
                    return
            if not self._validate_execution_preflight_before_motion(
                candidate, plan_targets, source_frame
            ):
                return
            if candidate.get("_golden_execution_replay_active"):
                replay_ok = self._execute_golden_execution_replay(candidate)
                if replay_ok and self._golden_execution_recorder is not None:
                    self._golden_execution_recorder.update(
                        {
                            "pick_ok": True,
                            "lift_ok": True,
                            "transport_ok": True,
                            "place_ok": True,
                            "return_home_ok": True,
                        }
                    )
                self._maybe_save_golden_execution_candidate(
                    candidate, plan_targets=plan_targets
                )
                if not replay_ok:
                    self.get_logger().error(
                        "[GOLDEN_EXECUTION_REPLAY] result=FAIL; aborting cycle"
                    )
                return
            skip_prelude = (
                self._plan_before_prelude
                and self._plan_before_prelude_skip_workspace_prelude
            )
            if not skip_prelude:
                self._log_pick_prelude_execution_contract(candidate)
                if not self._run_pick_workspace_prelude():
                    return
                if self._sugar_box_use_two_phase_pick_route(candidate):
                    if not self._post_prelude_validate_sugar_box_pick_route(
                        candidate, plan_targets, source_frame
                    ):
                        self.get_logger().error(
                            "[POST_PRELUDE_PICK_ROUTE_VALIDATE] result=FAIL "
                            "reason=no_full_route_from_pick_workspace_ready; "
                            "volviendo a HOME sin acercarse al objeto."
                        )
                        self._move_home_now(
                            dry_run=False, reason="post_prelude_route_failed"
                        )
                        return
                if self._require_full_pick_route_preplanned_before_prelude:
                    if not self._post_prelude_execute_cached_pregrasp(
                        candidate, plan_targets, source_frame
                    ):
                        self.get_logger().error(
                            "[POST_PRELUDE_PREGRASP_EXECUTE_CACHED] abortando ejecución: "
                            "ruta cacheada no ejecutable desde pick_workspace_ready."
                        )
                        return
                elif not self._post_prelude_pregrasp_replan(
                    candidate, plan_targets, source_frame
                ):
                    self.get_logger().error(
                        "[POST_PRELUDE_PREGRASP_REPLAN] abortando ejecución: "
                        "pregrasp no alcanzable desde pick_workspace_ready."
                    )
                    return
            elif self._plan_before_prelude:
                self.get_logger().info(
                    "[PLAN_BEFORE_MOTION] omitiendo pick_workspace_ready; "
                    "plan validado desde HOME"
                )
            self._run_snapshot(candidate, plan_targets, source_frame)
        except Exception:
            self.get_logger().error(
                "Pipeline fallo:\n" + traceback.format_exc()
            )
        finally:
            try:
                self._finalize_execution_cycle()
            finally:
                with self._pipeline_lock:
                    self._pipeline_running = False
                    self._snapshot_locked = False
                    self._logged_cycle_ignore_updates = False
                    if self._execute_once or self._shutdown_when_finished:
                        self._finished = True

    def _get_detection_list(self, data: Dict[str, Any]) -> Tuple[List[Any], Optional[str]]:
        for key in ("objects", "detections", "results", "items"):
            value = data.get(key)
            if isinstance(value, list):
                return value, key
        return [], None

    def _log_first_payload(
        self, payload: Dict[str, Any], detections: List[Any], source_key: str
    ) -> None:
        self.get_logger().info(f"Primer JSON: claves principales={list(payload.keys())}")
        self.get_logger().info(
            f"Primer JSON: key de lista='{source_key}', numero de detecciones={len(detections)}"
        )
        if detections:
            sample = detections[0]
            if isinstance(sample, dict):
                sample_pos = self._get_position(sample)
                sample_approach = self._get_approach_position(sample)
                preview = {
                    "keys": list(sample.keys()),
                    "label": self._get_label(sample),
                    "score": self._get_score(sample),
                    "position": sample_pos,
                    "approach_position": sample_approach,
                    "yaw": self._get_optional_yaw(sample),
                    "table_filter_pass": False
                    if sample_pos is None
                    else (True if not self._enable_table_filter else self._in_table_volume(sample_pos)),
                }
                self.get_logger().info(f"Ejemplo deteccion[0]: {preview}")
            else:
                self.get_logger().warning("detections[0] no es dict; parser tolerante continuara.")

    def _get_label(self, det: Dict[str, Any]) -> str:
        for key in ("label", "id", "class_name", "name"):
            value = det.get(key)
            if value is not None and str(value).strip():
                return str(value).strip()
        return ""

    def _get_score(self, det: Dict[str, Any]) -> float:
        for key in ("score", "confidence", "conf"):
            if key in det:
                casted = _to_float(det.get(key))
                if casted is not None:
                    return casted
        return 0.0

    def _extract_xyz_dict(self, container: Any) -> Optional[Tuple[float, float, float]]:
        if not isinstance(container, dict):
            return None
        x = _to_float(container.get("x"))
        y = _to_float(container.get("y"))
        z = _to_float(container.get("z"))
        if x is None or y is None or z is None:
            return None
        return (x, y, z)

    def _get_position(self, det: Dict[str, Any]) -> Optional[Tuple[float, float, float]]:
        for key in (
            "grasp_center_base",
            "position",
            "centroid_base",
            "center_3d",
            "centroid",
        ):
            raw = det.get(key)
            pos = _xyz_from_list(raw)
            if pos is not None:
                return pos
            pos = self._extract_xyz_dict(raw)
            if pos is not None:
                return pos

        pose = det.get("pose")
        if isinstance(pose, dict):
            pos = self._extract_xyz_dict(pose.get("position"))
            if pos is not None:
                return pos

        return None

    def _get_approach_position(self, det: Dict[str, Any]) -> Optional[Tuple[float, float, float]]:
        raw = det.get("approach_position")
        pos = _xyz_from_list(raw)
        if pos is not None:
            return pos
        return self._extract_xyz_dict(raw)

    def _get_optional_yaw(self, det: Dict[str, Any]) -> Optional[float]:
        for key in ("yaw", "yaw_rad", "obb_yaw", "grasp_yaw_rad"):
            yaw = _to_float(det.get(key))
            if yaw is not None:
                return yaw
        yaw_deg = _to_float(det.get("yaw_deg"))
        if yaw_deg is not None:
            return math.radians(yaw_deg)
        return None

    def _extract_grasp_yaw(self, det: Dict[str, Any]) -> Optional[float]:
        source = self._grasp_yaw_source.lower()
        if source == "grasp_yaw_deg":
            yaw_deg = _to_float(det.get("grasp_yaw_deg"))
            return None if yaw_deg is None else math.radians(yaw_deg)
        yaw_rad = _to_float(det.get("grasp_yaw_rad"))
        if yaw_rad is not None:
            return yaw_rad
        yaw_deg = _to_float(det.get("grasp_yaw_deg"))
        return None if yaw_deg is None else math.radians(yaw_deg)

    def _merge_grasp_policy_from_label(self, entry: Dict[str, Any]) -> Dict[str, Any]:
        """Aplica política canónica (anchura efectiva) sobre el candidato."""
        if not self._use_object_profile_params:
            return entry
        label = str(entry.get("label", "")).strip()
        if not label:
            return entry
        mp = export_grasp_policy_for_executor(
            label,
            measured_footprint_major_m=entry.get("footprint_major_m"),
            measured_footprint_minor_m=entry.get("footprint_minor_m"),
            measured_height_m=entry.get("measured_height_m"),
            use_measured_dimensions=False,
            edge_offset_m=entry.get("edge_offset_m"),
        )
        entry = merge_grasp_policy_preserving_runtime_gt(entry, mp)
        normalize_demo_grasp_sources(entry)
        return entry

